const genId=()=>Date.now().toString(36)+Math.random().toString(36).substr(2);
const encodeShare=data=>btoa(encodeURIComponent(JSON.stringify(data)));
const copyToClipboard=(text,msg='링크가 복사되었습니다! 카카오톡에 붙여넣기 하세요.')=>{
  if(navigator.clipboard){navigator.clipboard.writeText(text).then(()=>alert(msg)).catch(()=>{prompt('링크를 직접 복사하세요:',text);});}
  else{prompt('링크를 직접 복사하세요:',text);}
};
const fWon=v=>`₩${Number(v||0).toLocaleString()}`;
const fDate=d=>d||'-';
const today=()=>{const d=new Date();return`${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,'0')}-${String(d.getDate()).padStart(2,'0')}`;};
// 납부기한 계산 공통 함수
// setting.mode === 'fixed'  → 다음달 setting.fixedDay일
// setting.mode === 'joinDate' → 다음달 joinDate의 일(day)과 동일한 날
const calcTuitionDueDate=(joinDate,monthStr,setting)=>{
  const[cy,cm]=monthStr.split('-').map(Number);
  const ny=cm===12?cy+1:cy, nm=cm===12?1:cm+1;
  let day=1;
  if(setting&&setting.mode==='fixed'){
    day=Number(setting.fixedDay)||1;
  }else{
    day=Number((joinDate||today()).split('-')[2])||1;
  }
  day=Math.min(day,new Date(ny,nm,0).getDate());
  return`${ny}-${String(nm).padStart(2,'0')}-${String(day).padStart(2,'0')}`;
};
const sColor=s=>({active:'bg-green-100 text-green-700',inactive:'bg-gray-100 text-slate-600'}[s]||'bg-gray-100 text-slate-600');
const inp="w-full border border-gray-300 rounded-lg px-3 py-2 text-sm text-slate-900 focus:border-[#1e3a5f] focus:ring-1 focus:ring-[#1e3a5f]";
const btn=(c='indigo')=>`px-4 py-2 rounded-lg font-semibold text-sm cursor-pointer transition-colors `+
  (c==='indigo'?'bg-[#1e3a5f] text-white hover:bg-[#152d4a]':
   c==='red'?'bg-red-600 text-white hover:bg-red-700':
   c==='gray'?'bg-slate-100 text-slate-800 hover:bg-slate-200':
   c==='green'?'bg-emerald-600 text-white hover:bg-emerald-700':
   c==='orange'?'bg-amber-600 text-white hover:bg-amber-700':
   c==='blue'?'bg-blue-600 text-white hover:bg-blue-700':'');

