notices:[
  {id:'n1',date:'2025-10-01',category:'공지',title:'10월 학원 운영 안내',content:'안녕하세요, 하모니 피아노 학원입니다. 10월 공휴일(10/3 개천절, 10/9 한글날)은 휴원합니다. 정상 수업일에 맞춰 출석 부탁드립니다.',target:'전체',important:true},
  {id:'n2',date:'2025-10-10',category:'행사',title:'10월 학부모 참관 수업 안내',content:'10월 18일(토) 오후 2시 학부모 참관 수업을 진행합니다. 학생들의 성장을 직접 확인하실 수 있는 소중한 시간입니다. 많은 참석 바랍니다.',target:'전체',important:true},
  {id:'n3',date:'2025-10-25',category:'안내',title:'11월 수업료 납부 안내',content:'11월 수업료 납부 기한은 11월 10일(월)까지입니다. 계좌이체, 카드 결제 모두 가능합니다.',target:'전체',important:false},
  {id:'n4',date:'2025-11-05',category:'행사',title:'피아노 합주 워크숍 안내',content:'11월 8일(토) 중·고급반 학생들을 대상으로 합주 워크숍을 진행합니다. 앙상블 경험을 통해 음악성을 키울 수 있는 특별한 기회입니다.',target:'중급반 (체르니30·소나티네)',important:false},
  {id:'n5',date:'2025-11-20',category:'행사',title:'2025 겨울 발표회 안내',content:'12월 20일(토) 오후 3시, 연말 정기 발표회를 개최합니다. 장소: 학원 발표홀. 모든 반 학생들이 참가합니다.',target:'전체',important:true},
  {id:'n6',date:'2025-12-01',category:'공지',title:'12월 연말 수업 일정',content:'12월 25일(수) 성탄절 휴원. 나머지 수업은 정상 진행됩니다. 발표회 준비 열심히 해주세요!',target:'전체',important:false},
  {id:'n7',date:'2025-12-21',category:'행사',title:'겨울 발표회 성료!',content:'어제 겨울 발표회에 참석해 주신 학부모님께 감사드립니다. 모든 학생이 멋진 무대를 선보였습니다. 사진은 학원 SNS에 공유드립니다.',target:'전체',important:false},
  {id:'n8',date:'2026-01-02',category:'공지',title:'2026년 새해 인사 및 1월 수업 안내',content:'새해 복 많이 받으세요! 1월 수업은 1월 5일(월)부터 정상 운영됩니다. 올해도 하모니 피아노 학원과 함께해 주세요!',target:'전체',important:true},
  {id:'n9',date:'2026-01-15',category:'긴급',title:'콩쿠르반 특강 안내',content:'1월 17일(토) 오전 10시 콩쿠르·입시 집중반 특강을 진행합니다. 전국 대회 준비를 위한 필수 참석 수업입니다.',target:'콩쿠르·입시 집중반',important:true},
  {id:'n10',date:'2026-02-01',category:'공지',title:'신학기 수업 안내 및 신입생 모집',content:'3월 신학기를 앞두고 레벨 테스트를 통한 반 편성을 진행합니다. 신입생 모집 중이니 주변에 많이 알려주세요!',target:'전체',important:false},
  {id:'n11',date:'2026-02-14',category:'행사',title:'졸업 시즌 특별 레슨',content:'2월 졸업 시즌 기념 특별 레슨을 진행합니다. 새 학년을 앞두고 실력을 한층 더 업그레이드해요!',target:'전체',important:false},
  {id:'n12',date:'2026-03-03',category:'공지',title:'3월 신학기 시작!',content:'신학기 수업이 시작됩니다. 새로 등록하신 학생 여러분 환영합니다! 레슨실 배정 및 시간표는 학원으로 문의 주세요.',target:'전체',important:true},
  {id:'n13',date:'2026-03-20',category:'안내',title:'봄 발표회 준비 안내',content:'4월 12일 봄 미니 발표회를 앞두고 발표곡 준비에 집중해 주세요. 의상은 단정하게 준비해 주시기 바랍니다.',target:'전체',important:false},
  {id:'n14',date:'2026-04-01',category:'행사',title:'봄 발표회 최종 안내',content:'4월 12일(일) 오후 2시, 봄 미니 발표회가 진행됩니다. 학부모 좌석은 선착순 배정, 건물 지하 주차장 이용 바랍니다.',target:'전체',important:true},
  {id:'n15',date:'2026-04-13',category:'행사',title:'봄 발표회 성황리에 마무리!',content:'봄 미니 발표회에 참석해 주신 모든 분께 감사드립니다. 유아반부터 콩쿠르반까지 훌륭한 무대를 선보였습니다!',target:'전체',important:false}
],
