function useLS(key,init){
  const[val,setVal]=useState(()=>{if(isBlank)return Array.isArray(init)?[]:init;try{const s=localStorage.getItem(key);return s?JSON.parse(s):init;}catch{return init;}});
  const update=useCallback(v=>{const next=typeof v==='function'?v(val):v;setVal(next);if(!isBlank){localStorage.setItem(key,JSON.stringify(next));const tbl=SUPABASE_TABLES[key];if(tbl&&Array.isArray(next))dbSync(tbl,next);}},[key,val]);
  return[val,update];
}

// ── 공통 컴포넌트 ────────────────────────────────────────────────────────────
function Modal({open,onClose,title,children,wide}){
  if(!open)return null;
  return<div className="modal-overlay" onClick={e=>e.target===e.currentTarget&&onClose()}>
    <div className={`modal-box shadow-2xl ${wide?'modal-wide':''}`}>
      <div className="flex items-center justify-between p-5 border-b">
        <h3 className="text-lg font-bold text-slate-900">{title}</h3>
        <button onClick={onClose} className="w-8 h-8 flex items-center justify-center rounded-full hover:bg-gray-100 text-slate-600 text-xl">&times;</button>
      </div>
      <div className="p-5">{children}</div>
    </div>
  </div>;
}
function Field({label,children,required}){
  return<div className="mb-4">
    <label className="block text-sm font-semibold text-slate-900 mb-1">{label}{required&&<span className="text-red-500 ml-1">*</span>}</label>
    {children}
  </div>;
}
function Confirm({open,msg,onYes,onNo}){
  if(!open)return null;
  return<div className="modal-overlay"><div className="modal-box max-w-sm shadow-2xl p-6 text-center">
    <div className="text-4xl mb-3">⚠️</div>
    <p className="text-slate-800 mb-5">{msg}</p>
    <div className="flex gap-3 justify-center">
      <button className={btn('gray')} onClick={onNo}>취소</button>
      <button className={btn('red')} onClick={onYes}>삭제</button>
    </div>
  </div></div>;
}
function WonInput({value,onChange,placeholder,free=false}){
  const[local,setLocal]=useState(value===''||value==null?'':String(value));
  useEffect(()=>{setLocal(value===''||value==null?'':String(value));},[value]);
  const clamp=v=>{
    let n=Math.round(Number(v)||0);
    if(n<0)n=0;
    // free=true이면 1원 단위 허용 (예산 수입/지출), false이면 만원 단위 반올림 (수강료·급여)
    if(!free)n=Math.round(n/10000)*10000;
    return n;
  };
  return<input type="number" className={inp} step={free?1:10000} min={0} placeholder={placeholder}
    value={local}
    onChange={e=>setLocal(e.target.value)}
    onBlur={()=>{const n=clamp(local);setLocal(n===0&&local===''?'':String(n));onChange(n);}}/>;
}
function CountInput({value,onChange,placeholder,min=1}){
  const[local,setLocal]=useState(value===''||value==null?'':String(value));
  useEffect(()=>{setLocal(value===''||value==null?'':String(value));},[value]);
  const clamp=v=>{
    let n=parseInt(v,10);
    if(isNaN(n)||n<min)n=min;
    return n;
  };
  return<input type="text" inputMode="numeric" pattern="[0-9]*" className={inp} placeholder={placeholder}
    value={local}
    onChange={e=>{const digitsOnly=e.target.value.replace(/[^0-9]/g,'');setLocal(digitsOnly);}}
    onBlur={()=>{const n=clamp(local);setLocal(String(n));onChange(n);}}/>;
}

// ── 대시보드 상세 모달 ───────────────────────────────────────────────────────
function DashboardDetail({type,teachers,students,classes,income,expenses,onClose,setPage,role}){
  const titles={teacher:'👨‍🏫 강사 현황 상세',student:'🎓 학생 현황 상세',class:'📚 수업 현황 상세',income:'💰 수입 상세',expense:'📋 지출 상세',profit:'📈 손익 현황'};
  const activeT=teachers.filter(t=>t.status==='active');
  const getClsName=id=>classes.find(c=>c.id===id)?.name||id;
  const dayNames=['일','월','화','수','목','금','토'];
  // 공통 최근 6개월 — 현재 월 이후 미래 데이터는 탭에 노출하지 않음
  const curMonthStr=(()=>{const d=new Date();return`${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,'0')}`;})();
  const recentMonths=[...new Set([...income.map(i=>i.date&&i.date.substring(0,7)),...expenses.map(e=>e.date&&e.date.substring(0,7))].filter(Boolean))].sort().reverse().filter(m=>m<=curMonthStr).slice(0,6);
  const [selMonth,setSelMonth]=useState(recentMonths.includes(curMonthStr)?curMonthStr:(recentMonths[0]||''));
  const [studentSearch,setStudentSearch]=useState('');
  // 월 선택 UI 공통 컴포넌트
  const MonthTabs=({accentClass})=><div className="mb-4">
    <div className="text-xs text-slate-500 font-semibold mb-2">📅 조회 월 선택</div>
    <div className="flex flex-wrap gap-2">
      {recentMonths.map(m=>{const[my,mm]=m.split('-');return<button key={m} onClick={()=>setSelMonth(m)}
        className={`text-xs px-3 py-1.5 rounded-full border font-semibold transition-colors ${selMonth===m?`${accentClass} text-white`:'bg-white text-slate-600 border-gray-300 hover:border-slate-500'}`}>
        {my}년 {parseInt(mm)}월</button>;})}
    </div>
  </div>;

  // 수입/지출/손익 계산은 income·expense·profit 타입에서 공통으로 사용 (요약 영역과 목록 영역에서 함께 참조)
  const _todayStr2=today();
  const mInc=income.filter(i=>i.date&&i.date.startsWith(selMonth)&&i.date<=_todayStr2);
  const mIncTotal=mInc.reduce((s,i)=>s+Number(i.amount),0);
  const mIncByCat=mInc.reduce((a,i)=>{a[i.category]=(a[i.category]||0)+Number(i.amount);return a;},{});
  const mExp=expenses.filter(e=>e.date&&e.date.startsWith(selMonth)&&e.date<=_todayStr2);
  const mExpTotal=mExp.reduce((s,e)=>s+Number(e.amount),0);
  const mExpByCat=mExp.reduce((a,e)=>{a[e.category]=(a[e.category]||0)+Number(e.amount);return a;},{});
  const mPft=mIncTotal-mExpTotal;
  const[selY,selMo]=selMonth?selMonth.split('-'):['',''];
  // 하단에 표시할 전체 건수 (데이터가 늘어나도 한눈에 총량을 알 수 있도록)
  const totalCount={teacher:teachers.length,student:students.filter(s=>s.status!=='withdrawn'&&(!s.joinDate||s.joinDate<=today())).length,class:classes.length,income:mInc.length,expense:mExp.length,profit:0}[type]||0;
  // 카테고리 아코디언 — 처음엔 접혀 있고 클릭 시 펼침
  const[openCats,setOpenCats]=useState({});
  const toggleCat=key=>setOpenCats(p=>({...p,[key]:!p[key]}));

  return<div className="modal-overlay" onClick={e=>e.target===e.currentTarget&&onClose()}>
    <div className="modal-box modal-wide shadow-2xl" style={{maxHeight:'85vh',overflowY:'hidden'}}>
      <div className="flex items-center justify-between p-5 border-b">
        <h3 className="text-lg font-bold text-slate-900">{titles[type]}</h3>
        <button onClick={onClose} className="w-8 h-8 flex items-center justify-center rounded-full hover:bg-gray-100 text-slate-600 text-xl">&times;</button>
      </div>

      <div className="px-5 pt-5">
        {type==='teacher'&&<div className={`grid gap-3 ${role==='teacher'?'grid-cols-2':'grid-cols-3'}`}>
          <div className="bg-green-50 rounded-xl p-3 text-center"><div className="text-xs text-green-500">활동중</div><div className="text-2xl font-bold text-green-700">{activeT.length}명</div></div>
          <div className="bg-amber-50 rounded-xl p-3 text-center"><div className="text-xs text-amber-500">비활동</div><div className="text-2xl font-bold text-amber-700">{teachers.filter(t=>t.status==='inactive').length}명</div></div>
          {role!=='teacher'&&<div className="bg-orange-50 rounded-xl p-3 text-center"><div className="text-xs text-orange-500">월 급여 합계</div><div className="text-lg font-bold text-orange-700">{fWon(activeT.reduce((s,t)=>s+Number(t.salary||0),0))}</div></div>}
        </div>}
        {type==='student'&&(()=>{const curM=(()=>{const d=new Date();return`${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,'0')}`;})();const newThisMonth=students.filter(s=>s.joinDate&&s.joinDate.substring(0,7)===curM).length;return<div className="grid grid-cols-3 gap-3">
          <div className="bg-purple-50 rounded-xl p-3 text-center"><div className="text-xs text-purple-500">재원중</div><div className="text-2xl font-bold text-purple-700">{students.filter(s=>s.status!=='withdrawn'&&(!s.joinDate||s.joinDate<=today())).length}명</div></div>
          <div className="bg-orange-50 rounded-xl p-3 text-center"><div className="text-xs text-orange-500">이달 퇴원</div><div className="text-2xl font-bold text-orange-700">{students.filter(s=>s.status==='withdrawn'&&(s.enrollmentHistory||[]).slice(-1)[0]?.leaveDate?.startsWith(curM)).length}명</div></div>
          <div className="bg-green-50 rounded-xl p-3 text-center"><div className="text-xs text-green-500">이달 신규</div><div className="text-2xl font-bold text-green-700">{newThisMonth}명</div></div>
        </div>;})()}
        {type==='class'&&<div className="grid grid-cols-3 gap-3">
          <div className="bg-blue-50 rounded-xl p-3 text-center"><div className="text-xs text-blue-500">전체 수업</div><div className="text-2xl font-bold text-blue-700">{classes.length}개</div></div>
          <div className="bg-green-50 rounded-xl p-3 text-center"><div className="text-xs text-green-500">운영중</div><div className="text-2xl font-bold text-green-700">{classes.filter(c=>!(c.closeDate&&c.closeDate<=today())).length}개</div></div>
          <div className="bg-[#f1f5f9] rounded-xl p-3 text-center"><div className="text-xs text-[#475569]">총 정원</div><div className="text-2xl font-bold text-[#1e293b]">{classes.reduce((s,c)=>s+Number(c.maxStudents||0),0)}명</div></div>
        </div>}
        {type==='income'&&<>
          <MonthTabs accentClass="bg-emerald-600 border-emerald-600"/>
          {selMonth&&<>
            <div className="text-sm font-bold text-slate-800 mb-3">{selY}년 {parseInt(selMo)}월 수입 현황</div>
            <div className="grid grid-cols-2 gap-3 mb-4">
              <div className="bg-green-50 rounded-xl p-3 text-center"><div className="text-xs text-green-500">총 수입</div><div className="text-xl font-bold text-green-700">{fWon(mIncTotal)}</div></div>
              <div className="bg-blue-50 rounded-xl p-3 text-center"><div className="text-xs text-blue-500">건수</div><div className="text-2xl font-bold text-blue-700">{mInc.length}건</div></div>
            </div>
            {/* 카테고리별 소계는 아래 스크롤 영역에서 항목별로 묶어서 함께 보여주므로 여기서는 중복 표시하지 않음 */}
          </>}
        </>}
        {type==='expense'&&<>
          <MonthTabs accentClass="bg-red-600 border-red-600"/>
          {selMonth&&<>
            <div className="text-sm font-bold text-slate-800 mb-3">{selY}년 {parseInt(selMo)}월 지출 현황</div>
            <div className="grid grid-cols-2 gap-3 mb-4">
              <div className="bg-red-50 rounded-xl p-3 text-center"><div className="text-xs text-red-500">총 지출</div><div className="text-xl font-bold text-red-600">{fWon(mExpTotal)}</div></div>
              <div className="bg-orange-50 rounded-xl p-3 text-center"><div className="text-xs text-orange-500">건수</div><div className="text-2xl font-bold text-orange-700">{mExp.length}건</div></div>
            </div>
            {/* 카테고리별 소계는 아래 스크롤 영역에서 항목별로 묶어서 함께 보여주므로 여기서는 중복 표시하지 않음 */}
          </>}
        </>}
        {type==='profit'&&<>
          <MonthTabs accentClass="bg-[#1e3a5f] border-[#1e3a5f]"/>
          {selMonth&&<>
            <div className="text-sm font-bold text-slate-800 mb-3">{selY}년 {parseInt(selMo)}월 손익 현황</div>
            <div className="grid grid-cols-2 gap-3 mb-3">
              <div className="bg-green-50 rounded-xl p-4">
                <div className="text-xs text-green-500 mb-1.5 font-semibold">💰 총 수입</div>
                <div className="text-2xl font-bold text-green-700">{fWon(mIncTotal)}</div>
                <div className="text-xs text-green-400 mt-1.5">{mInc.length}건</div>
              </div>
              <div className="bg-red-50 rounded-xl p-4">
                <div className="text-xs text-red-500 mb-1.5 font-semibold">📋 총 지출</div>
                <div className="text-2xl font-bold text-red-600">{fWon(mExpTotal)}</div>
                <div className="text-xs text-red-400 mt-1.5">{mExp.length}건</div>
              </div>
            </div>
            <div className={`${mPft>=0?'bg-gradient-to-r from-blue-50 to-indigo-50 border border-blue-200':'bg-gradient-to-r from-orange-50 to-red-50 border border-orange-200'} rounded-xl p-5`}>
              <div className={`text-sm font-semibold mb-2 ${mPft>=0?'text-blue-600':'text-orange-600'}`}>{mPft>=0?'📈 순수익 (흑자)':'📉 순손실 (적자)'}</div>
              <div className={`text-3xl font-bold ${mPft>=0?'text-blue-700':'text-orange-600'}`}>{fWon(mPft)}</div>
              {mIncTotal>0&&<div className={`text-xs mt-2 ${mPft>=0?'text-blue-400':'text-orange-400'}`}>수익률 {mIncTotal>0?Math.round(mPft/mIncTotal*100):0}%</div>}
            </div>
            <div className="mt-3 pt-3 border-t border-gray-100">
              <div className="flex items-center gap-2 text-xs text-slate-500">
                <div className="flex-1 h-2 rounded-full bg-gray-100 overflow-hidden">
                  <div className="h-full bg-red-400 rounded-full" style={{width:mIncTotal>0?`${Math.min(100,Math.round(mExpTotal/mIncTotal*100))}%`:'0%'}}/>
                </div>
                <span className="shrink-0">지출 비율 {mIncTotal>0?Math.round(mExpTotal/mIncTotal*100):0}%</span>
              </div>
            </div>
          </>}
        </>}
      </div>

      <div className="overflow-x-auto overflow-y-auto tbl-scroll px-5 pb-5 pt-3 mt-1 border-t border-gray-100" style={{maxHeight:'calc(85vh - 370px)',minHeight:'60px'}}>
        {type==='teacher'&&<div className="overflow-x-auto"><table className="w-full text-sm app-table"><thead className="text-xs text-slate-600"><tr>{(role==='teacher'?['이름','과목','연락처','계약시작일','상태']:['이름','과목','연락처','월급여','계약시작일','상태']).map(h=><th key={h} className="px-3 py-2 text-left">{h}</th>)}</tr></thead>
        <tbody>{teachers.filter(t=>t.status==='active').map(t=><tr key={t.id} className="table-row border-t">
          <td className="px-3 py-2 font-semibold">{t.name}</td>
          <td className="px-3 py-2"><div className="flex flex-wrap gap-1">{(t.subjects||[]).map(s=><span key={s} className="badge bg-[#dbeafe] text-[#1e293b]">{s}</span>)}</div></td>
          <td className="px-3 py-2 text-slate-700">{t.phone}</td>
          {role!=='teacher'&&<td className="px-3 py-2 font-medium">{fWon(t.salary)}</td>}
          <td className="px-3 py-2 text-slate-600 text-xs">{fDate(t.contractStart)}</td>
          <td className="px-3 py-2"><span className={`badge ${sColor(t.status)}`}>{t.status==='active'?'활동중':'비활동'}</span></td>
        </tr>)}</tbody></table></div>}
        {type==='student'&&(()=>{
          const curM2=(()=>{const d=new Date();return`${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,'0')}`;})();
          const activeStudents=students.filter(s=>s.status!=='withdrawn'&&(!s.joinDate||s.joinDate<=today()));
          const filteredStudents=studentSearch.trim()?activeStudents.filter(s=>{const q=studentSearch.trim();return s.name.includes(q)||(s.parentName||'').includes(q)||((s.enrolledClasses||[]).some(id=>{const c=classes.find(x=>x.id===id);return c&&!(c.closeDate&&c.closeDate<=today())&&c.name.includes(q);}));}) :activeStudents;
          const withdrawnThisMonth=students.filter(s=>s.status==='withdrawn'&&(s.enrollmentHistory||[]).slice(-1)[0]?.leaveDate?.startsWith(curM2));
          return<div>
            <div className="mb-3"><input type="text" value={studentSearch} onChange={e=>setStudentSearch(e.target.value)} placeholder="이름, 학부모, 수업명으로 검색..." className="w-full border border-gray-300 rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-blue-300" style={{maxWidth:'320px'}}/>{studentSearch&&<span className="ml-2 text-xs text-slate-500">{filteredStudents.length}명 검색됨</span>}</div>
            <div className="overflow-x-auto"><table className="w-full text-sm app-table"><thead className="text-xs text-slate-600"><tr>{['이름','상태','학부모','연락처','수강 수업'].map(h=><th key={h} className="px-3 py-2 text-left">{h}</th>)}</tr></thead>
            <tbody>{filteredStudents.map(s=><tr key={s.id} className="table-row border-t">
              <td className="px-3 py-2 font-semibold">{s.name}</td>
              <td className="px-3 py-2"><span className="badge bg-green-100 text-green-700">재원중</span></td>
              <td className="px-3 py-2">{s.grade==='성인'?'본인':s.parentName}</td>
              <td className="px-3 py-2 text-slate-700">{s.grade==='성인'?s.phone:s.parentPhone}</td>
              <td className="px-3 py-2"><div className="flex flex-wrap gap-1">{(s.enrolledClasses||[]).filter(id=>{const c=classes.find(x=>x.id===id);return c&&!(c.closeDate&&c.closeDate<=today());}).map(id=><span key={id} className="badge bg-[#f1f5f9] text-[#1e3a5f] text-xs">{getClsName(id)}</span>)}</div></td>
            </tr>)}</tbody></table></div>
            {withdrawnThisMonth.length>0&&<div className="mt-5 pt-4 border-t border-orange-100">
              <div className="flex items-center gap-2 mb-3">
                <span className="text-sm font-bold text-orange-700">이달 퇴원생</span>
                <span className="badge bg-orange-100 text-orange-700">{withdrawnThisMonth.length}명</span>
              </div>
              <div className="overflow-x-auto"><table className="w-full text-sm app-table"><thead className="text-xs text-slate-600"><tr>{['이름','퇴원일','학부모','연락처'].map(h=><th key={h} className="px-3 py-2 text-left">{h}</th>)}</tr></thead>
              <tbody>{withdrawnThisMonth.map(s=>{const leaveDate=(s.enrollmentHistory||[]).slice(-1)[0]?.leaveDate;return<tr key={s.id} className="table-row border-t">
                <td className="px-3 py-2 font-semibold text-slate-700">{s.name}</td>
                <td className="px-3 py-2 text-slate-600 text-xs">{fDate(leaveDate)}</td>
                <td className="px-3 py-2">{s.grade==='성인'?'본인':s.parentName}</td>
                <td className="px-3 py-2 text-slate-700">{s.grade==='성인'?s.phone:s.parentPhone}</td>
              </tr>;})}</tbody></table></div>
            </div>}
          </div>;
        })()}
        {type==='class'&&<div className="overflow-x-auto"><table className="w-full text-sm app-table"><thead className="text-xs text-slate-600"><tr>{['수업명','강사','요일','시간','운영기간','정원','수강료'].map(h=><th key={h} className="px-3 py-2 text-left">{h}</th>)}</tr></thead>
        <tbody>{(()=>{const todayDow=new Date().getDay();return[...classes].sort((a,b)=>{const aT=(a.days||[]).includes(todayDow)?0:1;const bT=(b.days||[]).includes(todayDow)?0:1;if(aT!==bT)return aT-bT;return(a.name||'').localeCompare(b.name||'','ko');}).map(c=>{const t=teachers.find(x=>x.id===c.teacherId);const isToday=(c.days||[]).includes(todayDow);return<tr key={c.id} className={`table-row border-t ${isToday?'bg-green-50':''}`}>
          <td className="px-3 py-2"><div className="flex items-center gap-1.5"><span className="font-semibold">{c.name}</span>{isToday&&<span className="badge bg-green-100 text-green-700" style={{fontSize:'10px',padding:'1px 6px'}}>오늘</span>}</div></td>
          <td className="px-3 py-2">{t?.name||'-'}</td>
          <td className="px-3 py-2">{(c.days||[]).map(d=><span key={d} className={`badge mr-1 ${d===todayDow?'bg-green-100 text-green-700':'bg-[#f1f5f9] text-[#1e3a5f]'}`}>{dayNames[d]}</span>)}</td>
          <td className="px-3 py-2 text-slate-700 text-xs">{c.startTime}~{c.endTime}</td>
          <td className="px-3 py-2 text-slate-700 text-xs">{c.openDate?fDate(c.openDate):'-'}{c.closeDate?` ~ ${fDate(c.closeDate)}`:' ~ 운영중'}</td>
          <td className="px-3 py-2">{c.maxStudents}명</td>
          <td className="px-3 py-2 font-medium">{fWon(c.fee)}</td>
        </tr>;});})()}
        </tbody></table></div>}
        {/* 수입/지출 목록은 더 이상 표(table)로 길게 나열하지 않고, 카테고리(수강료/교재비 등)별로
            묶어서 카드 형태로 보여줌. 데이터가 8건이든 100건이든 항목이 같은 카테고리끼리 모여
            있어 한눈에 파악하기 쉽고, sticky 표 헤더가 스크롤 중 내용과 겹쳐 보이던 문제도
            구조적으로 사라짐 (sticky thead 자체를 사용하지 않음) */}
        {type==='income'&&selMonth&&(mInc.length>0?<div className="space-y-2">
          {Object.entries(mIncByCat).sort((a,b)=>b[1]-a[1]).map(([cat,amt])=>{
            const catKey=`i-${cat}`;
            const isOpen=!!openCats[catKey];
            const items=mInc.filter(i=>i.category===cat).sort((a,b)=>b.date.localeCompare(a.date));
            return<div key={cat} className="border border-gray-100 rounded-xl overflow-hidden">
              <button onClick={()=>toggleCat(catKey)} className="w-full flex items-center justify-between px-4 py-2.5 bg-green-50 hover:bg-green-100 transition-colors text-left">
                <div className="flex items-center gap-2">
                  <span className="badge bg-green-100 text-green-700">{cat}</span>
                  <span className="text-xs text-slate-500">{items.length}건</span>
                </div>
                <div className="flex items-center gap-2">
                  <span className="font-bold text-green-700">{fWon(amt)}</span>
                  <span className="text-slate-400 text-xs">{isOpen?'▲':'▼'}</span>
                </div>
              </button>
              {isOpen&&<div className="divide-y divide-gray-50">
                {items.map(i=><div key={i.id} className="flex items-center justify-between gap-3 px-4 py-2.5 text-sm hover:bg-green-50/60">
                  <span className="text-xs text-slate-500 shrink-0 w-20">{fDate(i.date)}</span>
                  <span className="text-slate-800 flex-1 truncate">{i.description}</span>
                  <span className="font-semibold text-green-600 shrink-0">{fWon(i.amount)}</span>
                </div>)}
              </div>}
            </div>;
          })}
        </div>:<div className="text-center text-slate-400 py-8 text-sm">상세 내역이 없습니다</div>)}
        {type==='expense'&&selMonth&&(mExp.length>0?<div className="space-y-2">
          {Object.entries(mExpByCat).sort((a,b)=>b[1]-a[1]).map(([cat,amt])=>{
            const catKey=`e-${cat}`;
            const isOpen=!!openCats[catKey];
            const items=mExp.filter(e=>e.category===cat).sort((a,b)=>b.date.localeCompare(a.date));
            return<div key={cat} className="border border-gray-100 rounded-xl overflow-hidden">
              <button onClick={()=>toggleCat(catKey)} className="w-full flex items-center justify-between px-4 py-2.5 bg-red-50 hover:bg-red-100 transition-colors text-left">
                <div className="flex items-center gap-2">
                  <span className="badge bg-red-100 text-red-700">{cat}</span>
                  <span className="text-xs text-slate-500">{items.length}건</span>
                </div>
                <div className="flex items-center gap-2">
                  <span className="font-bold text-red-600">{fWon(amt)}</span>
                  <span className="text-slate-400 text-xs">{isOpen?'▲':'▼'}</span>
                </div>
              </button>
              {isOpen&&<div className="divide-y divide-gray-50">
                {items.map(e=><div key={e.id} className="flex items-center justify-between gap-3 px-4 py-2.5 text-sm hover:bg-red-50/60">
                  <span className="text-xs text-slate-500 shrink-0 w-20">{fDate(e.date)}</span>
                  <span className="text-slate-800 flex-1 truncate">{e.description}</span>
                  <span className="font-semibold text-red-500 shrink-0">{fWon(e.amount)}</span>
                </div>)}
              </div>}
            </div>;
          })}
        </div>:<div className="text-center text-slate-400 py-8 text-sm">상세 내역이 없습니다</div>)}
      </div>

      <div className="p-4 border-t flex items-center justify-between">
        <span className="text-xs text-slate-400">{type!=='profit'&&`총 ${totalCount}건`}</span>
        <div className="flex gap-2">
          {setPage&&!(role==='teacher'&&type==='teacher')&&<button className={btn('indigo')} onClick={()=>{const pageMap={teacher:'teachers',student:'students',class:'classes',income:'budget',expense:'budget',profit:'budget'};setPage(pageMap[type]||'dashboard');onClose();}}>→ 관리 페이지로 이동</button>}
          <button className={btn('gray')} onClick={onClose}>닫기</button>
        </div>
      </div>
    </div>
  </div>;
}

// ── StatCard ─────────────────────────────────────────────────────────────────
function StatCard({label,value,sub,icon,color,onClick}){
  const colors={indigo:'from-[#1e3a5f] to-[#152d4a]',purple:'from-[#4c1d95] to-[#5b21b6]',green:'from-[#065f46] to-[#047857]',orange:'from-[#92400e] to-[#b45309]',pink:'from-[#9d174d] to-[#be185d]',blue:'from-[#1d4ed8] to-[#1e40af]'};
  return<div onClick={onClick} className={`stat-card-btn bg-gradient-to-br ${colors[color]||colors.indigo} rounded-2xl p-4 text-white shadow-lg flex flex-col justify-between`} style={{minHeight:'120px'}} title="클릭하면 상세 정보를 볼 수 있습니다">
    <div className="flex justify-between items-start gap-1 mb-2">
      <span className="text-2xl leading-none shrink-0">{icon}</span>
      <span className="bg-white/20 rounded-md px-2 py-0.5 text-xs font-medium text-right leading-tight" style={{maxWidth:'calc(100% - 36px)',wordBreak:'break-all'}}>{sub}</span>
    </div>
    <div>
      <div className="font-bold text-white mb-0.5 leading-tight" style={{fontSize:'clamp(13px,1.8vw,20px)',wordBreak:'break-all'}}>{value}</div>
      <div className="text-xs text-white" style={{opacity:0.85}}>{label}</div>
      <div className="text-xs mt-1" style={{opacity:0.6}}>▶ 클릭하여 상세보기</div>
    </div>
  </div>;
}

// ── 대시보드 ─────────────────────────────────────────────────────────────────
function getTeacherIcon(subj){
  const s=subj||'';
  if(s.includes('유아')||s.includes('초급'))return'🎹';
  if(s.includes('중급'))return'🎼';
  if(s.includes('고급'))return'🎵';
  if(s.includes('콩쿠르')||s.includes('입시'))return'🏆';
  if(s.includes('성인')||s.includes('청소년'))return'🎶';
  if(s.includes('이론'))return'📖';
  return'🎹';
}
function Dashboard({teachers,students,classes,income,expenses,tuitions,attendance,consultations,setPage,setAttContext,setConsultContext,role,loggedInTeacherId}){
  const[detail,setDetail]=useState(null);
  const[txModal,setTxModal]=useState(null);
  const activeT=teachers.filter(t=>t.status==='active').length;
  // '이달' 통계는 실제 현재 날짜(new Date()) 기준 월로 계산
  const curMonth=(()=>{const d=new Date();return`${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,'0')}`;})();
  const curMonthLabel=curMonth?`${curMonth.split('-')[0]}년 ${Number(curMonth.split('-')[1])}월 기준`:'월 기준';
  const monthIncome=income.filter(i=>i.date&&i.date.substring(0,7)===curMonth&&i.date<=today());
  const monthExpense=expenses.filter(e=>e.date&&e.date.substring(0,7)===curMonth&&e.date<=today());
  const totalInc=monthIncome.reduce((s,i)=>s+Number(i.amount),0);
  const totalExp=monthExpense.reduce((s,e)=>s+Number(e.amount),0);
  const profit=totalInc-totalExp;
  const expByCat=monthExpense.reduce((a,e)=>{a[e.category]=(a[e.category]||0)+Number(e.amount);return a;},{});
  const clsBySub=classes.reduce((a,c)=>{a[c.subject]=(a[c.subject]||0)+1;return a;},{});
  const subjColors={'유아·초급 과정':'bg-yellow-100 text-yellow-700','중급 과정 (체르니30·소나티네)':'bg-blue-100 text-blue-700','고급 과정 (소나타·인벤션)':'bg-purple-100 text-purple-700','콩쿠르·입시 과정':'bg-red-100 text-red-700','성인·청소년 과정':'bg-green-100 text-green-700','음악이론·시창 과정':'bg-indigo-100 text-indigo-700'};
  const todayStr=today();
  const recentAll=[...income.map(i=>({...i,_t:'income'})),...expenses.map(e=>({...e,_t:'expense'}))].filter(x=>x.date&&x.date<=todayStr).sort((a,b)=>b.date.localeCompare(a.date));
  const recent=recentAll.slice(0,10);
  return<div className="space-y-6">
    <div>
      <h1 className="text-2xl font-bold text-slate-900">대시보드</h1>
      <p className="text-slate-600 text-sm mt-1">{new Date().toLocaleDateString('ko-KR',{year:'numeric',month:'long',day:'numeric',weekday:'long'})}</p>
      <p className="text-xs text-[#475569] mt-1">💡 아래 카드를 클릭하면 상세 정보를 확인할 수 있습니다</p>
    </div>
    <div className="grid grid-cols-2 md:grid-cols-3 xl:grid-cols-6 gap-3">
      <StatCard label="활동 강사" value={`${activeT}명`} sub={`전체 ${teachers.length}명`} icon="👨‍🏫" color="indigo" onClick={()=>setDetail('teacher')}/>
      <StatCard label="재원 학생" value={`${students.filter(s=>s.status!=='withdrawn'&&(!s.joinDate||s.joinDate<=today())).length}명`} sub={`이달 퇴원 ${students.filter(s=>s.status==='withdrawn'&&(s.enrollmentHistory||[]).slice(-1)[0]?.leaveDate?.startsWith(curMonth)).length}명`} icon="🎓" color="purple" onClick={()=>setDetail('student')}/>
      <StatCard label="운영 수업" value={`${classes.filter(c=>!(c.closeDate&&c.closeDate<=today())).length}개`} sub="개설 수업" icon="📚" color="blue" onClick={()=>setDetail('class')}/>
      {role!=='teacher'&&<StatCard label="이달 수입" value={fWon(totalInc)} sub={curMonthLabel} icon="💰" color="green" onClick={()=>setDetail('income')}/>}
      {role!=='teacher'&&<StatCard label="이달 지출" value={fWon(totalExp)} sub={curMonthLabel} icon="📋" color="orange" onClick={()=>setDetail('expense')}/>}
      {role!=='teacher'&&<StatCard label="이달 손익" value={fWon(profit)} sub={`${curMonthLabel} · ${profit>=0?'흑자':'적자'}`} icon={profit>=0?'📈':'📉'} color={profit>=0?'green':'pink'} onClick={()=>setDetail('profit')}/>}
    </div>
    <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-5">
      <h3 className="text-lg font-bold text-slate-900 mb-5">🎯 오늘의 할 일</h3>
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        {(() => {
          // 표시 기준: 카운트는 전체 해당 건수, 이름은 최대 2명까지 보여주고 더 있으면 '외 N명' 표기
          const nameList=(arr,getName,unit)=>{
            if(!arr||arr.length===0)return null;
            const shown=arr.slice(0,2).map(getName).filter(Boolean).join(', ');
            const rest=arr.length-2;
            return rest>0?`${shown} 외 ${rest}${unit}`:shown;
          };
          // 강사 계정일 때 본인 담당 수업 ID 목록
          const myClassIds = role==='teacher'&&loggedInTeacherId
            ? classes.filter(c=>c.teacherId===loggedInTeacherId&&!(c.closeDate&&c.closeDate<=today())).map(c=>c.id)
            : null;
          // 강사 담당 학생 ID 목록 (담당 수업에 등록된 학생)
          const myStudentIds = myClassIds
            ? students.filter(s=>s.status!=='withdrawn'&&(!s.joinDate||s.joinDate<=today())&&(s.enrolledClasses||[]).some(cid=>myClassIds.includes(cid))).map(s=>s.id)
            : null;
          // 대시보드 미납 학생 수 = 이번 달 미납+연체 건수 (원장만 표시)
          const _effSt=t=>{if(t.status==='paid')return'paid';if(t.status==='overdue')return'overdue';if(t.dueDate&&t.dueDate<today())return'overdue';return'unpaid';};
          const unpaid = role!=='teacher' ? (tuitions && tuitions.filter(t => t.month===curMonth && _effSt(t)!=='paid')) : null;
          // 오늘 수업: 강사는 본인 담당 수업만
          const upcomingClasses = classes && classes.filter(c => {
            const today_d = new Date().getDay();
            const todayStr = new Date().toISOString().split('T')[0];
            const isToday = c.days?.includes(today_d) && !(c.closeDate && c.closeDate <= todayStr);
            if(!isToday)return false;
            if(myClassIds)return myClassIds.includes(c.id);
            return true;
          });
          // 결석경고: 강사는 본인 담당 학생만 / 3번째 결석 발생일로부터 7일 이내인 학생만 표시
          const absenceWarnings = attendance && students && (() => {
            const d_ym=new Date();const thisYM=`${d_ym.getFullYear()}-${String(d_ym.getMonth()+1).padStart(2,'0')}`;
            // 학생별 이번 달 결석 날짜 목록 수집 (중복 날짜 제거, 정렬)
            const absenceDates={};
            attendance.filter(a=>a.type==='student'&&a.date&&a.date.substring(0,7)===thisYM&&a.date<=today()&&a.status==='absent').forEach(a=>{
              if(!absenceDates[a.refId])absenceDates[a.refId]=new Set();
              absenceDates[a.refId].add(a.date);
            });
            // 3번째 결석일 기준 7일 이내인 학생만 경고
            const sevenDaysAgo=new Date();sevenDaysAgo.setDate(sevenDaysAgo.getDate()-7);
            const sevenDaysAgoStr=sevenDaysAgo.toISOString().split('T')[0];
            const baseStudents=myStudentIds
              ?students.filter(s=>myStudentIds.includes(s.id))
              :students.filter(s=>s.status!=='withdrawn'&&(!s.joinDate||s.joinDate<=today()));
            return baseStudents.filter(s=>{
              const dates=[...(absenceDates[s.id]||[])].sort();
              if(dates.length<3)return false;
              const thirdAbsenceDate=dates[2]; // 3번째 결석일
              return thirdAbsenceDate>=sevenDaysAgoStr; // 7일 이내
            });
          })() || [];
          const recentConsultations = role!=='teacher' ? (consultations && consultations.filter(c => c.status === 'inquiry' || c.status === 'trial').sort((a,b) => b.date.localeCompare(a.date))) : null;
          return (
            <>
              {role!=='teacher'&&<button onClick={()=>setPage&&setPage('tuition')} className="bg-red-50 rounded-xl p-4 border border-red-100 text-left w-full hover:bg-red-100 hover:border-red-200 transition-colors cursor-pointer">
                <div className="text-xs font-bold text-red-600 mb-2 uppercase">💳 미납·연체 학생</div>
                <div className="text-2xl font-bold text-red-700">{unpaid?.length || 0}명</div>
                {nameList(unpaid,t=>t.studentName,'명')&&<div className="text-xs text-red-600 mt-2">{nameList(unpaid,t=>t.studentName,'명')}</div>}
                <div className="text-xs text-red-400 mt-1">→ 학원비 관리로 이동</div>
              </button>}
              <button onClick={()=>setPage&&setPage('classes')} className="bg-blue-50 rounded-xl p-4 border border-blue-100 text-left w-full hover:bg-blue-100 hover:border-blue-200 transition-colors cursor-pointer">
                <div className="text-xs font-bold text-blue-600 mb-2 uppercase">📚 오늘 수업</div>
                <div className="text-2xl font-bold text-blue-700">{upcomingClasses?.length || 0}개</div>
                {nameList(upcomingClasses,c=>c.name,'개')&&<div className="text-xs text-blue-600 mt-2">{nameList(upcomingClasses,c=>c.name,'개')}</div>}
                <div className="text-xs text-blue-400 mt-1">→ 수업 관리로 이동</div>
              </button>
              <button onClick={()=>{if(setAttContext)setAttContext({warnIds:absenceWarnings?.length?absenceWarnings.map(s=>s.id):[],tab:'student'});setPage&&setPage('attendance');}} className="bg-orange-50 rounded-xl p-4 border border-orange-100 text-left w-full hover:bg-orange-100 hover:border-orange-200 transition-colors cursor-pointer">
                <div className="text-xs font-bold text-orange-600 mb-2 uppercase">⚠️ 결석 경고</div>
                <div className="text-2xl font-bold text-orange-700">{absenceWarnings?.length || 0}명</div>
                {nameList(absenceWarnings,s=>s.name,'명')&&<div className="text-xs text-orange-600 mt-2">{nameList(absenceWarnings,s=>s.name,'명')}</div>}
                <div className="text-xs text-orange-400 mt-1">→ 출결 관리로 이동</div>
              </button>
              {role!=='teacher'&&<button onClick={()=>{if(setConsultContext)setConsultContext({filterActive:true});setPage&&setPage('consultation');}} className="bg-purple-50 rounded-xl p-4 border border-purple-100 text-left w-full hover:bg-purple-100 hover:border-purple-200 transition-colors cursor-pointer">
                <div className="text-xs font-bold text-purple-600 mb-2 uppercase">💬 신규 상담</div>
                <div className="text-2xl font-bold text-purple-700">{recentConsultations?.length || 0}건</div>
                {nameList(recentConsultations,c=>c.name,'건')&&<div className="text-xs text-purple-600 mt-2">{nameList(recentConsultations,c=>c.name,'건')}</div>}
                <div className="text-xs text-purple-400 mt-1">→ 상담 관리로 이동</div>
              </button>}
            </>
          );
        })()}
      </div>
    </div>
    <div className="bg-white rounded-2xl p-5 shadow-sm border border-gray-100">
      <div className="flex items-center justify-between mb-4">
        <h3 className="font-bold text-slate-900">👨‍🏫 강사 현황</h3>
        {role!=='teacher'&&<span className="text-xs text-slate-400">클릭하면 강사 관리로 이동합니다</span>}
      </div>
      <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-6 gap-3">
        {teachers.filter(t=>t.status==='active'&&!(t.contractEnd&&t.contractEnd<today())).map(t=><button key={t.id} onClick={role!=='teacher'?()=>setPage&&setPage('teachers'):undefined} className={`text-center p-3 rounded-xl border border-gray-100 ${role!=='teacher'?'hover:border-[#cbd5e1] hover:bg-slate-50 transition-colors cursor-pointer':'cursor-default'}`}>
          <div className="w-12 h-12 rounded-full bg-[#dbeafe] flex items-center justify-center text-xl mx-auto mb-2">
            {getTeacherIcon((t.subjects||[])[0])}
          </div>
          <div className="text-sm font-semibold text-slate-800">{t.name}</div>
          <div className="text-xs text-slate-600">{(t.subjects||[]).join(', ')}</div>
          <span className="badge text-xs mt-1 bg-green-100 text-green-700">활동중</span>
        </button>)}
      </div>
    </div>
    <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
      <div className="bg-white rounded-2xl p-5 shadow-sm border border-gray-100">
        <h3 className="font-bold text-slate-900 mb-4">🎹 과정별 수업 현황</h3>
        <div className="space-y-3">{Object.entries(clsBySub).map(([subj,cnt])=>{
          const activeClsCount=classes.filter(c=>!(c.closeDate&&c.closeDate<=new Date().toISOString().split('T')[0])).length||1;
          const pct=Math.round((cnt/activeClsCount)*100);
          return<div key={subj}>
            <div className="flex justify-between text-sm mb-1"><span className={`badge ${subjColors[subj]||'bg-gray-100 text-slate-700'}`}>{subj}</span><span className="text-slate-700 font-medium">{cnt}반</span></div>
            <div className="h-2 bg-gray-100 rounded-full"><div className="h-2 bg-[#3b82f6] rounded-full" style={{width:pct+'%'}}/></div>
          </div>;
        })}</div>
      </div>
      {role!=='teacher'&&<div className="bg-white rounded-2xl p-5 shadow-sm border border-gray-100">
        <div className="flex items-center justify-between mb-4">
          <h3 className="font-bold text-slate-900">💳 최근 거래</h3>
          <span className="text-xs text-slate-400">최근 10건</span>
        </div>
        <div className="space-y-1">{recent.map(tx=><button key={tx.id} onClick={()=>setTxModal(tx)} className="w-full flex items-center justify-between py-1.5 px-2 border-b border-gray-50 rounded hover:bg-gray-50 transition-colors text-left cursor-pointer">
          <div style={{maxWidth:'60%'}}><div className="text-xs font-semibold text-slate-900 truncate">{tx.description}</div><div className="text-xs text-slate-500">{fDate(tx.date)} · {tx.category||''}</div></div>
          <span className={`text-xs font-bold ${tx._t==='income'?'text-green-600':'text-red-500'}`}>{tx._t==='income'?'+':'-'}{fWon(tx.amount)}</span>
        </button>)}</div>
      </div>}
    </div>
    {detail&&<DashboardDetail type={detail} teachers={teachers} students={students} classes={classes} income={income} expenses={expenses} onClose={()=>setDetail(null)} setPage={setPage} role={role}/>}
    {txModal&&<div className="modal-overlay" onClick={()=>setTxModal(null)}><div className="modal-box p-6" onClick={e=>e.stopPropagation()}>
      <div className="flex items-center justify-between mb-4">
        <h3 className="text-lg font-bold text-slate-900">거래 상세 정보</h3>
        <button onClick={()=>setTxModal(null)} className="text-slate-400 hover:text-slate-600 text-xl font-bold">×</button>
      </div>
      <div className={`inline-block px-3 py-1 rounded-full text-xs font-bold mb-4 ${txModal._t==='income'?'bg-green-100 text-green-700':'bg-red-100 text-red-600'}`}>
        {txModal._t==='income'?'💚 수입':'❤️ 지출'}
      </div>
      <div className="space-y-3">
        <div className="flex justify-between py-2 border-b border-gray-100"><span className="text-sm text-slate-600 font-medium">내용</span><span className="text-sm font-semibold text-slate-900">{txModal.description||'-'}</span></div>
        <div className="flex justify-between py-2 border-b border-gray-100"><span className="text-sm text-slate-600 font-medium">카테고리</span><span className="text-sm font-semibold text-slate-900">{txModal.category||'-'}</span></div>
        <div className="flex justify-between py-2 border-b border-gray-100"><span className="text-sm text-slate-600 font-medium">날짜</span><span className="text-sm font-semibold text-slate-900">{fDate(txModal.date)}</span></div>
        <div className="flex justify-between py-2 border-b border-gray-100"><span className="text-sm text-slate-600 font-medium">금액</span><span className={`text-lg font-bold ${txModal._t==='income'?'text-green-600':'text-red-600'}`}>{txModal._t==='income'?'+':'-'}{fWon(txModal.amount)}</span></div>
        {txModal.note&&<div className="flex justify-between py-2 border-b border-gray-100"><span className="text-sm text-slate-600 font-medium">비고</span><span className="text-sm text-slate-900">{txModal.note}</span></div>}
      </div>
      <div className="mt-5 flex justify-end gap-2">
        <button onClick={()=>{setPage&&setPage(txModal._t==='income'?'budget':'budget');setTxModal(null);}} className="text-xs px-4 py-2 rounded-lg bg-slate-100 text-slate-700 hover:bg-slate-200 font-medium">예산 관리로 이동</button>
        <button onClick={()=>setTxModal(null)} className="text-xs px-4 py-2 rounded-lg bg-[#1e3a5f] text-white hover:bg-[#2d4f7c] font-medium">닫기</button>
      </div>
    </div></div>}
  </div>;
}

// ── 강사 관리 (학력 추가) ────────────────────────────────────────────────────
function TeacherManagement({teachers,setTeachers,classes,setClasses,attendance,setAttendance}){
  const[modalOpen,setModalOpen]=useState(false);
  const[editTarget,setEditTarget]=useState(null);
  const[confirmId,setConfirmId]=useState(null);
  const[search,setSearch]=useState('');
  const[teacherTab,setTeacherTab]=useState('active');
  const[resignModal,setResignModal]=useState(false);
  const[resignTarget,setResignTarget]=useState(null);
  const[resignForm,setResignForm]=useState({date:'',reason:'',note:''});
  const[tSortKey,setTSortKey]=useState('name');
  const[tSortDir,setTSortDir]=useState('asc');
  const tSortField=k=>{if(tSortKey===k)setTSortDir(d=>d==='asc'?'desc':'asc');else{setTSortKey(k);setTSortDir('asc');}};
  const tArrow=k=>tSortKey===k?(tSortDir==='asc'?' ▲':' ▼'):'';
  const[inactiveModal,setInactiveModal]=useState(false);
  const[inactiveTarget,setInactiveTarget]=useState(null);
  const[inactiveForm,setInactiveForm]=useState({reason:'vacation',startDate:'',endDate:'',note:''});
  const inactiveReasonOpts=[{val:'halfday',label:'반차',attStatus:'halfday'},{val:'vacation',label:'휴가',attStatus:'vacation'},{val:'sick',label:'병가',attStatus:'sick'},{val:'training',label:'교육/연수',attStatus:'training'},{val:'other',label:'기타',attStatus:'other'}];
  const emptyForm={name:'',subjects:[],phone:'',email:'',contractStart:'',contractEnd:'',salary:'',dependents:1,status:'active',note:'',edu:{bachUniv:'',bachMajor:'',mastUniv:'',mastMajor:'',phdUniv:'',phdMajor:''},career:[],attachments:[]};
  const[form,setForm]=useState(emptyForm);
  const emptyCareer={org:'',role:'',startDate:'',endDate:''};
  const[careerForm,setCareerForm]=useState(emptyCareer);
  const MAX_FILE_SIZE=5*1024*1024;
  const subjectOptions=['유아·초급 과정','중급 과정 (체르니30·소나티네)','고급 과정 (소나타·인벤션)','콩쿠르·입시 과정','성인·청소년 과정','음악이론·시창 과정'];
  const setEdu=k=>e=>setForm(f=>({...f,edu:{...f.edu,[k]:e.target.value}}));
  const toggleSubject=s=>setForm(f=>({...f,subjects:(f.subjects||[]).includes(s)?f.subjects.filter(x=>x!==s):[...(f.subjects||[]),s]}));
  const openAdd=()=>{setEditTarget(null);setForm({...emptyForm,contractStart:today()});setCareerForm(emptyCareer);setModalOpen(true);};
  const openEdit=t=>{setEditTarget(t);setForm({...t,subjects:t.subjects||[],dependents:t.dependents||1,edu:t.edu||{bachUniv:'',bachMajor:'',mastUniv:'',mastMajor:'',phdUniv:'',phdMajor:''},career:t.career||[],attachments:t.attachments||[]});setCareerForm(emptyCareer);setModalOpen(true);};
  const addCareer=()=>{
    if(!careerForm.org||!careerForm.startDate){alert('근무 기관명과 시작일은 필수입니다.');return;}
    setForm(f=>({...f,career:[...(f.career||[]),careerForm]}));
    setCareerForm(emptyCareer);
  };
  const removeCareer=i=>setForm(f=>({...f,career:f.career.filter((_,idx)=>idx!==i)}));
  const handleFileUpload=e=>{
    const files=Array.from(e.target.files||[]);
    files.forEach(file=>{
      if(file.size>MAX_FILE_SIZE){alert(`"${file.name}" 파일이 5MB를 초과하여 업로드할 수 없습니다.`);return;}
      const reader=new FileReader();
      reader.onload=()=>{
        setForm(f=>({...f,attachments:[...(f.attachments||[]),{name:file.name,dataUrl:reader.result,size:file.size,uploadDate:today()}]}));
      };
      reader.readAsDataURL(file);
    });
    e.target.value='';
  };
  const removeAttachment=i=>setForm(f=>({...f,attachments:f.attachments.filter((_,idx)=>idx!==i)}));
  const save=()=>{
    if(!form.name||!(form.subjects&&form.subjects.length)){alert('이름과 담당 과정은 필수입니다 (최소 1개 선택).');return;}
    if(!form.email){alert('이메일은 필수입니다.');return;}
    if(!form.contractStart){alert('계약 시작일은 필수입니다.');return;}
    if(!form.salary){alert('월 급여는 필수입니다.');return;}
    if(!form.edu?.bachUniv||!form.edu?.bachMajor){alert('학사 대학교와 학과는 필수입니다.');return;}
    // 활동중 → 비활동 전환 시 비활동 설정 모달 표시
    if(editTarget&&editTarget.status==='active'&&form.status==='inactive'){
      const myClasses=(classes||[]).filter(c=>c.teacherId===editTarget.id&&!(c.closeDate&&c.closeDate<today()));
      if(myClasses.length>0){
        const classList=myClasses.map(c=>c.name).join(', ');
        const ok=confirm(`⚠️ ${editTarget.name} 강사를 비활동으로 전환합니다.\n\n현재 담당 수업: ${classList}\n\n비활동 처리 후에도 수업은 그대로 유지됩니다.\n\n계속하시겠습니까?`);
        if(!ok)return;
      }
      setInactiveTarget({...form,id:editTarget.id});
      setInactiveForm({reason:'vacation',startDate:today(),endDate:today(),note:''});
      setModalOpen(false);
      setInactiveModal(true);
      return;
    }
    if(editTarget)setTeachers(prev=>prev.map(t=>t.id===editTarget.id?{...form,id:t.id}:t));
    else setTeachers(prev=>[...prev,{...form,id:genId()}]);
    setModalOpen(false);
  };
  const del=id=>{setTeachers(prev=>prev.filter(t=>t.id!==id));setConfirmId(null);};
  const openResign=t=>{setResignTarget(t);setResignForm({date:today(),reason:'',note:''});setResignModal(true);};
  const confirmResign=()=>{
    if(!resignForm.date){alert('퇴직일을 입력해주세요.');return;}
    if(!resignForm.reason){alert('퇴직 사유를 선택해주세요.');return;}
    const myClasses=(classes||[]).filter(c=>c.teacherId===resignTarget.id&&!(c.closeDate&&c.closeDate<today()));
    if(myClasses.length>0){
      const classList=myClasses.map(c=>c.name).join(', ');
      const confirmed=confirm(`⚠️ 퇴직 처리 후 담당 수업 확인 필요\n\n현재 담당 수업: ${classList}\n\n퇴직 처리 후에도 수업 데이터는 3년간 보존됩니다.\n수업 관리 페이지에서 담당 강사를 다른 강사로 변경하거나, 더 이상 운영하지 않으면 수업을 마감 처리해주세요.\n\n계속하시겠습니까?`);
      if(!confirmed)return;
    }
    setTeachers(prev=>prev.map(t=>t.id===resignTarget.id?{...t,status:'resigned',resignedAt:resignForm.date,resignedReason:resignForm.reason,resignedNote:resignForm.note}:t));
    // 담당 수업이 있으면 배정 해제 여부 선택
    if(myClasses.length>0&&setClasses){
      const clearAssign=confirm(`${resignTarget.name} 강사의 담당 수업(${myClasses.map(c=>c.name).join(', ')})에서 강사 배정을 해제하시겠습니까?\n\n• 예: 수업에서 담당강사가 제거됩니다 (수업 데이터는 유지)\n• 아니오: 수업에 강사명이 그대로 남습니다`);
      if(clearAssign)setClasses(prev=>prev.map(c=>myClasses.some(mc=>mc.id===c.id)?{...c,teacherId:''}:c));
    }
    setResignModal(false);
  };
  const confirmInactive=()=>{
    if(!inactiveForm.startDate||!inactiveForm.endDate){alert('비활동 기간을 입력해주세요.');return;}
    if(inactiveForm.endDate<inactiveForm.startDate){alert('종료일이 시작일보다 빠릅니다.');return;}
    if(inactiveForm.reason==='other'&&!inactiveForm.note.trim()){alert('기타 사유를 입력해주세요.');return;}
    const ro=inactiveReasonOpts.find(r=>r.val===inactiveForm.reason)||inactiveReasonOpts[0];
    setTeachers(prev=>prev.map(t=>t.id===inactiveTarget.id?{...inactiveTarget,status:'inactive',inactiveReason:inactiveForm.reason,inactiveStartDate:inactiveForm.startDate,inactiveEndDate:inactiveForm.endDate,inactiveNote:inactiveForm.note}:t));
    if(setAttendance){
      const start=new Date(inactiveForm.startDate);const end=new Date(inactiveForm.endDate);
      const newRecs=[];let cur=new Date(start);
      while(cur<=end){
        const ds=cur.toISOString().split('T')[0];
        newRecs.push({id:genId(),date:ds,type:'teacher',refId:inactiveTarget.id,status:ro.attStatus,note:`비활동(${ro.label})${inactiveForm.note?' - '+inactiveForm.note:''}`});
        cur.setDate(cur.getDate()+1);
      }
      setAttendance(prev=>{
        // 비활동 기간 날짜의 기존 기록은 삭제하고 비활동 상태로 덮어씀
        const inactiveDates=new Set(newRecs.map(r=>r.date));
        const kept=prev.filter(a=>!(a.type==='teacher'&&a.refId===inactiveTarget.id&&inactiveDates.has(a.date)));
        return[...kept,...newRecs];
      });
    }
    setInactiveModal(false);setInactiveTarget(null);
  };
  const reinstateTeacher=id=>{
    const todayStr=today();
    const acName=localStorage.getItem('hm_academy_name')||'하모니 피아노 학원';
    setTeachers(prev=>prev.map(t=>{
      if(t.id!==id)return t;
      // 이전 근무 기간을 경력에 자동 등록
      const prevCareer={org:acName,role:'피아노 강사',startDate:t.contractStart||'',endDate:t.resignedAt||todayStr};
      const career=[...(t.career||[]),prevCareer];
      const endD=new Date(todayStr);endD.setFullYear(endD.getFullYear()+1);endD.setDate(endD.getDate()-1);
      const contractEndStr=endD.toISOString().split('T')[0];
      return{...t,status:'active',contractStart:todayStr,contractEnd:contractEndStr,career,resignedAt:undefined,resignedReason:undefined,resignedNote:undefined};
    }));
    alert('복직 처리되었습니다.\n이전 근무 기간이 경력으로 자동 등록되었으며,\n계약 시작일: 오늘 / 계약 종료일: 1년 후로 갱신되었습니다.');
  };
  const tGetters={name:t=>t.name||'',phone:t=>t.phone||'',salary:t=>Number(t.salary||0),status:t=>t.status||'',contractStart:t=>t.contractStart||''};
  const activeTeachers=teachers.filter(t=>t.status!=='resigned'&&(t.name.includes(search)||(t.subjects||[]).some(s=>s.includes(search)))).sort((a,b)=>{const g=tGetters[tSortKey]||tGetters.name;const av=g(a),bv=g(b);if(typeof av==='number')return tSortDir==='asc'?av-bv:bv-av;return tSortDir==='asc'?String(av).localeCompare(String(bv),'ko'):String(bv).localeCompare(String(av),'ko');});
  const resignedTeacherList=teachers.filter(t=>t.status==='resigned'&&(t.name.includes(search)||(t.subjects||[]).some(s=>s.includes(search)))).sort((a,b)=>(b.resignedAt||'').localeCompare(a.resignedAt||''));
  const filtered=teacherTab==='active'?activeTeachers:resignedTeacherList;
  const totalSalary=teachers.filter(t=>t.status==='active').reduce((s,t)=>s+Number(t.salary||0),0);
  const resignReasons=['계약만료','개인사정','이직','건강','기타'];
  const eduLabel=e=>{
    if(!e)return'-';
    const parts=[];
    if(e.bachUniv)parts.push(`학사: ${e.bachUniv} ${e.bachMajor}`);
    if(e.mastUniv)parts.push(`석사: ${e.mastUniv} ${e.mastMajor}`);
    if(e.phdUniv)parts.push(`박사: ${e.phdUniv} ${e.phdMajor}`);
    return parts.join(' / ')||'-';
  };
  const highestEdu=e=>{
    if(!e)return null;
    if(e.phdUniv)return<span className="badge bg-yellow-100 text-yellow-700">박사</span>;
    if(e.mastUniv)return<span className="badge bg-purple-100 text-purple-700">석사</span>;
    if(e.bachUniv)return<span className="badge bg-blue-100 text-blue-700">학사</span>;
    return null;
  };
  const highestEduInfo=e=>{
    if(!e)return{univ:'-',major:''};
    if(e.phdUniv)return{univ:e.phdUniv,major:e.phdMajor||''};
    if(e.mastUniv)return{univ:e.mastUniv,major:e.mastMajor||''};
    if(e.bachUniv)return{univ:e.bachUniv,major:e.bachMajor||''};
    return{univ:'-',major:''};
  };
  const isContractExpired=t=>t.contractEnd&&t.contractEnd<today();
  return<div className="space-y-5">
    <div className="flex items-center justify-between">
      <div><h1 className="text-2xl font-bold text-slate-900">강사 관리</h1>
        <p className="text-slate-600 text-sm mt-1">재직 {teachers.filter(t=>t.status!=='resigned').length}명 · 활동중 {teachers.filter(t=>t.status==='active').length}명 · 퇴직 {teachers.filter(t=>t.status==='resigned').length}명 · 월 급여 합계 {fWon(totalSalary)}</p>
      </div>
      {teacherTab==='active'&&<button className={btn('indigo')} onClick={openAdd}>+ 강사 등록</button>}
    </div>
    <div className="flex gap-2">
      <button onClick={()=>setTeacherTab('active')} className={`text-sm font-semibold px-4 py-2 rounded-lg ${teacherTab==='active'?'bg-[#1e3a5f] text-white':'bg-white text-slate-600 border border-gray-200'}`}>재직중 ({teachers.filter(t=>t.status!=='resigned').length})</button>
      <button onClick={()=>setTeacherTab('resigned')} className={`text-sm font-semibold px-4 py-2 rounded-lg ${teacherTab==='resigned'?'bg-[#1e3a5f] text-white':'bg-white text-slate-600 border border-gray-200'}`}>퇴직강사 ({teachers.filter(t=>t.status==='resigned').length})</button>
    </div>
    <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
      <div className="p-4 border-b border-gray-100"><input className={inp} placeholder="이름 또는 과목 검색..." value={search} onChange={e=>setSearch(e.target.value)} style={{maxWidth:'280px'}}/></div>
      <div className="overflow-x-auto overflow-y-auto tbl-scroll" style={{maxHeight:'calc(100vh - 310px)'}}>
        {teacherTab==='active'?<table className="w-full text-sm app-table">
          <thead className="bg-[#f1f5f9] text-slate-600 text-xs"><tr>
            <th className="px-3 py-3 text-left font-medium cursor-pointer select-none" style={{width:'90px'}} onClick={()=>tSortField('name')}>이름{tArrow('name')}</th>
            <th className="px-3 py-3 text-left font-medium" style={{width:'80px'}}>과목</th>
            <th className="px-3 py-3 text-left font-medium" style={{width:'90px'}}>최종학력</th>
            <th className="px-3 py-3 text-left font-medium cursor-pointer select-none" style={{width:'120px'}} onClick={()=>tSortField('phone')}>연락처{tArrow('phone')}</th>
            <th className="px-3 py-3 text-left font-medium" style={{width:'150px'}}>이메일</th>
            <th className="px-3 py-3 text-left font-medium cursor-pointer select-none" style={{width:'180px'}} onClick={()=>tSortField('contractStart')}>계약기간{tArrow('contractStart')}</th>
            <th className="px-3 py-3 text-left font-medium cursor-pointer select-none" style={{width:'110px'}} onClick={()=>tSortField('salary')}>월급여{tArrow('salary')}</th>
            <th className="px-3 py-3 text-left font-medium cursor-pointer select-none" style={{width:'90px'}} onClick={()=>tSortField('status')}>상태{tArrow('status')}</th>
            <th className="px-3 py-3 text-left font-medium" style={{width:'110px'}}>관리</th>
          </tr></thead>
          <tbody>{activeTeachers.map(t=><tr key={t.id} className="table-row border-t border-gray-50">
            <td className="px-3 py-3 font-semibold text-slate-900">{t.name}</td>
            <td className="px-3 py-3"><div className="flex flex-wrap gap-1">{(t.subjects||[]).map(s=><span key={s} className="badge bg-[#dbeafe] text-[#1e293b]">{s}</span>)}</div></td>
            <td className="px-3 py-3">{highestEdu(t.edu)}<div className="text-xs text-slate-600 mt-0.5" style={{maxWidth:'140px',overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap'}} title={eduLabel(t.edu)}>{(()=>{const ei=highestEduInfo(t.edu);return`${ei.univ} ${ei.major}`.trim()||'-';})()}</div></td>
            <td className="px-3 py-3 text-slate-700">{t.phone}</td>
            <td className="px-3 py-3 text-slate-600 text-xs">{t.email||'-'}</td>
            <td className="px-3 py-3 text-slate-600 text-xs">{fDate(t.contractStart)} ~<br/>{fDate(t.contractEnd)}</td>
            <td className="px-3 py-3 font-semibold text-slate-900">{fWon(t.salary)}</td>
            <td className="px-3 py-3">{(()=>{const expired=isContractExpired(t);const eff=expired?'inactive':t.status;return<><span className={`badge ${sColor(eff)}`}>{eff==='active'?'활동중':'비활동'}</span>{expired&&<div className="text-xs text-red-400 mt-0.5">계약종료</div>}</>;})()}</td>
            <td className="px-3 py-3">
              <div className="flex gap-1">
                <button onClick={()=>openEdit(t)} className="text-xs px-2 py-1 rounded bg-[#f1f5f9] text-[#1e3a5f] hover:bg-[#dbeafe]">수정</button>
                <button onClick={()=>openResign(t)} className="text-xs px-2 py-1 rounded bg-orange-50 text-orange-600 hover:bg-orange-100">퇴직</button>
                <button onClick={()=>setConfirmId(t.id)} className="text-xs px-2 py-1 rounded bg-red-50 text-red-500 hover:bg-red-100">삭제</button>
              </div>
            </td>
          </tr>)}
          {activeTeachers.length===0&&<tr><td colSpan={9} className="text-center py-12 text-slate-600">재직중인 강사가 없습니다</td></tr>}
          </tbody>
        </table>
        :<table className="w-full text-sm app-table">
          <thead className="bg-[#f1f5f9] text-slate-600 text-xs"><tr>
            <th className="px-3 py-3 text-left font-medium" style={{width:'90px'}}>이름</th>
            <th className="px-3 py-3 text-left font-medium" style={{width:'80px'}}>과목</th>
            <th className="px-3 py-3 text-left font-medium" style={{width:'90px'}}>최종학력</th>
            <th className="px-3 py-3 text-left font-medium" style={{width:'120px'}}>연락처</th>
            <th className="px-3 py-3 text-left font-medium" style={{width:'180px'}}>재직기간</th>
            <th className="px-3 py-3 text-left font-medium" style={{width:'100px'}}>퇴직일</th>
            <th className="px-3 py-3 text-left font-medium" style={{width:'100px'}}>퇴직사유</th>
            <th className="px-3 py-3 text-left font-medium" style={{width:'110px'}}>관리</th>
          </tr></thead>
          <tbody>{resignedTeacherList.map(t=><tr key={t.id} className="table-row border-t border-gray-50 bg-slate-50 opacity-80">
            <td className="px-3 py-3 font-semibold text-slate-700">{t.name}</td>
            <td className="px-3 py-3"><div className="flex flex-wrap gap-1">{(t.subjects||[]).map(s=><span key={s} className="badge bg-slate-200 text-slate-600">{s}</span>)}</div></td>
            <td className="px-3 py-3">{highestEdu(t.edu)}<div className="text-xs text-slate-500 mt-0.5">{(()=>{const ei=highestEduInfo(t.edu);return`${ei.univ} ${ei.major}`.trim()||'-';})()}</div></td>
            <td className="px-3 py-3 text-slate-600">{t.phone||'-'}</td>
            <td className="px-3 py-3 text-slate-500 text-xs">{fDate(t.contractStart)} ~ {t.resignedAt?fDate(t.resignedAt):'-'}</td>
            <td className="px-3 py-3 text-slate-600 text-xs font-medium">{fDate(t.resignedAt)||'-'}</td>
            <td className="px-3 py-3 text-slate-500 text-xs">{t.resignedReason||'-'}{t.resignedNote&&<div className="text-slate-400">{t.resignedNote}</div>}</td>
            <td className="px-3 py-3"><div className="flex gap-1">
              <button onClick={()=>reinstateTeacher(t.id)} className="text-xs px-2 py-1 rounded bg-emerald-50 text-emerald-600 hover:bg-emerald-100">복직</button>
              <button onClick={()=>setConfirmId(t.id)} className="text-xs px-2 py-1 rounded bg-red-50 text-red-500 hover:bg-red-100">삭제</button>
            </div></td>
          </tr>)}
          {resignedTeacherList.length===0&&<tr><td colSpan={8} className="text-center py-12 text-slate-600">퇴직한 강사가 없습니다</td></tr>}
          </tbody>
        </table>}
      </div>
    </div>
    <Modal open={modalOpen} onClose={()=>setModalOpen(false)} title={editTarget?'강사 정보 수정':'강사 등록'} wide>
      <div className="grid grid-cols-2 gap-x-4">
        <Field label="이름" required><input className={inp} value={form.name} onChange={e=>setForm({...form,name:e.target.value})}/></Field>
        <Field label="이메일" required><input className={inp} type="email" value={form.email} onChange={e=>setForm({...form,email:e.target.value})}/></Field>
        <Field label="연락처"><input className={inp} placeholder="010-0000-0000" value={form.phone} onChange={e=>setForm({...form,phone:e.target.value})}/></Field>
        <Field label="계약 시작일" required><input className={inp} type="date" value={form.contractStart} onChange={e=>{const s=e.target.value;let autoEnd='';if(s){const d=new Date(s);d.setFullYear(d.getFullYear()+1);d.setDate(d.getDate()-1);autoEnd=d.toISOString().split('T')[0];}setForm({...form,contractStart:s,contractEnd:form.contractEnd||autoEnd});}}/></Field>
        <Field label="계약 종료일"><div className="flex gap-2 items-center"><input className={inp} type="date" value={form.contractEnd} onChange={e=>setForm({...form,contractEnd:e.target.value})}/><button type="button" onClick={()=>{if(!form.contractStart)return;const d=new Date(form.contractStart);d.setFullYear(d.getFullYear()+1);d.setDate(d.getDate()-1);setForm({...form,contractEnd:d.toISOString().split('T')[0]});}} className="text-xs px-2 py-1.5 bg-slate-100 text-slate-600 rounded hover:bg-slate-200 shrink-0 whitespace-nowrap">+1년 자동</button></div><p className="text-xs text-slate-400 mt-1">계약 시작일을 입력하면 종료일이 자동으로 계산됩니다 (1년 단위 갱신)</p></Field>
        <Field label="월 급여 (원, 만원 단위)" required><WonInput value={form.salary} onChange={v=>setForm({...form,salary:v})}/></Field>
        <Field label="부양가족수 (본인 포함, 급여명세서 소득세 계산용)" required>
          <select className={inp} value={form.dependents||1} onChange={e=>setForm({...form,dependents:Number(e.target.value)})}>
            {Array.from({length:11},(_,i)=>i+1).map(n=><option key={n} value={n}>{n}명{n===1?' (본인만)':''}</option>)}
          </select>
        </Field>
        <Field label="상태"><select className={inp} value={form.status} onChange={e=>setForm({...form,status:e.target.value})}><option value="active">활동중</option><option value="inactive">비활동</option></select></Field>
      </div>
      <Field label="담당 과정 (복수 선택 가능)" required>
        <div className="flex flex-wrap gap-2">
          {subjectOptions.map(s=>{
            const checked=(form.subjects||[]).includes(s);
            return<button key={s} type="button" onClick={()=>toggleSubject(s)}
              className={`text-xs px-3 py-1.5 rounded-full border font-medium transition-colors ${checked?'bg-[#1e3a5f] text-white border-[#1e3a5f]':'bg-white text-slate-700 border-gray-300 hover:border-[#3b82f6]'}`}>{s}</button>;
          })}
        </div>
      </Field>
      <div className="border-t border-gray-100 pt-4 mt-2">
        <div className="text-sm font-semibold text-slate-800 mb-3">🎓 학력 사항</div>
        <div className="bg-blue-50 rounded-xl p-4 mb-3">
          <div className="text-xs font-semibold text-blue-700 mb-2">학사 (필수)</div>
          <div className="grid grid-cols-2 gap-3">
            <Field label="대학교" required><input className={inp} value={form.edu?.bachUniv||''} onChange={setEdu('bachUniv')} placeholder="예: 서울대학교"/></Field>
            <Field label="학과" required><input className={inp} value={form.edu?.bachMajor||''} onChange={setEdu('bachMajor')} placeholder="예: 음악학과"/></Field>
          </div>
        </div>
        <div className="bg-purple-50 rounded-xl p-4 mb-3">
          <div className="text-xs font-semibold text-purple-700 mb-2">석사 (선택)</div>
          <div className="grid grid-cols-2 gap-3">
            <Field label="대학원"><input className={inp} value={form.edu?.mastUniv||''} onChange={setEdu('mastUniv')} placeholder="예: 한국예술종합학교"/></Field>
            <Field label="학과"><input className={inp} value={form.edu?.mastMajor||''} onChange={setEdu('mastMajor')} placeholder="예: 피아노"/></Field>
          </div>
        </div>
        <div className="bg-yellow-50 rounded-xl p-4">
          <div className="text-xs font-semibold text-yellow-700 mb-2">박사 (선택)</div>
          <div className="grid grid-cols-2 gap-3">
            <Field label="대학원"><input className={inp} value={form.edu?.phdUniv||''} onChange={setEdu('phdUniv')} placeholder="예: 서울대학교 대학원"/></Field>
            <Field label="학과"><input className={inp} value={form.edu?.phdMajor||''} onChange={setEdu('phdMajor')} placeholder="예: 음악학"/></Field>
          </div>
        </div>
      </div>
      <div className="border-t border-gray-100 pt-4 mt-2">
        <div className="text-sm font-semibold text-slate-800 mb-3">💼 경력 사항</div>
        {(form.career||[]).length>0&&<div className="space-y-2 mb-3">
          {(form.career||[]).map((c,i)=>(
            <div key={i} className="flex items-center justify-between bg-[#f1f5f9] rounded-lg px-3 py-2">
              <div className="text-sm">
                <span className="font-medium text-slate-900">{c.org}</span>
                {c.role&&<span className="text-slate-600"> · {c.role}</span>}
                <div className="text-xs text-slate-500">{fDate(c.startDate)} ~ {c.endDate?fDate(c.endDate):'현재'}</div>
              </div>
              <button type="button" onClick={()=>removeCareer(i)} className="text-xs px-2 py-1 rounded bg-red-50 text-red-500 hover:bg-red-100">삭제</button>
            </div>
          ))}
        </div>}
        <div className="grid grid-cols-2 gap-3 bg-white border border-gray-200 rounded-xl p-3">
          <input className={inp} placeholder="근무 기관명 (예: OO음악학원)" value={careerForm.org} onChange={e=>setCareerForm({...careerForm,org:e.target.value})}/>
          <input className={inp} placeholder="직책/역할 (예: 피아노 강사)" value={careerForm.role} onChange={e=>setCareerForm({...careerForm,role:e.target.value})}/>
          <Field label="근무 시작일"><input className={inp} type="date" value={careerForm.startDate} onChange={e=>setCareerForm({...careerForm,startDate:e.target.value})}/></Field>
          <Field label="근무 종료일"><input className={inp} type="date" value={careerForm.endDate} onChange={e=>setCareerForm({...careerForm,endDate:e.target.value})}/></Field>
          <button type="button" className={btn('gray')} style={{gridColumn:'span 2'}} onClick={addCareer}>+ 경력 추가</button>
        </div>
      </div>
      <div className="border-t border-gray-100 pt-4 mt-2">
        <div className="text-sm font-semibold text-slate-800 mb-3">📎 첨부파일 (학력·경력 증명서)</div>
        <div className="text-xs text-slate-500 mb-2">PDF·이미지 파일만 가능, 파일당 5MB 이하</div>
        <input type="file" multiple accept=".pdf,.jpg,.jpeg,.png" onChange={handleFileUpload} className="text-sm mb-3"/>
        {(form.attachments||[]).length>0?<div className="space-y-2">
          {(form.attachments||[]).map((f,i)=>(
            <div key={i} className="flex items-center justify-between bg-[#f1f5f9] rounded-lg px-3 py-2">
              <div className="text-sm truncate" style={{maxWidth:'60%'}}>📄 {f.name}<div className="text-xs text-slate-500">{fDate(f.uploadDate)} · {Math.ceil(f.size/1024)}KB</div></div>
              <div className="flex gap-2">
                <a href={f.dataUrl} target="_blank" rel="noopener noreferrer" className="text-xs px-2 py-1 rounded bg-[#dbeafe] text-[#1e3a5f]">보기</a>
                <button type="button" onClick={()=>removeAttachment(i)} className="text-xs px-2 py-1 rounded bg-red-50 text-red-500 hover:bg-red-100">삭제</button>
              </div>
            </div>
          ))}
        </div>:<div className="text-xs text-slate-400">첨부된 파일이 없습니다</div>}
      </div>
      <Field label="비고"><textarea className={inp} rows={2} value={form.note} onChange={e=>setForm({...form,note:e.target.value})}/></Field>
      <div className="flex justify-end gap-3 mt-2">
        <button className={btn('indigo')} onClick={save}>저장</button>
        <button className={btn('gray')} onClick={()=>setModalOpen(false)}>취소</button>
      </div>
    </Modal>
    <Modal open={resignModal} onClose={()=>setResignModal(false)} title={`${resignTarget?.name||''} 강사 퇴직 처리`}>
      <Field label="퇴직일" required><input className={inp} type="date" value={resignForm.date} onChange={e=>setResignForm({...resignForm,date:e.target.value})}/></Field>
      <Field label="퇴직 사유" required><select className={inp} value={resignForm.reason} onChange={e=>setResignForm({...resignForm,reason:e.target.value})}><option value="">-- 사유 선택 --</option>{resignReasons.map(r=><option key={r} value={r}>{r}</option>)}</select></Field>
      <Field label="비고"><textarea className={inp} rows={2} value={resignForm.note} onChange={e=>setResignForm({...resignForm,note:e.target.value})}/></Field>
      <p className="text-xs text-slate-500 mb-2">퇴직 처리해도 강사 데이터는 삭제되지 않고 '퇴직강사' 탭에 그대로 남습니다. 필요 시 '복직' 버튼으로 다시 재직 처리할 수 있습니다.</p>
      <div className="flex justify-end gap-3 mt-2"><button className={btn('indigo')} onClick={confirmResign}>퇴직 처리</button><button className={btn('gray')} onClick={()=>setResignModal(false)}>취소</button></div>
    </Modal>
    <Modal open={inactiveModal} onClose={()=>{setInactiveModal(false);setInactiveTarget(null);}} title={`${inactiveTarget?.name||''} 강사 비활동 설정`}>
      <div className="bg-amber-50 border border-amber-200 rounded-lg p-3 mb-4 text-sm text-amber-700">비활동 기간 동안의 출결이 자동으로 등록됩니다. 기간 종료 후 강사 정보에서 다시 '활동중'으로 변경해주세요.</div>
      <Field label="비활동 사유" required><select className={inp} value={inactiveForm.reason} onChange={e=>setInactiveForm({...inactiveForm,reason:e.target.value,note:''})}>{inactiveReasonOpts.map(r=><option key={r.val} value={r.val}>{r.label}</option>)}</select></Field>
      {inactiveForm.reason==='other'&&<Field label="기타 사유" required><input className={inp} placeholder="구체적인 사유를 입력해주세요" value={inactiveForm.note} onChange={e=>setInactiveForm({...inactiveForm,note:e.target.value})}/></Field>}
      <div className="grid grid-cols-2 gap-4">
        <Field label="시작일" required><input className={inp} type="date" value={inactiveForm.startDate} onChange={e=>setInactiveForm({...inactiveForm,startDate:e.target.value})}/></Field>
        <Field label="종료일" required><input className={inp} type="date" value={inactiveForm.endDate} onChange={e=>setInactiveForm({...inactiveForm,endDate:e.target.value})}/></Field>
      </div>
      {inactiveForm.reason!=='other'&&<Field label="메모 (선택)"><input className={inp} placeholder="추가 메모" value={inactiveForm.note} onChange={e=>setInactiveForm({...inactiveForm,note:e.target.value})}/></Field>}
      {inactiveForm.startDate&&inactiveForm.endDate&&inactiveForm.endDate>=inactiveForm.startDate&&<div className="text-xs text-slate-500 bg-slate-50 rounded-lg p-2 mb-2">출결 자동 등록: {inactiveForm.startDate} ~ {inactiveForm.endDate} 총 {(()=>{const d=(new Date(inactiveForm.endDate)-new Date(inactiveForm.startDate))/(86400000)+1;return Math.max(0,Math.round(d));})()}일 — {inactiveReasonOpts.find(r=>r.val===inactiveForm.reason)?.label||''}</div>}
      <div className="flex justify-end gap-3 mt-2"><button className={btn('indigo')} onClick={confirmInactive}>비활동 처리 + 출결 등록</button><button className={btn('gray')} onClick={()=>{setInactiveModal(false);setInactiveTarget(null);}}>취소</button></div>
    </Modal>
    <Confirm open={!!confirmId} msg="이 강사를 완전히 삭제하시겠습니까? (복구 불가)" onYes={()=>del(confirmId)} onNo={()=>setConfirmId(null)}/>
  </div>;
}

// ── 수업 관리 ────────────────────────────────────────────────────────────────
function ClassManagement({classes,setClasses,teachers,students,role}){
  const[modalOpen,setModalOpen]=useState(false);
  const[editTarget,setEditTarget]=useState(null);
  const[confirmId,setConfirmId]=useState(null);
  const[viewMode,setViewMode]=useState('list');
  const[classTab,setClassTab]=useState('active');
  const[clsSortKey,setClsSortKey]=useState('name');
  const[clsSortDir,setClsSortDir]=useState('asc');
  const clsSortField=k=>{if(clsSortKey===k)setClsSortDir(d=>d==='asc'?'desc':'asc');else{setClsSortKey(k);setClsSortDir('asc');}};
  const clsArrow=k=>clsSortKey===k?(clsSortDir==='asc'?' ▲':' ▼'):'';
  const[form,setForm]=useState({name:'',teacherId:'',subject:'',days:[],startTime:'',endTime:'',room:'',maxStudents:'',fee:'',openDate:'',closeDate:''});
  const dayNames=['일','월','화','수','목','금','토'];
  const rooms=['1레슨실','2레슨실','3레슨실','그룹레슨실','이론강의실','발표홀'];
  const openAdd=()=>{setEditTarget(null);setForm({name:'',teacherId:'',subject:'',days:[],startTime:'09:00',endTime:'10:00',room:'',maxStudents:10,fee:'',openDate:today(),closeDate:''});setModalOpen(true);};
  const openEdit=c=>{setEditTarget(c);setForm({...c});setModalOpen(true);};
  const toggleDay=d=>setForm(f=>({...f,days:f.days.includes(d)?f.days.filter(x=>x!==d):[...f.days,d].sort()}));
  const selectedTeacher=teachers.find(t=>t.id===form.teacherId);
  const timeToMin=t=>{const[h,m]=(t||'0:0').split(':').map(Number);return(h||0)*60+(m||0);};
  const isTimeOverlap=(s1,e1,s2,e2)=>timeToMin(s1)<timeToMin(e2)&&timeToMin(s2)<timeToMin(e1);
  const findConflict=(f,excludeId)=>{
    const fStart=f.openDate||'0000-01-01';
    const fEnd=f.closeDate||'9999-12-31';
    for(const c of classes){
      if(c.id===excludeId)continue;
      // 운영기간이 서로 겹치지 않으면 충돌 없음 (종료된 수업 + 미래 개설 수업 제외)
      const cStart=c.openDate||'0000-01-01';
      const cEnd=c.closeDate||'9999-12-31';
      if(fStart>cEnd||cStart>fEnd)continue;
      const daysOverlap=(f.days||[]).some(d=>(c.days||[]).includes(d));
      if(!daysOverlap)continue;
      if(!isTimeOverlap(f.startTime,f.endTime,c.startTime,c.endTime))continue;
      if(f.room&&c.room&&f.room===c.room)return{type:'room',with:c};
      if(f.teacherId&&c.teacherId&&f.teacherId===c.teacherId)return{type:'teacher',with:c};
    }
    return null;
  };
  const save=()=>{
    if(!form.name||!form.teacherId){alert('수업명과 담당강사는 필수입니다.');return;}
    if(!form.subject){alert('수업 과정(과목)을 선택해주세요.');return;}
    if(!form.days||form.days.length===0){alert('수업 요일을 선택해주세요.');return;}
    if(!form.startTime||!form.endTime){alert('시작 시간과 종료 시간을 입력해주세요.');return;}
    if(timeToMin(form.endTime)<=timeToMin(form.startTime)){alert('종료 시간은 시작 시간보다 늦어야 합니다.');return;}
    if(form.openDate&&form.closeDate&&form.closeDate<form.openDate){alert('종료일은 개설일보다 늦어야 합니다.');return;}
    const conflict=findConflict(form,editTarget?.id);
    if(conflict){
      const overlapDays=(form.days||[]).filter(d=>(conflict.with.days||[]).includes(d)).map(d=>dayNames[d]).join(',');
      const label=conflict.type==='room'?`강의실(${form.room})`:'강사';
      alert(`일정이 겹칩니다!\n${label} 기준으로 '${conflict.with.name}' 수업과 ${overlapDays}요일 ${conflict.with.startTime}~${conflict.with.endTime}에 충돌합니다.\n요일/시간/강의실을 다시 확인해주세요.`);
      return;
    }
    if(editTarget)setClasses(prev=>prev.map(c=>c.id===editTarget.id?{...form,id:c.id}:c));
    else setClasses(prev=>[...prev,{...form,id:genId()}]);
    setModalOpen(false);
  };
  const del=id=>{setClasses(prev=>prev.filter(c=>c.id!==id));setConfirmId(null);};
  const getTeacher=id=>teachers.find(t=>t.id===id);
  // 종료된 수업: closeDate가 있고 오늘 이전이면 '종료'로 분류
  const isEnded=c=>!!(c.closeDate&&c.closeDate<=today());
  const activeClasses=classes.filter(c=>!isEnded(c));
  const endedClasses=classes.filter(c=>isEnded(c));
  const displayClasses=classTab==='active'?activeClasses:endedClasses;
  // 오늘 요일(0=일,1=월,...,6=토) — 수업 목록/시간표에서 "오늘 수업"을 강조 표시하기 위함 (Austin님 피드백[8])
  const todayDow=new Date().getDay();
  // 이 수업을 현재 수강 중인 학생 수 — 정원 대비 빈자리를 계산하기 위함 (Austin님 피드백[5])
  // 퇴원(withdrawn) 처리된 학생은 제외하고, 그 수업을 enrolledClasses에 담고 있는 재원생만 셈
  const enrolledCount=cid=>(students||[]).filter(s=>s.status!=='withdrawn'&&(!s.joinDate||s.joinDate<=today())&&(s.enrolledClasses||[]).includes(cid)).length;
  const ScheduleView=()=>{
    // 시간표에 보여줄 시간 범위: 8시~21시(13칸). 한 시간칸의 높이(px)를 ROW_H로 고정해두고,
    // 수업 박스의 세로 높이를 "실제 수업 시간(분)"에 정확히 비례하도록 계산합니다.
    // (예전에는 수업이 시작하는 시간 한 칸에만 박스를 넣어서, 16:30~17:30처럼 칸 경계를 걸치는
    //  수업도 항상 한 칸 높이로만 보여 "6시~7시"처럼 보이는 문제가 있었습니다 — Austin님 피드백[9] 재수정)
    const startHour=8,endHour=21;
    const hours=Array.from({length:endHour-startHour},(_,i)=>i+startHour);
    const cols=[1,2,3,4,5,6];
    // ROW_H(1시간당 높이)를 72px로 넉넉히 잡고, 박스 최소 높이(MIN_BOX_H)를 60px로 둡니다.
    // → 수업명/시간/강사 이름 3줄(글씨를 줄여도 최소 50px 안팎 필요)이 항상 박스 안에 깨지지 않고
    //   들어가도록 하면서, 그보다 긴 수업(60분·90분)은 실제 길이에 비례해 더 크게 보이도록 합니다.
    //   (Austin님이 캡처로 지적: 짧은 수업의 박스 높이가 모자라 강사 이름 줄이 잘려서 깨져 보였음)
    const ROW_H=72;
    const MIN_BOX_H=60;
    const sColors={'유아·초급 과정':'bg-yellow-100 border-yellow-300 text-yellow-800','중급 과정 (체르니30·소나티네)':'bg-blue-100 border-blue-300 text-blue-800','고급 과정 (소나타·인벤션)':'bg-purple-100 border-purple-300 text-purple-800','콩쿠르·입시 과정':'bg-red-100 border-red-300 text-red-800','성인·청소년 과정':'bg-green-100 border-green-300 text-green-800','음악이론·시창 과정':'bg-indigo-100 border-indigo-300 text-indigo-800'};
    // 같은 요일에 시간이 겹치는 수업이 여러 개 있으면(예: 다른 강사가 동시에 다른 반 수업) 한 줄에 겹쳐
    // 보이지 않도록 "레인(lane)" 번호를 매겨서 옆으로 나란히 배치합니다.
    const layoutForDay=d=>{
      const dayClasses=activeClasses.filter(c=>c.days?.includes(d)).map(c=>({...c,_start:timeToMin(c.startTime),_end:timeToMin(c.endTime)})).sort((a,b)=>a._start-b._start);
      const laneEnds=[];
      dayClasses.forEach(c=>{
        let lane=laneEnds.findIndex(end=>end<=c._start);
        if(lane===-1){lane=laneEnds.length;laneEnds.push(c._end);}
        else laneEnds[lane]=c._end;
        c._lane=lane;
      });
      dayClasses.forEach(c=>{
        const overlap=dayClasses.filter(o=>o._start<c._end&&o._end>c._start);
        c._lanes=Math.max(...overlap.map(o=>o._lane))+1;
      });
      return dayClasses;
    };
    return<div className="overflow-x-auto"><div style={{minWidth:'760px'}}>
      <div className="grid gap-px bg-gray-200" style={{gridTemplateColumns:'80px repeat(6,1fr)'}}>
        <div className="bg-[#f1f5f9] p-2 text-center text-xs text-slate-600">시간</div>
        {cols.map(d=><div key={d} className={`p-2 text-center text-sm font-semibold ${d===todayDow?'bg-blue-100 text-blue-800':'bg-[#f1f5f9] text-slate-900'}`}>
          {dayNames[d]}요일{d===todayDow&&<div className="text-[10px] font-bold text-blue-600 leading-tight">오늘</div>}
        </div>)}
        <div className="bg-white">
          {hours.map(h=><div key={h} className="flex items-center px-3 text-xs text-slate-600 border-t border-gray-100" style={{height:ROW_H}}>{h}:00</div>)}
        </div>
        {cols.map(d=>{
          const dayClasses=layoutForDay(d);
          return<div key={d} className={`relative border-t border-gray-100 ${d===todayDow?'bg-blue-50/40':'bg-white'}`} style={{height:ROW_H*hours.length}}>
            {hours.map((h,i)=>i>0&&<div key={h} className="absolute left-0 right-0 border-t border-gray-100" style={{top:ROW_H*i}}/>)}
            {dayClasses.map(c=>{
              const ct=getTeacher(c.teacherId);
              const top=(c._start-startHour*60)/60*ROW_H;
              const height=Math.max((c._end-c._start)/60*ROW_H-2,MIN_BOX_H);
              const widthPct=100/c._lanes;
              return<div key={c.id} title={`개설일: ${c.openDate?fDate(c.openDate):'-'} / 종료일: ${c.closeDate?fDate(c.closeDate):'운영중'}`} className={`${sColors[c.subject]||'bg-[#dbeafe] border-[#94a3b8] text-[#0f172a]'} border rounded px-1.5 py-1 text-xs leading-tight absolute overflow-hidden`}
                style={{top,height,left:`calc(${widthPct*c._lane}% + 2px)`,width:`calc(${widthPct}% - 4px)`}}>
                <div className="font-semibold truncate">{c.name}</div>
                <div className="opacity-70 truncate">{c.startTime}~{c.endTime}{c.room?` · ${c.room}`:''}</div>
                <div className="opacity-70 truncate">👤{ct?.name||'-'}</div>
              </div>;
            })}
          </div>;
        })}
      </div>
    </div></div>;
  };
  return<div className="space-y-5">
    <div className="flex items-center justify-between">
      <div><h1 className="text-2xl font-bold text-slate-900">수업 관리</h1><p className="text-slate-600 text-sm mt-1">운영중 {activeClasses.length}개 · 종료 {endedClasses.length}개</p></div>
      <div className="flex gap-3">
        <div className="flex bg-gray-100 rounded-lg p-1">
          <button onClick={()=>setViewMode('list')} className={`tab-btn text-xs py-1.5 ${viewMode==='list'?'active':''}`}>목록</button>
          <button onClick={()=>setViewMode('schedule')} className={`tab-btn text-xs py-1.5 ${viewMode==='schedule'?'active':''}`}>시간표</button>
        </div>
        {role!=='teacher'&&<button className={btn('indigo')} onClick={openAdd}>+ 수업 추가</button>}
      </div>
    </div>
    <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
      {viewMode==='list'&&<div className="flex gap-2 px-4 pt-4 pb-4 border-b border-gray-100">
        <button className={`tab-btn ${classTab==='active'?'active':''}`} onClick={()=>setClassTab('active')}>운영중 ({activeClasses.length})</button>
        <button className={`tab-btn ${classTab==='ended'?'active':''}`} onClick={()=>setClassTab('ended')}>종료된 수업 ({endedClasses.length})</button>
      </div>}
      {viewMode==='list'?<div className="overflow-x-auto overflow-y-auto tbl-scroll" style={{maxHeight:'calc(100vh - 320px)'}}><table className="w-full text-sm app-table">
        <thead className="bg-[#f1f5f9] text-slate-600 text-xs"><tr>
          <th className="px-4 py-3 text-left font-medium cursor-pointer select-none" style={{width:'130px'}} onClick={()=>clsSortField('name')}>수업명{clsArrow('name')}</th>
          <th className="px-4 py-3 text-left font-medium cursor-pointer select-none" style={{width:'90px'}} onClick={()=>clsSortField('teacher')}>담당강사{clsArrow('teacher')}</th>
          <th className="px-4 py-3 text-left font-medium" style={{width:'70px'}}>요일</th>
          <th className="px-4 py-3 text-left font-medium cursor-pointer select-none" style={{width:'90px'}} onClick={()=>clsSortField('startTime')}>시간{clsArrow('startTime')}</th>
          <th className="px-4 py-3 text-left font-medium" style={{width:'80px'}}>강의실</th>
          <th className="px-4 py-3 text-left font-medium cursor-pointer select-none" style={{width:'180px'}} onClick={()=>clsSortField('openDate')}>운영기간{clsArrow('openDate')}</th>
          <th className="px-4 py-3 text-left font-medium cursor-pointer select-none" style={{width:'120px'}} onClick={()=>clsSortField('maxStudents')}>정원(현재/총원){clsArrow('maxStudents')}</th>
          <th className="px-4 py-3 text-left font-medium cursor-pointer select-none" style={{width:'100px'}} onClick={()=>clsSortField('fee')}>수강료{clsArrow('fee')}</th>
          {role!=='teacher'&&<th className="px-4 py-3 text-left font-medium" style={{width:'80px'}}>관리</th>}
        </tr></thead>
        <tbody>{[...displayClasses].sort((a,b)=>{
          // 오늘 수업 최우선 정렬
          const aToday=(a.days||[]).includes(todayDow)?0:1;
          const bToday=(b.days||[]).includes(todayDow)?0:1;
          if(aToday!==bToday)return aToday-bToday;
          // 그 다음 선택된 정렬 기준 적용 (기본: 가나다순)
          const clsGetters={name:c=>c.name||'',teacher:c=>teachers.find(t=>t.id===c.teacherId)?.name||'',startTime:c=>c.startTime||'',openDate:c=>c.openDate||'',maxStudents:c=>Number(c.maxStudents||0),fee:c=>Number(c.fee||0)};
          const g=clsGetters[clsSortKey]||clsGetters.name;const av=g(a),bv=g(b);
          if(typeof av==='number')return clsSortDir==='asc'?av-bv:bv-av;
          return clsSortDir==='asc'?String(av).localeCompare(String(bv),'ko'):String(bv).localeCompare(String(av),'ko');
        }).map(c=>{
          const t=getTeacher(c.teacherId);
          const isToday=(c.days||[]).includes(todayDow);
          const cur=enrolledCount(c.id);
          const max=Number(c.maxStudents)||0;
          const remain=max-cur;
          return<tr key={c.id} className={`table-row border-t border-gray-50 ${isToday?'bg-blue-50/50':''}`}>
          <td className="px-4 py-3 font-semibold text-slate-900">{c.name}{isToday&&<span className="ml-1.5 badge bg-blue-100 text-blue-700">오늘 수업</span>}</td>
          <td className="px-4 py-3">{t?<span className="font-medium">{t.name}</span>:'-'}</td>
          <td className="px-4 py-3">{(c.days||[]).map(d=><span key={d} className={`badge mr-1 ${d===todayDow?'bg-blue-600 text-white':'bg-[#f1f5f9] text-[#1e3a5f]'}`}>{dayNames[d]}</span>)}</td>
          <td className="px-4 py-3 text-slate-700">{c.startTime}~{c.endTime}</td>
          <td className="px-4 py-3"><span className="badge bg-gray-100 text-slate-700">{c.room||'-'}</span></td>
          <td className="px-4 py-3 text-slate-700 text-xs">
            {c.openDate?fDate(c.openDate):'-'} ~ {c.closeDate?fDate(c.closeDate):<span className="text-green-700">운영중</span>}
          </td>
          <td className="px-4 py-3 text-slate-700">
            <span className="font-semibold text-slate-900">{cur}</span>/{max}명
            <span className={`ml-1.5 badge ${remain<=0?'bg-red-100 text-red-700':'bg-green-100 text-green-700'}`}>{remain<=0?'마감':`빈자리 ${remain}`}</span>
          </td>
          <td className="px-4 py-3 font-semibold text-slate-900">{fWon(c.fee)}</td>
          {role!=='teacher'&&<td className="px-4 py-3"><div className="flex gap-2">
            <button onClick={()=>openEdit(c)} className="text-xs px-2 py-1 rounded bg-[#f1f5f9] text-[#1e3a5f] hover:bg-[#dbeafe]">수정</button>
            <button onClick={()=>setConfirmId(c.id)} className="text-xs px-2 py-1 rounded bg-red-50 text-red-500 hover:bg-red-100">삭제</button>
          </div></td>}
        </tr>;})}
        {displayClasses.length===0&&<tr><td colSpan={9} className="text-center py-12 text-slate-600">{classTab==='active'?'운영중인 수업이 없습니다':'종료된 수업이 없습니다'}</td></tr>}
        </tbody></table></div>:<div className="p-4"><ScheduleView/></div>}
    </div>
    <Modal open={modalOpen} onClose={()=>setModalOpen(false)} title={editTarget?'수업 수정':'수업 추가'}>
      <Field label="수업명" required><input className={inp} value={form.name} onChange={e=>setForm({...form,name:e.target.value})}/></Field>
      <Field label="담당 강사" required><select className={inp} value={form.teacherId} onChange={e=>{
        const t=teachers.find(x=>x.id===e.target.value);
        setForm({...form,teacherId:e.target.value,subject:(t?.subjects||[])[0]||''});
      }}>
        <option value="">강사 선택</option>{teachers.filter(t=>t.status==='active').sort((a,b)=>a.name.localeCompare(b.name,'ko')).map(t=><option key={t.id} value={t.id}>{t.name} ({(t.subjects||[]).join(', ')})</option>)}
      </select></Field>
      <Field label="수업 과정 (과목)" required>
        <select className={inp} value={form.subject} onChange={e=>setForm({...form,subject:e.target.value})} disabled={!selectedTeacher}>
          <option value="">{selectedTeacher?'선택':'먼저 담당 강사를 선택하세요'}</option>
          {(selectedTeacher?.subjects||[]).map(s=><option key={s} value={s}>{s}</option>)}
        </select>
      </Field>
      <Field label="수업 요일 (복수 선택)"><div className="flex gap-2 flex-wrap">
        {[0,1,2,3,4,5,6].map(d=><button key={d} type="button" onClick={()=>toggleDay(d)}
          className={`w-9 h-9 rounded-full text-sm font-medium border transition-colors ${(form.days||[]).includes(d)?'bg-[#1e3a5f] text-white border-[#4a4a28]':'bg-white text-slate-700 border-gray-300 hover:border-[#3b82f6]'}`}>{dayNames[d]}</button>)}
      </div></Field>
      <div className="grid grid-cols-2 gap-x-4">
        <Field label="시작 시간"><input className={inp} type="time" value={form.startTime} onChange={e=>setForm({...form,startTime:e.target.value})}/></Field>
        <Field label="종료 시간"><input className={inp} type="time" value={form.endTime} onChange={e=>setForm({...form,endTime:e.target.value})}/></Field>
        <Field label="강의실"><select className={inp} value={form.room} onChange={e=>setForm({...form,room:e.target.value})}><option value="">선택</option>{rooms.map(r=><option key={r} value={r}>{r}</option>)}</select></Field>
        <Field label="정원 (명)"><CountInput value={form.maxStudents} onChange={v=>setForm({...form,maxStudents:v})}/></Field>
        <Field label="월 수강료 (원, 만원 단위)"><WonInput value={form.fee} onChange={v=>setForm({...form,fee:v})}/></Field>
        <Field label="개설일"><input className={inp} type="date" value={form.openDate} onChange={e=>setForm({...form,openDate:e.target.value})}/></Field>
        <Field label="종료일 (운영 중이면 비워두세요)"><input className={inp} type="date" value={form.closeDate} onChange={e=>setForm({...form,closeDate:e.target.value})}/></Field>
      </div>
      <div className="flex justify-end gap-3 mt-2"><button className={btn('indigo')} onClick={save}>저장</button><button className={btn('gray')} onClick={()=>setModalOpen(false)}>취소</button></div>
    </Modal>
    <Confirm open={!!confirmId} msg="이 수업을 삭제하시겠습니까?" onYes={()=>del(confirmId)} onNo={()=>setConfirmId(null)}/>
  </div>;
}

// ── 학생 관리 ────────────────────────────────────────────────────────────────
function StudentManagement({students,setStudents,classes,withdrawals,setWithdrawals,tuitions,setTuitions,role,loggedInTeacherId,defaultTab,tuitionDaySetting}){
  const[modalOpen,setModalOpen]=useState(false);
  const[editTarget,setEditTarget]=useState(null);
  const[confirmId,setConfirmId]=useState(null);
  const[search,setSearch]=useState('');
  const[tab,setTab]=useState(defaultTab||'active');
  const[sortKey,setSortKey]=useState('name');
  const[sortDir,setSortDir]=useState('asc');
  const[noteText,setNoteText]=useState('');
  const[editNoteIdx,setEditNoteIdx]=useState(null);
  const[editNoteText,setEditNoteText]=useState('');
  const[withdrawModalOpen,setWithdrawModalOpen]=useState(false);
  const[withdrawTarget,setWithdrawTarget]=useState(null);
  const[withdrawForm,setWithdrawForm]=useState({date:'',reason:'',note:''});
  const[rejoinModalOpen,setRejoinModalOpen]=useState(false);
  const[rejoinTarget,setRejoinTarget]=useState(null);
  const[rejoinForm,setRejoinForm]=useState({date:''});
  const[form,setForm]=useState({name:'',grade:'',phone:'',parentName:'',parentPhone:'',email:'',school:'',enrolledClasses:[],joinDate:'',status:'active',enrollmentHistory:[],progressNotes:[],note:''});
  const grades=['미취학','초1','초2','초3','초4','초5','초6','중1','중2','중3','고1','고2','고3','성인'];
  const withdrawReasons=['이사','학업','비용','불만족','건강','기타'];
  const openAdd=()=>{setEditTarget(null);setForm({name:'',grade:'',phone:'',parentName:'',parentPhone:'',email:'',school:'',enrolledClasses:[],joinDate:today(),status:'active',enrollmentHistory:[{joinDate:today(),leaveDate:null}],progressNotes:[],note:''});setNoteText('');setModalOpen(true);};
  const openEdit=s=>{setEditTarget(s);setForm({...s});setNoteText('');setModalOpen(true);};
  const toggleClass=id=>{
    const cls=classes.find(c=>c.id===id);
    setForm(f=>{
      if(f.enrolledClasses.includes(id)){return{...f,enrolledClasses:f.enrolledClasses.filter(x=>x!==id)};}
      if(cls&&cls.maxStudents){
        const curCount=(students||[]).filter(s=>s.status!=='withdrawn'&&(!s.joinDate||s.joinDate<=today())&&(s.enrolledClasses||[]).includes(id)).length;
        if(curCount>=cls.maxStudents){alert(`${cls.name}은(는) 정원(${cls.maxStudents}명)이 꽉 찼습니다. 마감 수업에는 추가할 수 없습니다.`);return f;}
      }
      return{...f,enrolledClasses:[...f.enrolledClasses,id]};
    });
  };
  const calcTuitionAmount=enrolledClasses=>(enrolledClasses||[]).reduce((sum,cid)=>{const cls=classes.find(c=>c.id===cid);return sum+(cls&&!(cls.closeDate&&cls.closeDate<=today())?cls.fee:0);},0);
  const save=()=>{
    if(!form.name){alert('학생 이름은 필수입니다.');return;}
    // 성인 학생은 학부모 연락처 칸이 화면에 보이지 않으므로, 혹시 이전에 입력되어 있던
    // 학부모 이름/연락처 값이 남아있다면 저장 시점에 비워서 데이터를 깨끗하게 유지합니다.
    const formToSave=form.grade==='성인'?{...form,parentName:'',parentPhone:''}:form;
    if(editTarget){
      setStudents(prev=>prev.map(s=>s.id===editTarget.id?{...formToSave,id:s.id}:s));
      // 학생 수정 시 수강반(enrolledClasses)이 바뀌었다면, 학원비 금액도 새 수강반 기준으로 자동 맞춰줍니다
      // (Austin님 확인: 수강반 변경도 학원비에 자동 반영 — 피드백[19]를 신규 등록뿐 아니라 수정 시점까지 확장)
      const oldKey=JSON.stringify([...(editTarget.enrolledClasses||[])].sort());
      const newKey=JSON.stringify([...(formToSave.enrolledClasses||[])].sort());
      if(setTuitions&&oldKey!==newKey){
        const newAmount=calcTuitionAmount(formToSave.enrolledClasses);
        const d=new Date();
        const month=`${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,'0')}`;
        setTuitions(prev=>{
          const hasCurrentMonth=prev.some(t=>t.studentId===editTarget.id&&t.month===month);
          if(hasCurrentMonth){
            // 이미 "납부완료"로 확정된 내역은 소급해서 금액을 바꾸지 않고, 아직 미납/연체인 내역만 새 금액으로 갱신합니다.
            return prev.map(t=>(t.studentId===editTarget.id&&t.month===month&&t.status!=='paid')?{...t,amount:newAmount,studentName:formToSave.name}:t);
          }
          // 이번 달 학원비 내역이 아직 없으면 신규 등록 때와 같은 방식으로 새로 만들어줍니다.
          return[...prev,{id:genId(),studentId:editTarget.id,studentName:formToSave.name,month,amount:newAmount,dueDate:calcTuitionDueDate(editTarget.joinDate,month,tuitionDaySetting),paidDate:'',status:'unpaid',payMethod:'',note:'수강반 변경으로 자동 생성'}];
        });
      }
    }else{
      const newId=genId();
      setStudents(prev=>[...prev,{...formToSave,id:newId}]);
      // 학생관리에서 새 학생을 등록하면 학원비 관리에도 자동으로 이번 달 수강료 내역이 생성되도록 연동
      // (예전에는 학생을 등록해도 학원비 관리에는 따로 "납부 등록"을 또 해줘야 했음 — Austin님 피드백 [19] 반영)
      if(setTuitions){
        const d=new Date();
        const month=`${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,'0')}`;
        const baseFee=calcTuitionAmount(form.enrolledClasses);
        // 일할 계산: 이번 달 중간에 등록한 학생은 남은 일수 비례로 학원비 산정
        const jDate=form.joinDate||today();
        const [jy,jm,jd]=jDate.split('-').map(Number);
        const [my,mm]=month.split('-').map(Number);
        // 등록일이 이번 달 이하인 경우에만 학원비 자동 생성 (미래 달 등록 예정 학생 제외)
        if(jy<my||(jy===my&&jm<=mm)){
          let finalFee=baseFee;
          let isProrated=false;
          let tuitionNote='학생 등록 시 자동 생성';
          if(jy===my&&jm===mm&&jd>1){
            const daysInMo=new Date(my,mm,0).getDate();
            const proratedDays=daysInMo-jd+1;
            finalFee=Math.round(proratedDays/daysInMo*baseFee/1000)*1000;
            isProrated=true;
            tuitionNote=`학생 등록 시 자동 생성 (${jDate} 등록 — ${proratedDays}/${daysInMo}일 일할 계산)`;
          }
          setTuitions(prev=>prev.some(t=>t.studentId===newId&&t.month===month)?prev:[...prev,{
            id:genId(),studentId:newId,studentName:form.name,month,
            amount:finalFee,isProrated,baseFee:isProrated?baseFee:undefined,
            dueDate:jDate,paidDate:'',status:'unpaid',payMethod:'',note:tuitionNote
          }]);
        }
      }
    }
    setModalOpen(false);
  };
  const addNote=()=>{
    if(!noteText.trim())return;
    setForm(f=>({...f,progressNotes:[...(f.progressNotes||[]),{date:today(),text:noteText.trim()}]}));
    setNoteText('');
  };
  const saveNoteEdit=()=>{
    if(!editNoteText.trim())return;
    setForm(f=>{const notes=[...(f.progressNotes||[])];notes[editNoteIdx]={...notes[editNoteIdx],text:editNoteText.trim()};return{...f,progressNotes:notes};});
    setEditNoteIdx(null);setEditNoteText('');
  };
  const deleteNote=idx=>{setForm(f=>({...f,progressNotes:(f.progressNotes||[]).filter((_,i)=>i!==idx)}));if(editNoteIdx===idx){setEditNoteIdx(null);setEditNoteText('');}};
  const del=id=>{setStudents(prev=>prev.filter(s=>s.id!==id));if(setTuitions)setTuitions(prev=>prev.filter(t=>!(t.studentId===id&&t.status!=='paid')));setConfirmId(null);};
  const getClsName=id=>classes.find(c=>c.id===id)?.name||id;
  const lastLeave=s=>{const h=s.enrollmentHistory||[];return h.length?h[h.length-1].leaveDate:null;};
  const diffMonths=(from,to)=>{
    if(!from||!to)return 0;
    const a=new Date(from),b=new Date(to);
    let m=(b.getFullYear()-a.getFullYear())*12+(b.getMonth()-a.getMonth());
    if(b.getDate()<a.getDate())m-=1;
    return Math.max(0,m);
  };
  const sortField=key=>{if(sortKey===key)setSortDir(d=>d==='asc'?'desc':'asc');else{setSortKey(key);setSortDir('asc');}};
  const sortArrow=key=>sortKey===key?(sortDir==='asc'?' ▲':' ▼'):'';
  const colGetters={
    name:s=>s.name||'',
    phone:s=>s.phone||'',
    parentName:s=>s.parentName||'',
    parentPhone:s=>s.parentPhone||'',
    classes:s=>(s.enrolledClasses||[]).map(getClsName).join(', '),
    date:s=>tab==='active'?(s.joinDate||''):(lastLeave(s)||'')
  };

  const openWithdraw=s=>{setWithdrawTarget(s);setWithdrawForm({date:today(),reason:'',note:''});setWithdrawModalOpen(true);};
  const confirmWithdraw=()=>{
    if(!withdrawForm.date){alert('퇴원일을 입력해주세요.');return;}
    const s=withdrawTarget;
    const hist=[...(s.enrollmentHistory||[])];
    if(hist.length&&hist[hist.length-1].leaveDate===null)hist[hist.length-1]={...hist[hist.length-1],leaveDate:withdrawForm.date};
    setStudents(prev=>prev.map(x=>x.id===s.id?{...x,status:'withdrawn',enrollmentHistory:hist}:x));
    // 퇴원 시 미납/연체 학원비 내역은 삭제, 납부완료 내역만 보존 (세금/회계 목적)
    if(setTuitions)setTuitions(prev=>prev.filter(t=>!(t.studentId===s.id&&t.status!=='paid')));
    const lastJoin=hist.length?hist[hist.length-1].joinDate:s.joinDate;
    setWithdrawals(prev=>[...prev,{id:genId(),studentId:s.id,studentName:s.name,grade:s.grade,classes:(s.enrolledClasses||[]).map(getClsName),joinDate:lastJoin,withdrawDate:withdrawForm.date,reason:withdrawForm.reason,note:withdrawForm.note,stayMonths:diffMonths(lastJoin,withdrawForm.date)}]);
    setWithdrawModalOpen(false);
  };
  const openRejoin=s=>{setRejoinTarget(s);setRejoinForm({date:today()});setRejoinModalOpen(true);};
  const confirmRejoin=()=>{
    if(!rejoinForm.date){alert('재등록일을 입력해주세요.');return;}
    const s=rejoinTarget;
    const hist=[...(s.enrollmentHistory||[]),{joinDate:rejoinForm.date,leaveDate:null}];
    setStudents(prev=>prev.map(x=>x.id===s.id?{...x,status:'active',joinDate:rejoinForm.date,enrollmentHistory:hist}:x));
    setRejoinModalOpen(false);
  };

  // 퇴원생 탭: status==='withdrawn' 이고 실제 퇴원일(leaveDate)이 오늘 이하인 경우만 표시
  const getLeaveDate=s=>{const h=s.enrollmentHistory||[];return(h[h.length-1]||{}).leaveDate||'';};
  // 강사 계정: 본인 담당 수업에 등록된 학생만 표시
  const myTeacherClassIds=role==='teacher'&&loggedInTeacherId
    ?classes.filter(c=>c.teacherId===loggedInTeacherId&&!(c.closeDate&&c.closeDate<=today())).map(c=>c.id)
    :null;
  const tabStudents=students.filter(s=>{
    const tabOk=tab==='active'
      ?(s.status!=='withdrawn'&&(!s.joinDate||s.joinDate<=today()))
      :(s.status==='withdrawn'&&(()=>{const ld=getLeaveDate(s);return !ld||ld<=today();})());
    if(!tabOk)return false;
    if(myTeacherClassIds)return(s.enrolledClasses||[]).some(cid=>myTeacherClassIds.includes(cid));
    return true;
  });
  const searched=tabStudents.filter(s=>s.name.includes(search)||s.parentName?.includes(search)||(s.enrolledClasses||[]).some(id=>getClsName(id).includes(search)));
  const filtered=[...searched].sort((a,b)=>{
    const getter=colGetters[sortKey]||colGetters.name;
    let av=getter(a)||'',bv=getter(b)||'';
    if(av<bv)return sortDir==='asc'?-1:1;
    if(av>bv)return sortDir==='asc'?1:-1;
    return 0;
  });
  const activeCount=students.filter(s=>{
    if(s.status==='withdrawn'||s.joinDate>today())return false;
    if(myTeacherClassIds)return(s.enrolledClasses||[]).some(cid=>myTeacherClassIds.includes(cid));
    return true;
  }).length;
  const withdrawnCount=students.filter(s=>s.status==='withdrawn'&&(()=>{const ld=getLeaveDate(s);return !ld||ld<=today();})()).length;
  return<div className="space-y-5">
    <div className="flex items-center justify-between">
      <div><h1 className="text-2xl font-bold text-slate-900">학생 관리</h1><p className="text-slate-600 text-sm mt-1">재원 {activeCount}명 · 퇴원 {withdrawnCount}명</p></div>
      {role!=='teacher'&&<button className={btn('indigo')} onClick={openAdd}>+ 학생 등록</button>}
    </div>
    <div className="flex gap-2">
      <button onClick={()=>setTab('active')} className={`text-sm font-semibold px-4 py-2 rounded-lg ${tab==='active'?'bg-[#1e3a5f] text-white':'bg-white text-slate-600 border border-gray-200'}`}>재원생 ({activeCount})</button>
      <button onClick={()=>setTab('withdrawn')} className={`text-sm font-semibold px-4 py-2 rounded-lg ${tab==='withdrawn'?'bg-[#1e3a5f] text-white':'bg-white text-slate-600 border border-gray-200'}`}>퇴원생 ({withdrawnCount})</button>
    </div>
    <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
      <div className="p-4 border-b border-gray-100"><input className={inp} placeholder="이름, 학부모, 수강 반(레벨) 검색..." value={search} onChange={e=>setSearch(e.target.value)} style={{maxWidth:'280px'}}/></div>
      <div className="overflow-x-auto overflow-y-auto tbl-scroll" style={{maxHeight:'calc(100vh - 280px)'}}><table className="w-full text-sm app-table">
        <thead className="bg-[#f1f5f9] text-slate-600 text-xs"><tr>
          <th className="px-4 py-3 text-left font-medium cursor-pointer select-none" style={{width:'90px'}} onClick={()=>sortField('name')}>이름{sortArrow('name')}</th>
          <th className="px-4 py-3 text-left font-medium cursor-pointer select-none" style={{width:'120px'}} onClick={()=>sortField('phone')}>학생 연락처{sortArrow('phone')}</th>
          <th className="px-4 py-3 text-left font-medium cursor-pointer select-none" style={{width:'80px'}} onClick={()=>sortField('parentName')}>학부모{sortArrow('parentName')}</th>
          <th className="px-4 py-3 text-left font-medium cursor-pointer select-none" style={{width:'120px'}} onClick={()=>sortField('parentPhone')}>학부모 연락처{sortArrow('parentPhone')}</th>
          <th className="px-4 py-3 text-left font-medium cursor-pointer select-none" style={{width:'130px'}} onClick={()=>sortField('classes')}>수강 수업{sortArrow('classes')}</th>
          <th className="px-4 py-3 text-left font-medium cursor-pointer select-none" style={{width:'100px'}} onClick={()=>sortField('date')}>{tab==='active'?'등록일':'퇴원일'}{sortArrow('date')}</th>
          <th className="px-4 py-3 text-left font-medium" style={{width:'80px'}}>관리</th>
        </tr></thead>
        <tbody>{filtered.map(s=><tr key={s.id} className="table-row border-t border-gray-50">
          <td className="px-4 py-3 font-semibold text-slate-900">{s.name}</td>
          <td className="px-4 py-3 text-slate-700">{s.phone||'-'}</td>
          <td className="px-4 py-3 font-medium">{s.grade==='성인'?<span className="text-slate-500 text-xs">본인(성인)</span>:(s.parentName||'-')}</td>
          <td className="px-4 py-3 text-slate-700">{s.grade==='성인'?<span className="text-slate-400">-</span>:(s.parentPhone||'-')}</td>
          <td className="px-4 py-3"><div className="flex flex-wrap gap-1">{(s.enrolledClasses||[]).filter(id=>{const c=classes.find(x=>x.id===id);return c&&!(c.closeDate&&c.closeDate<=today());}).map(id=><span key={id} className="badge bg-[#f1f5f9] text-[#1e3a5f] text-xs">{getClsName(id)}</span>)}</div></td>
          {tab==='active'?
            <td className="px-4 py-3 text-slate-600 text-xs">{fDate(s.joinDate)}</td>:
            <td className="px-4 py-3 text-slate-600 text-xs">{fDate(lastLeave(s))}</td>}
          <td className="px-4 py-3"><div className="flex gap-1">
            <button onClick={()=>openEdit(s)} className="text-xs px-2 py-1 rounded bg-[#f1f5f9] text-[#1e3a5f] hover:bg-[#dbeafe]">{role==='teacher'?'코멘트':'수정'}</button>
            {role!=='teacher'&&tab==='active'&&<button onClick={()=>openWithdraw(s)} className="text-xs px-2 py-1 rounded bg-orange-50 text-orange-600 hover:bg-orange-100">퇴원</button>}
            {role!=='teacher'&&tab!=='active'&&<>
              <button onClick={()=>openRejoin(s)} className="text-xs px-2 py-1 rounded bg-emerald-50 text-emerald-600 hover:bg-emerald-100">재등록</button>
              <button onClick={()=>setConfirmId(s.id)} className="text-xs px-2 py-1 rounded bg-red-50 text-red-500 hover:bg-red-100">삭제</button>
            </>}
          </div></td>
        </tr>)}
        {filtered.length===0&&<tr><td colSpan={7} className="text-center py-12 text-slate-600">{tab==='active'?'재원중인 학생이 없습니다':'퇴원한 학생이 없습니다'}</td></tr>}
        </tbody></table></div>
    </div>
    <Modal open={modalOpen} onClose={()=>setModalOpen(false)} title={editTarget?(role==='teacher'?`${editTarget.name} — 진도 코멘트`:'학생 정보 수정'):'학생 등록'}>
      {role==='teacher'&&editTarget&&<div className="mb-3 bg-blue-50 border border-blue-200 rounded-lg px-3 py-2 text-xs text-blue-700">강사 모드: 진도 코멘트와 비고만 작성할 수 있습니다.</div>}
      <div className={role==='teacher'&&editTarget?'hidden':''}>
      <div className="grid grid-cols-2 gap-x-4">
        <Field label="학생 이름" required><input className={inp} value={form.name} onChange={e=>setForm({...form,name:e.target.value})}/></Field>
        <Field label="학년"><select className={inp} value={form.grade} onChange={e=>setForm({...form,grade:e.target.value})}><option value="">선택</option>{grades.map(g=><option key={g} value={g}>{g}</option>)}</select></Field>
        <Field label={form.grade==='성인'?'본인 연락처':'학생 연락처'}><input className={inp} placeholder="010-0000-0000" value={form.phone} onChange={e=>setForm({...form,phone:e.target.value})}/></Field>
        <Field label="등록일"><input className={inp} type="date" value={form.joinDate} onChange={e=>setForm({...form,joinDate:e.target.value})}/></Field>
        {form.grade!=='성인'&&<Field label="학부모 이름"><input className={inp} value={form.parentName} onChange={e=>setForm({...form,parentName:e.target.value})}/></Field>}
        {form.grade!=='성인'&&<Field label="학부모 연락처"><input className={inp} placeholder="010-0000-0000" value={form.parentPhone} onChange={e=>setForm({...form,parentPhone:e.target.value})}/></Field>}
        {form.grade==='성인'&&<div className="text-xs text-slate-500 flex items-center px-1">※ 성인 학생은 본인이 직접 연락처를 등록하므로 학부모 정보 입력칸이 표시되지 않습니다.</div>}
      </div>
      <Field label="이메일"><input className={inp} type="email" value={form.email} onChange={e=>setForm({...form,email:e.target.value})}/></Field>
      <Field label="재학 학교 (예: OO초등학교, OO중학교, OO고등학교)"><input className={inp} placeholder="ex) 한국초등학교" value={form.school||''} onChange={e=>setForm({...form,school:e.target.value})}/></Field>
      <Field label="수강 수업 (복수 선택)"><div className="flex flex-wrap gap-2 border border-gray-200 rounded-lg p-3 max-h-32 overflow-y-auto">
        {classes.filter(c=>!(c.closeDate&&c.closeDate<=today())).map(c=>{
          const isEnrolled=(form.enrolledClasses||[]).includes(c.id);
          const curCnt=(students||[]).filter(s=>s.status!=='withdrawn'&&(!s.joinDate||s.joinDate<=today())&&(s.enrolledClasses||[]).includes(c.id)).length;
          const isFull=c.maxStudents&&curCnt>=c.maxStudents&&!isEnrolled;
          return<button key={c.id} type="button" onClick={()=>toggleClass(c.id)} disabled={isFull}
            className={`text-xs px-3 py-1.5 rounded-full border transition-colors ${isEnrolled?'bg-[#1e3a5f] text-white border-[#4a4a28]':isFull?'bg-red-50 text-red-400 border-red-200 cursor-not-allowed':'bg-white text-slate-700 border-gray-300 hover:border-[#3b82f6]'}`}>
            {c.name}{isFull?' (마감)':''}
          </button>;
        })}
      </div></Field>
      </div>
      {editTarget&&<Field label="재원 이력">
        <div className="space-y-1 text-xs text-slate-600 border border-gray-200 rounded-lg p-3">
          {(form.enrollmentHistory||[]).length===0&&<div className="text-slate-400">이력 없음</div>}
          {(form.enrollmentHistory||[]).map((h,i)=><div key={i}>{fDate(h.joinDate)} ~ {h.leaveDate?fDate(h.leaveDate):'재원중'}</div>)}
        </div>
      </Field>}
      {editTarget&&<Field label="진도 코멘트">
        <div className="space-y-1 max-h-40 overflow-y-auto border border-gray-200 rounded-lg p-3 mb-2">
          {(form.progressNotes||[]).length===0&&<div className="text-xs text-slate-400">아직 코멘트가 없습니다</div>}
          {[...(form.progressNotes||[])].map((n,i)=>({...n,_i:i})).reverse().map(n=>(
            <div key={n._i} className="text-xs border-b border-gray-100 pb-1 last:border-0">
              {editNoteIdx===n._i
                ?<div className="flex gap-1 items-center">
                    <input className={inp+' text-xs py-0.5'} value={editNoteText} onChange={e=>setEditNoteText(e.target.value)} autoFocus/>
                    <button type="button" className="text-xs px-2 py-0.5 rounded bg-indigo-100 text-indigo-700 hover:bg-indigo-200" onClick={saveNoteEdit}>저장</button>
                    <button type="button" className="text-xs px-2 py-0.5 rounded bg-gray-100 text-gray-600 hover:bg-gray-200" onClick={()=>{setEditNoteIdx(null);setEditNoteText('');}}>취소</button>
                  </div>
                :<div className="flex items-start gap-1">
                    <span className="text-slate-400 mr-1 whitespace-nowrap">{fDate(n.date)}</span>
                    <span className="text-slate-700 flex-1">{n.text}</span>
                    <button type="button" className="text-blue-400 hover:text-blue-600 px-1 flex-shrink-0" onClick={()=>{setEditNoteIdx(n._i);setEditNoteText(n.text);}} title="수정">✏</button>
                    <button type="button" className="text-red-400 hover:text-red-600 px-1 flex-shrink-0" onClick={()=>deleteNote(n._i)} title="삭제">✕</button>
                  </div>
              }
            </div>
          ))}
        </div>
        <div className="flex gap-2">
          <input className={inp} placeholder="오늘 진도/코멘트 입력..." value={noteText} onChange={e=>setNoteText(e.target.value)} onKeyDown={e=>e.key==='Enter'&&addNote()}/>
          <button type="button" className={btn('gray')} onClick={addNote}>추가</button>
        </div>
      </Field>}
      <Field label="비고"><textarea className={inp} rows={2} value={form.note} onChange={e=>setForm({...form,note:e.target.value})}/></Field>
      <div className="flex justify-between items-center mt-2">
        {editTarget&&role!=='teacher'
          ?<button className={btn('red')} onClick={()=>{setModalOpen(false);setTimeout(()=>setConfirmId(editTarget.id),100);}}>학생 삭제</button>
          :<div/>}
        <div className="flex gap-3"><button className={btn('indigo')} onClick={save}>저장</button><button className={btn('gray')} onClick={()=>setModalOpen(false)}>취소</button></div>
      </div>
    </Modal>
    <Modal open={withdrawModalOpen} onClose={()=>setWithdrawModalOpen(false)} title={`${withdrawTarget?.name||''} 학생 퇴원 처리`}>
      <Field label="퇴원일" required><input className={inp} type="date" value={withdrawForm.date} onChange={e=>setWithdrawForm({...withdrawForm,date:e.target.value})}/></Field>
      <Field label="퇴원 사유"><select className={inp} value={withdrawForm.reason} onChange={e=>setWithdrawForm({...withdrawForm,reason:e.target.value})}><option value="">선택</option>{withdrawReasons.map(r=><option key={r} value={r}>{r}</option>)}</select></Field>
      <Field label="비고"><textarea className={inp} rows={2} value={withdrawForm.note} onChange={e=>setWithdrawForm({...withdrawForm,note:e.target.value})}/></Field>
      <p className="text-xs text-slate-500 mb-2">퇴원 처리해도 학생 데이터는 삭제되지 않고 '퇴원생' 탭에 그대로 남으며, 퇴원 관리 페이지에도 자동으로 기록됩니다. 나중에 '재등록' 버튼으로 다시 재원 처리할 수 있어요.</p>
      <div className="flex justify-end gap-3 mt-2"><button className={btn('indigo')} onClick={confirmWithdraw}>퇴원 처리</button><button className={btn('gray')} onClick={()=>setWithdrawModalOpen(false)}>취소</button></div>
    </Modal>
    <Modal open={rejoinModalOpen} onClose={()=>setRejoinModalOpen(false)} title={`${rejoinTarget?.name||''} 학생 재등록`}>
      <Field label="재등록일" required><input className={inp} type="date" value={rejoinForm.date} onChange={e=>setRejoinForm({...rejoinForm,date:e.target.value})}/></Field>
      <p className="text-xs text-slate-500 mb-2">재등록하면 '재원생' 탭으로 다시 이동하고, 새로운 재원 기간이 이력에 추가됩니다.</p>
      <div className="flex justify-end gap-3 mt-2"><button className={btn('indigo')} onClick={confirmRejoin}>재등록 처리</button><button className={btn('gray')} onClick={()=>setRejoinModalOpen(false)}>취소</button></div>
    </Modal>
    <Confirm open={!!confirmId} msg="이 학생 기록을 영구 삭제하시겠습니까? (퇴원 처리와는 달리 복구할 수 없습니다)" onYes={()=>del(confirmId)} onNo={()=>setConfirmId(null)}/>
  </div>;
}

// ── 예산 관리 (PDF 수정) ─────────────────────────────────────────────────────
function BudgetManagement({income,setIncome,expenses,setExpenses}){
  const[tab,setTab]=useState('overview');
  const[modalOpen,setModalOpen]=useState(false);
  const[modalType,setModalType]=useState('income');
  const[editTarget,setEditTarget]=useState(null);
  const[confirmItem,setConfirmItem]=useState(null);
  const budgetTodayYM=(()=>{const d=new Date();return`${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,'0')}`;})();
  const[pdfMonth,setPdfMonth]=useState(budgetTodayYM);
  const handlePdfMonthChange=e=>{if(e.target.value<=budgetTodayYM)setPdfMonth(e.target.value);};
  // 전체보기: 체크하면 위 월 선택기를 무시하고 수입/지출 목록에 전체 기간 내역을 표시합니다.
  const[showAllList,setShowAllList]=useState(false);
  const[incCatFilter,setIncCatFilter]=useState('전체');
  const[expCatFilter,setExpCatFilter]=useState('전체');
  const[form,setForm]=useState({date:'',category:'',description:'',amount:''});
  const incCats=['수강료','교재비','악기대여료','행사수입','기타수입'];
  const expCats=['강사급여','임대료','전기·수도요금','관리비','소모품','교육용품','마케팅','시설유지','기타지출'];
  const _budgetToday=today();
  const totalInc=income.filter(i=>i.date&&i.date<=_budgetToday).reduce((s,i)=>s+Number(i.amount),0);
  const totalExp=expenses.filter(e=>e.date&&e.date<=_budgetToday).reduce((s,e)=>s+Number(e.amount),0);
  const profit=totalInc-totalExp;
  // 선택 월 기준 수입/지출/순수익 (개요 탭 메인 카드에 표시) — 미래 날짜 제외
  const mIncItems=income.filter(i=>i.date&&i.date.startsWith(pdfMonth)&&i.date<=_budgetToday);
  const mExpItems=expenses.filter(e=>e.date&&e.date.startsWith(pdfMonth)&&e.date<=_budgetToday);
  const mIncSum=mIncItems.reduce((s,i)=>s+Number(i.amount),0);
  const mExpSum=mExpItems.reduce((s,e)=>s+Number(e.amount),0);
  const mProfit=mIncSum-mExpSum;
  const mMonthLabel=`${pdfMonth.split('-')[0]}년 ${parseInt(pdfMonth.split('-')[1])}월`;
  const openAdd=type=>{setModalType(type);setEditTarget(null);setForm({date:today(),category:'',description:'',amount:''});setModalOpen(true);};
  const openEdit=(item,type)=>{setModalType(type);setEditTarget(item);setForm({...item});setModalOpen(true);};
  const save=()=>{
    if(!form.date||!form.amount){alert('날짜와 금액은 필수입니다.');return;}
    const data={...form,amount:Number(form.amount)};
    if(modalType==='income'){
      if(editTarget)setIncome(prev=>prev.map(i=>i.id===editTarget.id?{...data,id:i.id}:i));
      else setIncome(prev=>[...prev,{...data,id:genId()}]);
    }else{
      if(editTarget)setExpenses(prev=>prev.map(e=>e.id===editTarget.id?{...data,id:e.id}:e));
      else setExpenses(prev=>[...prev,{...data,id:genId()}]);
    }
    setModalOpen(false);
  };
  const del=()=>{
    if(confirmItem.type==='income')setIncome(prev=>prev.filter(i=>i.id!==confirmItem.id));
    else setExpenses(prev=>prev.filter(e=>e.id!==confirmItem.id));
    setConfirmItem(null);
  };

  const printPDF=(type='all')=>{
    const ym=pdfMonth;
    const[yyyy,mm]=ym.split('-');
    const mInc=income.filter(i=>i.date&&i.date.startsWith(ym)&&i.date<=_budgetToday);
    const mExp=expenses.filter(e=>e.date&&e.date.startsWith(ym)&&e.date<=_budgetToday);
    const sumInc=mInc.reduce((s,i)=>s+Number(i.amount),0);
    const sumExp=mExp.reduce((s,e)=>s+Number(e.amount),0);
    const mPft=sumInc-sumExp;
    const incByCat=mInc.reduce((a,i)=>{a[i.category]=(a[i.category]||0)+Number(i.amount);return a;},{});
    const expByCat=mExp.reduce((a,e)=>{a[e.category]=(a[e.category]||0)+Number(e.amount);return a;},{});
    const toKRW=n=>'₩'+Number(n).toLocaleString();
    const toKRDate=d=>{if(!d)return'-';const dt=new Date(d);return`${dt.getFullYear()}.${dt.getMonth()+1}.${dt.getDate()}`;};
    const catRowsHTML=(obj,color)=>Object.entries(obj).sort((a,b)=>b[1]-a[1]).map(([c,a])=>
      `<tr><td style="padding:6px 12px;border-bottom:1px solid #f3f4f6;">${c}</td><td style="padding:6px 12px;border-bottom:1px solid #f3f4f6;text-align:right;color:${color};font-weight:700;">${toKRW(a)}</td></tr>`).join('');
    const detailRowsHTML=(items,color)=>[...items].sort((a,b)=>a.date.localeCompare(b.date)).map(x=>
      `<tr><td style="padding:5px 10px;border-bottom:1px solid #f9fafb;font-size:12px;">${toKRDate(x.date)}</td><td style="padding:5px 10px;border-bottom:1px solid #f9fafb;font-size:12px;">${x.category||''}</td><td style="padding:5px 10px;border-bottom:1px solid #f9fafb;font-size:12px;">${x.description||''}</td><td style="padding:5px 10px;border-bottom:1px solid #f9fafb;font-size:12px;text-align:right;color:${color};font-weight:700;">${toKRW(x.amount)}</td></tr>`).join('');
    const titleLabel=type==='income'?'수입 분석 보고서':type==='expense'?'지출 분석 보고서':'예산 종합 보고서';
    const summaryHTML=type==='income'
      ?`<div class="summary"><div class="sbox" style="background:#f0fdf4;border:1px solid #bbf7d0;"><div class="sl" style="color:#16a34a;">총 수입</div><div class="sv" style="color:#15803d;">${toKRW(sumInc)}</div></div><div class="sbox" style="background:#f0fdf4;border:1px solid #bbf7d0;"><div class="sl" style="color:#16a34a;">수입 건수</div><div class="sv" style="color:#15803d;">${mInc.length}건</div></div></div>`
      :type==='expense'
      ?`<div class="summary"><div class="sbox" style="background:#fef2f2;border:1px solid #fecaca;"><div class="sl" style="color:#dc2626;">총 지출</div><div class="sv" style="color:#b91c1c;">${toKRW(sumExp)}</div></div><div class="sbox" style="background:#fef2f2;border:1px solid #fecaca;"><div class="sl" style="color:#dc2626;">지출 건수</div><div class="sv" style="color:#b91c1c;">${mExp.length}건</div></div></div>`
      :`<div class="summary"><div class="sbox" style="background:#f0fdf4;border:1px solid #bbf7d0;"><div class="sl" style="color:#16a34a;">총 수입</div><div class="sv" style="color:#15803d;">${toKRW(sumInc)}</div></div><div class="sbox" style="background:#fef2f2;border:1px solid #fecaca;"><div class="sl" style="color:#dc2626;">총 지출</div><div class="sv" style="color:#b91c1c;">${toKRW(sumExp)}</div></div><div class="sbox" style="background:${mPft>=0?'#eff6ff':'#fff7ed'};border:1px solid ${mPft>=0?'#bfdbfe':'#fed7aa'};"><div class="sl" style="color:${mPft>=0?'#2563eb':'#ea580c'};">순수익</div><div class="sv" style="color:${mPft>=0?'#1d4ed8':'#c2410c'};">${toKRW(mPft)}</div></div></div>`;
    const bodyHTML=type==='income'
      ?`<h2>💚 수입 항목별 요약 (${mInc.length}건)</h2>
        ${Object.keys(incByCat).length>0?`<table><thead><tr><th>카테고리</th><th style="text-align:right">금액</th></tr></thead><tbody>${catRowsHTML(incByCat,'#16a34a')}</tbody></table>`:'<div class="no-data">해당 월 수입 내역이 없습니다</div>'}
        <h2>💚 수입 상세 내역</h2>
        ${mInc.length>0?`<table><thead><tr><th>날짜</th><th>카테고리</th><th>내용</th><th style="text-align:right">금액</th></tr></thead><tbody>${detailRowsHTML(mInc,'#16a34a')}</tbody></table>`:'<div class="no-data">내역 없음</div>'}`
      :type==='expense'
      ?`<h2>❤️ 지출 항목별 요약 (${mExp.length}건)</h2>
        ${Object.keys(expByCat).length>0?`<table><thead><tr><th>카테고리</th><th style="text-align:right">금액</th></tr></thead><tbody>${catRowsHTML(expByCat,'#dc2626')}</tbody></table>`:'<div class="no-data">해당 월 지출 내역이 없습니다</div>'}
        <h2>❤️ 지출 상세 내역</h2>
        ${mExp.length>0?`<table><thead><tr><th>날짜</th><th>카테고리</th><th>내용</th><th style="text-align:right">금액</th></tr></thead><tbody>${detailRowsHTML(mExp,'#dc2626')}</tbody></table>`:'<div class="no-data">내역 없음</div>'}`
      :`<h2>💚 수입 항목별 요약 (${mInc.length}건)</h2>
        ${Object.keys(incByCat).length>0?`<table><thead><tr><th>카테고리</th><th style="text-align:right">금액</th></tr></thead><tbody>${catRowsHTML(incByCat,'#16a34a')}</tbody></table>`:'<div class="no-data">해당 월 수입 내역이 없습니다</div>'}
        <h2>❤️ 지출 항목별 요약 (${mExp.length}건)</h2>
        ${Object.keys(expByCat).length>0?`<table><thead><tr><th>카테고리</th><th style="text-align:right">금액</th></tr></thead><tbody>${catRowsHTML(expByCat,'#dc2626')}</tbody></table>`:'<div class="no-data">해당 월 지출 내역이 없습니다</div>'}
        <h2>💚 수입 상세 내역</h2>
        ${mInc.length>0?`<table><thead><tr><th>날짜</th><th>카테고리</th><th>내용</th><th style="text-align:right">금액</th></tr></thead><tbody>${detailRowsHTML(mInc,'#16a34a')}</tbody></table>`:'<div class="no-data">내역 없음</div>'}
        <h2>❤️ 지출 상세 내역</h2>
        ${mExp.length>0?`<table><thead><tr><th>날짜</th><th>카테고리</th><th>내용</th><th style="text-align:right">금액</th></tr></thead><tbody>${detailRowsHTML(mExp,'#dc2626')}</tbody></table>`:'<div class="no-data">내역 없음</div>'}`;
    const html=`<!DOCTYPE html><html lang="ko"><head><meta charset="UTF-8"><title>${yyyy}년 ${mm}월 ${titleLabel}</title>
    <style>body{font-family:'Malgun Gothic',sans-serif;color:#1f2937;padding:32px;max-width:800px;margin:0 auto;}
    h1{font-size:22px;font-weight:800;color:#4f46e5;border-bottom:3px solid #4f46e5;padding-bottom:12px;margin-bottom:24px;}
    h2{font-size:14px;font-weight:700;color:#374151;margin:20px 0 8px 0;padding-left:10px;border-left:4px solid #6366f1;}
    .summary{display:flex;gap:16px;margin-bottom:24px;}
    .sbox{flex:1;padding:16px;border-radius:10px;text-align:center;}
    .sl{font-size:11px;font-weight:600;margin-bottom:4px;}
    .sv{font-size:20px;font-weight:800;}
    table{width:100%;border-collapse:collapse;margin-bottom:20px;}
    th{background:#f9fafb;padding:8px 12px;text-align:left;font-size:11px;color:#6b7280;font-weight:700;border-bottom:2px solid #e5e7eb;}
    .footer{margin-top:32px;font-size:11px;color:#9ca3af;text-align:center;border-top:1px solid #e5e7eb;padding-top:12px;}
    .no-data{padding:20px;text-align:center;color:#9ca3af;font-size:13px;}
    @media print{.no-print{display:none;}}</style></head><body>
    <div class="no-print" style="text-align:right;margin-bottom:12px;"><button onclick="window.print()" style="background:#4f46e5;color:white;border:none;padding:10px 24px;border-radius:8px;cursor:pointer;font-size:14px;font-weight:600;">🖨️ 인쇄 / PDF 저장</button></div>
    <h1>🏫 학원 ${yyyy}년 ${mm}월 ${titleLabel}</h1>
    <p style="font-size:13px;color:#6b7280;margin-bottom:20px;">기준월: <strong>${yyyy}년 ${mm}월</strong> &nbsp;|&nbsp; 출력일: ${new Date().toLocaleDateString('ko-KR')}</p>
    ${summaryHTML}
    ${bodyHTML}
    <div class="footer">본 보고서는 학원 관리 시스템에서 자동 생성되었습니다.</div></body></html>`;
    const w=window.open('','_blank','width=900,height=750,scrollbars=yes');
    if(w){w.document.write(html);w.document.close();}else{alert('팝업이 차단되었습니다. 브라우저 팝업 허용 후 다시 시도해주세요.');}
  };

  // 개요 탭 항목별 분류도 선택 월 기준으로 표시
  const incByCat=mIncItems.reduce((a,i)=>{a[i.category]=(a[i.category]||0)+Number(i.amount);return a;},{});
  const expByCat=mExpItems.reduce((a,e)=>{a[e.category]=(a[e.category]||0)+Number(e.amount);return a;},{});
  // 수입/지출 목록을 우측 상단의 월 선택기(pdfMonth)로 필터링합니다.
  // showAllList가 true이면(전체보기 체크) 월 필터를 무시하고 전체 내역을 보여줍니다.
  const ListTable=({items,type,catFilter,setCatFilter})=>{
    const nowYM2=(()=>{const d=new Date();return`${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,'0')}`;})();
    const selectedYear=pdfMonth.substring(0,4);
    const todayDateStr=today();
    // 현재 월 이후 항목 제외 + 미래 날짜 항목도 제외 (오늘 이후 날짜는 표시 안 함)
    const pastItems=items.filter(it=>it.date&&it.date.substring(0,7)<=nowYM2&&it.date<=todayDateStr);
    // [15] 전체보기는 조회 연도 전체만 표시
    const yearItems=items.filter(it=>it.date&&it.date.startsWith(selectedYear)&&it.date<=todayDateStr);
    const monthItems=pastItems.filter(it=>it.date.startsWith(pdfMonth));
    const baseItems=showAllList?yearItems:monthItems;
    const allCats=['전체',...new Set(baseItems.map(it=>it.category).filter(Boolean))];
    const visibleItems=catFilter==='전체'?baseItems:baseItems.filter(it=>it.category===catFilter);
    const catSums=baseItems.reduce((a,it)=>{const c=it.category||'미분류';a[c]=(a[c]||0)+Number(it.amount);return a;},{});
    const totalVisible=visibleItems.reduce((s,it)=>s+Number(it.amount),0);
    return<div>
    <div className="p-4 flex items-center justify-between flex-wrap gap-2">
      <div className="flex items-center gap-3 flex-wrap">
        <label className="flex items-center gap-2 text-sm text-slate-600 cursor-pointer select-none">
          <input type="checkbox" checked={showAllList} onChange={e=>setShowAllList(e.target.checked)}/>
          {selectedYear}년 전체보기
        </label>
        <div className="flex items-center gap-1">
          <span className="text-xs text-slate-500">카테고리:</span>
          <select className="text-xs border border-gray-300 rounded-lg px-2 py-1.5 bg-white text-slate-700 focus:outline-none focus:ring-1 focus:ring-blue-400" value={catFilter} onChange={e=>setCatFilter(e.target.value)}>
            {allCats.map(c=><option key={c} value={c}>{c}</option>)}
          </select>
        </div>
        {catFilter!=='전체'&&<button onClick={()=>setCatFilter('전체')} className="text-xs px-2 py-1 rounded bg-gray-100 text-gray-600 hover:bg-gray-200">✕ 필터 초기화</button>}
      </div>
      <button className={btn(type==='income'?'green':'red')} onClick={()=>openAdd(type)}>+ {type==='income'?'수입':'지출'} 추가</button>
    </div>
    {catFilter==='전체'&&Object.keys(catSums).length>1&&<div className="px-4 pb-3 flex flex-wrap gap-2 border-b border-gray-100">
      {Object.entries(catSums).sort((a,b)=>b[1]-a[1]).map(([cat,amt])=>(
        <button key={cat} onClick={()=>setCatFilter(cat)}
          className={`text-xs px-3 py-1.5 rounded-lg font-medium transition-colors cursor-pointer ${type==='income'?'bg-green-50 text-green-700 hover:bg-green-100':'bg-red-50 text-red-600 hover:bg-red-100'}`}>
          {cat} {fWon(amt)}
        </button>
      ))}
    </div>}
    <div className="overflow-x-auto overflow-y-auto tbl-scroll" style={{maxHeight:'calc(100vh - 400px)',minHeight:'200px'}}>
    <table className="w-full text-sm app-table" style={{tableLayout:'fixed'}}>
      <colgroup><col style={{width:'14%'}}/><col style={{width:'16%'}}/><col style={{width:'42%'}}/><col style={{width:'16%'}}/><col style={{width:'12%'}}/></colgroup>
      <thead className="bg-[#f1f5f9] text-slate-600 text-xs sticky top-0 z-10"><tr>
        <th className="px-4 py-3 text-left font-medium">날짜</th>
        <th className="px-4 py-3 text-left font-medium">카테고리</th>
        <th className="px-4 py-3 text-left font-medium">내용</th>
        <th className="px-4 py-3 text-left font-medium">금액</th>
        <th className="px-4 py-3 text-left font-medium">관리</th>
      </tr></thead>
      <tbody>{[...visibleItems].sort((a,b)=>b.date.localeCompare(a.date)).map(item=><tr key={item.id} className="table-row border-t border-gray-50">
        <td className="px-4 py-3 text-slate-700">{fDate(item.date)}</td>
        <td className="px-4 py-3"><span className={`badge ${type==='income'?'bg-green-100 text-green-700':'bg-red-100 text-red-700'}`}>{item.category}</span></td>
        <td className="px-4 py-3 text-slate-800 truncate">{item.description}</td>
        <td className={`px-4 py-3 font-bold ${type==='income'?'text-green-600':'text-red-500'}`}>{fWon(item.amount)}</td>
        <td className="px-4 py-3"><div className="flex gap-1">
          <button onClick={()=>openEdit(item,type)} className="text-xs px-2 py-1 rounded bg-[#f1f5f9] text-[#1e3a5f] hover:bg-[#dbeafe]">수정</button>
          <button onClick={()=>setConfirmItem({...item,type})} className="text-xs px-2 py-1 rounded bg-red-50 text-red-500 hover:bg-red-100">삭제</button>
        </div></td>
      </tr>)}
      {visibleItems.length===0&&<tr><td colSpan={5} className="text-center py-12 text-slate-600">{showAllList?`${selectedYear}년 내역이 없습니다`:`${pdfMonth.split('-')[0]}년 ${parseInt(pdfMonth.split('-')[1])}월 내역이 없습니다. 다른 월을 선택하거나 연도 전체보기를 사용해보세요.`}</td></tr>}
      </tbody>
    </table>
    </div>
    {visibleItems.length>0&&<div className="px-4 py-2.5 border-t border-gray-200 bg-[#f8fafc] flex items-center justify-end gap-2">
      <span className="text-xs text-slate-500">{catFilter!=='전체'?`"${catFilter}" 합계`:'합계'}</span>
      <span className={`text-sm font-bold ${type==='income'?'text-green-700':'text-red-600'}`}>{fWon(totalVisible)}</span>
      {catFilter!=='전체'&&<span className="text-xs text-slate-400">({visibleItems.length}건)</span>}
    </div>}
  </div>;
  };
  return<div className="space-y-5">
    <div className="flex items-center justify-between flex-wrap gap-3">
      <div><h1 className="text-2xl font-bold text-slate-900">예산/지출 관리</h1>
        <p className="text-slate-600 text-sm mt-1">{mMonthLabel} — 수입 {fWon(mIncSum)} · 지출 {fWon(mExpSum)} · 순수익 {fWon(mProfit)}</p>
      </div>
      <div className="flex items-center gap-2 bg-white border border-gray-200 rounded-xl px-4 py-2 shadow-sm">
        <span className="text-sm text-slate-700 font-medium">📅 조회월</span>
        <input className={inp} type="month" value={pdfMonth} onChange={handlePdfMonthChange} max={budgetTodayYM} style={{width:'150px'}}/>
        <button className={btn(tab==='income'?'green':tab==='expense'?'red':'orange')} onClick={()=>printPDF(tab==='income'?'income':tab==='expense'?'expense':'all')}>PDF 출력</button>
      </div>
    </div>
    <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
      <div className="flex gap-2 p-4 border-b border-gray-100">
        {[['overview','📊 개요'],['income','💚 수입'],['expense','❤️ 지출']].map(([k,l])=><button key={k} className={`tab-btn ${tab===k?'active':''}`} onClick={()=>setTab(k)}>{l}</button>)}
      </div>
      {tab==='overview'&&<div className="p-5 space-y-6">
        <div className="text-xs text-slate-500 font-medium mb-1">📅 {mMonthLabel} 기준 (우측 조회월 선택기로 변경)</div>
        <div className="grid grid-cols-3 gap-4">
          <div className="bg-green-50 border border-green-100 rounded-xl p-4 text-center"><div className="text-sm text-green-600 font-medium mb-1">수입 합계</div><div className="text-2xl font-bold text-green-700">{fWon(mIncSum)}</div></div>
          <div className="bg-red-50 border border-red-100 rounded-xl p-4 text-center"><div className="text-sm text-red-500 font-medium mb-1">지출 합계</div><div className="text-2xl font-bold text-red-600">{fWon(mExpSum)}</div></div>
          <div className={`${mProfit>=0?'bg-blue-50 border-blue-100':'bg-orange-50 border-orange-100'} border rounded-xl p-4 text-center`}><div className={`text-sm font-medium mb-1 ${mProfit>=0?'text-blue-600':'text-orange-500'}`}>순수익</div><div className={`text-2xl font-bold ${mProfit>=0?'text-blue-700':'text-orange-600'}`}>{fWon(mProfit)}</div></div>
        </div>
        <div className="grid grid-cols-2 gap-6">
          <div><h4 className="font-semibold text-slate-800 mb-3">💚 수입 항목별</h4><div className="space-y-2">{Object.entries(incByCat).sort((a,b)=>b[1]-a[1]).map(([cat,amt])=><div key={cat} className="flex justify-between items-center p-3 bg-green-50 rounded-lg"><span className="text-sm text-slate-800">{cat}</span><span className="text-sm font-bold text-green-700">{fWon(amt)}</span></div>)}</div></div>
          <div><h4 className="font-semibold text-slate-800 mb-3">❤️ 지출 항목별</h4><div className="space-y-2">{Object.entries(expByCat).sort((a,b)=>b[1]-a[1]).map(([cat,amt])=><div key={cat} className="flex justify-between items-center p-3 bg-red-50 rounded-lg"><span className="text-sm text-slate-800">{cat}</span><span className="text-sm font-bold text-red-600">{fWon(amt)}</span></div>)}</div></div>
        </div>
        <div>{(()=>{
          const nowYM=(()=>{const d=new Date();return`${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,'0')}`;})();
          const allMonths=[...new Set([...income.map(x=>x.date&&x.date.substring(0,7)),...expenses.map(x=>x.date&&x.date.substring(0,7))].filter(Boolean))].filter(m=>m<=nowYM).sort().reverse().slice(0,3);
          return<><h4 className="font-semibold text-slate-800 mb-3">📅 월별 요약 (최근 3개월)</h4>
          <div className="space-y-2">{allMonths.length===0?<div className="text-sm text-slate-500 p-3">데이터가 없습니다</div>:allMonths.map(m=>{
            const mI=income.filter(x=>x.date&&x.date.startsWith(m)&&x.date<=_budgetToday).reduce((s,x)=>s+Number(x.amount),0);
            const mE=expenses.filter(x=>x.date&&x.date.startsWith(m)&&x.date<=_budgetToday).reduce((s,x)=>s+Number(x.amount),0);
            const mP=mI-mE;
            const[y,mo]=m.split('-');
            return<div key={m} className="flex items-center gap-3 p-3 bg-[#f1f5f9] rounded-lg">
              <span className="text-sm font-medium text-slate-700 w-20">{y}년 {parseInt(mo)}월</span>
              <span className="text-sm text-green-600 flex-1">수입 {fWon(mI)}</span>
              <span className="text-sm text-red-500 flex-1">지출 {fWon(mE)}</span>
              <span className={`text-sm font-bold ${mP>=0?'text-blue-600':'text-orange-500'}`}>{mP>=0?'▲':'▼'}{fWon(Math.abs(mP))}</span>
            </div>;
          })}</div></>;
        })()}</div>
      </div>}
      {tab==='income'&&<ListTable items={income} type="income" catFilter={incCatFilter} setCatFilter={setIncCatFilter}/>}
      {tab==='expense'&&<ListTable items={expenses} type="expense" catFilter={expCatFilter} setCatFilter={setExpCatFilter}/>}
    </div>
    <Modal open={modalOpen} onClose={()=>setModalOpen(false)} title={`${editTarget?'수정':'추가'} - ${modalType==='income'?'수입':'지출'}`}>
      <Field label="날짜" required><input className={inp} type="date" value={form.date} onChange={e=>setForm({...form,date:e.target.value})}/></Field>
      <Field label="카테고리"><select className={inp} value={form.category} onChange={e=>setForm({...form,category:e.target.value})}><option value="">선택</option>{(modalType==='income'?incCats:expCats).map(c=><option key={c} value={c}>{c}</option>)}</select></Field>
      <Field label="내용"><input className={inp} value={form.description} onChange={e=>setForm({...form,description:e.target.value})}/></Field>
      <Field label="금액 (원, 1원 단위 입력 가능)" required><WonInput value={form.amount} onChange={v=>setForm({...form,amount:v})} free={true}/></Field>
      <div className="flex justify-end gap-3 mt-2"><button className={btn('indigo')} onClick={save}>저장</button><button className={btn('gray')} onClick={()=>setModalOpen(false)}>취소</button></div>
    </Modal>
    <Confirm open={!!confirmItem} msg="이 내역을 삭제하시겠습니까?" onYes={del} onNo={()=>setConfirmItem(null)}/>
  </div>;
}

// ── 학원비 관리 ───────────────────────────────────────────────────────────
function TuitionManagement({tuitions,setTuitions,students,classes,income,setIncome,tuitionDaySetting}){
  const[tab,setTab]=useState('monthly');
  // 이달 납부현황 안에서 "미납" / "납부완료"를 탭으로 나눠서 보여주기 위한 상태
  // (이미 납부완료한 학생까지 계속 한 화면에 보이면 학생이 많아질수록 찾기 힘들다는 피드백 반영)
  const[monthlySubTab,setMonthlySubTab]=useState('unpaid');
  // 이달 납부현황 정렬
  const[tuSortKey,setTuSortKey]=useState('studentName');
  const[tuSortDir,setTuSortDir]=useState('asc');
  const tuSortField=k=>{if(tuSortKey===k)setTuSortDir(d=>d==='asc'?'desc':'asc');else{setTuSortKey(k);setTuSortDir('asc');}};
  const tuArrow=k=>tuSortKey===k?(tuSortDir==='asc'?' ▲':' ▼'):'';
  // 전체내역 정렬
  const[hisSortKey,setHisSortKey]=useState('month');
  const[hisSortDir,setHisSortDir]=useState('desc');
  const hisSortField=k=>{if(hisSortKey===k)setHisSortDir(d=>d==='asc'?'desc':'asc');else{setHisSortKey(k);setHisSortDir('asc');}};
  const hisArrow=k=>hisSortKey===k?(hisSortDir==='asc'?' ▲':' ▼'):'';
  // 조회월은 오늘 기준 현재 월로 초기화하고, 미래 월 선택 불가
  const tuitionTodayYM=(()=>{const d=new Date();return`${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,'0')}`;})();
  const tuitionNextYM=(()=>{const d=new Date();const ny=d.getMonth()===11?d.getFullYear()+1:d.getFullYear();const nm=d.getMonth()===11?1:d.getMonth()+2;return`${ny}-${String(nm).padStart(2,'0')}`;})();
  const[viewMonth,setViewMonth]=useState(tuitionTodayYM);
  const handleViewMonthChange=e=>{if(e.target.value<=tuitionNextYM)setViewMonth(e.target.value);};
  const[modalOpen,setModalOpen]=useState(false);
  const[editTarget,setEditTarget]=useState(null);
  const[form,setForm]=useState({studentId:'',studentName:'',month:'',amount:'',dueDate:'',paidDate:'',payMethod:'',status:'unpaid',note:''});
  const[confirmItem,setConfirmItem]=useState(null);
  const payMethods=['현금','카드','계좌이체','기타'];
  const getStudentInfo=id=>students.find(s=>s.id===id)||{};
  const calcTuition=studentId=>{
    const student=students.find(s=>s.id===studentId);
    if(!student)return 0;
    return student.enrolledClasses.reduce((sum,cid)=>{const cls=classes.find(c=>c.id===cid);return sum+(cls?cls.fee:0);},0);
  };
  const monthTuitions=tuitions.filter(t=>t.month===viewMonth);
  // 연체 판단: 납부기한의 "월"이 이번달보다 이전일 때만 연체로 표시
  // 예) 납부기한 2026-07-01 → 7월 중에는 미납, 8월 넘어가면 연체
  // 예) 납부기한 2026-05-01 → 현재 7월이므로 연체
  const effectiveStatus=t=>{
    if(t.status==='paid')return'paid';
    if(t.status==='overdue')return'overdue';
    if(t.dueDate&&t.dueDate.slice(0,7)<today().slice(0,7))return'overdue';
    return'unpaid';
  };
  const paidCount=monthTuitions.filter(t=>effectiveStatus(t)==='paid').length;
  const unpaidCount=monthTuitions.filter(t=>effectiveStatus(t)==='unpaid').length;
  const overdueCount=monthTuitions.filter(t=>effectiveStatus(t)==='overdue').length;
  const unpaidAmount=monthTuitions.filter(t=>effectiveStatus(t)==='unpaid').reduce((s,t)=>s+Number(t.amount),0);
  const overdueAmount=monthTuitions.filter(t=>effectiveStatus(t)==='overdue').reduce((s,t)=>s+Number(t.amount),0);
  // 미납 탭 = 미납+연체를 함께 보여줌(둘 다 "아직 돈을 못 받은" 상태), 납부완료 탭 = 납부완료만
  const monthlyTabTuitions=monthTuitions.filter(t=>monthlySubTab==='unpaid'?effectiveStatus(t)!=='paid':effectiveStatus(t)==='paid');
  const totalPaid=monthTuitions.filter(t=>effectiveStatus(t)==='paid').reduce((s,t)=>s+Number(t.amount),0);
  const expectedTotal=monthTuitions.reduce((s,t)=>s+Number(t.amount),0);
  const isDueSoon=dueDate=>{if(!dueDate)return false;const due=new Date(dueDate);const now=new Date();const diff=(due-now)/(1000*60*60*24);return diff>=0&&diff<=3;};
  const unpaidAll=tuitions.filter(t=>effectiveStatus(t)!=='paid');
  // [12][13] 연체 알림 탭: 미래 월 제외, 연체 항목만 표시
  const todayMonth=today().slice(0,7);
  const overdueAll=tuitions.filter(t=>effectiveStatus(t)==='overdue'&&t.month&&t.month<todayMonth);
  // [14] 학생별 누적 연체 그룹
  const overdueByStudent=(()=>{const m={};overdueAll.forEach(t=>{if(!m[t.studentId])m[t.studentId]=[];m[t.studentId].push(t);});return m;})();
  const openAdd=()=>{setEditTarget(null);setForm({studentId:'',studentName:'',month:viewMonth,amount:'',dueDate:calcTuitionDueDate(today(),viewMonth,tuitionDaySetting),paidDate:'',payMethod:'',status:'unpaid',note:''});setModalOpen(true);};
  const migrateAllDueDates=()=>{
    const toUpdate=tuitions.filter(t=>{
      if(!t.month)return false;
      const s=students.find(x=>x.id===t.studentId);
      return s&&s.joinDate;
    });
    if(toUpdate.length===0){alert('재산출할 내역이 없습니다.');return;}
    const modeText=tuitionDaySetting?.mode==='fixed'?`매달 ${tuitionDaySetting.fixedDay}일 고정`:'등록일 기준';
    if(!confirm(`전체 수강료 ${toUpdate.length}건의 납부기한을 재산출합니다.\n(납부완료 포함 전체)\n\n• 등록월 수강료 → 등록일 당일\n• 이후 월 수강료 → ${modeText}\n\n계속하시겠습니까?`))return;
    setTuitions(prev=>prev.map(t=>{
      if(!t.month)return t;
      const s=students.find(x=>x.id===t.studentId);
      if(!s||!s.joinDate)return t;
      const regMonth=s.joinDate.slice(0,7);
      const newDue=t.month===regMonth?s.joinDate:calcTuitionDueDate(s.joinDate,t.month,tuitionDaySetting);
      return{...t,dueDate:newDue};
    }));
    alert(`${toUpdate.length}건의 납부기한 재산출이 완료되었습니다.`);
  };
  const generateFullHistory=()=>{
    const activeStudents=students.filter(s=>s.status!=='withdrawn'&&s.joinDate);
    if(!activeStudents.length){alert('재원 학생이 없습니다.');return;}
    const newRecords=[];
    activeStudents.forEach(s=>{
      const joinMonthStr=s.joinDate.slice(0,7);
      const[jy,jm]=joinMonthStr.split('-').map(Number);
      const[cy,cm]=tuitionTodayYM.split('-').map(Number);
      let year=jy,month=jm;
      while(year<cy||(year===cy&&month<=cm)){
        const monthStr=`${year}-${String(month).padStart(2,'0')}`;
        const monthStart=`${monthStr}-01`;
        if(!tuitions.some(t=>t.studentId===s.id&&t.month===monthStr)){
          const baseFee=(s.enrolledClasses||[]).reduce((sum,cid)=>{
            const cls=classes.find(c=>c.id===cid);
            if(!cls)return sum;
            if(cls.closeDate&&cls.closeDate<monthStart)return sum;
            return sum+(cls.fee||0);
          },0);
          if(baseFee>0){
            const isRegMonth=joinMonthStr===monthStr;
            let finalFee=baseFee,isProrated=false;
            if(isRegMonth){
              const jd=Number(s.joinDate.split('-')[2]);
              if(jd>1){
                const daysInMo=new Date(year,month,0).getDate();
                const proratedDays=daysInMo-jd+1;
                finalFee=Math.round(proratedDays/daysInMo*baseFee/1000)*1000;
                isProrated=true;
              }
            }
            const dueDate=isRegMonth?s.joinDate:calcTuitionDueDate(s.joinDate,monthStr,tuitionDaySetting);
            const isPast=monthStr<tuitionTodayYM;
            newRecords.push({id:genId(),studentId:s.id,studentName:s.name,month:monthStr,amount:finalFee,isProrated,baseFee:isProrated?baseFee:undefined,dueDate,paidDate:isPast?dueDate:'',status:isPast?'paid':'unpaid',payMethod:'',note:isPast?'과거 내역 자동 생성':'자동 생성'});
          }
        }
        if(month===12){year++;month=1;}else{month++;}
      }
    });
    if(newRecords.length===0){alert('생성할 누락 내역이 없습니다.\n모든 달의 내역이 이미 있습니다.');return;}
    const pastCount=newRecords.filter(r=>r.month<tuitionTodayYM).length;
    const curCount=newRecords.length-pastCount;
    if(!confirm(`누락된 수강료 내역 ${newRecords.length}건을 생성합니다.\n\n• 과거 ${pastCount}건 → 납부완료 처리\n  (실제 미납 건은 직접 수정 필요)\n• 이번달 ${curCount}건 → 미납으로 생성\n\n계속하시겠습니까?`))return;
    setTuitions(prev=>[...prev,...newRecords]);
    alert(`${newRecords.length}건 생성 완료`);
  };
  const batchGenerate=()=>{
    const[vy,vm]=viewMonth.split('-');
    const monthStart=`${vy}-${vm}-01`;
    // 해당 월에 재원 중인 학생: 퇴원 아님 + 해당 월 시작 전에 등록한 학생
    const activeStudents=students.filter(s=>s.status!=='withdrawn'&&s.joinDate&&s.joinDate<monthStart);
    const existingIds=new Set(tuitions.filter(t=>t.month===viewMonth).map(t=>t.studentId));
    const newRecords=[];
    activeStudents.forEach(s=>{
      if(existingIds.has(s.id))return;
      // 해당 월에 운영 중인 수업 수강료만 합산 (closeDate가 이달 시작 전이면 제외)
      const amount=(s.enrolledClasses||[]).reduce((sum,cid)=>{
        const cls=classes.find(c=>c.id===cid);
        if(!cls)return sum;
        if(cls.closeDate&&cls.closeDate<monthStart)return sum;
        return sum+(cls.fee||0);
      },0);
      if(!amount)return;
      const dueDate=calcTuitionDueDate(s.joinDate,viewMonth,tuitionDaySetting);
      newRecords.push({id:genId(),studentId:s.id,studentName:s.name,month:viewMonth,amount,dueDate,paidDate:'',payMethod:'',status:'unpaid',note:'',isProrated:false});
    });
    if(newRecords.length===0){alert(`${vy}년 ${vm}월은 이미 모든 재원 학생의 수강료가 등록되어 있습니다.`);return;}
    const modeText=tuitionDaySetting?.mode==='fixed'?`매달 ${tuitionDaySetting.fixedDay}일`:'등록일 기준';
    if(!confirm(`${vy}년 ${vm}월 재원 학생 ${newRecords.length}명의 수강료를 일괄 생성합니다.\n납부기한 방식: ${modeText}\n\n계속하시겠습니까?`))return;
    setTuitions(prev=>[...prev,...newRecords]);
  };
  const openEdit=t=>{setEditTarget(t);setForm({...t});setModalOpen(true);};
  const openPayment=t=>{setEditTarget(t);setForm({...t,paidDate:today(),payMethod:t.payMethod||'계좌이체',status:'paid'});setModalOpen(true);};
  const save=()=>{
    if(!form.studentId||!form.month||!form.amount){alert('학생, 월, 금액은 필수입니다.');return;}
    const student=getStudentInfo(form.studentId);
    const data={...form,amount:Number(form.amount),studentName:student.name||form.studentName||''};
    const wasAlreadyPaid=editTarget&&editTarget.status==='paid';
    const isNowPaid=form.status==='paid';
    if(editTarget){
      setTuitions(prev=>prev.map(t=>t.id===editTarget.id?{...data,id:t.id}:t));
      if(setIncome){
        if(!wasAlreadyPaid&&isNowPaid){
          // 미납→납부완료: 수입 레코드 자동 생성
          setIncome(prev=>[...prev,{id:genId(),date:form.paidDate||today(),category:'수강료',description:`${data.studentName} ${form.month} 수강료`,amount:Number(form.amount),tuitionId:editTarget.id}]);
        }else if(wasAlreadyPaid&&!isNowPaid){
          // 납부완료→미납 취소: 연결된 수입 레코드 삭제
          setIncome(prev=>prev.filter(i=>i.tuitionId!==editTarget.id));
        }else if(wasAlreadyPaid&&isNowPaid){
          // 납부완료 유지, 금액/날짜 수정: 수입 레코드 업데이트
          setIncome(prev=>{
            const exists=prev.some(i=>i.tuitionId===editTarget.id);
            if(exists)return prev.map(i=>i.tuitionId===editTarget.id?{...i,date:form.paidDate||i.date,amount:Number(form.amount),description:`${data.studentName} ${form.month} 수강료`}:i);
            return[...prev,{id:genId(),date:form.paidDate||today(),category:'수강료',description:`${data.studentName} ${form.month} 수강료`,amount:Number(form.amount),tuitionId:editTarget.id}];
          });
        }
      }
    }else{
      const newId=genId();
      setTuitions(prev=>[...prev,{...data,id:newId}]);
      if(setIncome&&isNowPaid){
        // 새 납부완료 항목 등록 시 수입 레코드 생성
        setIncome(prev=>[...prev,{id:genId(),date:form.paidDate||today(),category:'수강료',description:`${data.studentName} ${form.month} 수강료`,amount:Number(form.amount),tuitionId:newId}]);
      }
    }
    setModalOpen(false);
  };
  const del=()=>{
    if(setIncome)setIncome(prev=>prev.filter(i=>i.tuitionId!==confirmItem.id));
    setTuitions(prev=>prev.filter(t=>t.id!==confirmItem.id));
    setConfirmItem(null);
  };
  const statusBadge=status=>({
    paid:<span className="badge bg-green-100 text-green-700">납부완료</span>,
    unpaid:<span className="badge bg-yellow-100 text-yellow-700">미납</span>,
    overdue:<span className="badge bg-red-100 text-red-700">연체</span>,
  }[status]||<span className="badge bg-gray-100 text-slate-600">{status}</span>);
  const genSmsText=t=>{
    const student=getStudentInfo(t.studentId);
    const[y,m]=t.month.split('-');
    const receiver=student.grade==='성인'?`${student.name}님`:`${student.parentName||'학부모'}님께`;
    return`[${receiver}]\n${y}년 ${m}월 수강료 ${fWon(t.amount)} 납부 안내드립니다.\n납부기한: ${t.dueDate||'-'}${effectiveStatus(t)==='overdue'?'\n⚠️ 연체 중입니다. 빠른 납부 부탁드립니다.':''}\n감사합니다. 학원 드림`;
  };
  const printTuitionPDF=()=>{
    const[y,m]=viewMonth.split('-');
    const rows=monthTuitions.map(t=>{
      const student=getStudentInfo(t.studentId);
      const es=effectiveStatus(t);
      const statusLabel={paid:'납부완료',unpaid:'미납',overdue:'연체'}[es]||es;
      const statusColor={paid:'#16a34a',unpaid:'#d97706',overdue:'#dc2626'}[es]||'#6b7280';
      return`<tr><td style="padding:7px 12px;border-bottom:1px solid #f3f4f6;">${t.studentName||student.name||'-'}</td><td style="padding:7px 12px;border-bottom:1px solid #f3f4f6;">${student.grade||'-'}</td><td style="padding:7px 12px;border-bottom:1px solid #f3f4f6;text-align:right;font-weight:700;">₩${Number(t.amount).toLocaleString()}</td><td style="padding:7px 12px;border-bottom:1px solid #f3f4f6;">${t.dueDate||'-'}</td><td style="padding:7px 12px;border-bottom:1px solid #f3f4f6;">${t.paidDate||'-'}</td><td style="padding:7px 12px;border-bottom:1px solid #f3f4f6;">${t.payMethod||'-'}</td><td style="padding:7px 12px;border-bottom:1px solid #f3f4f6;font-weight:700;color:${statusColor};">${statusLabel}</td></tr>`;
    }).join('');
    const html=`<!DOCTYPE html><html lang="ko"><head><meta charset="UTF-8"><title>${y}년 ${m}월 수강료 납부 현황</title><style>body{font-family:'Malgun Gothic',sans-serif;color:#1f2937;padding:32px;max-width:900px;margin:0 auto;}h1{font-size:22px;font-weight:800;color:#4f46e5;border-bottom:3px solid #4f46e5;padding-bottom:12px;margin-bottom:24px;}.summary{display:flex;gap:16px;margin-bottom:24px;}.sbox{flex:1;padding:16px;border-radius:10px;text-align:center;}.sl{font-size:11px;font-weight:600;margin-bottom:4px;}.sv{font-size:20px;font-weight:800;}table{width:100%;border-collapse:collapse;}th{background:#f9fafb;padding:8px 12px;text-align:left;font-size:11px;color:#6b7280;font-weight:700;border-bottom:2px solid #e5e7eb;}.footer{margin-top:32px;font-size:11px;color:#9ca3af;text-align:center;border-top:1px solid #e5e7eb;padding-top:12px;}@media print{.no-print{display:none;}}</style></head><body>
    <div class="no-print" style="text-align:right;margin-bottom:12px;"><button onclick="window.print()" style="background:#4f46e5;color:white;border:none;padding:10px 24px;border-radius:8px;cursor:pointer;font-size:14px;font-weight:600;">🖨️ 인쇄 / PDF 저장</button></div>
    <h1>💳 ${y}년 ${m}월 수강료 납부 현황</h1>
    <div class="summary">
      <div class="sbox" style="background:#f0fdf4;border:1px solid #bbf7d0;"><div class="sl" style="color:#16a34a;">납부완료</div><div class="sv" style="color:#15803d;">${paidCount}명 · ₩${totalPaid.toLocaleString()}</div></div>
      <div class="sbox" style="background:#fefce8;border:1px solid #fde68a;"><div class="sl" style="color:#d97706;">미납</div><div class="sv" style="color:#b45309;">${unpaidCount}명</div></div>
      <div class="sbox" style="background:#fef2f2;border:1px solid #fecaca;"><div class="sl" style="color:#dc2626;">연체</div><div class="sv" style="color:#b91c1c;">${overdueCount}명</div></div>
      <div class="sbox" style="background:#eff6ff;border:1px solid #bfdbfe;"><div class="sl" style="color:#2563eb;">납부율</div><div class="sv" style="color:#1d4ed8;">${monthTuitions.length?Math.round(paidCount/monthTuitions.length*100):0}%</div></div>
    </div>
    <table><thead><tr><th>학생</th><th>레벨</th><th style="text-align:right">금액</th><th>납부기한</th><th>납부일</th><th>결제방법</th><th>상태</th></tr></thead><tbody>${rows}</tbody></table>
    <div class="footer">출력일: ${new Date().toLocaleDateString('ko-KR')} · 학원 관리 시스템</div></body></html>`;
    const w=window.open('','_blank','width=1000,height=750,scrollbars=yes');
    if(w){w.document.write(html);w.document.close();}else{alert('팝업이 차단되었습니다.');}
  };
  return<div className="space-y-5">
    <div className="flex items-center justify-between flex-wrap gap-3">
      <div>
        <h1 className="text-2xl font-bold text-slate-900">학원비 관리</h1>
        <p className="text-slate-600 text-sm mt-1">수강료 납부 현황 및 미납 알림 관리</p>
        <p className="text-xs text-slate-500 mt-0.5">💡 <strong>미납(기한 전)</strong>: 납부기한이 아직 지나지 않은 건 · <strong>연체(기한 초과)</strong>: 납부기한이 지났으나 납부 안 된 건 — 납부기한 자동 감지</p>
      </div>
      <div className="flex items-center gap-2">
        <input className={inp} type="month" value={viewMonth} onChange={handleViewMonthChange} max={tuitionNextYM} style={{width:'160px'}}/>
        <button className={btn('indigo')} onClick={batchGenerate}>⚡ 수강료 일괄 생성</button>
        <button className={btn('orange')} onClick={generateFullHistory} title="전체 재원 학생의 누락된 수강료 내역을 등록일부터 현재까지 일괄 생성">📅 전 기간 누락 생성</button>
        <button className={btn('gray')} onClick={migrateAllDueDates} title="기존 미납 내역의 납부기한을 현재 설정 기준으로 전체 재산출">📐 납부기한 재산출</button>
        <button className={btn('green')} onClick={printTuitionPDF}>🖨️ PDF</button>
      </div>
    </div>
    <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
      {[
        {label:'납부완료',value:paidCount+'명',sub:fWon(totalPaid),color:'bg-green-50 border-green-200',tc:'text-green-700',sc:'text-green-500'},
        {label:'미납 (기한 전)',value:unpaidCount+'명',sub:fWon(unpaidAmount),color:'bg-yellow-50 border-yellow-200',tc:'text-yellow-700',sc:'text-yellow-500'},
        {label:'연체 (기한 초과)',value:overdueCount+'명',sub:fWon(overdueAmount),color:'bg-red-50 border-red-200',tc:'text-red-700',sc:'text-red-500'},
        {label:'납부율',value:monthTuitions.length?Math.round(paidCount/monthTuitions.length*100)+'%':'0%',sub:fWon(expectedTotal)+' 예상',color:'bg-[#f1f5f9] border-[#cbd5e1]',tc:'text-[#1e293b]',sc:'text-[#475569]'},
      ].map(({label,value,sub,color,tc,sc})=>(
        <div key={label} className={`rounded-2xl border p-4 ${color}`}>
          <div className={`text-xs font-semibold ${tc} mb-1`}>{label}</div>
          <div className={`text-2xl font-bold ${tc}`}>{value}</div>
          <div className={`text-xs mt-1 ${sc}`}>{sub}</div>
        </div>
      ))}
    </div>
    <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
      <div className="flex gap-2 p-4 border-b border-gray-100 flex-wrap">
        <button className={`tab-btn ${tab==='monthly'?'active':''}`} onClick={()=>setTab('monthly')}>📅 이달 납부현황</button>
        <button className={`tab-btn ${tab==='history'?'active':''}`} onClick={()=>setTab('history')}>📋 전체 내역</button>
        <button className={`tab-btn ${tab==='alert'?'active':''}`} onClick={()=>setTab('alert')}>
          🔔 연체 알림{overdueAll.length>0&&<span className="ml-1.5 bg-red-500 text-white rounded-full text-xs px-1.5 py-0.5">{overdueAll.length}</span>}
        </button>
      </div>
      {tab==='monthly'&&<div>
        <div className="flex gap-2 px-4 pt-4 pb-3 mb-1 border-b border-gray-100">
          <button className={`tab-btn ${monthlySubTab==='unpaid'?'active':''}`} onClick={()=>setMonthlySubTab('unpaid')}>
            ⚠️ 미납/연체 <span className="ml-1 bg-yellow-100 text-yellow-700 rounded-full text-xs px-1.5 py-0.5">{unpaidCount+overdueCount}</span>
          </button>
          <button className={`tab-btn ${monthlySubTab==='paid'?'active':''}`} onClick={()=>setMonthlySubTab('paid')}>
            ✅ 납부완료 <span className="ml-1 bg-green-100 text-green-700 rounded-full text-xs px-1.5 py-0.5">{paidCount}</span>
          </button>
        </div>
        {monthlyTabTuitions.length===0
        ?<div className="p-12 text-center text-slate-600"><div className="text-4xl mb-3">💳</div><div className="font-medium">{monthlySubTab==='unpaid'?'미납/연체 내역이 없습니다':'납부완료 내역이 없습니다'}</div></div>
        :<div className="overflow-x-auto overflow-y-auto tbl-scroll" style={{maxHeight:'calc(100vh - 320px)'}}><table className="w-full min-w-[700px] app-table">
          <thead><tr className="text-xs text-slate-600 font-semibold">
            <th className="px-4 py-3 text-left cursor-pointer select-none" style={{width:'90px'}} onClick={()=>tuSortField('studentName')}>학생{tuArrow('studentName')}</th>
            <th className="px-4 py-3 text-left" style={{width:'100px'}}>레벨</th>
            <th className="px-4 py-3 text-right cursor-pointer select-none" style={{width:'100px'}} onClick={()=>tuSortField('amount')}>수강료{tuArrow('amount')}</th>
            <th className="px-4 py-3 text-left cursor-pointer select-none" style={{width:'100px'}} onClick={()=>tuSortField('dueDate')}>납부기한{tuArrow('dueDate')}</th>
            <th className="px-4 py-3 text-left cursor-pointer select-none" style={{width:'100px'}} onClick={()=>tuSortField('paidDate')}>납부일{tuArrow('paidDate')}</th>
            <th className="px-4 py-3 text-left" style={{width:'90px'}}>결제방법</th>
            <th className="px-4 py-3 text-left cursor-pointer select-none" style={{width:'90px'}} onClick={()=>tuSortField('status')}>상태{tuArrow('status')}</th>
            <th className="px-4 py-3 text-left" style={{width:'110px'}}>관리</th>
          </tr></thead>
          <tbody>{[...monthlyTabTuitions].sort((a,b)=>{
            const tuGetters={studentName:t=>t.studentName||'',amount:t=>Number(t.amount||0),dueDate:t=>t.dueDate||'',paidDate:t=>t.paidDate||'',status:t=>t.status||''};
            const g=tuGetters[tuSortKey]||tuGetters.studentName;const av=g(a),bv=g(b);
            if(typeof av==='number')return tuSortDir==='asc'?av-bv:bv-av;
            return tuSortDir==='asc'?String(av).localeCompare(String(bv),'ko'):String(bv).localeCompare(String(av),'ko');
          }).map(t=>{
            const student=getStudentInfo(t.studentId);
            const es=effectiveStatus(t);
            const dueSoon=es!=='paid'&&isDueSoon(t.dueDate);
            return<tr key={t.id} className={`table-row border-t border-gray-50 ${dueSoon?'bg-amber-50':es==='overdue'?'bg-red-50':''}`}>
              <td className="px-4 py-3 font-semibold text-slate-900">{t.studentName||student.name||'-'}{students.find(s=>s.id===t.studentId)?.status==='withdrawn'&&<span className="ml-1.5 text-xs bg-gray-100 text-gray-500 rounded px-1.5 py-0.5 font-normal">퇴원</span>}</td>
              <td className="px-4 py-3 text-slate-600 text-sm">{student.level||student.grade||'-'}</td>
              <td className="px-4 py-3 text-right font-semibold text-slate-800 whitespace-nowrap">{fWon(t.amount)}{t.isProrated&&<span className="text-xs text-amber-600 font-normal ml-1" title={t.baseFee?`정액 ${fWon(t.baseFee)}`:''}>(일할)</span>}</td>
              <td className="px-4 py-3 text-sm">{t.dueDate?<span className={dueSoon?'text-orange-600 font-semibold':'text-slate-700'}>{fDate(t.dueDate)}{dueSoon&&' ⚠️'}</span>:'-'}</td>
              <td className="px-4 py-3 text-sm text-slate-700">{t.paidDate?fDate(t.paidDate):'-'}</td>
              <td className="px-4 py-3 text-sm text-slate-700">{t.payMethod||'-'}</td>
              <td className="px-4 py-3">{statusBadge(es)}</td>
              <td className="px-4 py-3"><div className="flex gap-1.5 flex-wrap">
                {t.status!=='paid'&&<button className="text-xs px-2 py-1 bg-green-100 text-green-700 rounded-lg hover:bg-green-200 font-medium whitespace-nowrap" onClick={()=>openPayment(t)}>✅ 납부처리</button>}
                <button className="text-xs px-2 py-1 bg-gray-100 text-slate-700 rounded-lg hover:bg-gray-200" onClick={()=>openEdit(t)}>수정</button>
                <button className="text-xs px-2 py-1 bg-red-50 text-red-500 rounded-lg hover:bg-red-100" onClick={()=>setConfirmItem(t)}>삭제</button>
              </div></td>
            </tr>;
          })}</tbody>
        </table>
        <div className={`px-5 py-3 border-t flex items-center justify-between ${monthlySubTab==='unpaid'?'bg-red-50 border-red-100':'bg-green-50 border-green-100'}`}>
          <span className="text-xs text-slate-600">
            {monthlySubTab==='unpaid'
              ?<>미납 <strong className="text-yellow-700">{unpaidCount}명 {fWon(unpaidAmount)}</strong>{overdueCount>0&&<> · 연체 <strong className="text-red-700">{overdueCount}명 {fWon(overdueAmount)}</strong></>}</>
              :<>납부완료 <strong className="text-green-700">{paidCount}명</strong></>
            }
          </span>
          <span className="text-sm font-bold text-slate-900">합계 {fWon(monthlyTabTuitions.reduce((s,t)=>s+Number(t.amount),0))}</span>
        </div>
        </div>
        }
      </div>}
      {tab==='history'&&(tuitions.length===0
        ?<div className="p-12 text-center text-slate-600"><div className="text-4xl mb-3">📋</div><div>납부 내역이 없습니다</div></div>
        :<div className="overflow-x-auto overflow-y-auto tbl-scroll" style={{maxHeight:'calc(100vh - 320px)'}}><table className="w-full min-w-[650px] app-table">
          <thead><tr className="text-xs text-slate-600 font-semibold">
            <th className="px-4 py-3 text-left cursor-pointer select-none" style={{width:'80px'}} onClick={()=>hisSortField('month')}>월{hisArrow('month')}</th>
            <th className="px-4 py-3 text-left cursor-pointer select-none" style={{width:'90px'}} onClick={()=>hisSortField('studentName')}>학생{hisArrow('studentName')}</th>
            <th className="px-4 py-3 text-right cursor-pointer select-none" style={{width:'100px'}} onClick={()=>hisSortField('amount')}>금액{hisArrow('amount')}</th>
            <th className="px-4 py-3 text-left cursor-pointer select-none" style={{width:'100px'}} onClick={()=>hisSortField('paidDate')}>납부일{hisArrow('paidDate')}</th>
            <th className="px-4 py-3 text-left" style={{width:'90px'}}>결제방법</th>
            <th className="px-4 py-3 text-left cursor-pointer select-none" style={{width:'90px'}} onClick={()=>hisSortField('status')}>상태{hisArrow('status')}</th>
            <th className="px-4 py-3 text-left" style={{width:'110px'}}>관리</th>
          </tr></thead>
          <tbody>{[...tuitions].filter(t=>!t.month||t.month<=tuitionTodayYM).sort((a,b)=>{
            const hisGetters={month:t=>t.month||'',studentName:t=>t.studentName||'',amount:t=>Number(t.amount||0),paidDate:t=>t.paidDate||'',status:t=>t.status||''};
            const g=hisGetters[hisSortKey]||hisGetters.month;const av=g(a),bv=g(b);
            if(typeof av==='number')return hisSortDir==='asc'?av-bv:bv-av;
            return hisSortDir==='asc'?String(av).localeCompare(String(bv),'ko'):String(bv).localeCompare(String(av),'ko');
          }).map(t=>{
            const student=getStudentInfo(t.studentId);
            return<tr key={t.id} className="table-row border-t border-gray-50">
              <td className="px-4 py-3 text-sm text-slate-700">{t.month}</td>
              <td className="px-4 py-3 font-semibold text-slate-900">{t.studentName||student.name||'-'}{students.find(s=>s.id===t.studentId)?.status==='withdrawn'&&<span className="ml-1.5 text-xs bg-gray-100 text-gray-500 rounded px-1.5 py-0.5 font-normal">퇴원</span>}</td>
              <td className="px-4 py-3 text-right font-semibold text-slate-800">{fWon(t.amount)}</td>
              <td className="px-4 py-3 text-sm text-slate-700">{t.paidDate?fDate(t.paidDate):'-'}</td>
              <td className="px-4 py-3 text-sm text-slate-700">{t.payMethod||'-'}</td>
              <td className="px-4 py-3">{statusBadge(t.status)}</td>
              <td className="px-4 py-3"><div className="flex gap-1.5 flex-wrap">
                {t.status!=='paid'&&<button className="text-xs px-2 py-1 bg-green-100 text-green-700 rounded-lg hover:bg-green-200 font-medium" onClick={()=>openPayment(t)}>✅ 납부처리</button>}
                <button className="text-xs px-2 py-1 bg-gray-100 text-slate-700 rounded-lg hover:bg-gray-200" onClick={()=>openEdit(t)}>수정</button>
                <button className="text-xs px-2 py-1 bg-red-50 text-red-500 rounded-lg hover:bg-red-100" onClick={()=>setConfirmItem(t)}>삭제</button>
              </div></td>
            </tr>;
          })}</tbody>
        </table></div>
      )}
      {tab==='alert'&&<div className="p-5 space-y-4">
        <div className="bg-blue-50 border border-blue-200 rounded-xl p-4">
          <div className="text-sm font-semibold text-blue-800 mb-1">📱 연체 알림 발송 방법</div>
          <div className="text-sm text-blue-700">아래 학생들의 <strong>문자 내용 복사</strong> 버튼을 누르면 발송용 문자가 복사됩니다. 카카오톡 또는 문자로 직접 붙여넣기 하여 발송하세요.</div>
          <div className="mt-2 text-xs text-blue-500">💡 납부기한이 지난 <strong>연체 항목만</strong> 표시됩니다. 미래 월·납부 기한 전 항목은 제외됩니다.</div>
        </div>
        {Object.keys(overdueByStudent).length===0
          ?<div className="p-8 text-center text-slate-600"><div className="text-4xl mb-2">🎉</div><div className="font-medium">연체 학생이 없습니다! 모든 납부기한이 지난 수강료가 처리되었습니다.</div></div>
          :<div className="space-y-4">{Object.entries(overdueByStudent).sort((a,b)=>b[1].length-a[1].length).map(([sid,tList])=>{
            const student=getStudentInfo(sid);
            const totalAmt=tList.reduce((s,t)=>s+Number(t.amount),0);
            const sortedList=[...tList].sort((a,b)=>(a.month||'').localeCompare(b.month||''));
            return<div key={sid} className="rounded-xl border border-red-200 bg-red-50 p-4">
              <div className="flex items-start justify-between gap-3 flex-wrap mb-3">
                <div>
                  <div className="flex items-center gap-2 mb-1 flex-wrap">
                    <span className="font-bold text-slate-900">{student.name}</span>
                    <span className="text-xs text-slate-600">{student.level||student.grade}</span>
                    <span className="badge bg-red-100 text-red-700">연체 {tList.length}개월</span>
                    <span className="badge bg-red-200 text-red-800 font-bold">누적 {fWon(totalAmt)}</span>
                  </div>
                  <div className="text-sm text-slate-600">{student.grade==='성인'?`본인 📞 ${student.phone||'-'}`:`학부모: ${student.parentName||'-'} · 📞 ${student.parentPhone||'-'}`}</div>
                </div>
                <button className="text-xs px-3 py-1.5 bg-white border border-gray-200 rounded-lg hover:bg-[#f1f5f9] text-slate-800 font-medium shrink-0"
                  onClick={()=>copyToClipboard(genSmsText(sortedList[0]),'문자 내용이 복사되었습니다!')}>📋 문자 복사</button>
              </div>
              <div className="space-y-1">
                {sortedList.map(t=><div key={t.id} className="flex items-center justify-between bg-white rounded-lg px-3 py-2 text-sm border border-red-100">
                  <span className="text-slate-700">{t.month} · {fWon(t.amount)} · 기한 {t.dueDate?fDate(t.dueDate):'-'}</span>
                  <button className="text-xs px-2 py-1 bg-green-600 text-white rounded hover:bg-green-700"
                    onClick={()=>openPayment(t)}>납부처리</button>
                </div>)}
              </div>
            </div>;
          })}</div>
        }
      </div>}
    </div>
    <Modal open={modalOpen} onClose={()=>setModalOpen(false)} title={editTarget?'납부 내역 수정':'납부 등록'}>
      <Field label="학생" required>
        <select className={inp} value={form.studentId} onChange={e=>{
          const s=students.find(st=>st.id===e.target.value);
          const amt=s?calcTuition(s.id):0;
          const newDue=s?.joinDate?calcTuitionDueDate(s.joinDate,form.month||viewMonth,tuitionDaySetting):form.dueDate;
          setForm({...form,studentId:e.target.value,studentName:s?.name||'',amount:amt||form.amount,dueDate:newDue});
        }}><option value="">학생 선택</option>{[...students].sort((a,b)=>a.name.localeCompare(b.name,'ko')).map(s=><option key={s.id} value={s.id}>{s.name} ({s.level||s.grade})</option>)}</select>
      </Field>
      {form.studentId&&<div className="mb-3 text-xs text-[#1e3a5f] bg-[#f1f5f9] rounded-lg px-3 py-2">
        💡 수강 중인 수업 기준 자동 계산 금액: <strong>{fWon(calcTuition(form.studentId))}</strong>
      </div>}
      <div className="grid grid-cols-2 gap-3">
        <Field label="납부 월" required><input className={inp} type="month" value={form.month} onChange={e=>setForm({...form,month:e.target.value})}/></Field>
        <Field label="납부기한"><input className={inp} type="date" value={form.dueDate} onChange={e=>setForm({...form,dueDate:e.target.value})}/></Field>
      </div>
      {form.studentId&&form.month&&(()=>{
        const stu=students.find(s=>s.id===form.studentId);
        const enroll=stu?.joinDate||stu?.enrollDate||(stu?.enrollmentHistory?.[0]?.joinDate)||'';
        if(!enroll)return null;
        const[ey,em,ed]=enroll.split('-').map(Number);
        const[fy,fm]=form.month.split('-').map(Number);
        if(ey!==fy||em!==fm)return null;
        const daysInMonth=new Date(fy,fm,0).getDate();
        const remaining=daysInMonth-ed+1;
        const baseFeeAmt=calcTuition(form.studentId)||Number(form.amount)||0;
        const proratedAmt=baseFeeAmt?Math.round(baseFeeAmt*remaining/daysInMonth/1000)*1000:0;
        return<div className="mb-3 bg-amber-50 border border-amber-200 rounded-xl p-3">
          <div className="font-semibold text-amber-800 text-sm mb-1">📅 월중간 등록 — 일할계산 가능</div>
          <div className="text-amber-700 text-xs mb-2">입학일 {enroll} · {fm}월 총 {daysInMonth}일 중 <strong>{remaining}일</strong> 수강 ({Math.round(remaining/daysInMonth*100)}%)</div>
          <div className="flex items-center gap-2 flex-wrap">
            <span className="text-xs text-amber-900">정액 <strong>{fWon(baseFeeAmt)}</strong> → 일할 <strong>{fWon(proratedAmt)}</strong></span>
            {!form.isProrated
              ?<button className="text-xs px-3 py-1 bg-amber-600 text-white rounded-lg hover:bg-amber-700 font-medium"
                  onClick={()=>setForm(f=>({...f,amount:proratedAmt,baseFee:baseFeeAmt,isProrated:true}))}>일할계산 적용</button>
              :<span className="flex items-center gap-2"><span className="badge bg-amber-100 text-amber-700">일할계산 적용됨</span>
                <button className="text-xs px-2 py-0.5 bg-gray-200 text-slate-700 rounded hover:bg-gray-300"
                  onClick={()=>setForm(f=>({...f,amount:baseFeeAmt,baseFee:undefined,isProrated:false}))}>정액으로 되돌리기</button>
              </span>}
          </div>
        </div>;
      })()}
      <Field label="수강료 (원, 만원 단위)" required><WonInput value={form.amount} onChange={v=>setForm({...form,amount:v})}/></Field>
      <Field label="납부 상태">
        <select className={inp} value={form.status} onChange={e=>{const s=e.target.value;setForm({...form,status:s,...(s!=='paid'?{paidDate:'',payMethod:''}:{})});}}>
          <option value="unpaid">미납</option><option value="paid">납부완료</option><option value="overdue">연체</option>
        </select>
      </Field>
      {form.status==='paid'&&<div className="grid grid-cols-2 gap-3">
        <Field label="납부일"><input className={inp} type="date" value={form.paidDate} onChange={e=>setForm({...form,paidDate:e.target.value})}/></Field>
        <Field label="결제방법"><select className={inp} value={form.payMethod} onChange={e=>setForm({...form,payMethod:e.target.value})}>
          <option value="">선택</option>{payMethods.map(m=><option key={m} value={m}>{m}</option>)}
        </select></Field>
      </div>}
      <Field label="메모"><input className={inp} value={form.note} onChange={e=>setForm({...form,note:e.target.value})} placeholder="특이사항 메모"/></Field>
      <div className="flex justify-end gap-3 mt-2">
        <button className={btn('indigo')} onClick={save}>저장</button>
        <button className={btn('gray')} onClick={()=>setModalOpen(false)}>취소</button>
      </div>
    </Modal>
    <Confirm open={!!confirmItem} msg="이 납부 내역을 삭제하시겠습니까?" onYes={del} onNo={()=>setConfirmItem(null)}/>
  </div>;
}

// ── 출결 관리 (학생 학교급별 분류) ──────────────────────────────────────────
// AttRow는 AttendanceManagement 함수 "바깥"(모듈 최상위)에 선언합니다.
// 만약 부모 컴포넌트 안에서 선언하면, 부모가 리렌더링될 때마다 AttRow가 매번 "새로운 컴포넌트"로
// 취급되어 React가 기존 <input> DOM을 통째로 버리고 새로 만듭니다 → 글자 하나 입력할 때마다
// input이 새로 생성되면서 포커스가 풀려버려 "한 글자만 입력해도 끊기는" 버그가 발생했습니다.
// 바깥으로 빼고 필요한 값들을 모두 props로 전달하면, React가 같은 컴포넌트로 인식해 input을
// 재사용하므로 포커스가 유지됩니다.
function AttRow({person,type,classId,cur,statusBtns,setStatus,setAttendance,isWarn,onAddMakeup,hasMakeup,onCancelMakeup,teacherBadge,teacherBadgeColor,isWithdrawn}){
  // 버튼 목록(statusBtns)이 비어있어도(퇴직 강사 등) 기록된 상태를 올바르게 표시하기 위한 전체 상태 맵
  const _allStatusMap={present:{label:'출석',color:'bg-green-100 text-green-700'},late:{label:'지각',color:'bg-yellow-100 text-yellow-700'},halfday:{label:'반차',color:'bg-cyan-100 text-cyan-700'},vacation:{label:'휴가',color:'bg-blue-100 text-blue-700'},sick:{label:'병가',color:'bg-pink-100 text-pink-700'},training:{label:'교육/연수',color:'bg-purple-100 text-purple-700'},other:{label:'기타',color:'bg-slate-100 text-slate-600'},absent:{label:'결석',color:'bg-red-100 text-red-700'},leave:{label:'조퇴',color:'bg-orange-100 text-orange-700'},cancelled:{label:'휴강',color:'bg-slate-100 text-slate-600'}};
  const _di=(s)=>{const f=statusBtns.find(b=>b.s===s);return f||_allStatusMap[s]||{label:s,color:'bg-gray-100'};};
  return<tr className={`table-row border-t border-gray-50${isWarn?' bg-orange-50':isWithdrawn?' bg-gray-50':''}`}>
    <td className="px-4 py-3 font-semibold text-slate-900" style={{width:'110px',minWidth:'110px'}}><div>{person.name}</div>{isWithdrawn&&<span className="text-xs bg-gray-200 text-gray-500 px-1.5 py-0.5 rounded-full" style={{display:'inline-block',marginTop:'2px'}}>퇴원</span>}{isWarn&&<span className="text-xs bg-orange-200 text-orange-700 px-1.5 py-0.5 rounded-full" style={{display:'inline-block',marginTop:'2px'}}>경고</span>}{teacherBadge&&<span className={`text-xs px-1.5 py-0.5 rounded-full ${teacherBadgeColor||'bg-amber-100 text-amber-700'}`} style={{display:'inline-block',marginTop:'2px'}}>{teacherBadge}</span>}</td>
    <td className="px-4 py-3 text-slate-600 text-sm">{type==='teacher'?(person.subjects||[]).join(', '):person.level||person.grade}</td>
    <td className="px-4 py-3"><div className="flex gap-2 flex-wrap">
      {statusBtns.map(({s,label,color})=><button key={s} onClick={()=>setStatus(type,person.id,s,cur?.note||'',classId)}
        className={`text-xs px-3 py-1.5 rounded-full border font-medium transition-all ${cur?.status===s?color+' ring-2 ring-offset-1':'border-gray-200 text-slate-600 hover:border-gray-300'}`}>{label}</button>)}
    </div></td>
    <td className="px-4 py-3" style={{width:'130px',minWidth:'130px'}}>{cur?<span className={`badge ${_di(cur.status).color}`}>{_di(cur.status).label}</span>:<span className="text-xs text-gray-300">미기록</span>}</td>
    <td className="px-4 py-3" style={{width:'180px',minWidth:'180px'}}>
      <div className="flex items-center gap-2">
        <input className="text-xs border border-gray-200 rounded px-2 py-1 w-28" placeholder="비고..." value={cur?.note||''}
          onChange={e=>{if(cur)setAttendance(prev=>prev.map(a=>a.id===cur.id?{...a,note:e.target.value}:a));}}/>
        {type==='student'&&cur?.status==='absent'&&(hasMakeup
          ?<div className="flex items-center gap-1">
              <span className="text-xs bg-indigo-50 text-indigo-500 px-2 py-0.5 rounded-full border border-indigo-200">보강등록됨</span>
              {onCancelMakeup&&<button onClick={onCancelMakeup} className="text-xs bg-red-50 text-red-500 border border-red-200 hover:bg-red-100 px-1.5 py-0.5 rounded-full font-medium" title="보강 취소">✕</button>}
            </div>
          :<button onClick={onAddMakeup} className="text-xs bg-amber-50 text-amber-700 border border-amber-300 hover:bg-amber-100 px-2 py-0.5 rounded-full font-medium">+ 보강</button>)}
      </div>
    </td>
  </tr>;
}
function AttendanceManagement({attendance,setAttendance,teachers,students,classes,attContext,clearAttContext,makeups,setMakeups,role,loggedInTeacherId}){
  const[tab,setTab]=useState('teacher');
  const[date,setDate]=useState(today());
  const[nameSearch,setNameSearch]=useState('');
  // 강사 로그인 시 초기 탭 및 반 필터 자동 설정
  useEffect(()=>{
    if(role==='teacher'&&loggedInTeacherId){
      const myClasses=classes.filter(c=>c.teacherId===loggedInTeacherId&&!(c.closeDate&&c.closeDate<=today()));
      if(myClasses.length>0)setClassFilter(myClasses[0].id);
    }
  },[loggedInTeacherId]);
  // 대시보드에서 결석경고 클릭 시 학생 탭 + 경고 학생 하이라이트
  useEffect(()=>{
    if(attContext?.tab==='student')setTab('student');
    if(attContext?.warnIds?.length){setShowWarnOnly(true);}else{setShowWarnOnly(false);}
  },[attContext]);
  // 결석경고 실시간 계산 — 출결 수정 시 자동 반영 (대시보드 정적 context 대신 live 데이터 사용)
  const liveWarnIds=(()=>{
    const d_ym=new Date();const thisYM=`${d_ym.getFullYear()}-${String(d_ym.getMonth()+1).padStart(2,'0')}`;
    const absenceDates={};
    attendance.filter(a=>a.type==='student'&&a.date&&a.date.substring(0,7)===thisYM&&a.date<=today()&&a.status==='absent').forEach(a=>{
      if(!absenceDates[a.refId])absenceDates[a.refId]=new Set();
      absenceDates[a.refId].add(a.date);
    });
    const sevenDaysAgo=new Date();sevenDaysAgo.setDate(sevenDaysAgo.getDate()-7);
    const sevenDaysAgoStr=sevenDaysAgo.toISOString().split('T')[0];
    const baseStudents=students.filter(s=>s.status!=='withdrawn'&&(!s.joinDate||s.joinDate<=today()));
    return baseStudents.filter(s=>{
      const dates=[...(absenceDates[s.id]||[])].sort();
      if(dates.length<3)return false;
      return dates[2]>=sevenDaysAgoStr;
    }).map(s=>s.id);
  })();
  // 학생 출결 탭에서 "반별로 보기"를 선택할 수 있는 필터 (Austin님 피드백[11]: 학생이 많아지면
  // 모든 반이 한 화면에 계속 나열되어 스크롤이 길어진다는 지적 → 반 하나만 골라서 보면 스크롤이 줄어듦)
  // 'all'=전체 반 다 보기, 'unassigned'=반 미배정 학생만, 그 외=선택한 수업 id 하나만
  const[classFilter,setClassFilter]=useState('all');
  const[showWarnOnly,setShowWarnOnly]=useState(false);
  // 일괄휴강 후 보강 일정 일괄 입력 모달
  const[batchMkModal,setBatchMkModal]=useState(false);
  const[batchMkCls,setBatchMkCls]=useState(null);
  const[batchMkStudents,setBatchMkStudents]=useState([]);
  const[batchMkSelected,setBatchMkSelected]=useState(new Set());
  const[batchMkForm,setBatchMkForm]=useState({makeupDate:'',startTime:'',endTime:'',room:''});
  const batchMkRooms=['1레슨실','2레슨실','3레슨실','그룹레슨실','이론강의실','발표홀'];
  // 충돌 검사 (강의실+날짜+시간 겹침)
  const batchTimeToMin=t=>{if(!t)return-1;const[h,m]=(t||'0:0').split(':').map(Number);return(h||0)*60+(m||0);};
  const batchCheckConflict=(room,mkDate,st,et)=>{
    if(!room||!mkDate||!st||!et)return[];
    const sM=batchTimeToMin(st),eM=batchTimeToMin(et);
    const conflicts=[];
    for(const m of (makeups||[])){
      if(m.room!==room||m.makeupDate!==mkDate||!m.makeupStartTime||!m.makeupEndTime)continue;
      const mS=batchTimeToMin(m.makeupStartTime),mE=batchTimeToMin(m.makeupEndTime);
      if(sM<mE&&mS<eM)conflicts.push(`보강: ${m.studentName} (${m.makeupStartTime}~${m.makeupEndTime})`);
    }
    const dow=new Date(mkDate).getDay();
    for(const c of (classes||[])){
      if(c.room!==room||!(c.days||[]).includes(dow)||!c.startTime||!c.endTime)continue;
      const cS=batchTimeToMin(c.startTime),cE=batchTimeToMin(c.endTime);
      if(sM<cE&&cS<eM)conflicts.push(`정규수업: ${c.name} (${c.startTime}~${c.endTime})`);
    }
    return conflicts;
  };
  const[attTeaSortKey,setAttTeaSortKey]=useState('name');
  const[attTeaSortDir,setAttTeaSortDir]=useState('asc');
  const attTeaSortField=k=>{if(attTeaSortKey===k)setAttTeaSortDir(d=>d==='asc'?'desc':'asc');else{setAttTeaSortKey(k);setAttTeaSortDir('asc');}};
  const attTeaArrow=k=>attTeaSortKey===k?(attTeaSortDir==='asc'?' ▲':' ▼'):'';
  const[attStuSortKey,setAttStuSortKey]=useState('name');
  const[attStuSortDir,setAttStuSortDir]=useState('asc');
  const attStuSortField=k=>{if(attStuSortKey===k)setAttStuSortDir(d=>d==='asc'?'desc':'asc');else{setAttStuSortKey(k);setAttStuSortDir('asc');}};
  const attStuArrow=k=>attStuSortKey===k?(attStuSortDir==='asc'?' ▲':' ▼'):'';
  // 학생(student)은 같은 날이라도 수업(classId)마다 따로 출결을 기록하고, 강사(teacher)는 수업 구분 없이 하루에 1건만 기록합니다.
  const getStatus=(type,refId,classId)=>attendance.find(a=>a.date===date&&a.type===type&&a.refId===refId&&(type==='student'?a.classId===classId:true));
  const dayAtt=attendance.filter(a=>a.date===date&&a.type===tab);
  const presentCnt=dayAtt.filter(a=>a.status==='present').length;
  // 강사 탭에서는 "결석"이 없으므로 휴가·병가 합계를, 학생 탭에서는 결석 합계를 두번째 숫자로 보여줍니다.
  const secondaryLabel=tab==='teacher'?'휴가·병가':'결석';
  const secondaryCnt=tab==='teacher'?dayAtt.filter(a=>a.status==='vacation'||a.status==='sick').length:dayAtt.filter(a=>a.status==='absent').length;
  const setStatus=(type,refId,status,note='',classId)=>{
    const existing=getStatus(type,refId,classId);
    if(existing)setAttendance(prev=>prev.map(a=>a.id===existing.id?{...a,status,note}:a));
    else setAttendance(prev=>[...prev,{id:genId(),date,type,refId,status,note,...(type==='student'?{classId}:{})}]);
    // [20] 결석/휴강 → 다른 상태로 변경 시 연결된 보강 자동 삭제
    if(type==='student'&&status!=='absent'&&status!=='cancelled'&&setMakeups){
      const prevStatus=existing?.status;
      if(prevStatus==='absent'||prevStatus==='cancelled'||!prevStatus){
        setMakeups(prev=>prev.filter(m=>!(m.studentId===refId&&m.absenceDate===date&&m.classId===classId)));
      }
    }
  };
  // 강사는 "결석" 대신 "휴가/병가"로 구분합니다 (강사는 무단 결석이 아니라 사전에 알려진 휴가·병가이기 때문).
  const teacherStatusBtns=[
    {s:'present',label:'출석',color:'bg-green-100 text-green-700 border-green-300'},
    {s:'late',label:'지각',color:'bg-yellow-100 text-yellow-700 border-yellow-300'},
    {s:'halfday',label:'반차',color:'bg-cyan-100 text-cyan-700 border-cyan-300'},
    {s:'vacation',label:'휴가',color:'bg-blue-100 text-blue-700 border-blue-300'},
    {s:'sick',label:'병가',color:'bg-pink-100 text-pink-700 border-pink-300'},
    {s:'training',label:'교육/연수',color:'bg-purple-100 text-purple-700 border-purple-300'},
    {s:'other',label:'기타',color:'bg-slate-100 text-slate-600 border-slate-300'},
  ];
  const studentStatusBtns=[
    {s:'present',label:'출석',color:'bg-green-100 text-green-700 border-green-300'},
    {s:'late',label:'지각',color:'bg-yellow-100 text-yellow-700 border-yellow-300'},
    {s:'absent',label:'결석',color:'bg-red-100 text-red-700 border-red-300'},
    {s:'leave',label:'조퇴',color:'bg-orange-100 text-orange-700 border-orange-300'},
    {s:'cancelled',label:'휴강',color:'bg-slate-100 text-slate-600 border-slate-300'},
  ];
  // [19] 반 일괄 휴강 처리 — 모달에서 학생 선택 후 확정 시 휴강+보강 동시 처리
  const batchCancelClass=(cls,classStudents)=>{
    if(classStudents.length===0){alert('이 반에 출석 대상 학생이 없습니다.');return;}
    if(!confirm(`[${cls.name}] ${date} 수업을 일괄 휴강 처리하시겠습니까?\n아래 모달에서 대상 학생을 선택한 후 확정하면 휴강 처리됩니다.`))return;
    // 휴강 처리는 모달 확정 시 선택된 학생만 적용 — 여기서는 모달만 열기
    setBatchMkCls(cls);
    setBatchMkStudents(classStudents);
    setBatchMkSelected(new Set(classStudents.map(s=>s.id)));
    setBatchMkForm({makeupDate:'',startTime:cls.startTime||'',endTime:cls.endTime||'',room:cls.room||''});
    setBatchMkModal(true);
  };
  // 일괄 보강 확정 저장 — 선택된 학생만 휴강 처리 + 보강 등록
  const confirmBatchMakeup=(withSchedule)=>{
    if(batchMkSelected.size===0){alert('휴강 처리할 학생을 한 명 이상 선택하세요.');return;}
    if(withSchedule){
      if(!batchMkForm.makeupDate){alert('보강 날짜를 입력해주세요.');return;}
      if(batchMkForm.startTime&&batchMkForm.endTime&&batchTimeToMin(batchMkForm.endTime)<=batchTimeToMin(batchMkForm.startTime)){alert('종료 시간은 시작 시간보다 늦어야 합니다.');return;}
      const conflicts=batchCheckConflict(batchMkForm.room,batchMkForm.makeupDate,batchMkForm.startTime,batchMkForm.endTime);
      if(conflicts.length>0){
        const ok=confirm(`⚠️ 강의실 시간이 겹칩니다!\n${conflicts.join('\n')}\n\n그래도 등록하시겠습니까?`);
        if(!ok)return;
      }
    }
    const selectedList=batchMkStudents.filter(s=>batchMkSelected.has(s.id));
    // ① 선택된 학생만 휴강 처리
    setAttendance(prev=>{
      const sIds=new Set(selectedList.map(s=>s.id));
      const filtered=prev.filter(a=>!(a.type==='student'&&a.date===date&&a.classId===batchMkCls.id&&sIds.has(a.refId)));
      const newRecs=selectedList.map(s=>({id:genId(),date,type:'student',refId:s.id,status:'cancelled',classId:batchMkCls.id,note:'일괄 휴강'}));
      return[...filtered,...newRecs];
    });
    // ② 선택된 학생만 보강 등록
    setMakeups(prev=>{
      const existingKeys=new Set(prev.map(m=>`${m.studentId}_${m.classId}_${m.absenceDate}`));
      const newMks=selectedList.filter(s=>!existingKeys.has(`${s.id}_${batchMkCls.id}_${date}`))
        .map(s=>({
          id:genId(),studentId:s.id,studentName:s.name,
          classId:batchMkCls.id,className:batchMkCls.name||'',
          absenceDate:date,
          makeupDate:withSchedule?batchMkForm.makeupDate:'',
          makeupStartTime:withSchedule?batchMkForm.startTime:'',
          makeupEndTime:withSchedule?batchMkForm.endTime:'',
          room:withSchedule?batchMkForm.room:'',
          status:withSchedule?'pending':'unscheduled',
          note:'휴강으로 인한 자동 보강 등록'
        }));
      return[...prev,...newMks];
    });
    setBatchMkModal(false);
    const skipped=batchMkStudents.length-selectedList.length;
    alert(`휴강 처리 및 보강 등록 완료!\n▪ 처리: ${selectedList.length}명${skipped>0?`\n▪ 제외: ${skipped}명 (출결 변경 없음)`:''}`);
  };
  // 반 구분은 더 이상 c1~c6로 하드코딩하지 않고, 실제 수업관리(classes)에 등록된 수업을 그대로 사용합니다.
  // → 나중에 수업관리에서 새 반을 추가/삭제해도 출결 화면에 자동으로 반영됩니다.
  const groupPalette=['bg-yellow-50 text-yellow-700','bg-blue-50 text-blue-700','bg-indigo-50 text-indigo-700','bg-purple-50 text-purple-700','bg-red-50 text-red-700','bg-green-50 text-green-700','bg-pink-50 text-pink-700','bg-teal-50 text-teal-700'];
  // 학생이 여러 수업(enrolledClasses)을 듣고 있으면, 수업마다 한 줄씩 따로 나와서 수업별로 독립적으로 출결을 체크할 수 있습니다.
  const unassignedStudents=students.filter(s=>!(s.enrolledClasses&&s.enrolledClasses.length));
  return<div className="space-y-5">
    <div className="flex items-center justify-between flex-wrap gap-3">
      <div><h1 className="text-2xl font-bold text-slate-900">출결 관리</h1><p className="text-slate-600 text-sm mt-1">출석 {presentCnt}명 · {secondaryLabel} {secondaryCnt}명</p></div>
      <input className={inp} type="date" value={date} onChange={e=>setDate(e.target.value)} style={{width:'160px'}}/>
    </div>
    {/* [2][6] 경고 배너: 학생 탭일 때만, 해제 안 했을 때만 표시 */}
    {tab==='student'&&liveWarnIds.length>0&&<div className="flex items-center justify-between gap-3 px-4 py-3 bg-orange-50 border border-orange-200 rounded-xl">
      <div className="flex items-center gap-2 text-sm text-orange-700">
        <span className="font-bold">⚠️ 결석경고 학생 {liveWarnIds.length}명</span>
        <span className="text-xs text-orange-500">({showWarnOnly?'경고 학생만 표시 중':'전체 학생 표시 중'})</span>
      </div>
      <button onClick={()=>setShowWarnOnly(v=>!v)} className="text-xs px-3 py-1 rounded-full border border-orange-300 bg-white text-orange-700 hover:bg-orange-100 font-medium">{showWarnOnly?'전체보기':'경고만 보기'}</button>
    </div>}
    <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
      <div className="flex gap-2 p-4 border-b border-gray-100">
        <button className={`tab-btn ${tab==='teacher'?'active':''}`} onClick={()=>setTab('teacher')}>👨‍🏫 강사 출결</button>
        <button className={`tab-btn ${tab==='student'?'active':''}`} onClick={()=>setTab('student')}>🎓 학생 출결</button>
      </div>
      {tab==='student'&&<div className="flex items-center gap-2 px-4 pt-4 pb-3 mb-1 border-b border-gray-100 flex-wrap">
        <span className="text-xs font-semibold text-slate-600 shrink-0">반별로 보기</span>
        <select className={inp} style={{width:'220px'}} value={classFilter} onChange={e=>setClassFilter(e.target.value)}>
          {!(role==='teacher'&&loggedInTeacherId)&&<option value="all">전체 반 보기</option>}
          {(role==='teacher'&&loggedInTeacherId?classes.filter(c=>c.teacherId===loggedInTeacherId&&!(c.closeDate&&c.closeDate<=today())):classes.filter(c=>!(c.closeDate&&c.closeDate<=today()))).sort((a,b)=>a.name.localeCompare(b.name,'ko')).map(c=><option key={c.id} value={c.id}>{c.name}</option>)}
          {!(role==='teacher'&&loggedInTeacherId)&&unassignedStudents.length>0&&<option value="unassigned">기타 (반 미배정)</option>}
        </select>
        <input className={inp} placeholder="이름 검색..." value={nameSearch} onChange={e=>setNameSearch(e.target.value)} style={{width:'140px'}}/>
        {nameSearch&&<button onClick={()=>setNameSearch('')} className="text-xs text-slate-400 hover:text-slate-600">✕</button>}
      </div>}
      {tab==='teacher'&&<div className="overflow-x-auto overflow-y-auto tbl-scroll" style={{maxHeight:'calc(100vh - 280px)'}}><table className="w-full text-sm app-table">
        <thead className="bg-[#f1f5f9] text-slate-600 text-xs"><tr>
          <th className="px-4 py-3 text-left font-medium cursor-pointer select-none" style={{width:'110px',width:'110px'}} onClick={()=>attTeaSortField('name')}>이름{attTeaArrow('name')}</th>
          <th className="px-4 py-3 text-left font-medium" style={{width:'200px'}}>담당 과정</th>
          <th className="px-4 py-3 text-left font-medium" style={{width:'520px'}}>출결 입력</th>
          <th className="px-4 py-3 text-left font-medium cursor-pointer select-none" style={{width:'130px'}} onClick={()=>attTeaSortField('status')}>현재 상태{attTeaArrow('status')}</th>
          <th className="px-4 py-3 text-left font-medium" style={{width:'180px'}}>비고</th>
        </tr></thead>
        <tbody>{[...(role==='teacher'&&loggedInTeacherId?teachers.filter(t=>t.id===loggedInTeacherId):teachers.filter(t=>{
          if(t.status==='active'||t.status==='inactive')return true;
          if(t.status==='resigned'&&t.resignedAt){
            // 퇴직일 이전 1년 ~ 퇴직당일까지의 날짜를 선택한 경우에만 표시
            const d=new Date(t.resignedAt);d.setFullYear(d.getFullYear()-1);
            return date<=t.resignedAt&&date>=d.toISOString().split('T')[0];
          }
          return false;
        }))].sort((a,b)=>{
          // 퇴직 강사는 항상 맨 아래
          if(a.status==='resigned'&&b.status!=='resigned')return 1;
          if(b.status==='resigned'&&a.status!=='resigned')return -1;
          if(attTeaSortKey==='status'){
            const sa=getStatus('teacher',a.id)?.status||'';const sb=getStatus('teacher',b.id)?.status||'';
            return attTeaSortDir==='asc'?sa.localeCompare(sb,'ko'):sb.localeCompare(sa,'ko');
          }
          return attTeaSortDir==='asc'?a.name.localeCompare(b.name,'ko'):b.name.localeCompare(a.name,'ko');
        }).map(p=>{
          const inactiveLabels={halfday:'반차',vacation:'휴가',sick:'병가',training:'교육/연수',other:p.inactiveNote||'기타'};
          const inactiveColors={halfday:'bg-cyan-100 text-cyan-700',vacation:'bg-blue-100 text-blue-700',sick:'bg-pink-100 text-pink-700',training:'bg-purple-100 text-purple-700',other:'bg-slate-100 text-slate-600'};
          const isResigned=p.status==='resigned';
          const isInactive=p.status==='inactive';
          // 뱃지는 선택한 날짜가 비활동 기간 안에 있을 때만 표시
          const inInactivePeriod=isInactive&&p.inactiveStartDate&&p.inactiveEndDate&&date>=p.inactiveStartDate&&date<=p.inactiveEndDate;
          const badge=isResigned?'퇴직':inInactivePeriod?(inactiveLabels[p.inactiveReason]||'비활동'):null;
          const badgeColor=isResigned?'bg-red-100 text-red-600':(inInactivePeriod?(inactiveColors[p.inactiveReason]||'bg-amber-100 text-amber-700'):null);
          return<AttRow key={p.id} person={p} type="teacher" cur={getStatus('teacher',p.id)} statusBtns={isResigned?[]:teacherStatusBtns} setStatus={setStatus} setAttendance={setAttendance} onAddMakeup={null} hasMakeup={false} teacherBadge={badge} teacherBadgeColor={badgeColor}/>;
        })}</tbody>
      </table></div>}
      {tab==='student'&&<div className="overflow-x-auto overflow-y-auto tbl-scroll" style={{maxHeight:'calc(100vh - 280px)'}}><table className="w-full text-sm app-table">
        <thead className="bg-[#f1f5f9] text-slate-600 text-xs"><tr>
          <th className="px-4 py-3 text-left font-medium cursor-pointer select-none" style={{width:'110px',width:'110px'}} onClick={()=>attStuSortField('name')}>이름{attStuArrow('name')}</th>
          <th className="px-4 py-3 text-left font-medium" style={{width:'180px'}}>레벨</th>
          <th className="px-4 py-3 text-left font-medium" style={{width:'380px'}}>출결 입력</th>
          <th className="px-4 py-3 text-left font-medium cursor-pointer select-none" style={{width:'130px'}} onClick={()=>attStuSortField('status')}>현재 상태{attStuArrow('status')}</th>
          <th className="px-4 py-3 text-left font-medium" style={{width:'180px'}}>비고</th>
        </tr></thead>
        <tbody>
          {(role==='teacher'&&loggedInTeacherId?classes.filter(c=>c.teacherId===loggedInTeacherId&&!(c.closeDate&&c.closeDate<=today())):classes.filter(c=>!(c.closeDate&&c.closeDate<=today()))).sort((a,b)=>a.name.localeCompare(b.name,'ko')).filter(c=>classFilter==='all'?true:classFilter==='unassigned'?false:c.id===classFilter).map((c,idx)=>{
            const groupStudentsAll=students.filter(s=>{
              if(!(s.enrolledClasses||[]).includes(c.id))return false;
              if(nameSearch&&!s.name.includes(nameSearch))return false;
              if(s.status!=='withdrawn')return !s.joinDate||s.joinDate<=today();
              // 퇴원생: 출결 조회 날짜(date)가 퇴원일 이하이면 표시 (다니던 시기 데이터 유지)
              const h=s.enrollmentHistory||[];
              const lastLeave=(h[h.length-1]||{}).leaveDate||'';
              return !!lastLeave&&date<=lastLeave;
            });
            const groupStudents=showWarnOnly&&liveWarnIds.length?groupStudentsAll.filter(s=>liveWarnIds.includes(s.id)):groupStudentsAll;
            if(groupStudents.length===0)return null;
            return<React.Fragment key={c.id}>
              <tr><td colSpan={5} className={`group-header ${groupPalette[idx%groupPalette.length]}`}>
                <div className="flex items-center justify-between">
                  <span>🎹 {c.name} ({groupStudents.length}{showWarnOnly?` / 전체 ${groupStudentsAll.length}`:''}명)</span>
                  <button onClick={()=>batchCancelClass(c,groupStudents)} className="text-xs px-2 py-0.5 rounded bg-white/70 text-slate-600 hover:bg-white border border-slate-300 ml-2 shrink-0">일괄 휴강</button>
                </div>
              </td></tr>
              {[...groupStudents].sort((a,b)=>{
                if(attStuSortKey==='status'){
                  const sa=getStatus('student',a.id,c.id)?.status||'';const sb=getStatus('student',b.id,c.id)?.status||'';
                  return attStuSortDir==='asc'?sa.localeCompare(sb,'ko'):sb.localeCompare(sa,'ko');
                }
                return attStuSortDir==='asc'?a.name.localeCompare(b.name,'ko'):b.name.localeCompare(a.name,'ko');
              }).map(p=>{const _mk=(makeups||[]).find(m=>m.studentId===p.id&&m.absenceDate===date&&m.classId===c.id);return<AttRow key={p.id+'-'+c.id} person={p} type="student" classId={c.id} cur={getStatus('student',p.id,c.id)} statusBtns={studentStatusBtns} setStatus={setStatus} setAttendance={setAttendance} isWarn={!!(liveWarnIds.includes(p.id))} isWithdrawn={p.status==='withdrawn'} onAddMakeup={()=>{const st=students.find(s=>s.id===p.id);const cl=classes.find(x=>x.id===c.id);if(st&&cl&&!_mk){setMakeups(prev=>[...prev,{id:genId(),studentId:p.id,studentName:st.name,classId:c.id,className:cl.name,absenceDate:date,makeupDate:'',status:'unscheduled',note:''}]);}}} hasMakeup={!!_mk} onCancelMakeup={_mk?()=>setMakeups(prev=>prev.filter(m=>m.id!==_mk.id)):null}/>;})}
            </React.Fragment>;
          })}
          {(classFilter==='all'||classFilter==='unassigned')&&unassignedStudents.length>0&&(()=>{
            const dispUnassigned=(showWarnOnly&&liveWarnIds.length?unassignedStudents.filter(s=>liveWarnIds.includes(s.id)):unassignedStudents).filter(s=>!nameSearch||s.name.includes(nameSearch));
            if(dispUnassigned.length===0)return null;
            return<React.Fragment>
              <tr><td colSpan={5} className="group-header bg-[#f1f5f9] text-slate-700">
                🎹 기타 (반 미배정) ({dispUnassigned.length}{showWarnOnly?` / 전체 ${unassignedStudents.length}`:''}명)
              </td></tr>
              {[...dispUnassigned].sort((a,b)=>a.name.localeCompare(b.name,'ko')).map(p=><AttRow key={p.id} person={p} type="student" classId={null} cur={getStatus('student',p.id,null)} statusBtns={studentStatusBtns} setStatus={setStatus} setAttendance={setAttendance} isWarn={!!(liveWarnIds.includes(p.id))} onAddMakeup={null} hasMakeup={false}/>)}
            </React.Fragment>;
          })()}
          {classFilter!=='all'&&classFilter!=='unassigned'&&students.filter(s=>s.status!=='withdrawn'&&(!s.joinDate||s.joinDate<=today())&&(s.enrolledClasses||[]).includes(classFilter)).length===0&&
            <tr><td colSpan={5} className="text-center py-12 text-slate-600">이 반에 등록된 학생이 없습니다</td></tr>}
        </tbody>
      </table></div>}
    </div>

    {/* 일괄휴강 보강 일정 입력 모달 */}
    {batchMkModal&&batchMkCls&&<div className="modal-overlay" onClick={e=>e.target===e.currentTarget&&setBatchMkModal(false)}>
      <div className="modal-box shadow-2xl" style={{maxWidth:'480px'}}>
        <div className="flex items-center justify-between p-5 border-b">
          <div>
            <h3 className="text-lg font-bold text-slate-900">📅 일괄 보강 일정 등록</h3>
            <p className="text-sm text-slate-500 mt-0.5">[{batchMkCls.name}] 휴강일: {date} · 전체 {batchMkStudents.length}명</p>
          </div>
          <button onClick={()=>setBatchMkModal(false)} className="w-8 h-8 flex items-center justify-center rounded-full hover:bg-gray-100 text-slate-600 text-xl">&times;</button>
        </div>
        <div className="p-5 space-y-4">
          <div className="bg-blue-50 border border-blue-200 rounded-xl p-3 text-sm text-blue-800">
            체크된 학생만 <strong>휴강 처리 + 보강 등록</strong>이 됩니다.<br/>
            체크 해제 시 해당 학생은 출결 변경 없이 제외됩니다. 날짜를 입력하지 않으면 "일정 미정"으로 등록됩니다.
          </div>
          <div className="bg-slate-50 rounded-xl p-3">
            <div className="flex items-center justify-between mb-2">
              <div className="text-xs font-semibold text-slate-500">대상 학생 ({batchMkSelected.size}/{batchMkStudents.length}명 선택)</div>
              <button className="text-xs text-blue-600 hover:underline" onClick={()=>setBatchMkSelected(prev=>prev.size===batchMkStudents.length?new Set():new Set(batchMkStudents.map(s=>s.id)))}>
                {batchMkSelected.size===batchMkStudents.length?'전체 해제':'전체 선택'}
              </button>
            </div>
            <div className="flex flex-wrap gap-1.5 max-h-32 overflow-y-auto">
              {batchMkStudents.map(s=><label key={s.id} className={`flex items-center gap-1 text-xs px-2 py-1 rounded-lg border cursor-pointer select-none ${batchMkSelected.has(s.id)?'bg-blue-50 border-blue-300 text-blue-800':'bg-white border-slate-200 text-slate-400 line-through'}`}>
                <input type="checkbox" className="w-3 h-3" checked={batchMkSelected.has(s.id)} onChange={()=>setBatchMkSelected(prev=>{const n=new Set(prev);n.has(s.id)?n.delete(s.id):n.add(s.id);return n;})}/>
                {s.name}
              </label>)}
            </div>
          </div>
          <Field label="보강 날짜">
            <input className={inp} type="date" value={batchMkForm.makeupDate} onChange={e=>setBatchMkForm(f=>({...f,makeupDate:e.target.value}))}/>
          </Field>
          <div className="grid grid-cols-2 gap-3">
            <Field label="시작 시간">
              <input className={inp} type="time" value={batchMkForm.startTime} onChange={e=>setBatchMkForm(f=>({...f,startTime:e.target.value}))}/>
            </Field>
            <Field label="종료 시간">
              <input className={inp} type="time" value={batchMkForm.endTime} onChange={e=>setBatchMkForm(f=>({...f,endTime:e.target.value}))}/>
            </Field>
          </div>
          <Field label="강의실">
            <select className={inp} value={batchMkForm.room} onChange={e=>setBatchMkForm(f=>({...f,room:e.target.value}))}>
              <option value="">선택 안 함</option>
              {batchMkRooms.map(r=><option key={r} value={r}>{r}</option>)}
            </select>
          </Field>
          <div className="flex gap-2 justify-end pt-1">
            <button className={btn('gray')} onClick={()=>confirmBatchMakeup(false)}>일정 미정으로 등록</button>
            <button className={btn('indigo')} onClick={()=>confirmBatchMakeup(true)}>일정 포함 등록</button>
          </div>
        </div>
      </div>
    </div>}
  </div>;
}

// ── 공지사항 관리 (학부모 발송 기능) ────────────────────────────────────────
function NoticeManagement({notices,setNotices,students,classes,academyName,baseUrl}){
  const[modalOpen,setModalOpen]=useState(false);
  const[detailNotice,setDetailNotice]=useState(null);
  const[sendNotice,setSendNotice]=useState(null);
  const[editTarget,setEditTarget]=useState(null);
  const[confirmId,setConfirmId]=useState(null);
  const[filterCat,setFilterCat]=useState('전체');
  const[selectedContacts,setSelectedContacts]=useState([]);
  const[form,setForm]=useState({date:'',category:'공지',title:'',content:'',target:'전체',important:false,posterImg:'',attachments:[]});
  const[noticeImgModal,setNoticeImgModal]=useState(null);
  const handlePosterUpload=e=>{
    const file=e.target.files&&e.target.files[0];
    if(!file)return;
    if(file.size>5*1024*1024){alert('파일이 5MB를 초과합니다.');return;}
    const reader=new FileReader();
    reader.onload=ev=>setForm(f=>({...f,posterImg:ev.target.result}));
    reader.readAsDataURL(file);
    e.target.value='';
  };
  const handleAttachUpload=e=>{
    const files=Array.from(e.target.files||[]);
    files.forEach(file=>{
      if(file.size>5*1024*1024){alert(`"${file.name}" 파일이 5MB를 초과합니다.`);return;}
      const reader=new FileReader();
      reader.onload=ev=>setForm(f=>({...f,attachments:[...(f.attachments||[]),{name:file.name,dataUrl:ev.target.result,size:file.size}]}));
      reader.readAsDataURL(file);
    });
    e.target.value='';
  };
  const catColors={공지:'bg-blue-100 text-blue-700',긴급:'bg-red-100 text-red-700',행사:'bg-green-100 text-green-700',안내:'bg-gray-100 text-slate-700'};

  // 공지 대상에 따른 학부모 목록 필터 (퇴원생·미래등록 제외)
  const getTargetParents=(target)=>{
    let filtered=students.filter(s=>s.status!=='withdrawn'&&(!s.joinDate||s.joinDate<=today()));
    if(target&&target!=='전체'){
      // 수업명이 target과 일치하는 수업의 ID 목록 조회
      const targetClassIds=(classes||[]).filter(c=>c.name===target).map(c=>c.id);
      if(targetClassIds.length>0){
        filtered=filtered.filter(s=>(s.enrolledClasses||[]).some(cid=>targetClassIds.includes(cid)));
      }else{
        // 일치하는 수업이 없으면 빈 배열 반환
        filtered=[];
      }
    }
    // 성인 학생은 학부모 연락처가 없으므로 본인 연락처(phone)를 대신 사용합니다.
    return filtered.filter(s=>s.grade==='성인'?s.phone:(s.parentName&&s.parentPhone))
      .map(s=>s.grade==='성인'?{id:s.id,name:s.name,phone:s.phone,student:s.name}:{id:s.id,name:s.parentName,phone:s.parentPhone,student:s.name});
  };

  const shareNoticeLink=n=>{
    const payload={type:'notice',academy:academyName||'우리 학원',
      notice:{title:n.title,content:n.content,category:n.category,date:n.date,important:n.important}};
    const link=`${baseUrl||'학부모앱.html'}#${encodeShare(payload)}`;
    copyToClipboard(link,`'${n.title}' 공지 링크가 복사되었습니다! 카카오톡에 붙여넣기 하세요.`);
  };
  const openSend=n=>{
    setSendNotice(n);
    const parents=getTargetParents(n.target);
    setSelectedContacts(parents.map(p=>p.phone).filter(p=>!(n.sentContacts||[]).includes(p)));
  };
  const confirmSend=()=>{
    setNotices(prev=>prev.map(n=>n.id===sendNotice.id?{...n,sentContacts:[...new Set([...(n.sentContacts||[]),...selectedContacts])],sentDate:today()}:n));
    setSendNotice(null);
    setSelectedContacts([]);
    alert(`✅ ${selectedContacts.length}명의 학부모에게 발송 처리되었습니다.`);
  };
  const openAdd=()=>{setEditTarget(null);setForm({date:today(),category:'공지',title:'',content:'',target:'전체',important:false,posterImg:'',attachments:[]});setModalOpen(true);};
  const openEdit=n=>{setEditTarget(n);setForm({...n,posterImg:n.posterImg||'',attachments:n.attachments||[]});setModalOpen(true);};
  const save=()=>{
    if(!form.title||!form.content){alert('제목과 내용은 필수입니다.');return;}
    if(editTarget)setNotices(prev=>prev.map(n=>n.id===editTarget.id?{...form,id:n.id,sentContacts:n.sentContacts||[],sentDate:n.sentDate||''}:n));
    else setNotices(prev=>[{...form,id:genId(),sentContacts:[],sentDate:''},...prev]);
    setModalOpen(false);
  };
  const del=id=>{setNotices(prev=>prev.filter(n=>n.id!==id));setConfirmId(null);setDetailNotice(null);};
  const filtered=notices.filter(n=>filterCat==='전체'||n.category===filterCat).sort((a,b)=>b.date.localeCompare(a.date));

  return<div className="space-y-5">
    <div className="flex items-center justify-between">
      <div><h1 className="text-2xl font-bold text-slate-900">공지사항 관리</h1><p className="text-slate-600 text-sm mt-1">학부모 공지 · 긴급 알림 · 행사 · 안내</p></div>
      <button className={btn('indigo')} onClick={openAdd}>+ 공지 작성</button>
    </div>
    <div className="flex gap-2 items-center">
      {['전체','공지','긴급'].map(c=><button key={c} onClick={()=>setFilterCat(c)} className={`tab-btn py-1.5 text-sm ${filterCat===c?'active':''}`}>{c}</button>)}
      <button onClick={()=>setFilterCat('행사')} className={`tab-btn py-1.5 text-sm ${filterCat==='행사'?'active':''}`}>행사</button>
      <span className="text-slate-300 font-bold select-none">·</span>
      <button onClick={()=>setFilterCat('안내')} className={`tab-btn py-1.5 text-sm ${filterCat==='안내'?'active':''}`}>안내</button>
    </div>
    <div className="space-y-3">{filtered.map(n=><div key={n.id} className={`bg-white rounded-2xl border shadow-sm overflow-hidden ${n.important?'border-red-200':'border-gray-100'}`}>
      <div className="flex items-center gap-4 p-4">
        <div className="shrink-0 flex items-center gap-2">
          {n.important&&<span className="text-red-500">🔴</span>}
          <span className={`badge ${catColors[n.category]||'bg-gray-100'}`}>{n.category}</span>
        </div>
        <div className="flex-1 min-w-0 cursor-pointer" onClick={()=>setDetailNotice(n)}>
          <div className="font-semibold text-slate-900 truncate">{n.title}</div>
          <div className="text-sm text-slate-600 truncate mt-0.5">{n.content}</div>
          {n.posterImg&&<div className="mt-2"><img src={n.posterImg} alt="포스터" className="h-16 rounded-lg object-cover border border-gray-200 cursor-pointer" onClick={e=>{e.stopPropagation();setNoticeImgModal(n.posterImg);}}/></div>}
          {(n.attachments||[]).length>0&&<div className="mt-1 flex gap-1 flex-wrap">{n.attachments.map((a,i)=><a key={i} href={a.dataUrl} download={a.name} className="text-xs px-2 py-0.5 rounded bg-blue-50 text-blue-600 hover:bg-blue-100">📎 {a.name}</a>)}</div>}
        </div>
        <div className="shrink-0 text-right flex flex-col items-end gap-1">
          <div className="text-xs text-slate-600">{fDate(n.date)}</div>
          {(n.sentContacts||[]).length>0?
            <span className="badge bg-green-100 text-green-700 text-xs">✅ {n.sentContacts.length}명 발송완료</span>:
            <span className="badge bg-gray-100 text-slate-600 text-xs">미발송</span>}
          <button onClick={()=>openSend(n)} className="text-xs px-3 py-1 rounded-lg bg-blue-50 text-blue-600 hover:bg-blue-100 mt-1">📱 학부모 발송</button>
          <button onClick={()=>shareNoticeLink(n)} className="text-xs px-3 py-1 rounded-lg bg-purple-50 text-purple-600 hover:bg-purple-100 mt-1">🔗 링크 복사</button>
        </div>
      </div>
    </div>)}
    {filtered.length===0&&<div className="bg-white rounded-2xl border border-gray-100 p-16 text-center"><div className="text-4xl mb-3">📢</div><div className="text-slate-600">등록된 공지사항이 없습니다</div></div>}
    </div>

    {/* 상세 모달 */}
    {detailNotice&&<div className="modal-overlay" onClick={e=>e.target===e.currentTarget&&setDetailNotice(null)}>
      <div className="modal-box modal-wide shadow-2xl">
        <div className="flex items-center justify-between p-5 border-b">
          <div className="flex items-center gap-3">
            {detailNotice.important&&<span className="text-red-500">🔴</span>}
            <span className={`badge ${catColors[detailNotice.category]||'bg-gray-100'}`}>{detailNotice.category}</span>
            <h3 className="text-lg font-bold text-slate-900">{detailNotice.title}</h3>
          </div>
          <button onClick={()=>setDetailNotice(null)} className="w-8 h-8 flex items-center justify-center rounded-full hover:bg-gray-100 text-slate-600 text-xl">&times;</button>
        </div>
        <div className="p-5">
          <div className="flex gap-4 text-sm text-slate-600 mb-4"><span>📅 {fDate(detailNotice.date)}</span><span>👥 대상: {detailNotice.target}</span></div>
          <div className="bg-[#f1f5f9] rounded-xl p-4 text-slate-800 whitespace-pre-wrap leading-relaxed">{detailNotice.content}</div>
          {detailNotice.posterImg&&<div className="mt-4"><div className="text-xs font-semibold text-slate-600 mb-2">포스터 이미지</div><img src={detailNotice.posterImg} alt="포스터" className="max-w-full rounded-xl border border-gray-200 cursor-pointer hover:opacity-90" onClick={()=>setNoticeImgModal(detailNotice.posterImg)}/></div>}
          {(detailNotice.attachments||[]).length>0&&<div className="mt-3"><div className="text-xs font-semibold text-slate-600 mb-1">첨부파일</div><div className="flex flex-wrap gap-2">{detailNotice.attachments.map((a,i)=><a key={i} href={a.dataUrl} download={a.name} className="text-sm px-3 py-1.5 rounded-lg bg-blue-50 text-blue-700 hover:bg-blue-100 font-medium">📎 {a.name}</a>)}</div></div>}
          {(detailNotice.sentContacts||[]).length>0&&<div className="mt-3 text-sm text-green-600">✅ {detailNotice.sentContacts.length}명 학부모 발송 완료 ({fDate(detailNotice.sentDate)})</div>}
          <div className="flex justify-between mt-5">
            <div className="flex gap-2">
              <button className={btn('gray')} onClick={()=>{setDetailNotice(null);openEdit(detailNotice);}}>수정</button>
              <button className={btn('red')} onClick={()=>setConfirmId(detailNotice.id)}>삭제</button>
            </div>
            <div className="flex gap-2">
              <button className={btn('blue')} onClick={()=>{setDetailNotice(null);openSend(detailNotice);}}>📱 학부모 발송</button>
              <button className={btn('gray')} onClick={()=>setDetailNotice(null)}>닫기</button>
            </div>
          </div>
        </div>
      </div>
    </div>}

    {/* 학부모 발송 모달 */}
    {sendNotice&&<div className="modal-overlay" onClick={e=>e.target===e.currentTarget&&setSendNotice(null)}>
      <div className="modal-box modal-wide shadow-2xl">
        <div className="flex items-center justify-between p-5 border-b">
          <h3 className="text-lg font-bold text-slate-900">📱 학부모 발송 확인</h3>
          <button onClick={()=>setSendNotice(null)} className="w-8 h-8 flex items-center justify-center rounded-full hover:bg-gray-100 text-slate-600 text-xl">&times;</button>
        </div>
        <div className="p-5">
          <div className="bg-[#f1f5f9] rounded-xl p-4 mb-4">
            <div className="text-sm font-semibold text-[#0f172a] mb-1">발송할 공지</div>
            <div className="text-sm text-slate-800 font-medium">{sendNotice.title}</div>
            <div className="text-xs text-slate-600 mt-1 line-clamp-2">{sendNotice.content}</div>
          </div>
          <div className="flex items-center justify-between mb-3">
            <div className="text-sm font-semibold text-slate-800">발송 대상 학부모 선택</div>
            <button className="text-xs text-[#1e3a5f] hover:underline" onClick={()=>{
              const parents=getTargetParents(sendNotice.target);
              setSelectedContacts(parents.map(p=>p.phone));
            }}>전체 선택</button>
          </div>
          <div className="border border-gray-200 rounded-xl overflow-hidden max-h-56 overflow-y-auto">
            {getTargetParents(sendNotice.target).map(p=>{
              const isSent=(sendNotice.sentContacts||[]).includes(p.phone);
              const isSelected=selectedContacts.includes(p.phone);
              return<div key={p.id} className={`flex items-center gap-3 p-3 border-b border-gray-50 ${isSent?'opacity-50':''}`}>
                <input type="checkbox" checked={isSelected} disabled={isSent} onChange={e=>{
                  if(e.target.checked)setSelectedContacts(prev=>[...prev,p.phone]);
                  else setSelectedContacts(prev=>prev.filter(x=>x!==p.phone));
                }} className="w-4 h-4"/>
                <div className="flex-1">
                  <span className="text-sm font-semibold text-slate-900">{p.name}</span>
                  <span className="text-xs text-slate-600 ml-2">({p.student} 학부모)</span>
                </div>
                <span className="text-sm text-slate-700">{p.phone}</span>
                {isSent&&<span className="badge bg-green-100 text-green-600 text-xs">발송완료</span>}
              </div>;
            })}
          </div>
          <div className="mt-3 text-xs text-slate-600">※ 실제 문자 발송은 별도 SMS 서비스 연동이 필요합니다. 이 버튼은 발송 현황을 기록합니다.</div>
          <div className="flex justify-end gap-3 mt-4">
            <button className={btn('blue')} onClick={confirmSend} disabled={selectedContacts.length===0}>
              📱 {selectedContacts.length}명에게 발송 완료 처리
            </button>
            <button className={btn('gray')} onClick={()=>setSendNotice(null)}>취소</button>
          </div>
        </div>
      </div>
    </div>}

    <Modal open={modalOpen} onClose={()=>setModalOpen(false)} title={editTarget?'공지 수정':'공지 작성'} wide>
      <div className="grid grid-cols-2 gap-x-4">
        <Field label="날짜" required><input className={inp} type="date" value={form.date} onChange={e=>setForm({...form,date:e.target.value})}/></Field>
        <Field label="카테고리"><select className={inp} value={form.category} onChange={e=>setForm({...form,category:e.target.value})}>{['공지','긴급','행사','안내'].map(c=><option key={c} value={c}>{c}</option>)}</select></Field>
      </div>
      <Field label="제목" required><input className={inp} value={form.title} onChange={e=>setForm({...form,title:e.target.value})}/></Field>
      <Field label="내용" required><textarea className={inp} rows={5} value={form.content} onChange={e=>setForm({...form,content:e.target.value})}/></Field>
      <div className="grid grid-cols-2 gap-x-4">
        <Field label="공지 대상"><select className={inp} value={form.target} onChange={e=>setForm({...form,target:e.target.value})}>
          <option value="전체">전체 학부모</option>
          {(classes||[]).filter(c=>!(c.closeDate&&c.closeDate<=today())).sort((a,b)=>a.name.localeCompare(b.name,'ko')).map(c=><option key={c.id} value={c.name}>{c.name}</option>)}
        </select></Field>
        <Field label="중요 공지"><div className="flex items-center gap-2 mt-2">
          <input type="checkbox" id="imp" checked={form.important} onChange={e=>setForm({...form,important:e.target.checked})} className="w-4 h-4"/>
          <label htmlFor="imp" className="text-sm text-slate-700">🔴 중요 표시</label>
        </div></Field>
      </div>
      <Field label="포스터 이미지 (선택)">
        <div className="flex items-center gap-3">
          <label className="cursor-pointer px-3 py-1.5 rounded-lg bg-slate-100 hover:bg-slate-200 text-slate-700 text-sm font-medium border border-slate-300">
            이미지 선택
            <input type="file" accept="image/*" className="hidden" onChange={handlePosterUpload}/>
          </label>
          {form.posterImg&&<div className="flex items-center gap-2">
            <img src={form.posterImg} alt="미리보기" className="h-14 w-14 object-cover rounded-lg border border-gray-200"/>
            <button className="text-xs text-red-500 hover:text-red-700 font-medium" onClick={()=>setForm(f=>({...f,posterImg:''}))}>제거</button>
          </div>}
          {!form.posterImg&&<span className="text-xs text-slate-400">최대 5MB · JPG, PNG, GIF</span>}
        </div>
      </Field>
      <Field label="첨부파일 (선택)">
        <div>
          <label className="cursor-pointer inline-flex items-center gap-1 px-3 py-1.5 rounded-lg bg-slate-100 hover:bg-slate-200 text-slate-700 text-sm font-medium border border-slate-300">
            📎 파일 추가
            <input type="file" multiple className="hidden" onChange={handleAttachUpload}/>
          </label>
          {(form.attachments||[]).length>0&&<div className="flex flex-wrap gap-2 mt-2">{form.attachments.map((a,i)=><div key={i} className="flex items-center gap-1 px-2 py-1 rounded-lg bg-blue-50 border border-blue-200 text-sm text-blue-700"><span>📎 {a.name}</span><button className="text-red-400 hover:text-red-600 ml-1 font-bold" onClick={()=>setForm(f=>({...f,attachments:f.attachments.filter((_,j)=>j!==i)}))} title="제거">×</button></div>)}</div>}
        </div>
      </Field>
      <div className="flex justify-end gap-3 mt-2"><button className={btn('indigo')} onClick={save}>저장</button><button className={btn('gray')} onClick={()=>setModalOpen(false)}>취소</button></div>
    </Modal>
    {noticeImgModal&&<Modal open={!!noticeImgModal} onClose={()=>setNoticeImgModal(null)} title="포스터 이미지" wide>
      <div className="flex justify-center"><img src={noticeImgModal} alt="포스터 전체" className="max-w-full max-h-[70vh] rounded-xl border border-gray-200 object-contain"/></div>
      <div className="flex justify-end mt-3"><button className={btn('gray')} onClick={()=>setNoticeImgModal(null)}>닫기</button></div>
    </Modal>}
    <Confirm open={!!confirmId} msg="이 공지를 삭제하시겠습니까?" onYes={()=>del(confirmId)} onNo={()=>setConfirmId(null)}/>
  </div>;
}

// ── 연습영상 관리 (비공개 + 코멘트 후 학부모 발송) ───────────────────────────
function VideoManagement({videos,setVideos,students,teachers,academyName,baseUrl}){
  const[modalOpen,setModalOpen]=useState(false);
  const[commentModal,setCommentModal]=useState(null);
  const[sendModal,setSendModal]=useState(null);
  const[editTarget,setEditTarget]=useState(null);
  const[confirmId,setConfirmId]=useState(null);
  const[filterStudent,setFilterStudent]=useState('');
  const[commentText,setCommentText]=useState('');
  const[commentTeacher,setCommentTeacher]=useState('');
  const[form,setForm]=useState({studentId:'',studentName:'',subject:'',title:'',date:'',filePath:'',_fileName:'',description:''});
  const[dragOver,setDragOver]=useState(false);
  const videoFileRef=useRef(null);

  const handleVideoFile=file=>{
    if(!file)return;
    if(!file.type.startsWith('video/')&&!file.type.startsWith('image/')){alert('영상 또는 사진 파일만 업로드 가능합니다.');return;}
    const url=URL.createObjectURL(file);
    setForm(f=>({...f,filePath:url,_fileName:file.name,_fileType:file.type}));
  };

  const openAdd=()=>{setEditTarget(null);setForm({studentId:'',studentName:'',subject:'',title:'',date:today(),filePath:'',_fileName:'',description:''});setModalOpen(true);};
  const openEdit=v=>{setEditTarget(v);setForm({...v,_fileName:v._fileName||''});setModalOpen(true);};
  const save=()=>{
    if(!form.studentId||!form.title){alert('학생과 제목은 필수입니다.');return;}
    const st=students.find(s=>s.id===form.studentId);
    const base={teacherComment:'',commentDate:'',commentTeacher:'',sentToParent:false,sentDate:''};
    const data={...(editTarget?{teacherComment:editTarget.teacherComment,commentDate:editTarget.commentDate,commentTeacher:editTarget.commentTeacher,sentToParent:editTarget.sentToParent,sentDate:editTarget.sentDate}:base),...form,studentName:st?.name||form.studentName};
    if(editTarget)setVideos(prev=>prev.map(v=>v.id===editTarget.id?{...data,id:v.id}:v));
    else setVideos(prev=>[...prev,{...data,id:genId()}]);
    setModalOpen(false);
  };
  const openComment=v=>{setCommentModal(v);setCommentText(v.teacherComment||'');setCommentTeacher(v.commentTeacher||'');};
  const saveComment=()=>{
    if(!commentTeacher){alert('선생님 이름을 선택해주세요.');return;}
    if(!commentText.trim()){alert('코멘트 내용을 입력해주세요.');return;}
    setVideos(prev=>prev.map(v=>v.id===commentModal.id?{...v,teacherComment:commentText,commentDate:today(),commentTeacher}:v));
    setCommentModal(null);
  };
  const shareVideoLink=v=>{
    const st=students.find(s=>s.id===v.studentId);
    const payload={type:'video',academy:academyName||'우리 학원',student:v.studentName,
      video:{title:v.title,subject:v.subject,date:v.date,description:v.description,
        teacherComment:v.teacherComment,commentTeacher:v.commentTeacher,commentDate:v.commentDate}};
    const link=`${baseUrl||'학부모앱.html'}#${encodeShare(payload)}`;
    copyToClipboard(link,`${v.studentName} 연습영상 링크가 복사되었습니다! 카카오톡에 붙여넣기 하세요.`);
  };
  const openSend=v=>{setSendModal(v);};
  const confirmSend=()=>{
    setVideos(prev=>prev.map(v=>v.id===sendModal.id?{...v,sentToParent:true,sentDate:today()}:v));
    setSendModal(null);
    alert('✅ 학부모 발송 처리가 완료되었습니다.');
  };
  const del=id=>{setVideos(prev=>prev.filter(v=>v.id!==id));setConfirmId(null);};

  const getParent=studentId=>{const s=students.find(x=>x.id===studentId);if(!s)return{name:'-',phone:'-',isAdult:false};return s.grade==='성인'?{name:s.name,phone:s.phone,isAdult:true}:{name:s.parentName,phone:s.parentPhone,isAdult:false};};
  const isVideoFile=(p,ft)=>ft?ft.startsWith('video/'):p&&/\.(mp4|webm|mov|avi|mkv)$/i.test(p);
  const isImageFile=(p,ft)=>ft?ft.startsWith('image/'):p&&/\.(jpg|jpeg|png|gif|webp|heic|heif)$/i.test(p);

  const filtered=videos.filter(v=>!filterStudent||(v.studentName||'').includes(filterStudent)||(v.subject||'').includes(filterStudent)).sort((a,b)=>b.date.localeCompare(a.date));

  return<div className="space-y-5">
    <div className="flex items-center justify-between">
      <div><h1 className="text-2xl font-bold text-slate-900">학생피드백</h1>
        <p className="text-slate-600 text-sm mt-1">🔒 비공개 · 선생님 코멘트 작성 후 학부모 발송 가능</p>
      </div>
      <button className={btn('indigo')} onClick={openAdd}>+ 피드백 등록</button>
    </div>
    <div className="flex gap-3 items-center flex-wrap">
      <input className={inp} placeholder="학생 이름 또는 과목 검색..." value={filterStudent} onChange={e=>setFilterStudent(e.target.value)} style={{maxWidth:'280px'}}/>
      <div className="flex gap-3 text-xs text-slate-600">
        <span className="flex items-center gap-1"><span className="w-3 h-3 rounded-full bg-green-500 inline-block"/>코멘트+발송완료</span>
        <span className="flex items-center gap-1"><span className="w-3 h-3 rounded-full bg-yellow-400 inline-block"/>코멘트작성됨</span>
        <span className="flex items-center gap-1"><span className="w-3 h-3 rounded-full bg-gray-300 inline-block"/>코멘트대기</span>
      </div>
    </div>
    <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">
      {filtered.map(v=>{
        const parent=getParent(v.studentId);
        const hasComment=!!v.teacherComment;
        const isSent=v.sentToParent;
        const borderColor=isSent?'border-green-200':hasComment?'border-yellow-200':'border-gray-100';
        const dotColor=isSent?'bg-green-500':hasComment?'bg-yellow-400':'bg-gray-300';
        return<div key={v.id} className={`bg-white rounded-2xl border ${borderColor} shadow-sm overflow-hidden`}>
          {/* 미디어 영역 - 비공개 */}
          <div className="bg-gray-900 relative" style={{height:'160px'}}>
            {isVideoFile(v.filePath,v._fileType)?(
              <video src={v.filePath} controls className="w-full h-full object-contain"/>
            ):isImageFile(v.filePath,v._fileType)?(
              <img src={v.filePath} alt={v.title} className="w-full h-full object-contain"/>
            ):(
              <div className="w-full h-full flex flex-col items-center justify-center gap-2 text-slate-600">
                <span className="text-4xl">📎</span>
                <span className="text-sm">{v.filePath?v._fileName||v.filePath.split('/').pop():'파일 미등록'}</span>
                {v.filePath&&<a href={v.filePath} target="_blank" rel="noopener noreferrer" className="text-xs text-[#475569] underline">링크 열기</a>}
              </div>
            )}
            <div className="absolute top-2 left-2 flex gap-1">
              <span className="bg-black/70 text-white text-xs px-2 py-0.5 rounded">🔒 비공개</span>
              <span className={`w-3 h-3 rounded-full ${dotColor} border-2 border-white mt-0.5`}/>
            </div>
            {isSent&&<div className="absolute top-2 right-2"><span className="bg-green-500 text-white text-xs px-2 py-0.5 rounded">✅ 발송완료</span></div>}
          </div>
          {/* 내용 */}
          <div className="p-4">
            <div className="flex items-start justify-between gap-2 mb-2">
              <div>
                <div className="font-semibold text-slate-900">{v.title}</div>
                <div className="flex items-center gap-2 mt-1">
                  <span className="badge bg-[#dbeafe] text-[#1e293b]">{v.studentName}</span>
                  <span className="badge bg-purple-100 text-purple-700">{v.subject}</span>
                  <span className="text-xs text-slate-600">{fDate(v.date)}</span>
                </div>
              </div>
              <div className="flex gap-1 shrink-0">
                <button onClick={()=>openEdit(v)} className="text-xs px-2 py-1 rounded bg-gray-100 text-slate-700 hover:bg-gray-200">수정</button>
                <button onClick={()=>setConfirmId(v.id)} className="text-xs px-2 py-1 rounded bg-red-50 text-red-500 hover:bg-red-100">삭제</button>
              </div>
            </div>
            {v.description&&<p className="text-xs text-slate-600 mb-3 bg-[#f1f5f9] rounded-lg p-2">{v.description}</p>}
            {/* 코멘트 */}
            {hasComment?(
              <div className="bg-[#f1f5f9] rounded-xl p-3 border border-[#e2e8f0] mb-3">
                <div className="flex items-center gap-2 mb-1">
                  <span className="text-xs font-semibold text-[#1e293b]">💬 {v.commentTeacher} 선생님 코멘트</span>
                  <span className="text-xs text-slate-600">{fDate(v.commentDate)}</span>
                </div>
                <p className="text-sm text-slate-800 leading-relaxed">{v.teacherComment}</p>
                <button onClick={()=>openComment(v)} className="text-xs text-[#475569] hover:underline mt-1">코멘트 수정</button>
              </div>
            ):(
              <div className="mb-3">
                <button onClick={()=>openComment(v)} className="w-full py-2 rounded-xl border-2 border-dashed border-gray-200 text-sm text-slate-600 hover:border-yellow-300 hover:text-yellow-600 transition-colors">
                  ✏️ 선생님 코멘트 작성 (발송 전 필수)
                </button>
              </div>
            )}
            {/* 발송 버튼 */}
            {!hasComment&&<div className="text-xs text-slate-600 text-center py-1">코멘트 작성 후 학부모 발송이 가능합니다</div>}
            {hasComment&&!isSent&&<div className="flex gap-2">
              <button onClick={()=>openSend(v)} className={`flex-1 py-2 rounded-xl text-sm font-medium ${btn('blue')} text-center`}>📱 발송 처리</button>
              <button onClick={()=>shareVideoLink(v)} className="flex-1 py-2 rounded-xl text-sm font-medium bg-purple-100 text-purple-700 hover:bg-purple-200 transition-colors">🔗 링크 복사</button>
            </div>}
            {isSent&&<div className="space-y-1">
              <div className="text-center py-2 text-sm text-green-600 font-medium">✅ {parent.name}님({parent.phone}) 발송 완료 · {fDate(v.sentDate)}</div>
              <button onClick={()=>shareVideoLink(v)} className="w-full py-1.5 rounded-xl text-xs text-purple-600 bg-purple-50 hover:bg-purple-100 transition-colors">🔗 링크 다시 복사</button>
            </div>}
          </div>
        </div>;
      })}
      {filtered.length===0&&<div className="col-span-2 bg-white rounded-2xl border border-gray-100 p-16 text-center">
        <div className="text-4xl mb-3">💬</div><div className="text-slate-600">등록된 피드백이 없습니다</div>
        <button className={`${btn('indigo')} mt-4`} onClick={openAdd}>첫 피드백 등록하기</button>
      </div>}
    </div>

    {/* 영상 등록/수정 모달 */}
    <Modal open={modalOpen} onClose={()=>setModalOpen(false)} title={editTarget?'피드백 수정':'피드백 등록'}>
      <div className="grid grid-cols-2 gap-x-4">
        <Field label="학생 선택" required><select className={inp} value={form.studentId} onChange={e=>setForm({...form,studentId:e.target.value})}>
          <option value="">선택</option>{[...students].sort((a,b)=>a.name.localeCompare(b.name,'ko')).map(s=><option key={s.id} value={s.id}>{s.name} ({s.level||s.grade})</option>)}
        </select></Field>
        <Field label="과목"><input className={inp} value={form.subject} onChange={e=>setForm({...form,subject:e.target.value})} placeholder="예: 피아노"/></Field>
      </div>
      <Field label="제목" required><input className={inp} value={form.title} onChange={e=>setForm({...form,title:e.target.value})} placeholder="예: 쇼팽 녹턴 1번 연습"/></Field>
      <Field label="날짜"><input className={inp} type="date" value={form.date} onChange={e=>setForm({...form,date:e.target.value})}/></Field>
      <Field label="영상 / 사진 파일 업로드">
        <div
          className={`border-2 border-dashed rounded-xl p-5 text-center cursor-pointer transition-all ${dragOver?'border-[#3b82f6] bg-[#f1f5f9]':'border-gray-300 hover:border-[#3b82f6] hover:bg-[#f1f5f9]'}`}
          onDragOver={e=>{e.preventDefault();setDragOver(true);}}
          onDragLeave={e=>{e.preventDefault();setDragOver(false);}}
          onDrop={e=>{e.preventDefault();setDragOver(false);handleVideoFile(e.dataTransfer.files[0]);}}
          onClick={()=>videoFileRef.current&&videoFileRef.current.click()}
        >
          <input ref={videoFileRef} type="file" accept="video/*,image/*" className="hidden" onChange={e=>handleVideoFile(e.target.files[0])}/>
          {form.filePath&&form._fileName?(
            <div>
              <div className="text-3xl mb-2">{form._fileType&&form._fileType.startsWith('image/')?'🖼️':'🎬'}</div>
              <div className="text-sm font-semibold text-[#1e293b] truncate max-w-xs mx-auto">{form._fileName}</div>
              <div className="text-xs text-slate-600 mt-1">파일이 선택되었습니다 · 변경하려면 다시 클릭하세요</div>
            </div>
          ):(
            <div>
              <div className="text-3xl mb-2">📁</div>
              <div className="text-sm font-semibold text-slate-700">영상 또는 사진을 여기에 드래그하거나</div>
              <div className="text-sm text-[#475569] font-semibold mt-1">클릭하여 파일 선택</div>
              <div className="text-xs text-slate-600 mt-2">🎬 MP4 · MOV · AVI · WebM</div>
              <div className="text-xs text-slate-600">🖼️ JPG · PNG · GIF · WebP</div>
            </div>
          )}
        </div>
        {form.filePath&&!form._fileName&&(
          <div className="mt-2">
            <input className={inp} value={form.filePath} onChange={e=>setForm({...form,filePath:e.target.value})} placeholder="또는 직접 경로/URL 입력"/>
          </div>
        )}
      </Field>
      <Field label="설명 / 연습 포인트"><textarea className={inp} rows={3} value={form.description} onChange={e=>setForm({...form,description:e.target.value})} placeholder="이번 영상에서 집중한 부분, 연습 포인트 등을 입력하세요"/></Field>
      <div className="flex justify-end gap-3 mt-2"><button className={btn('indigo')} onClick={save}>저장</button><button className={btn('gray')} onClick={()=>setModalOpen(false)}>취소</button></div>
    </Modal>

    {/* 코멘트 모달 */}
    {commentModal&&<div className="modal-overlay" onClick={e=>e.target===e.currentTarget&&setCommentModal(null)}>
      <div className="modal-box shadow-2xl">
        <div className="flex items-center justify-between p-5 border-b">
          <h3 className="text-lg font-bold text-slate-900">💬 선생님 코멘트 작성</h3>
          <button onClick={()=>setCommentModal(null)} className="w-8 h-8 flex items-center justify-center rounded-full hover:bg-gray-100 text-slate-600 text-xl">&times;</button>
        </div>
        <div className="p-5">
          <div className="bg-[#f1f5f9] rounded-xl p-3 mb-4 text-sm text-slate-700">
            <span className="font-medium">{commentModal.studentName}</span> · {commentModal.title}
          </div>
          <Field label="담당 선생님" required><select className={inp} value={commentTeacher} onChange={e=>setCommentTeacher(e.target.value)}>
            <option value="">선생님 선택</option>{teachers.filter(t=>t.status==='active').sort((a,b)=>a.name.localeCompare(b.name,'ko')).map(t=><option key={t.id} value={t.name}>{t.name} ({(t.subjects||[]).join(', ')})</option>)}
          </select></Field>
          <Field label="코멘트 내용"><textarea className={inp} rows={5} value={commentText} onChange={e=>setCommentText(e.target.value)}
            placeholder="잘된 점, 개선할 점, 다음 연습 목표 등을 구체적으로 작성해주세요.&#10;&#10;이 코멘트는 학부모 발송 시 함께 전달됩니다."/></Field>
          <div className="flex justify-end gap-3 mt-2"><button className={btn('indigo')} onClick={saveComment}>코멘트 저장</button><button className={btn('gray')} onClick={()=>setCommentModal(null)}>취소</button></div>
        </div>
      </div>
    </div>}

    {/* 학부모 발송 확인 모달 */}
    {sendModal&&<div className="modal-overlay" onClick={e=>e.target===e.currentTarget&&setSendModal(null)}>
      <div className="modal-box shadow-2xl">
        <div className="flex items-center justify-between p-5 border-b">
          <h3 className="text-lg font-bold text-slate-900">📱 학부모 발송 확인</h3>
          <button onClick={()=>setSendModal(null)} className="w-8 h-8 flex items-center justify-center rounded-full hover:bg-gray-100 text-slate-600 text-xl">&times;</button>
        </div>
        <div className="p-5">
          <div className="bg-[#f1f5f9] rounded-xl p-4 mb-4 space-y-2">
            <div className="text-sm font-semibold text-slate-800">발송 내용 미리보기</div>
            <div className="border border-gray-200 rounded-lg p-3 bg-white text-sm text-slate-800">
              <div className="font-medium mb-1">🏫 {sendModal.studentName} 학생 연습 영상 안내</div>
              <div className="text-xs text-slate-600 mb-2">{sendModal.title} · {fDate(sendModal.date)}</div>
              <div className="text-xs bg-[#f1f5f9] rounded p-2 text-[#0f172a]">
                <span className="font-medium">선생님 코멘트:</span> {sendModal.teacherComment}
              </div>
            </div>
          </div>
          <div className="bg-blue-50 rounded-xl p-3 mb-4">
            <div className="text-sm font-medium text-blue-700 mb-1">발송 대상</div>
            <div className="text-sm text-slate-800">{getParent(sendModal.studentId).name}{getParent(sendModal.studentId).isAdult?'님 (본인)':' 학부모님'}</div>
            <div className="text-sm text-slate-700">{getParent(sendModal.studentId).phone}</div>
          </div>
          <div className="text-xs text-slate-600 mb-4">※ 실제 문자 발송은 별도 SMS 서비스 연동이 필요합니다. 이 버튼은 발송 현황을 기록합니다.</div>
          <div className="flex justify-end gap-3"><button className={btn('blue')} onClick={confirmSend}>📱 발송 완료 처리</button><button className={btn('gray')} onClick={()=>setSendModal(null)}>취소</button></div>
        </div>
      </div>
    </div>}
    <Confirm open={!!confirmId} msg="이 영상을 삭제하시겠습니까?" onYes={()=>del(confirmId)} onNo={()=>setConfirmId(null)}/>
  </div>;
}

// ── 세금 신고 관리 ────────────────────────────────────────────────────────────
function TaxManagement({income,expenses}){
  const[year,setYear]=useState(()=>new Date().getFullYear());
  const[tab,setTab]=useState('summary'); // summary | expenses | calc | guide
  const[deductions,setDeductions]=useState({basic:1500000,elderly:0,disabled:0,other:0});

  const yInc=income.filter(i=>i.date?.startsWith(String(year)));
  const yExp=expenses.filter(e=>e.date?.startsWith(String(year)));
  const totalInc=yInc.reduce((s,i)=>s+Number(i.amount),0);
  const totalExp=yExp.reduce((s,e)=>s+Number(e.amount),0);
  const bizIncome=totalInc-totalExp;
  const totalDed=Object.values(deductions).reduce((s,v)=>s+Number(v||0),0);
  const taxBase=Math.max(0,bizIncome-totalDed);

  const calcIncomeTax=base=>{
    if(base<=0)return 0;
    const brackets=[
      {limit:14000000,rate:0.06,ded:0},
      {limit:50000000,rate:0.15,ded:1260000},
      {limit:88000000,rate:0.24,ded:5760000},
      {limit:150000000,rate:0.35,ded:15440000},
      {limit:300000000,rate:0.38,ded:19940000},
      {limit:500000000,rate:0.40,ded:25940000},
      {limit:1000000000,rate:0.42,ded:35940000},
      {limit:Infinity,rate:0.45,ded:65940000},
    ];
    for(const b of brackets){if(base<=b.limit)return Math.max(0,Math.round(base*b.rate-b.ded));}
    return 0;
  };
  const bracket=(()=>{const list=[{limit:14000000,rate:6,label:'1,400만원 이하'},{limit:50000000,rate:15,label:'1,400~5,000만원'},{limit:88000000,rate:24,label:'5,000~8,800만원'},{limit:150000000,rate:35,label:'8,800만원~1.5억'},{limit:300000000,rate:38,label:'1.5억~3억'},{limit:500000000,rate:40,label:'3억~5억'},{limit:1000000000,rate:42,label:'5억~10억'},{limit:Infinity,rate:45,label:'10억 초과'}];for(const b of list){if(taxBase<=b.limit)return b;}return list[list.length-1];})();
  const incomeTax=calcIncomeTax(taxBase);
  const localTax=Math.round(incomeTax*0.1);
  const totalTax=incomeTax+localTax;

  const expByCat=yExp.reduce((a,e)=>{a[e.category]=(a[e.category]||0)+Number(e.amount);return a;},{});
  const taxCatMap={'강사급여':'인건비 (필요경비 100% 인정)','임대료':'임차료 (필요경비 100% 인정)','관리비':'공과금·관리비 (필요경비 인정)','소모품':'소모품비 (필요경비 인정)','교육용품':'교육재료비 (필요경비 인정)','마케팅':'광고선전비 (필요경비 인정)','시설유지':'수선비 (필요경비 인정)','전기·수도요금':'공과금·관리비 (필요경비 인정)','기타지출':'기타 경비 (세무사 확인 권장)'};

  const availableYears=Array.from(new Set([...income,...expenses].map(x=>x.date?.substr(0,4)).filter(Boolean))).sort((a,b)=>b-a);

  const printTaxPDF=()=>{
    const fW=n=>'₩'+Number(n||0).toLocaleString();
    const months=Array.from({length:12},(_,i)=>{
      const m=String(i+1).padStart(2,'0');const k=`${year}-${m}`;
      const inc=yInc.filter(x=>x.date?.startsWith(k)).reduce((s,x)=>s+Number(x.amount),0);
      const exp=yExp.filter(x=>x.date?.startsWith(k)).reduce((s,x)=>s+Number(x.amount),0);
      return{label:`${i+1}월`,inc,exp,profit:inc-exp};
    });
    const mRows=months.map(r=>`<tr><td style="padding:6px 10px;border-bottom:1px solid #f3f4f6;">${r.label}</td><td style="padding:6px 10px;border-bottom:1px solid #f3f4f6;text-align:right;color:#16a34a;font-weight:600;">${fW(r.inc)}</td><td style="padding:6px 10px;border-bottom:1px solid #f3f4f6;text-align:right;color:#dc2626;font-weight:600;">${fW(r.exp)}</td><td style="padding:6px 10px;border-bottom:1px solid #f3f4f6;text-align:right;color:${r.profit>=0?'#1d4ed8':'#c2410c'};font-weight:700;">${fW(r.profit)}</td></tr>`).join('');
    const eRows=Object.entries(expByCat).sort((a,b)=>b[1]-a[1]).map(([cat,amt])=>`<tr><td style="padding:6px 10px;border-bottom:1px solid #f3f4f6;">${cat}</td><td style="padding:6px 10px;border-bottom:1px solid #f3f4f6;">${taxCatMap[cat]||'기타 경비'}</td><td style="padding:6px 10px;border-bottom:1px solid #f3f4f6;text-align:right;font-weight:600;color:#dc2626;">${fW(amt)}</td></tr>`).join('');
    const html=`<!DOCTYPE html><html lang="ko"><head><meta charset="UTF-8"><title>${year}년 종합소득세 신고 자료</title>
    <style>body{font-family:'Malgun Gothic',sans-serif;color:#1f2937;padding:32px;max-width:800px;margin:0 auto;}
    h1{font-size:22px;font-weight:800;color:#4f46e5;border-bottom:3px solid #4f46e5;padding-bottom:12px;margin-bottom:20px;}
    h2{font-size:14px;font-weight:700;color:#374151;margin:20px 0 8px;padding-left:10px;border-left:4px solid #6366f1;}
    .summary{display:flex;gap:12px;margin-bottom:20px;flex-wrap:wrap;}
    .sbox{flex:1;min-width:150px;padding:14px;border-radius:10px;text-align:center;}
    .sl{font-size:11px;font-weight:600;margin-bottom:4px;}.sv{font-size:18px;font-weight:800;}
    table{width:100%;border-collapse:collapse;margin-bottom:16px;}
    th{background:#f9fafb;padding:7px 10px;text-align:left;font-size:11px;color:#6b7280;font-weight:700;border-bottom:2px solid #e5e7eb;}
    .tax-box{background:#fefce8;border:2px solid #fde047;border-radius:12px;padding:16px;margin:16px 0;}
    .footer{margin-top:28px;font-size:11px;color:#9ca3af;text-align:center;border-top:1px solid #e5e7eb;padding-top:12px;}
    .warning{background:#fff7ed;border:1px solid #fed7aa;border-radius:8px;padding:12px;font-size:12px;color:#c2410c;margin-top:12px;}
    @media print{.no-print{display:none;}}</style></head><body>
    <div class="no-print" style="text-align:right;margin-bottom:12px;"><button onclick="window.print()" style="background:#4f46e5;color:white;border:none;padding:10px 24px;border-radius:8px;cursor:pointer;font-size:14px;font-weight:600;">🖨️ 인쇄 / PDF 저장</button></div>
    <h1>📊 ${year}년 종합소득세 신고 준비 자료</h1>
    <p style="font-size:13px;color:#6b7280;margin-bottom:16px;">사업자 유형: <strong>면세사업자 (교육서비스업)</strong> | 신고기간: ${year+1}년 5월 1일~31일</p>
    <div class="summary">
      <div class="sbox" style="background:#f0fdf4;border:1px solid #bbf7d0;"><div class="sl" style="color:#16a34a;">연간 총 수입</div><div class="sv" style="color:#15803d;">${fW(totalInc)}</div></div>
      <div class="sbox" style="background:#fef2f2;border:1px solid #fecaca;"><div class="sl" style="color:#dc2626;">연간 총 지출</div><div class="sv" style="color:#b91c1c;">${fW(totalExp)}</div></div>
      <div class="sbox" style="background:#eff6ff;border:1px solid #bfdbfe;"><div class="sl" style="color:#2563eb;">사업소득금액</div><div class="sv" style="color:#1d4ed8;">${fW(bizIncome)}</div></div>
    </div>
    <h2>📅 월별 수입/지출 현황</h2>
    <table><thead><tr><th>월</th><th style="text-align:right">수입</th><th style="text-align:right">지출</th><th style="text-align:right">순손익</th></tr></thead><tbody>${mRows}</tbody>
    <tfoot><tr style="background:#f9fafb;font-weight:700;"><td style="padding:8px 10px;">합계</td><td style="padding:8px 10px;text-align:right;color:#16a34a;">${fW(totalInc)}</td><td style="padding:8px 10px;text-align:right;color:#dc2626;">${fW(totalExp)}</td><td style="padding:8px 10px;text-align:right;">${fW(bizIncome)}</td></tr></tfoot></table>
    <h2>💼 지출 항목별 필요경비 내역 (홈택스 입력용)</h2>
    <table><thead><tr><th>항목</th><th>세법상 분류</th><th style="text-align:right">금액</th></tr></thead><tbody>${eRows}</tbody>
    <tfoot><tr style="background:#f9fafb;font-weight:700;"><td colspan="2" style="padding:8px 10px;">필요경비 합계</td><td style="padding:8px 10px;text-align:right;">${fW(totalExp)}</td></tr></tfoot></table>
    <div class="tax-box">
      <div style="font-size:14px;font-weight:700;color:#854d0e;margin-bottom:10px;">⚡ 예상 세액 (참고용)</div>
      <table style="margin:0;"><tbody>
        <tr><td style="padding:5px 10px;">사업소득금액</td><td style="padding:5px 10px;text-align:right;font-weight:600;">${fW(bizIncome)}</td></tr>
        <tr><td style="padding:5px 10px;">소득공제 (기본공제 등)</td><td style="padding:5px 10px;text-align:right;color:#dc2626;">- ${fW(totalDed)}</td></tr>
        <tr><td style="padding:5px 10px;font-weight:700;">종합소득 과세표준</td><td style="padding:5px 10px;text-align:right;font-weight:700;">${fW(taxBase)}</td></tr>
        <tr><td style="padding:5px 10px;">적용 세율 (${bracket.label})</td><td style="padding:5px 10px;text-align:right;">${bracket.rate}%</td></tr>
        <tr><td style="padding:5px 10px;font-weight:700;color:#1d4ed8;">종합소득세</td><td style="padding:5px 10px;text-align:right;font-weight:700;color:#1d4ed8;">${fW(incomeTax)}</td></tr>
        <tr><td style="padding:5px 10px;">지방소득세 (10%)</td><td style="padding:5px 10px;text-align:right;">${fW(localTax)}</td></tr>
        <tr style="border-top:2px solid #e5e7eb;"><td style="padding:8px 10px;font-weight:800;font-size:15px;">납부 예상 세액 합계</td><td style="padding:8px 10px;text-align:right;font-weight:800;font-size:15px;color:#1d4ed8;">${fW(totalTax)}</td></tr>
      </tbody></table>
    </div>
    <div class="warning">⚠️ 본 자료는 참고용입니다. 실제 신고 시 홈택스(hometax.go.kr)에서 공식 계산하시고, 불확실한 항목은 세무사 또는 국세청 126 상담을 이용하세요.</div>
    <div class="footer">출력일: ${new Date().toLocaleDateString('ko-KR')} | 학원 관리 시스템 자동 생성</div>
    </body></html>`;
    const w=window.open('','_blank','width=900,height=750,scrollbars=yes');
    if(w){w.document.write(html);w.document.close();}else{alert('팝업이 차단되었습니다.');}
  };

  const guideSteps=[
    {icon:'🌐',title:'홈택스 접속 및 로그인',desc:'hometax.go.kr 접속 → 공동인증서(구 공인인증서) 또는 간편인증(카카오·네이버 등)으로 로그인'},
    {icon:'📋',title:'종합소득세 신고 메뉴',desc:'신고/납부 → 세금신고 → 종합소득세 → 일반신고 → [확정신고 작성]'},
    {icon:'🏢',title:'기본정보 입력',desc:'사업자 유형: 개인사업자 / 업종코드: 85100(교육서비스업) / 면세사업자 체크 / 간편장부 or 복식부기 선택'},
    {icon:'💰',title:'수입금액 입력',desc:`${year}년 총수입 ${fWon(totalInc)} 입력. 업종코드 85100, 면세수입으로 입력`},
    {icon:'💼',title:'필요경비 입력',desc:`인건비 ${fWon(expByCat['강사급여']||0)} / 임차료 ${fWon(expByCat['임대료']||0)} / 기타 경비 순서대로 입력. 영수증·계좌내역 보관 필수`},
    {icon:'🎁',title:'소득공제 입력',desc:'기본공제(본인 150만원) 필수 입력. 노인·장애인 해당 시 추가공제. 국민연금·건강보험료 등 연금보험료 공제도 확인'},
    {icon:'🧮',title:'세액 자동 계산 확인',desc:'홈택스가 자동으로 세액을 계산합니다. 화면의 세액이 이 시스템 예상액과 비슷한지 확인'},
    {icon:'✅',title:'신고서 제출 및 납부',desc:'신고서 최종 확인 후 [신고서 제출] 클릭. 납부할 세금은 5월 31일까지 가상계좌 또는 인터넷뱅킹으로 납부'},
  ];

  return<div className="space-y-5">
    {/* 🚧 관리자 전용 안내 (화면에만 보임) ─ Austin님 피드백[16] 관련: 세금 계산 항목에는
        근거가 되는 법적 출처를 명시하고, 실제 신고 전 재확인이 필요하다는 점을 표시해 둠.
        여기 종합소득세 세율표(6%~45%) 자체는 소득세법 제55조 기본세율을 그대로 적용한 것이라
        정확하지만, 소득공제 항목은 기본공제/경로우대/장애인공제만 입력칸이 있고 그 외 특별공제·
        연금보험료공제 등은 반영되지 않으므로 "참고용"임을 분명히 안내함. */}
    <div className="no-print bg-orange-50 border-2 border-orange-300 rounded-xl p-3 flex items-start gap-2 text-sm text-orange-800">
      <span className="text-lg leading-none">🚧</span>
      <div><strong>확인 필요</strong>: 세율표(6~45%)는 소득세법 제55조 기준으로 정확하지만, 소득공제는 기본공제·경로우대·장애인공제만 반영되어 있습니다. 특별공제·연금보험료공제 등 다른 공제 항목이 있다면 추가 입력 후 홈택스에서 최종 금액을 다시 확인해주세요.</div>
    </div>

    <div className="flex items-center justify-between flex-wrap gap-3">
      <div><h1 className="text-2xl font-bold text-slate-900">세금 신고 관리</h1>
        <p className="text-slate-600 text-sm mt-1">종합소득세 신고 준비 · 홈택스 직접 신고 가이드</p></div>
      <div className="flex items-center gap-2">
        <select className={inp} value={year} onChange={e=>setYear(Number(e.target.value))} style={{width:'120px'}}>
          {[...Array(5)].map((_,i)=>{const y=new Date().getFullYear()-i;return<option key={y} value={y}>{y}년</option>;})}
        </select>
        <button className={btn('green')} onClick={printTaxPDF}>🖨️ 신고자료 PDF</button>
      </div>
    </div>

    {/* 연간 요약 카드 */}
    <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
      {[
        {label:'연간 총 수입',value:fWon(totalInc),sub:`${yInc.length}건`,color:'bg-green-50 border-green-200',tc:'text-green-700',sc:'text-green-500'},
        {label:'연간 총 지출 (필요경비)',value:fWon(totalExp),sub:`${yExp.length}건`,color:'bg-red-50 border-red-200',tc:'text-red-700',sc:'text-red-500'},
        {label:'사업소득금액 (손수익)',value:fWon(bizIncome),sub:'수입 - 필요경비',color:bizIncome>=0?'bg-blue-50 border-blue-200':'bg-red-50 border-red-200',tc:bizIncome>=0?'text-blue-700':'text-red-700',sc:bizIncome>=0?'text-blue-500':'text-red-500'},
        {label:'예상 납부 세액',value:fWon(totalTax),sub:`소득세 + 지방세`,color:'bg-yellow-50 border-yellow-200',tc:'text-yellow-700',sc:'text-yellow-500'},
      ].map(({label,value,sub,color,tc,sc})=>(
        <div key={label} className={`rounded-2xl border p-4 ${color}`}>
          <div className={`text-xs font-semibold ${tc} mb-1`}>{label}</div>
          <div className={`text-xl font-bold ${tc} leading-tight`}>{value}</div>
          <div className={`text-xs mt-1 ${sc}`}>{sub}</div>
        </div>
      ))}
    </div>

    {yInc.length===0&&yExp.length===0&&(
      <div className="bg-yellow-50 border border-yellow-200 rounded-xl p-4 text-sm text-yellow-700">
        ⚠️ {year}년 수입·지출 데이터가 없습니다. 예산관리 파트에서 먼저 데이터를 입력해주세요.
      </div>
    )}

    {/* 탭 */}
    <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
      <div className="flex gap-2 p-4 border-b border-gray-100 flex-wrap">
        <button className={`tab-btn ${tab==='summary'?'active':''}`} onClick={()=>setTab('summary')}>📊 월별 현황</button>
        <button className={`tab-btn ${tab==='expenses'?'active':''}`} onClick={()=>setTab('expenses')}>💼 필요경비 분류</button>
        <button className={`tab-btn ${tab==='calc'?'active':''}`} onClick={()=>setTab('calc')}>🧮 세액 계산</button>
        <button className={`tab-btn ${tab==='guide'?'active':''}`} onClick={()=>setTab('guide')}>📋 홈택스 신고 방법</button>
      </div>

      {/* 월별 현황 */}
      {tab==='summary'&&<div className="overflow-x-auto overflow-y-auto tbl-scroll" style={{maxHeight:'calc(100vh - 280px)'}}>
        <table className="w-full min-w-[500px] app-table">
          <thead><tr className="text-xs text-slate-600 font-semibold uppercase">
            <th className="px-4 py-3 text-left">월</th>
            <th className="px-4 py-3 text-right">수입</th>
            <th className="px-4 py-3 text-right">지출</th>
            <th className="px-4 py-3 text-right">순손익</th>
            <th className="px-4 py-3 text-right">누적 수입</th>
          </tr></thead>
          <tbody>{Array.from({length:12},(_,i)=>{
            const m=String(i+1).padStart(2,'0');const k=`${year}-${m}`;
            const inc=yInc.filter(x=>x.date?.startsWith(k)).reduce((s,x)=>s+Number(x.amount),0);
            const exp=yExp.filter(x=>x.date?.startsWith(k)).reduce((s,x)=>s+Number(x.amount),0);
            const profit=inc-exp;
            const cumInc=yInc.filter(x=>x.date?.startsWith(year.toString())&&x.date<=`${year}-${m}-99`).reduce((s,x)=>s+Number(x.amount),0);
            return<tr key={i} className="table-row border-t border-gray-50">
              <td className="px-4 py-3 font-semibold text-slate-900">{i+1}월</td>
              <td className="px-4 py-3 text-right text-green-700 font-semibold">{inc>0?fWon(inc):'-'}</td>
              <td className="px-4 py-3 text-right text-red-600 font-semibold">{exp>0?fWon(exp):'-'}</td>
              <td className={`px-4 py-3 text-right font-bold ${profit>0?'text-green-700':profit<0?'text-red-600':'text-slate-600'}`}>{inc>0||exp>0?fWon(profit):'-'}</td>
              <td className="px-4 py-3 text-right text-slate-600 text-sm">{cumInc>0?fWon(cumInc):'-'}</td>
            </tr>;
          })}</tbody>
          <tfoot><tr className="bg-[#f1f5f9] font-bold">
            <td className="px-4 py-3 text-[#1e293b]">연간 합계</td>
            <td className="px-4 py-3 text-right text-green-700">{fWon(totalInc)}</td>
            <td className="px-4 py-3 text-right text-red-600">{fWon(totalExp)}</td>
            <td className={`px-4 py-3 text-right ${bizIncome>=0?'text-green-700':'text-red-600'}`}>{fWon(bizIncome)}</td>
            <td className="px-4 py-3"></td>
          </tr></tfoot>
        </table>
      </div>}

      {/* 필요경비 분류 */}
      {tab==='expenses'&&<div className="p-5">
        <div className="bg-blue-50 border border-blue-200 rounded-xl p-4 mb-4 text-sm text-blue-700">
          💡 아래 항목들은 홈택스 종합소득세 신고 시 <strong>필요경비</strong>로 입력할 금액입니다. 각 항목의 영수증·계좌내역을 5년간 보관하세요.
        </div>
        <div className="overflow-x-auto overflow-y-auto tbl-scroll" style={{maxHeight:'calc(100vh - 360px)'}}>
          <table className="w-full app-table">
            <thead><tr className="text-xs text-slate-600 font-semibold uppercase">
              <th className="px-4 py-3 text-left">지출 항목</th>
              <th className="px-4 py-3 text-left">세법상 분류</th>
              <th className="px-4 py-3 text-right">금액</th>
              <th className="px-4 py-3 text-left">비고</th>
            </tr></thead>
            <tbody>{Object.entries(expByCat).sort((a,b)=>b[1]-a[1]).map(([cat,amt])=>(
              <tr key={cat} className="table-row border-t border-gray-50">
                <td className="px-4 py-3 font-medium text-slate-900">{cat}</td>
                <td className="px-4 py-3 text-sm text-slate-700">{taxCatMap[cat]||'기타 경비'}</td>
                <td className="px-4 py-3 text-right font-bold text-red-600">{fWon(amt)}</td>
                <td className="px-4 py-3">
                  {cat==='기타지출'
                    ?<span className="text-xs bg-yellow-100 text-yellow-700 px-2 py-0.5 rounded-full">세무사 확인 권장</span>
                    :<span className="text-xs bg-green-100 text-green-700 px-2 py-0.5 rounded-full">경비 인정</span>}
                </td>
              </tr>
            ))}</tbody>
            <tfoot><tr className="bg-red-50 font-bold">
              <td colSpan="2" className="px-4 py-3 text-red-700">필요경비 합계</td>
              <td className="px-4 py-3 text-right text-red-700">{fWon(totalExp)}</td>
              <td className="px-4 py-3"></td>
            </tr></tfoot>
          </table>
        </div>
        {Object.keys(expByCat).length===0&&<div className="py-10 text-center text-slate-600">지출 내역이 없습니다</div>}
        <div className="mt-4 bg-yellow-50 border border-yellow-200 rounded-xl p-4 text-sm text-yellow-700">
          ⚠️ <strong>중요</strong>: 학원 운영 면세사업자는 부가세 신고 의무가 없지만, 종합소득세 신고 시 위 필요경비 증빙서류(세금계산서·카드영수증·계좌이체 내역)를 반드시 보관해야 합니다.
        </div>
      </div>}

      {/* 세액 계산 */}
      {tab==='calc'&&<div className="p-5 space-y-4">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
          {/* 소득공제 입력 */}
          <div className="bg-[#f1f5f9] rounded-xl p-5 border border-gray-200">
            <h3 className="font-bold text-slate-900 mb-4">🎁 소득공제 입력</h3>
            <div className="space-y-3">
              {[
                {key:'basic',label:'기본공제 (본인)',desc:'본인 1인 150만원 기본',hint:'150만원 기본'},
                {key:'elderly',label:'경로우대자 공제',desc:'70세 이상 부양가족 1인당 100만원',hint:'해당 시 입력'},
                {key:'disabled',label:'장애인 공제',desc:'장애인 1인당 200만원',hint:'해당 시 입력'},
                {key:'other',label:'기타 공제',desc:'연금보험료·국민연금 등',hint:'금액 입력'},
              ].map(({key,label,desc,hint})=>(
                <div key={key}>
                  <div className="flex justify-between items-start mb-1">
                    <div>
                      <div className="text-sm font-semibold text-slate-900">{label}</div>
                      <div className="text-xs text-slate-600">{desc}</div>
                    </div>
                  </div>
                  <WonInput value={deductions[key]}
                    onChange={v=>setDeductions(prev=>({...prev,[key]:v}))}
                    placeholder={hint}/>
                </div>
              ))}
              <div className="border-t border-gray-200 pt-2 flex justify-between font-semibold text-sm text-slate-800">
                <span>총 소득공제</span><span className="text-[#1e293b]">{fWon(totalDed)}</span>
              </div>
            </div>
          </div>

          {/* 세액 계산 결과 */}
          <div className="bg-gradient-to-br from-[#f1f5f9] to-[#e2e8f0] rounded-xl p-5 border border-[#cbd5e1]">
            <h3 className="font-bold text-[#1e293b] mb-4">🧮 예상 세액 계산</h3>
            <div className="space-y-2">
              {[
                {label:'사업소득금액',val:fWon(bizIncome),color:bizIncome<0?'text-red-600':'text-slate-900'},
                {label:'소득공제 합계',val:`- ${fWon(totalDed)}`,color:'text-red-600'},
                {label:'종합소득 과세표준',val:fWon(taxBase),color:'text-blue-700',bold:true},
                {label:`적용세율 (${bracket.label})`,val:`${bracket.rate}%`,color:'text-slate-700'},
                {label:'종합소득세',val:fWon(incomeTax),color:'text-[#1e293b]',bold:true},
                {label:'지방소득세 (10%)',val:fWon(localTax),color:'text-slate-700'},
              ].map(({label,val,color,bold})=>(
                <div key={label} className={`flex justify-between items-center py-1.5 ${bold?'border-t border-[#cbd5e1] mt-1 pt-2':''}`}>
                  <span className="text-sm text-slate-700">{label}</span>
                  <span className={`text-sm font-${bold?'bold':'semibold'} ${color}`}>{val}</span>
                </div>
              ))}
              <div className="border-t-2 border-[#94a3b8] pt-3 mt-2">
                <div className="flex justify-between items-center">
                  <span className="font-bold text-slate-900">총 납부 예상액</span>
                  <span className="text-2xl font-bold text-[#1e293b]">{fWon(totalTax)}</span>
                </div>
                <div className="text-xs text-slate-600 mt-1 text-right">종합소득세 + 지방소득세 합계</div>
              </div>
            </div>
            <div className="mt-4 bg-white rounded-lg p-3 text-xs text-slate-600 border border-[#e2e8f0]">
              ⚠️ 이 금액은 <strong>참고용 추정치</strong>입니다. 기납부세액(중간예납 등)이 있으면 실제 납부액이 줄어들 수 있습니다. 홈택스에서 최종 확인하세요.
            </div>
          </div>
        </div>

        {/* 세율 구간 표 */}
        <div className="bg-white rounded-xl border border-gray-200 overflow-hidden">
          <div className="bg-[#f1f5f9] px-4 py-3 font-semibold text-slate-800 text-sm">📊 2024년 종합소득세 세율 구간</div>
          <table className="w-full app-table">
            <thead><tr className="text-xs text-slate-600 font-semibold">
              <th className="px-4 py-2 text-left">과세표준</th><th className="px-4 py-2 text-center">세율</th><th className="px-4 py-2 text-right">누진공제액</th>
            </tr></thead>
            <tbody>{[
              {range:'1,400만원 이하',rate:'6%',ded:'-',mark:taxBase<=14000000},
              {range:'1,400만원 ~ 5,000만원',rate:'15%',ded:'126만원',mark:taxBase>14000000&&taxBase<=50000000},
              {range:'5,000만원 ~ 8,800만원',rate:'24%',ded:'576만원',mark:taxBase>50000000&&taxBase<=88000000},
              {range:'8,800만원 ~ 1.5억원',rate:'35%',ded:'1,544만원',mark:taxBase>88000000&&taxBase<=150000000},
              {range:'1.5억 ~ 3억원',rate:'38%',ded:'1,994만원',mark:taxBase>150000000&&taxBase<=300000000},
              {range:'3억 ~ 5억원',rate:'40%',ded:'2,594만원',mark:taxBase>300000000&&taxBase<=500000000},
              {range:'5억 ~ 10억원',rate:'42%',ded:'3,594만원',mark:taxBase>500000000&&taxBase<=1000000000},
              {range:'10억원 초과',rate:'45%',ded:'6,594만원',mark:taxBase>1000000000},
            ].map(({range,rate,ded,mark})=>(
              <tr key={range} className={`border-t border-gray-50 ${mark?'bg-[#f1f5f9]':''}`}>
                <td className={`px-4 py-2 text-sm ${mark?'font-bold text-[#1e293b]':''}`}>{range}{mark&&' ← 현재'}</td>
                <td className={`px-4 py-2 text-center font-bold ${mark?'text-[#1e293b]':''}`}>{rate}</td>
                <td className="px-4 py-2 text-right text-slate-600 text-sm">{ded}</td>
              </tr>
            ))}</tbody>
          </table>
        </div>
      </div>}

      {/* 홈택스 신고 방법 */}
      {tab==='guide'&&<div className="p-5 space-y-4">
        <div className="bg-green-50 border border-green-200 rounded-xl p-4">
          <div className="font-bold text-green-800 mb-1">✅ 홈택스 직접 신고 안내</div>
          <div className="text-sm text-green-700">신고기간: 매년 <strong>5월 1일 ~ 5월 31일</strong> | 홈택스: <strong>hometax.go.kr</strong> | 문의: 국세청 ☎ <strong>126</strong></div>
        </div>
        <div className="space-y-3">
          {guideSteps.map((step,i)=>(
            <div key={i} className="bg-white rounded-xl border border-gray-200 p-4 flex gap-4">
              <div className="w-10 h-10 rounded-xl bg-[#dbeafe] text-[#1e293b] flex items-center justify-center text-xl shrink-0">{step.icon}</div>
              <div className="flex-1">
                <div className="flex items-center gap-2 mb-1">
                  <span className="text-xs bg-[#1e3a5f] text-white rounded-full w-5 h-5 flex items-center justify-center font-bold shrink-0">{i+1}</span>
                  <div className="font-semibold text-slate-900">{step.title}</div>
                </div>
                <div className="text-sm text-slate-700">{step.desc}</div>
              </div>
            </div>
          ))}
        </div>
        <div className="bg-orange-50 border border-orange-200 rounded-xl p-4">
          <div className="font-semibold text-orange-800 mb-2">📌 면세사업자 학원 신고 시 주의사항</div>
          <div className="space-y-1.5 text-sm text-orange-700">
            <div>• <strong>사업자 유형</strong>: 교육서비스업 / 업종코드 85100 또는 세부 코드 확인</div>
            <div>• <strong>면세사업자</strong>이므로 부가세 신고 불필요 (종합소득세만 신고)</div>
            <div>• 연간 수입이 <strong>7,500만원 초과</strong>시 복식부기 의무 대상 (세무사 활용 권장)</div>
            <div>• <strong>현금영수증 발행</strong>: 30만원 이상 현금 거래 시 소비자 요청 없어도 의무 발행</div>
            <div>• 인건비 지급 시 <strong>원천징수(3.3%)</strong> 후 매월 다음달 10일까지 신고·납부 필요</div>
            <div>• 간편장부 대상자: 직전년도 수입 <strong>1.5억원 미만</strong>. 이상이면 복식부기 작성 의무</div>
          </div>
        </div>
        <div className="bg-white rounded-xl border border-gray-200 p-4">
          <div className="font-semibold text-slate-800 mb-3">🔗 유용한 링크</div>
          <div className="space-y-2">
            {[
              {label:'홈택스 (세금신고·납부)','url':'https://www.hometax.go.kr'},
              {label:'국세청 세금정보 포털','url':'https://www.nts.go.kr'},
              {label:'국세상담센터 (전화: 126)','url':'https://www.nts.go.kr/nts/cm/cntnts/cntntsView.do?mi=2346&cntntsId=7726'},
            ].map(({label,url})=>(
              <div key={label} className="flex items-center justify-between">
                <span className="text-sm text-slate-800">{label}</span>
                <a href={url} target="_blank" rel="noopener noreferrer" className="text-xs text-[#1e3a5f] hover:text-[#0f172a] underline">{url.replace('https://','')}</a>
              </div>
            ))}
          </div>
        </div>
      </div>}
    </div>
  </div>;
}

// ── 학부모 포털 관리 ──────────────────────────────────────────────────────────
function ParentPortalManager({students,notices,videos,attendance,academyName,setAcademyName,baseUrl,setBaseUrl}){
  const[copied,setCopied]=useState(null);
  const[previewStudent,setPreviewStudent]=useState(null);

  const genPortalLink=student=>{
    const studentVideos=[...videos].filter(v=>v.studentId===student.id)
      .sort((a,b)=>b.date.localeCompare(a.date)).slice(0,5)
      .map(v=>({title:v.title,subject:v.subject,date:v.date,description:v.description,teacherComment:v.teacherComment,commentTeacher:v.commentTeacher,commentDate:v.commentDate}));
    const studentAtt=attendance.filter(a=>a.type==='student'&&a.refId===student.id)
      .sort((a,b)=>b.date.localeCompare(a.date)).slice(0,20);
    const recentNotices=[...notices].sort((a,b)=>b.date.localeCompare(a.date)).slice(0,8)
      .map(n=>({title:n.title,content:n.content,category:n.category,date:n.date,important:n.important}));
    const payload={
      type:'portal',academy:academyName,
      generatedAt:new Date().toISOString().split('T')[0],
      student:{name:student.name,grade:student.grade,parentName:student.grade==='성인'?'본인':(student.parentName||'학부모')},
      notices:recentNotices,videos:studentVideos,attendance:studentAtt
    };
    return`${baseUrl||'학부모앱.html'}#${encodeShare(payload)}`;
  };

  const handleCopy=(student)=>{
    const link=genPortalLink(student);
    copyToClipboard(link,student.grade==='성인'?`${student.name}님 본인 포털 링크가 복사되었습니다!\n카카오톡에 붙여넣기 하세요.`:`${student.parentName||student.name} 학부모님 포털 링크가 복사되었습니다!\n카카오톡에 붙여넣기 하세요.`);
    setCopied(student.id);setTimeout(()=>setCopied(null),2500);
  };

  return<div className="space-y-5">
    <div>
      <h1 className="text-2xl font-bold text-slate-900">학부모 포털 관리</h1>
      <p className="text-slate-600 text-sm mt-1">학부모에게 공유할 링크를 생성하세요 · 카카오톡으로 전송 가능</p>
    </div>

    {/* 설정 카드 */}
    <div className="bg-[#f1f5f9] border border-[#e2e8f0] rounded-2xl p-4 space-y-3">
      <div className="flex items-center gap-2">
        <span className="text-[#1e3a5f] font-semibold text-sm">⚙️ 학원 기본 설정</span>
      </div>
      <div className="grid grid-cols-1 gap-3">
        <div>
          <label className="text-xs text-slate-700 font-medium mb-1 block">학원 이름 (학부모 앱에 표시)</label>
          <input className={inp} value={academyName} onChange={e=>setAcademyName(e.target.value)} placeholder="예: 하모니 피아노 학원"/>
        </div>
        <div>
          <label className="text-xs text-slate-700 font-medium mb-1 block">학부모 앱 주소</label>
          <input className={inp} value={baseUrl} onChange={e=>setBaseUrl(e.target.value)} placeholder="예: https://my-academy.netlify.app/학부모앱.html"/>
          <p className="text-xs text-slate-600 mt-1">🌐 온라인 호스팅 후 주소 입력 · 비워두면 같은 폴더의 학부모앱.html 사용</p>
        </div>
      </div>
    </div>

    {/* 학생별 포털 링크 */}
    <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
      <div className="px-5 py-4 border-b border-gray-100 flex items-center justify-between">
        <div>
          <div className="font-semibold text-slate-900">학생별 학부모 포털 링크</div>
          <div className="text-xs text-slate-600 mt-0.5">링크에는 공지사항(최근 8개), 자녀 영상(최근 5개), 출결 내역(최근 20개)이 포함됩니다</div>
        </div>
      </div>
      <div className="divide-y divide-gray-50">
        {students.map(student=>(
          <div key={student.id} className="flex items-center gap-4 px-5 py-4">
            <div className="w-10 h-10 rounded-full bg-gradient-to-br from-[#2563eb] to-[#1e3a5f] flex items-center justify-center text-white font-bold text-sm shrink-0">
              {student.name[0]}
            </div>
            <div className="flex-1 min-w-0">
              <div className="font-medium text-slate-900">{student.name} <span className="text-sm text-slate-600">({student.level||student.grade})</span></div>
              <div className="text-xs text-slate-600 mt-0.5">
                {student.grade==='성인'?`본인 연락처: ${student.phone||'-'}`:`학부모: ${student.parentName||'-'} · ${student.parentPhone||'-'}`}
              </div>
            </div>
            <div className="flex gap-2 shrink-0">
              <button onClick={()=>setPreviewStudent(previewStudent?.id===student.id?null:student)}
                className="text-xs px-3 py-1.5 rounded-lg bg-gray-100 text-slate-700 hover:bg-gray-200 transition-colors">
                미리보기
              </button>
              <button onClick={()=>handleCopy(student)}
                className={`text-xs px-3 py-1.5 rounded-lg font-medium transition-all ${copied===student.id?'bg-green-100 text-green-700':'bg-[#dbeafe] text-[#1e293b] hover:bg-[#bfdbfe]'}`}>
                {copied===student.id?'✅ 복사완료':'🔗 링크 복사'}
              </button>
            </div>
          </div>
        ))}
        {students.length===0&&<div className="text-center py-12 text-slate-600">등록된 학생이 없습니다</div>}
      </div>
    </div>

    {/* 미리보기 */}
    {previewStudent&&(
      <div className="bg-white rounded-2xl shadow-sm border border-[#e2e8f0] overflow-hidden">
        <div className="px-5 py-3 bg-[#f1f5f9] border-b border-[#e2e8f0] flex items-center justify-between">
          <div className="text-sm font-semibold text-[#1e293b]">👁 링크 미리보기 — {previewStudent.name}</div>
          <button onClick={()=>setPreviewStudent(null)} className="text-slate-600 hover:text-slate-700 text-lg">&times;</button>
        </div>
        <div className="p-4">
          <div className="bg-[#f1f5f9] rounded-xl p-3 break-all text-xs text-slate-600 font-mono mb-3" style={{maxHeight:'80px',overflowY:'auto'}}>
            {genPortalLink(previewStudent)}
          </div>
          <div className="text-xs text-slate-600 space-y-1">
            <div>📢 공지사항 {Math.min(notices.length,8)}개 포함</div>
            <div>🎬 {previewStudent.name} 연습영상 {Math.min(videos.filter(v=>v.studentId===previewStudent.id).length,5)}개 포함</div>
            <div>✅ 출결 기록 {Math.min(attendance.filter(a=>a.type==='student'&&a.refId===previewStudent.id).length,20)}개 포함</div>
          </div>
          <button onClick={()=>handleCopy(previewStudent)}
            className={`w-full mt-3 py-2 rounded-xl text-sm font-semibold transition-all ${copied===previewStudent.id?'bg-green-100 text-green-700':'bg-[#1e3a5f] text-white hover:bg-[#152d4a]'}`}>
            {copied===previewStudent.id?'✅ 복사 완료!':'🔗 이 링크 복사하기'}
          </button>
        </div>
      </div>
    )}

    {/* 사용 안내 */}
    <div className="bg-white rounded-2xl border border-gray-100 p-5">
      <div className="font-semibold text-slate-800 mb-3">📱 카카오톡 발송 방법</div>
      <div className="space-y-3">
        {[
          ['1','링크 복사','학생 이름 오른쪽의 🔗 링크 복사 버튼을 누릅니다'],
          ['2','카카오톡 열기','학부모님과의 1:1 채팅 또는 학원 단체 채팅방을 엽니다'],
          ['3','붙여넣기 & 전송','입력창에 붙여넣기(길게 누르기) 후 전송합니다'],
          ['4','학부모 앱 확인','학부모님이 링크를 누르면 자녀 정보가 바로 열립니다'],
        ].map(([num,title,desc])=>(
          <div key={num} className="flex items-start gap-3">
            <div className="w-6 h-6 rounded-full bg-[#dbeafe] text-[#1e293b] text-xs font-bold flex items-center justify-center shrink-0 mt-0.5">{num}</div>
            <div><div className="text-sm font-semibold text-slate-900">{title}</div>
              <div className="text-xs text-slate-600">{desc}</div></div>
          </div>
        ))}
      </div>
      <div className="mt-4 bg-yellow-50 rounded-xl p-3 border border-yellow-100">
        <div className="text-xs text-yellow-700">
          💡 <strong>온라인 배포 팁</strong>: 더 편리한 사용을 위해 Netlify(netlify.com)에 두 파일을 업로드하면 학부모님이 어디서든 링크를 열 수 있습니다. 완전 무료!
        </div>
      </div>
    </div>
  </div>;
}

// ── 상담 관리 ────────────────────────────────────────────────────────────
function ConsultationManagement({consultations,setConsultations,consultContext,clearConsultContext,teachers,role,loggedInTeacherId}){
  const[modalOpen,setModalOpen]=useState(false);
  const[editTarget,setEditTarget]=useState(null);
  const[confirmId,setConfirmId]=useState(null);
  const[filter,setFilter]=useState('all');
  // 대시보드 신규상담 클릭 시 문의 중인 상담만 필터
  useEffect(()=>{if(consultContext?.filterActive){setFilter('inquiry');}},[consultContext]);
  const[cSortKey,setCSortKey]=useState('date');
  const[cSortDir,setCSortDir]=useState('desc');
  const cSortField=k=>{if(cSortKey===k)setCSortDir(d=>d==='asc'?'desc':'asc');else{setCSortKey(k);setCSortDir('asc');}};
  const cArrow=k=>cSortKey===k?(cSortDir==='asc'?' ▲':' ▼'):'';
  const[form,setForm]=useState({date:today(),name:'',phone:'',grade:'',interestedClass:'',source:'',sourceNote:'',status:'inquiry',trialDate:'',registerDate:'',assignedTeacherId:'',note:''});
  const emptyForm={date:today(),name:'',phone:'',grade:'',interestedClass:'',source:'',sourceNote:'',status:'inquiry',trialDate:'',registerDate:'',assignedTeacherId:role==='teacher'?loggedInTeacherId||'':'',note:''};
  const sources=['소개','인스타그램','페이스북','네이버','현수막','기타'];
  const statuses=['inquiry','trial','registered','dropped'];
  const statusLabels={inquiry:'문의',trial:'체험예정',registered:'등록완료',dropped:'미등록'};
  const statusColors={inquiry:'bg-blue-100 text-blue-700',trial:'bg-yellow-100 text-yellow-700',registered:'bg-green-100 text-green-700',dropped:'bg-gray-100 text-slate-600'};
  const activeTeacherList=(teachers||[]).filter(t=>t.status!=='resigned');
  const teacherName=id=>{const t=(teachers||[]).find(t=>t.id===id);return t?t.name:'';};

  const openAdd=()=>{setEditTarget(null);setForm({...emptyForm,date:today()});setModalOpen(true);};
  const openEdit=c=>{setEditTarget(c);setForm({...emptyForm,...c});setModalOpen(true);};
  const save=()=>{
    if(!form.name||!form.phone||!form.interestedClass){alert('이름, 연락처, 관심수업은 필수입니다.');return;}
    // [21] 등록완료(registered) 시 등록일 필수
    if(form.status==='registered'&&!form.registerDate){alert('등록완료 상태에서는 등록일을 입력해야 합니다.');return;}
    if(editTarget)setConsultations(prev=>prev.map(c=>c.id===editTarget.id?{...form,id:c.id}:c));
    else setConsultations(prev=>[...prev,{...form,id:genId()}]);
    setModalOpen(false);
  };
  const del=id=>{setConsultations(prev=>prev.filter(c=>c.id!==id));setConfirmId(null);};
  // 강사 권한: 자신에게 배정된 상담만 노출
  const visibleConsultations=role==='teacher'&&loggedInTeacherId
    ?consultations.filter(c=>c.assignedTeacherId===loggedInTeacherId)
    :consultations;

  const cGetters={date:c=>c.date||'',name:c=>c.name||'',status:c=>c.status||'',grade:c=>c.grade||''};
  const filtered=[...visibleConsultations.filter(c=>filter==='all'?true:c.status===filter)].sort((a,b)=>{const g=cGetters[cSortKey]||cGetters.date;const av=g(a)||'',bv=g(b)||'';return cSortDir==='asc'?av.localeCompare(bv,'ko'):bv.localeCompare(av,'ko');});
  const thisMonth=new Date().toISOString().slice(0,7);
  const monthInquiries=visibleConsultations.filter(c=>c.date.startsWith(thisMonth)&&c.status==='inquiry').length;
  const trials=visibleConsultations.filter(c=>c.status==='trial'||c.status==='registered').filter(c=>c.trialDate).length;
  const registered=visibleConsultations.filter(c=>c.status==='registered').length;
  const totalInquiries=visibleConsultations.length;
  // 미등록: status==='dropped'인 건만 카운트
  const droppedCount=visibleConsultations.filter(c=>c.status==='dropped').length;
  // 전환율: 체험까지 완료한 사람(등록완료+미등록) 중 등록 비율
  const completedTrials=registered+droppedCount;
  const convRate=completedTrials>0?Math.round((registered/completedTrials)*100):0;

  const sourceStats=visibleConsultations.reduce((a,c)=>{a[c.source]=(a[c.source]||0)+1;return a;},{});

  return<div className="space-y-6">
    <div>
      <h1 className="text-2xl font-bold text-slate-900">상담 관리</h1>
      <p className="text-slate-600 text-sm mt-1">학생 문의에서 등록까지의 전환율을 추적하세요</p>
    </div>
    {consultContext?.filterActive&&<div className="flex items-center justify-between gap-3 px-4 py-3 bg-purple-50 border border-purple-200 rounded-xl">
      <span className="text-sm text-purple-700 font-medium">💬 대시보드에서 이동 — 신규 상담(문의 중) 건만 표시됩니다</span>
      <button onClick={()=>{clearConsultContext&&clearConsultContext();setFilter('all');}} className="text-xs px-2 py-1 bg-purple-100 text-purple-600 rounded hover:bg-purple-200">✕ 전체 보기</button>
    </div>}
    <div className="grid grid-cols-2 md:grid-cols-5 gap-3">
      <div className="bg-white rounded-2xl p-4 shadow-sm border border-slate-200">
        <div className="text-xs text-slate-600 font-semibold mb-1">이번 달 문의</div>
        <div className="text-2xl font-bold text-slate-900">{monthInquiries}</div>
      </div>
      <div className="bg-white rounded-2xl p-4 shadow-sm border border-slate-200">
        <div className="text-xs text-slate-600 font-semibold mb-1">체험 완료</div>
        <div className="text-2xl font-bold text-slate-900">{completedTrials}</div>
      </div>
      <div className="bg-white rounded-2xl p-4 shadow-sm border border-slate-200">
        <div className="text-xs text-slate-600 font-semibold mb-1">등록 완료</div>
        <div className="text-2xl font-bold text-green-700">{registered}</div>
      </div>
      <div className="bg-white rounded-2xl p-4 shadow-sm border border-slate-200">
        <div className="text-xs text-slate-600 font-semibold mb-1">미등록</div>
        <div className="text-2xl font-bold text-red-600">{droppedCount}</div>
      </div>
      <div className={`rounded-2xl p-4 shadow-sm border ${convRate>=50?'bg-green-50 border-green-200':convRate>=30?'bg-yellow-50 border-yellow-200':'bg-red-50 border-red-200'}`}>
        <div className="text-xs font-semibold mb-1 text-slate-600">상담→등록 전환율</div>
        <div className={`text-2xl font-bold ${convRate>=50?'text-green-700':convRate>=30?'text-yellow-700':'text-red-600'}`}>{convRate}%</div>
        <div className="text-xs text-slate-400 mt-1">체험 후 {registered}/{completedTrials}명 등록</div>
      </div>
    </div>

    <div className="flex gap-2 flex-wrap">
      {['all','inquiry','trial','registered','dropped'].map(s=>(
        <button key={s} onClick={()=>setFilter(s)} className={`tab-btn ${filter===s?'active':''}`}>
          {s==='all'?'전체':statusLabels[s]}
        </button>
      ))}
    </div>

    {role!=='teacher'&&<button onClick={openAdd} className={btn('indigo')}>+ 새 상담 추가</button>}
    {role==='teacher'&&<div className="text-sm text-slate-500 bg-slate-50 border border-slate-200 rounded-xl px-4 py-2">내 담당 상담 내역만 표시됩니다. 새 상담 등록은 원장만 가능합니다.</div>}

    <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
      <div className="overflow-x-auto overflow-y-auto tbl-scroll" style={{maxHeight:'calc(100vh - 360px)'}}>
      <table className="w-full text-sm app-table">
        <thead><tr className="border-b">
          <th className="px-4 py-3 text-left text-xs font-bold text-slate-600 cursor-pointer select-none" style={{width:'100px'}} onClick={()=>cSortField('date')}>날짜{cArrow('date')}</th>
            <th className="px-4 py-3 text-left text-xs font-bold text-slate-600 cursor-pointer select-none" style={{width:'90px'}} onClick={()=>cSortField('name')}>이름{cArrow('name')}</th>
            <th className="px-4 py-3 text-left text-xs font-bold text-slate-600 cursor-pointer select-none" style={{width:'70px'}} onClick={()=>cSortField('grade')}>학년{cArrow('grade')}</th>
            <th className="px-4 py-3 text-left text-xs font-bold text-slate-600" style={{width:'100px'}}>관심수업</th>
            <th className="px-4 py-3 text-left text-xs font-bold text-slate-600" style={{width:'90px'}}>유입경로</th>
            <th className="px-4 py-3 text-left text-xs font-bold text-slate-600 cursor-pointer select-none" style={{width:'90px'}} onClick={()=>cSortField('status')}>상태{cArrow('status')}</th>
            <th className="px-4 py-3 text-left text-xs font-bold text-slate-600" style={{width:'90px'}}>담당강사</th>
            <th className="px-4 py-3 text-left text-xs font-bold text-slate-600" style={{width:'100px'}}>체험일</th>
            <th className="px-4 py-3 text-left text-xs font-bold text-slate-600" style={{width:'100px'}}>등록일</th>
            <th className="px-4 py-3 text-left text-xs font-bold text-slate-600" style={{width:'110px'}}>관리</th>
        </tr></thead>
        <tbody>
          {filtered.map(c=><tr key={c.id} className="table-row border-b">
            <td className="px-4 py-3 text-xs text-slate-600">{fDate(c.date)}</td>
            <td className="px-4 py-3 font-semibold text-slate-900">{c.name}</td>
            <td className="px-4 py-3 text-slate-700">{c.grade}</td>
            <td className="px-4 py-3 text-slate-700">{c.interestedClass}</td>
            <td className="px-4 py-3 text-slate-700 text-xs">{c.source}{c.sourceNote&&<span className="text-slate-400"> ({c.sourceNote})</span>}</td>
            <td className="px-4 py-3"><span className={`badge ${statusColors[c.status]}`}>{statusLabels[c.status]}</span></td>
            <td className="px-4 py-3 text-xs text-slate-600">{c.assignedTeacherId?<span className="px-2 py-0.5 rounded-full bg-indigo-50 text-indigo-700 font-medium">{teacherName(c.assignedTeacherId)}</span>:<span className="text-slate-300">-</span>}</td>
            <td className="px-4 py-3 text-xs text-slate-600">{fDate(c.trialDate)}</td>
            <td className="px-4 py-3 text-xs text-slate-600">{c.status==='registered'?fDate(c.registerDate):'-'}</td>
            <td className="px-4 py-3 flex gap-2">
              <button onClick={()=>openEdit(c)} className={btn('gray')} style={{padding:'4px 8px',fontSize:'12px'}}>수정</button>
              {role!=='teacher'&&<button onClick={()=>setConfirmId(c.id)} className={btn('red')} style={{padding:'4px 8px',fontSize:'12px'}}>삭제</button>}
            </td>
          </tr>)}
        </tbody>
      </table>
      </div>
    </div>

    <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-5">
      <h3 className="text-lg font-bold text-slate-900 mb-4">📊 유입경로 분석</h3>
      <div className="grid grid-cols-2 md:grid-cols-3 gap-4">
        {Object.entries(sourceStats).map(([source,count])=>(
          <div key={source} className="border border-slate-200 rounded-xl p-3 text-center">
            <div className="text-2xl font-bold text-slate-900">{count}</div>
            <div className="text-xs text-slate-600 mt-1">{source}</div>
          </div>
        ))}
      </div>
    </div>

    <Modal open={modalOpen} onClose={()=>setModalOpen(false)} title={editTarget?'상담 수정':'새 상담 추가'}>
      <div className="space-y-4">
        <Field label="상담 날짜" required>
          <input type="date" className={inp} value={form.date} onChange={e=>setForm({...form,date:e.target.value})}/>
        </Field>
        <Field label="학생명" required>
          <input className={inp} value={form.name} onChange={e=>setForm({...form,name:e.target.value})} placeholder="예: 김민준"/>
        </Field>
        <Field label="연락처" required>
          <input className={inp} value={form.phone} onChange={e=>setForm({...form,phone:e.target.value})} placeholder="010-0000-0000"/>
        </Field>
        <Field label="학년">
          <input className={inp} value={form.grade} onChange={e=>setForm({...form,grade:e.target.value})} placeholder="초3, 중1, 고1 등"/>
        </Field>
        <Field label="관심 수업" required>
          <input className={inp} value={form.interestedClass} onChange={e=>setForm({...form,interestedClass:e.target.value})} placeholder="피아노 기초반"/>
        </Field>
        <Field label="유입경로">
          <select className={inp} value={form.source} onChange={e=>setForm({...form,source:e.target.value,sourceNote:''})}>
            <option value="">선택</option>
            {sources.map(s=><option key={s} value={s}>{s}</option>)}
          </select>
          {form.source==='기타'&&<input className={`${inp} mt-2`} placeholder="기타 유입경로 상세 입력 (예: 지인소개, 유튜브...)" value={form.sourceNote||''} onChange={e=>setForm({...form,sourceNote:e.target.value})}/>}
        </Field>
        <Field label="상태">
          <select className={inp} value={form.status} onChange={e=>setForm({...form,status:e.target.value})}>
            {statuses.map(s=><option key={s} value={s}>{statusLabels[s]}</option>)}
          </select>
        </Field>
        <Field label="체험일">
          <input type="date" className={inp} value={form.trialDate} onChange={e=>setForm({...form,trialDate:e.target.value})}/>
        </Field>
        {form.status==='registered'&&<Field label="등록일" required>
          <input type="date" className={inp} value={form.registerDate} onChange={e=>setForm({...form,registerDate:e.target.value})}/>
        </Field>}
        <Field label="담당강사">
          {role==='teacher'
            ?<div className={`${inp} bg-gray-50 text-slate-700`}>{teacherName(loggedInTeacherId)||'(본인)'}</div>
            :<select className={inp} value={form.assignedTeacherId||''} onChange={e=>setForm({...form,assignedTeacherId:e.target.value})}>
              <option value="">미배정</option>
              {activeTeacherList.map(t=><option key={t.id} value={t.id}>{t.name}{(t.subjects||[]).length>0?` (${(t.subjects||[]).join(', ')})`:''}</option>)}
            </select>
          }
        </Field>
        <Field label="비고">
          <textarea className={inp} value={form.note} onChange={e=>setForm({...form,note:e.target.value})} rows={2} placeholder="특이사항 메모"/>
        </Field>
        <div className="flex gap-3 justify-end pt-2">
          <button onClick={save} className={btn('indigo')}>저장</button>
          <button onClick={()=>setModalOpen(false)} className={btn('gray')}>취소</button>
        </div>
      </div>
    </Modal>
    <Confirm open={confirmId!==null} msg="이 상담 기록을 삭제하시겠습니까?" onYes={()=>del(confirmId)} onNo={()=>setConfirmId(null)}/>
  </div>;
}

// ── 학원 캘린더 ──────────────────────────────────────────────────────────────
function CalendarView({events,setEvents,consultations,makeups,notices,setNotices,role,loggedInTeacherId,students,classes}){
  const[month,setMonth]=useState(new Date());
  const[modalOpen,setModalOpen]=useState(false);
  const[editTarget,setEditTarget]=useState(null);
  const[confirmId,setConfirmId]=useState(null);
  const[form,setForm]=useState({date:today(),title:'',type:'행사',note:''});
  const[addToNotice,setAddToNotice]=useState(false);
  const eventTypes=[{val:'행사',color:'bg-purple-100 text-purple-700'},{val:'휴원',color:'bg-red-100 text-red-700'},{val:'시험',color:'bg-orange-100 text-orange-700'},{val:'기타',color:'bg-gray-100 text-slate-600'}];

  const prevMonth=()=>setMonth(new Date(month.getFullYear(),month.getMonth()-1));
  const nextMonth=()=>setMonth(new Date(month.getFullYear(),month.getMonth()+1));

  const firstDay=new Date(month.getFullYear(),month.getMonth(),1).getDay();
  const daysInMonth=new Date(month.getFullYear(),month.getMonth()+1,0).getDate();
  const days=Array(firstDay).fill(null).concat(Array.from({length:daysInMonth},(_, i)=>i+1));

  const openAdd=()=>{setEditTarget(null);setForm({date:today(),title:'',type:'행사',note:''});setAddToNotice(false);setModalOpen(true);};
  const openEdit=e=>{setEditTarget(e);setForm({date:e.date,title:e.title,type:e.type,note:e.note||''});setAddToNotice(false);setModalOpen(true);};
  const del=id=>{setEvents(prev=>prev.filter(e=>e.id!==id));setConfirmId(null);};
  const save=()=>{
    if(!form.title){alert('제목은 필수입니다.');return;}
    if(editTarget){
      setEvents(prev=>prev.map(e=>e.id===editTarget.id?{...form,id:e.id}:e));
    }else{
      setEvents(prev=>[...prev,{...form,id:genId()}]);
      if(addToNotice&&setNotices){
        const catMap={'행사':'행사','휴원':'공지','시험':'안내','기타':'안내'};
        setNotices(prev=>[{id:genId(),date:form.date,category:catMap[form.type]||'공지',title:form.title,content:form.note||form.title,target:'전체',important:false},...prev]);
      }
    }
    setModalOpen(false);
  };

  // 상담 체험일·보강일·공지사항을 캘린더용 이벤트로 변환
  const consultEvents=(consultations||[]).filter(c=>c.trialDate).map(c=>({_id:c.id,date:c.trialDate,title:`[체험] ${c.name}`,type:'상담',color:'bg-yellow-100 text-yellow-700',_readonly:true}));
  // 강사 계정: 본인 담당 수업에 등록된 학생의 보강만 표시
  const myStudentIds=role==='teacher'&&loggedInTeacherId&&students&&classes
    ?new Set((classes||[]).filter(c=>c.teacherId===loggedInTeacherId&&!(c.closeDate&&c.closeDate<=today())).flatMap(c=>(students||[]).filter(s=>s.status!=='withdrawn'&&(s.enrolledClasses||[]).includes(c.id)).map(s=>s.id)))
    :null;
  const makeupEvents=(makeups||[]).filter(m=>m.makeupDate&&m.status!=='unscheduled'&&(!myStudentIds||myStudentIds.has(m.studentId))).map(m=>({_id:m.id,date:m.makeupDate,title:`[보강] ${m.studentName||''}${m.makeupStartTime?' '+m.makeupStartTime:''}${m.room?' @'+m.room:''}`,type:'보강',color:m.status==='completed'?'bg-green-100 text-green-700':'bg-sky-100 text-sky-700',_readonly:true}));
  // [22] 공지사항 캘린더 표시
  const noticeEvents=(notices||[]).map(n=>({_id:n.id,date:n.date,title:`[공지] ${n.title}`,type:'공지',color:n.category==='긴급'?'bg-red-100 text-red-700':n.category==='행사'?'bg-green-100 text-green-700':'bg-blue-100 text-blue-700',_readonly:true}));

  const getEventsForDay=day=>{
    if(!day)return[];
    const dateStr=`${month.getFullYear()}-${String(month.getMonth()+1).padStart(2,'0')}-${String(day).padStart(2,'0')}`;
    const base=events.filter(e=>e.date===dateStr).map(e=>({...e,color:eventTypes.find(t=>t.val===e.type)?.color||'bg-gray-100 text-slate-600'}));
    const cEvt=consultEvents.filter(e=>e.date===dateStr);
    const mEvt=makeupEvents.filter(e=>e.date===dateStr);
    const nEvt=noticeEvents.filter(e=>e.date===dateStr);
    return[...base,...cEvt,...mEvt,...nEvt];
  };

  const dayNames=['일','월','화','수','목','금','토'];
  const todayStr=today();
  const ym=month.getFullYear()+'-'+String(month.getMonth()+1).padStart(2,'0');
  const thisMonthEvents=events.filter(e=>e.date.startsWith(ym));
  const thisMonthConsult=consultEvents.filter(e=>e.date.startsWith(ym));
  const thisMonthMakeup=makeupEvents.filter(e=>e.date.startsWith(ym));
  const thisMonthNotices=noticeEvents.filter(e=>e.date.startsWith(ym));
  const allThisMonth=[...thisMonthEvents.map(e=>({...e,color:eventTypes.find(t=>t.val===e.type)?.color||'bg-gray-100 text-slate-600'})),...thisMonthConsult,...thisMonthMakeup,...thisMonthNotices].sort((a,b)=>a.date.localeCompare(b.date));
  // 오늘 일정 — 실제 오늘 날짜 기준 (표시 중인 월과 무관)
  const todayEvents=[
    ...events.filter(e=>e.date===todayStr).map(e=>({...e,color:eventTypes.find(t=>t.val===e.type)?.color||'bg-gray-100 text-slate-600'})),
    ...consultEvents.filter(e=>e.date===todayStr),
    ...makeupEvents.filter(e=>e.date===todayStr),
    ...noticeEvents.filter(e=>e.date===todayStr)
  ];

  return<div className="space-y-6">
    <div>
      <h1 className="text-2xl font-bold text-slate-900">학원 캘린더</h1>
      <p className="text-slate-600 text-sm mt-1">학원 행사, 휴원, 시험 일정을 관리하세요</p>
    </div>

    <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
      <div className="lg:col-span-2">
        <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-5">
          <div className="flex items-center justify-between mb-4">
            <button onClick={prevMonth} className={btn('gray')} style={{padding:'6px 12px',fontSize:'12px'}}>◀ 이전</button>
            <h2 className="text-lg font-bold text-slate-900">{month.getFullYear()}년 {month.getMonth()+1}월</h2>
            <button onClick={nextMonth} className={btn('gray')} style={{padding:'6px 12px',fontSize:'12px'}}>다음 ▶</button>
          </div>

          <table className="w-full mb-4" style={{tableLayout:'fixed',borderCollapse:'collapse'}}>
            <thead><tr>
              {dayNames.map((d,i)=><th key={d} className="px-2 py-2 text-xs font-bold text-center" style={{width:'14.28%',color:i===0?'#ef4444':i===6?'#3b82f6':'#475569'}}>{d}</th>)}
            </tr></thead>
            <tbody>
              {Array(Math.ceil(days.length/7)).fill(null).map((_, week)=>(
                <tr key={week}>
                  {days.slice(week*7, (week+1)*7).map((day, idx)=>{
                    const dateStr=day?`${month.getFullYear()}-${String(month.getMonth()+1).padStart(2,'0')}-${String(day).padStart(2,'0')}`:'';
                    const dayEvents=getEventsForDay(day);
                    const isToday=dateStr===todayStr;
                    return(
                      <td key={idx} className={`border p-1.5 text-xs align-top ${!day?'bg-gray-50':(isToday?'border-2 border-[#1e3a5f]':'')}`} style={{height:'96px',minHeight:'96px',maxHeight:'96px',overflow:'hidden',width:'14.28%',verticalAlign:'top'}}>
                        {day&&<div className={isToday?'font-bold text-[#1e3a5f]':idx%7===0?'text-red-500':idx%7===6?'text-blue-500':'text-slate-900'}>{day}</div>}
                        <div className="mt-0.5 space-y-0.5 overflow-hidden" style={{maxHeight:'70px'}}>
                          {dayEvents.slice(0,3).map((e,i)=>(
                            <div key={i} onClick={(e._readonly||role==='teacher')?undefined:()=>openEdit(e)} className={`badge text-xs ${e.color||'bg-gray-100 text-slate-600'} w-full truncate ${(e._readonly||role==='teacher')?'cursor-default opacity-90':'cursor-pointer hover:opacity-80'}`} style={{display:'block',overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap'}}>{e.title}</div>
                          ))}
                          {dayEvents.length>3&&<div className="text-xs text-slate-500">+{dayEvents.length-3}개</div>}
                        </div>
                      </td>
                    );
                  })}
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      <div className="space-y-4">
        <div className="bg-amber-50 border border-amber-200 rounded-2xl p-4">
          <h3 className="font-bold text-amber-800 mb-2 text-sm">오늘의 일정 ({todayStr} · {todayEvents.length}건)</h3>
          {todayEvents.length>0?(
            <div className="space-y-1.5">
              {todayEvents.map((e,i)=>(
                <div key={i} className={`flex items-center gap-2 px-2 py-1 rounded-lg ${e.color||'bg-white'}`}>
                  <span className="text-xs font-bold shrink-0">{e.type}</span>
                  <span className="text-xs flex-1 truncate">{e.title}</span>
                </div>
              ))}
            </div>
          ):(
            <div className="text-xs text-amber-600 text-center py-2">오늘 등록된 일정이 없습니다</div>
          )}
        </div>
        <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-5">
          <div className="flex items-center justify-between mb-4">
            <h3 className="font-bold text-slate-900">📅 이번 달 일정</h3>
            {role!=='teacher'&&<button onClick={openAdd} className={btn('indigo')} style={{padding:'6px 12px',fontSize:'12px'}}>+ 추가</button>}
          </div>
          <div className="space-y-2 overflow-y-auto" style={{maxHeight:'400px'}}>
            {allThisMonth.length===0?(
              <div className="text-center text-slate-600 py-8">일정이 없습니다</div>
            ):(
              allThisMonth.map((e,i)=>(
                <div key={e.id||e._id||i} className="border border-slate-200 rounded-lg p-2.5">
                  <div className="flex items-center justify-between mb-1">
                    <span className={`badge text-xs ${e.color||'bg-gray-100 text-slate-600'}`}>{e.type}</span>
                    <span className="text-xs text-slate-600">{fDate(e.date)}</span>
                  </div>
                  <div className="flex items-start justify-between gap-2">
                    <div className="flex-1 min-w-0">
                      <div className="font-semibold text-sm text-slate-900">{e.title}</div>
                      {e.note&&<div className="text-xs text-slate-600 mt-1">{e.note}</div>}
                    </div>
                    {!e._readonly&&role!=='teacher'&&<div className="flex gap-1 shrink-0">
                      <button onClick={()=>openEdit(e)} className="text-xs px-2 py-0.5 bg-indigo-50 text-indigo-600 rounded hover:bg-indigo-100">수정</button>
                      {confirmId===e.id?(
                        <span className="flex gap-1">
                          <button onClick={()=>del(e.id)} className="text-xs px-2 py-0.5 bg-red-500 text-white rounded hover:bg-red-600">확인</button>
                          <button onClick={()=>setConfirmId(null)} className="text-xs px-2 py-0.5 bg-slate-200 text-slate-600 rounded hover:bg-slate-300">취소</button>
                        </span>
                      ):(
                        <button onClick={()=>setConfirmId(e.id)} className="text-xs px-2 py-0.5 bg-red-50 text-red-500 rounded hover:bg-red-100">삭제</button>
                      )}
                    </div>}
                  </div>
                </div>
              ))
            )}
          </div>
        </div>
      </div>
    </div>

    <Modal open={modalOpen} onClose={()=>{setModalOpen(false);setEditTarget(null);}} title={editTarget?'일정 수정':'새 일정 추가'}>
      <div className="space-y-4">
        <Field label="날짜" required>
          <input type="date" className={inp} value={form.date} onChange={e=>setForm({...form,date:e.target.value})}/>
        </Field>
        <Field label="제목" required>
          <input className={inp} value={form.title} onChange={e=>setForm({...form,title:e.target.value})} placeholder="행사 이름"/>
        </Field>
        <Field label="유형">
          <select className={inp} value={form.type} onChange={e=>setForm({...form,type:e.target.value})}>
            {eventTypes.map(t=><option key={t.val} value={t.val}>{t.val}</option>)}
          </select>
        </Field>
        <Field label="메모">
          <textarea className={inp} value={form.note} onChange={e=>setForm({...form,note:e.target.value})} rows={3} placeholder="세부 사항"/>
        </Field>
        {!editTarget&&<div className="flex items-center gap-2 px-1 pb-1">
          <input type="checkbox" id="calNoticeChk" checked={addToNotice} onChange={e=>setAddToNotice(e.target.checked)} className="w-4 h-4 accent-indigo-600"/>
          <label htmlFor="calNoticeChk" className="text-sm text-slate-700 cursor-pointer">공지사항에도 자동 등록</label>
        </div>}
        <div className="flex gap-3 justify-end pt-2">
          <button onClick={save} className={btn('indigo')}>저장</button>
          <button onClick={()=>setModalOpen(false)} className={btn('gray')}>취소</button>
        </div>
      </div>
    </Modal>
  </div>;
}

// ── 보강 관리 ────────────────────────────────────────────────────────────
function MakeupManagement({makeups,setMakeups,students,classes,teachers,role,loggedInTeacherId}){
  const[modalOpen,setModalOpen]=useState(false);
  const[editTarget,setEditTarget]=useState(null);
  const[confirmId,setConfirmId]=useState(null);
  const[filter,setFilter]=useState('all');
  // [19] 강사 결석 일괄 보강 등록 모달
  const[bulkModalOpen,setBulkModalOpen]=useState(false);
  const[bulkTeacherId,setBulkTeacherId]=useState('');
  const[bulkAbsenceDate,setBulkAbsenceDate]=useState(today());
  const[bulkClassId,setBulkClassId]=useState('');
  const[bulkNote,setBulkNote]=useState('');
  const[bulkSelected,setBulkSelected]=useState(new Set());
  const[bulkMakeupDate,setBulkMakeupDate]=useState('');
  const[bulkRoom,setBulkRoom]=useState('');
  const[bulkStartTime,setBulkStartTime]=useState('');
  const[bulkEndTime,setBulkEndTime]=useState('');
  const openBulkModal=()=>{setBulkTeacherId('');setBulkAbsenceDate(today());setBulkClassId('');setBulkNote('');setBulkSelected(new Set());setBulkMakeupDate('');setBulkRoom('');setBulkStartTime('');setBulkEndTime('');setBulkModalOpen(true);};
  const bulkTeacherClasses=bulkTeacherId?(classes||[]).filter(c=>c.teacherId===bulkTeacherId&&!(c.closeDate&&c.closeDate<=today())):[];
  const bulkStudents=bulkClassId?(students||[]).filter(s=>s.status!=='withdrawn'&&(!s.joinDate||s.joinDate<=today())&&(s.enrolledClasses||[]).includes(bulkClassId)):[];
  const toggleBulkStudent=id=>setBulkSelected(prev=>{const n=new Set(prev);n.has(id)?n.delete(id):n.add(id);return n;});
  const toggleBulkAll=()=>setBulkSelected(prev=>prev.size===bulkStudents.length?new Set():new Set(bulkStudents.map(s=>s.id)));
  // 시간 → 분 변환 (충돌 감지용)
  const timeToMin=t=>{if(!t)return-1;const[h,m]=(t||'0:0').split(':').map(Number);return(h||0)*60+(m||0);};
  // 충돌 감지: 강의실+날짜+시간이 기존 보강 또는 정규수업과 겹치는지 확인
  const checkBulkConflict=(room,date,st,et)=>{
    if(!room||!date||!st||!et)return[];
    const sM=timeToMin(st),eM=timeToMin(et);
    const conflicts=[];
    // 기존 보강 충돌
    for(const m of makeups){
      if(m.room!==room||m.makeupDate!==date||!m.makeupStartTime||!m.makeupEndTime)continue;
      const mS=timeToMin(m.makeupStartTime),mE=timeToMin(m.makeupEndTime);
      if(sM<mE&&mS<eM)conflicts.push(`보강: ${m.studentName} (${m.makeupStartTime}~${m.makeupEndTime})`);
    }
    // 정규수업 충돌 (해당 요일)
    const dayOfWeek=new Date(date).getDay();
    for(const c of (classes||[])){
      if(c.room!==room||!(c.days||[]).includes(dayOfWeek)||!c.startTime||!c.endTime)continue;
      const cS=timeToMin(c.startTime),cE=timeToMin(c.endTime);
      if(sM<cE&&cS<eM)conflicts.push(`정규수업: ${c.name} (${c.startTime}~${c.endTime})`);
    }
    return conflicts;
  };
  const bulkConflicts=checkBulkConflict(bulkRoom,bulkMakeupDate,bulkStartTime,bulkEndTime);
  const saveBulk=()=>{
    if(!bulkTeacherId||!bulkAbsenceDate||!bulkClassId){alert('강사, 결석일, 수업은 필수입니다.');return;}
    if(bulkSelected.size===0){alert('보강 등록할 학생을 한 명 이상 선택하세요.');return;}
    if(bulkStartTime&&bulkEndTime&&timeToMin(bulkEndTime)<=timeToMin(bulkStartTime)){alert('종료 시간은 시작 시간보다 늦어야 합니다.');return;}
    if(bulkConflicts.length>0){
      const ok=confirm(`⚠️ 강의실 시간이 겹칩니다!\n${bulkConflicts.join('\n')}\n\n그래도 등록하시겠습니까?`);
      if(!ok)return;
    }
    const cls=classes.find(c=>c.id===bulkClassId);
    const selectedStudents=bulkStudents.filter(s=>bulkSelected.has(s.id));
    const mkStatus=(bulkMakeupDate&&bulkStartTime)?'pending':'unscheduled';
    const newMakeups=selectedStudents.map(s=>({
      id:genId(),studentId:s.id,studentName:s.name,classId:bulkClassId,className:cls?.name||'',
      absenceDate:bulkAbsenceDate,makeupDate:bulkMakeupDate||'',makeupStartTime:bulkStartTime||'',makeupEndTime:bulkEndTime||'',room:bulkRoom||'',status:mkStatus,note:bulkNote||'강사 결석으로 인한 일괄 보강 등록'
    }));
    // 이미 같은 날, 같은 수업, 같은 학생의 보강이 있으면 중복 등록 방지
    const existingKeys=new Set(makeups.map(m=>`${m.studentId}_${m.classId}_${m.absenceDate}`));
    const toAdd=newMakeups.filter(m=>!existingKeys.has(`${m.studentId}_${m.classId}_${m.absenceDate}`));
    const skipped=newMakeups.length-toAdd.length;
    setMakeups(prev=>[...prev,...toAdd]);
    setBulkModalOpen(false);
    alert(`${toAdd.length}명의 보강이 등록되었습니다.${skipped>0?` (중복 ${skipped}건 제외)`:''}`);
  };
  // 반별로 보기 필터 (Austin님 피드백[18]: 학생 수가 많아지면(예: 200명) 보강 목록을
  // 계속 스크롤해야 해서 불편하다는 지적 → 반을 하나 선택하면 그 반의 보강 건만 보여서 스크롤이 줄어듦)
  const[classFilter,setClassFilter]=useState('all');
  const[mkSortKey,setMkSortKey]=useState('absenceDate');
  const[mkSortDir,setMkSortDir]=useState('desc');
  const mkSortField=k=>{if(mkSortKey===k)setMkSortDir(d=>d==='asc'?'desc':'asc');else{setMkSortKey(k);setMkSortDir('asc');}};
  const mkArrow=k=>mkSortKey===k?(mkSortDir==='asc'?' ▲':' ▼'):'';
  const[listSelected,setListSelected]=useState(new Set());
  const[bulkEditOpen,setBulkEditOpen]=useState(false);
  const[bulkEditForm,setBulkEditForm]=useState({makeupDate:'',makeupStartTime:'',makeupEndTime:'',room:'',status:'unscheduled',note:''});
  const[bulkEditApply,setBulkEditApply]=useState({makeupDate:false,time:false,room:false,status:false,note:false});
  const toggleListSelect=id=>setListSelected(prev=>{const n=new Set(prev);n.has(id)?n.delete(id):n.add(id);return n;});
  const toggleListAll=()=>setListSelected(prev=>prev.size===filtered.length?new Set():new Set(filtered.map(m=>m.id)));
  const openBulkEdit=()=>{setBulkEditForm({makeupDate:'',makeupStartTime:'',makeupEndTime:'',room:'',status:'unscheduled',note:''});setBulkEditApply({makeupDate:false,time:false,room:false,status:false,note:false});setBulkEditOpen(true);};
  const checkBulkEditConflicts=()=>{
    const conflicts=[];
    const seen=new Set();
    for(const m of makeups.filter(x=>listSelected.has(x.id))){
      const newDate=bulkEditApply.makeupDate?bulkEditForm.makeupDate:m.makeupDate;
      const newRoom=bulkEditApply.room?bulkEditForm.room:m.room;
      const newSt=bulkEditApply.time?bulkEditForm.makeupStartTime:m.makeupStartTime;
      const newEt=bulkEditApply.time?bulkEditForm.makeupEndTime:m.makeupEndTime;
      if(!newRoom||!newDate||!newSt||!newEt)continue;
      const sM=timeToMin(newSt),eM=timeToMin(newEt);
      for(const other of makeups){
        if(listSelected.has(other.id)||other.room!==newRoom||other.makeupDate!==newDate||!other.makeupStartTime||!other.makeupEndTime)continue;
        const oS=timeToMin(other.makeupStartTime),oE=timeToMin(other.makeupEndTime);
        if(sM<oE&&oS<eM){const k=`보강: ${other.studentName} (${other.makeupStartTime}~${other.makeupEndTime})`;if(!seen.has(k)){seen.add(k);conflicts.push(k);}}
      }
      const dow=new Date(newDate).getDay();
      for(const c of(classes||[])){
        if(c.room!==newRoom||!(c.days||[]).includes(dow)||!c.startTime||!c.endTime)continue;
        const cS=timeToMin(c.startTime),cE=timeToMin(c.endTime);
        if(sM<cE&&cS<eM){const k=`정규수업: ${c.name} (${c.startTime}~${c.endTime})`;if(!seen.has(k)){seen.add(k);conflicts.push(k);}}
      }
    }
    return conflicts;
  };
  const saveBulkEdit=()=>{
    if(!Object.values(bulkEditApply).some(Boolean)){alert('수정할 항목을 하나 이상 체크하세요.');return;}
    if(bulkEditApply.time&&bulkEditForm.makeupStartTime&&bulkEditForm.makeupEndTime&&timeToMin(bulkEditForm.makeupEndTime)<=timeToMin(bulkEditForm.makeupStartTime)){alert('종료 시간은 시작 시간보다 늦어야 합니다.');return;}
    const conflicts=checkBulkEditConflicts();
    if(conflicts.length>0){
      const ok=confirm(`⚠️ 강의실 시간이 겹칩니다!\n${conflicts.join('\n')}\n\n그래도 수정하시겠습니까?`);
      if(!ok)return;
    }
    const count=listSelected.size;
    setMakeups(prev=>prev.map(m=>{
      if(!listSelected.has(m.id))return m;
      const u={...m};
      if(bulkEditApply.makeupDate){u.makeupDate=bulkEditForm.makeupDate;if(bulkEditForm.makeupDate&&u.status==='unscheduled')u.status='pending';}
      if(bulkEditApply.time){u.makeupStartTime=bulkEditForm.makeupStartTime;u.makeupEndTime=bulkEditForm.makeupEndTime;}
      if(bulkEditApply.room)u.room=bulkEditForm.room;
      if(bulkEditApply.status)u.status=bulkEditForm.status;
      if(bulkEditApply.note)u.note=bulkEditForm.note;
      return u;
    }));
    setBulkEditOpen(false);setListSelected(new Set());
    alert(`${count}건이 수정되었습니다.`);
  };
  const[form,setForm]=useState({studentId:'',studentName:'',classId:'',className:'',absenceDate:today(),makeupDate:'',makeupStartTime:'',makeupEndTime:'',room:'',status:'unscheduled',note:''});
  const emptyForm={studentId:'',studentName:'',classId:'',className:'',absenceDate:today(),makeupDate:'',makeupStartTime:'',makeupEndTime:'',room:'',status:'unscheduled',note:''};
  const makeupRooms=['1레슨실','2레슨실','3레슨실','그룹레슨실','이론강의실','발표홀'];

  const openAdd=()=>{setEditTarget(null);setForm(emptyForm);setModalOpen(true);};
  const openEdit=m=>{setEditTarget(m);setForm(m);setModalOpen(true);};
  const checkRoomConflict=(f,excludeId)=>{
    if(!f.room||!f.makeupDate||!f.makeupStartTime||!f.makeupEndTime)return null;
    const sMin=timeToMin(f.makeupStartTime),eMin=timeToMin(f.makeupEndTime);
    for(const m of makeups){
      if(m.id===excludeId||m.room!==f.room||m.makeupDate!==f.makeupDate)continue;
      if(!m.makeupStartTime||!m.makeupEndTime)continue;
      const mS=timeToMin(m.makeupStartTime),mE=timeToMin(m.makeupEndTime);
      if(sMin<mE&&mS<eMin)return m;
    }
    return null;
  };
  // [Bug Fix] 보강관리 개별 등록 시 정규수업 충돌 체크 추가 (일괄 등록엔 있었으나 개별 등록에는 누락)
  const checkRegularClassConflict=(f)=>{
    if(!f.room||!f.makeupDate||!f.makeupStartTime||!f.makeupEndTime)return null;
    const sMin=timeToMin(f.makeupStartTime),eMin=timeToMin(f.makeupEndTime);
    const dow=new Date(f.makeupDate).getDay();
    for(const c of (classes||[])){
      if(c.room!==f.room||!(c.days||[]).includes(dow)||!c.startTime||!c.endTime)continue;
      const cS=timeToMin(c.startTime),cE=timeToMin(c.endTime);
      if(sMin<cE&&cS<eMin)return c;
    }
    return null;
  };
  const save=()=>{
    if(!form.studentId||!form.classId){alert('학생과 수업은 필수입니다.');return;}
    if(form.makeupStartTime&&form.makeupEndTime&&timeToMin(form.makeupEndTime)<=timeToMin(form.makeupStartTime)){alert('종료 시간은 시작 시간보다 늦어야 합니다.');return;}
    // [Bug Fix] 신규 등록 시 같은 학생+수업+결석일 중복 등록 방지 (출결관리·일괄 등록엔 있었으나 개별 등록에는 누락)
    if(!editTarget){
      const dupKey=`${form.studentId}_${form.classId}_${form.absenceDate}`;
      if(makeups.some(m=>`${m.studentId}_${m.classId}_${m.absenceDate}`===dupKey)){
        alert('이미 같은 학생·수업·결석일의 보강이 등록되어 있습니다.\n수정이 필요하면 목록에서 해당 건을 선택해 편집하세요.');
        return;
      }
    }
    const mkConflict=checkRoomConflict(form,editTarget?.id);
    const clsConflict=!mkConflict?checkRegularClassConflict(form):null;
    if(mkConflict||clsConflict){
      const msg=mkConflict
        ?`${form.room}에 ${fDate(form.makeupDate)} ${form.makeupStartTime}~${form.makeupEndTime}\n이미 "${mkConflict.studentName}" 학생의 보강이 예약되어 있습니다.`
        :`${form.room}에 ${fDate(form.makeupDate)} ${form.makeupStartTime}~${form.makeupEndTime}\n정규수업 "${clsConflict.name}"과 시간이 겹칩니다.`;
      const confirmed=confirm(`⚠️ 강의실 시간이 겹칩니다!\n${msg}\n\n그래도 저장하시겠습니까?`);
      if(!confirmed)return;
    }
    if(editTarget)setMakeups(prev=>prev.map(m=>m.id===editTarget.id?{...form,id:m.id}:m));
    else setMakeups(prev=>[...prev,{...form,id:genId()}]);
    setModalOpen(false);
  };
  const del=id=>{setMakeups(prev=>prev.filter(m=>m.id!==id));setConfirmId(null);};
  const updateStatus=(id,status)=>{setMakeups(prev=>prev.map(m=>m.id===id?{...m,status}:m));};

  const baseMakeups=role==='teacher'&&loggedInTeacherId
    ?makeups.filter(m=>{const cls=classes.find(c=>c.id===m.classId);return cls&&cls.teacherId===loggedInTeacherId;})
    :makeups;
  const filtered=baseMakeups.filter(m=>(filter==='all'?true:m.status===filter)&&(classFilter==='all'?true:m.classId===classFilter));
  const unscheduled=baseMakeups.filter(m=>m.status==='unscheduled').length;
  const pending=baseMakeups.filter(m=>m.status==='pending').length;
  const completed=baseMakeups.filter(m=>m.status==='completed').length;

  return<div className="space-y-6">
    <div>
      <h1 className="text-2xl font-bold text-slate-900">보강 관리</h1>
      <p className="text-slate-600 text-sm mt-1">결석한 학생의 보강 수업을 예약하세요</p>
    </div>

    <div className="grid grid-cols-3 gap-3">
      <div className="bg-red-50 rounded-2xl p-4 shadow-sm border border-red-100">
        <div className="text-xs text-red-600 font-semibold mb-1">미예약 보강</div>
        <div className="text-2xl font-bold text-red-700">{unscheduled}</div>
      </div>
      <div className="bg-yellow-50 rounded-2xl p-4 shadow-sm border border-yellow-100">
        <div className="text-xs text-yellow-600 font-semibold mb-1">예정 보강</div>
        <div className="text-2xl font-bold text-yellow-700">{pending}</div>
      </div>
      <div className="bg-green-50 rounded-2xl p-4 shadow-sm border border-green-100">
        <div className="text-xs text-green-600 font-semibold mb-1">완료 보강</div>
        <div className="text-2xl font-bold text-green-700">{completed}</div>
      </div>
    </div>

    <div className="flex items-center gap-3 flex-wrap">
      <div className="flex gap-2 flex-wrap">
        {['all','unscheduled','pending','completed'].map(s=>(
          <button key={s} onClick={()=>setFilter(s)} className={`tab-btn ${filter===s?'active':''}`}>
            {s==='all'?'전체':s==='unscheduled'?'미예약':s==='pending'?'예정':'완료'}
          </button>
        ))}
      </div>
      <div className="flex items-center gap-2 ml-auto">
        <span className="text-xs font-semibold text-slate-600">반별로 보기</span>
        <select className={inp} style={{width:'200px'}} value={classFilter} onChange={e=>setClassFilter(e.target.value)}>
          <option value="all">전체 반 보기</option>
          {classes.filter(c=>!(c.closeDate&&c.closeDate<=today())).sort((a,b)=>a.name.localeCompare(b.name,'ko')).map(c=><option key={c.id} value={c.id}>{c.name}</option>)}
        </select>
      </div>
    </div>

    <div className="flex gap-2 flex-wrap items-center">
      <button onClick={openAdd} className={btn('indigo')}>+ 개별 보강 추가</button>
      {role!=='teacher'&&<button onClick={openBulkModal} className={btn('orange')}>강사 결석 일괄 보강 등록</button>}
      {listSelected.size>0&&<>
        <button onClick={openBulkEdit} className={btn('teal')} style={{background:'#0d9488',color:'#fff'}}>선택 {listSelected.size}건 일괄 수정</button>
        <button onClick={()=>setListSelected(new Set())} className={btn('gray')}>선택 해제</button>
      </>}
    </div>

    <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
      <div className="overflow-x-auto overflow-y-auto tbl-scroll" style={{maxHeight:'calc(100vh - 320px)'}}>
      <table className="w-full text-sm app-table">
        <thead><tr className="border-b">
          <th className="px-4 py-3 text-center" style={{width:'36px'}}><input type="checkbox" checked={listSelected.size===filtered.length&&filtered.length>0} onChange={toggleListAll} className="accent-indigo-600" title="전체 선택/해제"/></th>
          <th className="px-4 py-3 text-left text-xs font-bold text-slate-600 cursor-pointer select-none" style={{width:'90px'}} onClick={()=>mkSortField('studentName')}>학생{mkArrow('studentName')}</th>
          <th className="px-4 py-3 text-left text-xs font-bold text-slate-600 cursor-pointer select-none" style={{width:'110px'}} onClick={()=>mkSortField('className')}>수업{mkArrow('className')}</th>
          <th className="px-4 py-3 text-left text-xs font-bold text-slate-600 cursor-pointer select-none" style={{width:'100px'}} onClick={()=>mkSortField('absenceDate')}>결석일{mkArrow('absenceDate')}</th>
          <th className="px-4 py-3 text-left text-xs font-bold text-slate-600 cursor-pointer select-none" style={{width:'110px'}} onClick={()=>mkSortField('makeupDate')}>보강예정일{mkArrow('makeupDate')}</th>
          <th className="px-4 py-3 text-left text-xs font-bold text-slate-600" style={{width:'80px'}}>시간</th>
          <th className="px-4 py-3 text-left text-xs font-bold text-slate-600" style={{width:'80px'}}>강의실</th>
          <th className="px-4 py-3 text-left text-xs font-bold text-slate-600 cursor-pointer select-none" style={{width:'90px'}} onClick={()=>mkSortField('status')}>상태{mkArrow('status')}</th>
          <th className="px-4 py-3 text-left text-xs font-bold text-slate-600" style={{width:'100px'}}>비고</th>
          <th className="px-4 py-3 text-left text-xs font-bold text-slate-600" style={{width:'110px'}}>관리</th>
        </tr></thead>
        <tbody>
          {[...filtered].sort((a,b)=>{
            const mkGetters={studentName:m=>m.studentName||'',className:m=>m.className||'',absenceDate:m=>m.absenceDate||'',makeupDate:m=>m.makeupDate||'',status:m=>m.status||''};
            const g=mkGetters[mkSortKey]||mkGetters.absenceDate;const av=g(a),bv=g(b);
            return mkSortDir==='asc'?String(av).localeCompare(String(bv),'ko'):String(bv).localeCompare(String(av),'ko');
          }).map(m=><tr key={m.id} className={`table-row border-b${listSelected.has(m.id)?' bg-indigo-50':''}`}>
            <td className="px-4 py-3 text-center"><input type="checkbox" checked={listSelected.has(m.id)} onChange={()=>toggleListSelect(m.id)} className="accent-indigo-600"/></td>
            <td className="px-4 py-3 font-semibold text-slate-900">{m.studentName}</td>
            <td className="px-4 py-3 text-slate-700">{m.className}</td>
            <td className="px-4 py-3 text-xs text-slate-600">{fDate(m.absenceDate)}</td>
            <td className="px-4 py-3 text-xs text-slate-600">{fDate(m.makeupDate)}</td>
            <td className="px-4 py-3 text-xs text-slate-600">{m.makeupStartTime&&m.makeupEndTime?`${m.makeupStartTime}~${m.makeupEndTime}`:'-'}</td>
            <td className="px-4 py-3 text-xs text-slate-600">{m.room?<span className="badge bg-blue-50 text-blue-700">{m.room}</span>:'-'}</td>
            <td className="px-4 py-3">
              <span className={`badge ${m.status==='unscheduled'?'bg-red-100 text-red-700':m.status==='pending'?'bg-yellow-100 text-yellow-700':'bg-green-100 text-green-700'}`}>
                {m.status==='unscheduled'?'미예약':m.status==='pending'?'예정':'완료'}
              </span>
            </td>
            <td className="px-4 py-3 text-xs text-slate-600">{m.note}</td>
            <td className="px-4 py-3 flex gap-1">
              {m.status==='unscheduled'&&<button onClick={()=>updateStatus(m.id,'pending')} className={btn('blue')} style={{padding:'4px 8px',fontSize:'11px'}}>예약</button>}
              {m.status==='pending'&&<button onClick={()=>updateStatus(m.id,'completed')} className={btn('green')} style={{padding:'4px 8px',fontSize:'11px'}}>완료</button>}
              <button onClick={()=>openEdit(m)} className={btn('gray')} style={{padding:'4px 8px',fontSize:'11px'}}>수정</button>
              <button onClick={()=>setConfirmId(m.id)} className="text-xs px-2 py-1 rounded bg-red-50 text-red-500 hover:bg-red-100 border border-red-200" style={{fontSize:'11px'}}>삭제</button>
            </td>
          </tr>)}
          {filtered.length===0&&<tr><td colSpan={10} className="text-center py-12 text-slate-600">조건에 맞는 보강 내역이 없습니다</td></tr>}
        </tbody>
      </table>
      </div>
    </div>

    <Modal open={modalOpen} onClose={()=>setModalOpen(false)} title={editTarget?'보강 수정':'보강 추가'}>
      <div className="space-y-4">
        <Field label="학생" required>
          <select className={inp} value={form.studentId} onChange={e=>{
            const st=students.find(s=>s.id===e.target.value);
            setForm({...form,studentId:e.target.value,studentName:st?.name||''});
          }}>
            <option value="">선택</option>
            {[...students].sort((a,b)=>a.name.localeCompare(b.name,'ko')).map(s=><option key={s.id} value={s.id}>{s.name}</option>)}
          </select>
        </Field>
        <Field label="수업" required>
          <select className={inp} value={form.classId} onChange={e=>{
            const cls=classes.find(c=>c.id===e.target.value);
            setForm({...form,classId:e.target.value,className:cls?.name||''});
          }}>
            <option value="">선택</option>
            {classes.filter(c=>!(c.closeDate&&c.closeDate<=today())).sort((a,b)=>a.name.localeCompare(b.name,'ko')).map(c=><option key={c.id} value={c.id}>{c.name}</option>)}
          </select>
        </Field>
        <Field label="결석일" required>
          <input type="date" className={inp} value={form.absenceDate} onChange={e=>setForm({...form,absenceDate:e.target.value})}/>
        </Field>
        <Field label="보강예정일">
          <input type="date" className={inp} value={form.makeupDate} onChange={e=>setForm({...form,makeupDate:e.target.value})}/>
        </Field>
        <Field label="보강 시간 (선택)">
          <div className="flex gap-2 items-center">
            <input type="time" className={inp} value={form.makeupStartTime||''} onChange={e=>setForm({...form,makeupStartTime:e.target.value})}/>
            <span className="text-slate-500">~</span>
            <input type="time" className={inp} value={form.makeupEndTime||''} onChange={e=>setForm({...form,makeupEndTime:e.target.value})}/>
          </div>
        </Field>
        <Field label="강의실 (선택)">
          <select className={inp} value={form.room||''} onChange={e=>setForm({...form,room:e.target.value})}>
            <option value="">선택 안 함</option>
            {makeupRooms.map(r=><option key={r} value={r}>{r}</option>)}
          </select>
          {(()=>{const mkC=checkRoomConflict(form,editTarget?.id);const clsC=!mkC?checkRegularClassConflict(form):null;if(mkC)return<div className="mt-1 text-xs text-red-500 font-medium">⚠️ {mkC.studentName} 학생의 보강과 시간이 겹칩니다 ({mkC.makeupStartTime}~{mkC.makeupEndTime})</div>;if(clsC)return<div className="mt-1 text-xs text-red-500 font-medium">⚠️ 정규수업 "{clsC.name}"과 시간이 겹칩니다 ({clsC.startTime}~{clsC.endTime})</div>;return null;})()}
        </Field>
        <Field label="상태">
          <select className={inp} value={form.status} onChange={e=>setForm({...form,status:e.target.value})}>
            <option value="unscheduled">미예약</option>
            <option value="pending">예정</option>
            <option value="completed">완료</option>
          </select>
        </Field>
        <Field label="비고">
          <textarea className={inp} value={form.note} onChange={e=>setForm({...form,note:e.target.value})} rows={2}/>
        </Field>
        <div className="flex gap-3 justify-end pt-2">
          <button onClick={save} className={btn('indigo')}>저장</button>
          <button onClick={()=>setModalOpen(false)} className={btn('gray')}>취소</button>
        </div>
      </div>
    </Modal>
    <Confirm open={confirmId!==null} msg="이 보강 기록을 삭제하시겠습니까?" onYes={()=>del(confirmId)} onNo={()=>setConfirmId(null)}/>
    <Modal open={bulkEditOpen} onClose={()=>setBulkEditOpen(false)} title={`선택 ${listSelected.size}건 일괄 수정`}>
      <p className="text-xs text-slate-500 mb-4">수정할 항목에 체크하세요. 체크한 항목만 선택된 모든 건에 일괄 적용됩니다.</p>
      <div className="space-y-2">
        <div className={`flex items-center gap-3 p-2.5 rounded-lg border ${bulkEditApply.makeupDate?'border-indigo-200 bg-indigo-50':'border-transparent hover:bg-slate-50'}`}>
          <input type="checkbox" id="be_date" checked={bulkEditApply.makeupDate} onChange={e=>setBulkEditApply({...bulkEditApply,makeupDate:e.target.checked})} className="accent-indigo-600"/>
          <label htmlFor="be_date" className="text-sm font-semibold text-slate-700 w-24 shrink-0 cursor-pointer">보강예정일</label>
          <input type="date" className={inp} value={bulkEditForm.makeupDate} onChange={e=>{setBulkEditForm({...bulkEditForm,makeupDate:e.target.value});if(e.target.value)setBulkEditApply(p=>({...p,makeupDate:true}));}} disabled={!bulkEditApply.makeupDate} style={{flex:1,opacity:bulkEditApply.makeupDate?1:0.4}}/>
        </div>
        <div className={`flex items-center gap-3 p-2.5 rounded-lg border ${bulkEditApply.time?'border-indigo-200 bg-indigo-50':'border-transparent hover:bg-slate-50'}`}>
          <input type="checkbox" id="be_time" checked={bulkEditApply.time} onChange={e=>setBulkEditApply({...bulkEditApply,time:e.target.checked})} className="accent-indigo-600"/>
          <label htmlFor="be_time" className="text-sm font-semibold text-slate-700 w-24 shrink-0 cursor-pointer">보강 시간</label>
          <div className="flex gap-2 items-center" style={{flex:1,opacity:bulkEditApply.time?1:0.4}}>
            <input type="time" className={inp} value={bulkEditForm.makeupStartTime} onChange={e=>setBulkEditForm({...bulkEditForm,makeupStartTime:e.target.value})} disabled={!bulkEditApply.time}/>
            <span className="text-slate-400 shrink-0">~</span>
            <input type="time" className={inp} value={bulkEditForm.makeupEndTime} onChange={e=>setBulkEditForm({...bulkEditForm,makeupEndTime:e.target.value})} disabled={!bulkEditApply.time}/>
          </div>
        </div>
        <div className={`flex items-center gap-3 p-2.5 rounded-lg border ${bulkEditApply.room?'border-indigo-200 bg-indigo-50':'border-transparent hover:bg-slate-50'}`}>
          <input type="checkbox" id="be_room" checked={bulkEditApply.room} onChange={e=>setBulkEditApply({...bulkEditApply,room:e.target.checked})} className="accent-indigo-600"/>
          <label htmlFor="be_room" className="text-sm font-semibold text-slate-700 w-24 shrink-0 cursor-pointer">강의실</label>
          <select className={inp} value={bulkEditForm.room} onChange={e=>setBulkEditForm({...bulkEditForm,room:e.target.value})} disabled={!bulkEditApply.room} style={{flex:1,opacity:bulkEditApply.room?1:0.4}}>
            <option value="">선택 안 함 (비우기)</option>
            {makeupRooms.map(r=><option key={r} value={r}>{r}</option>)}
          </select>
        </div>
        <div className={`flex items-center gap-3 p-2.5 rounded-lg border ${bulkEditApply.status?'border-indigo-200 bg-indigo-50':'border-transparent hover:bg-slate-50'}`}>
          <input type="checkbox" id="be_status" checked={bulkEditApply.status} onChange={e=>setBulkEditApply({...bulkEditApply,status:e.target.checked})} className="accent-indigo-600"/>
          <label htmlFor="be_status" className="text-sm font-semibold text-slate-700 w-24 shrink-0 cursor-pointer">상태</label>
          <select className={inp} value={bulkEditForm.status} onChange={e=>setBulkEditForm({...bulkEditForm,status:e.target.value})} disabled={!bulkEditApply.status} style={{flex:1,opacity:bulkEditApply.status?1:0.4}}>
            <option value="unscheduled">미예약</option>
            <option value="pending">예정</option>
            <option value="completed">완료</option>
          </select>
        </div>
        <div className={`flex items-start gap-3 p-2.5 rounded-lg border ${bulkEditApply.note?'border-indigo-200 bg-indigo-50':'border-transparent hover:bg-slate-50'}`}>
          <input type="checkbox" id="be_note" checked={bulkEditApply.note} onChange={e=>setBulkEditApply({...bulkEditApply,note:e.target.checked})} className="accent-indigo-600 mt-1"/>
          <label htmlFor="be_note" className="text-sm font-semibold text-slate-700 w-24 shrink-0 cursor-pointer pt-0.5">비고</label>
          <textarea className={inp} value={bulkEditForm.note} onChange={e=>setBulkEditForm({...bulkEditForm,note:e.target.value})} rows={2} disabled={!bulkEditApply.note} style={{flex:1,opacity:bulkEditApply.note?1:0.4}}/>
        </div>
      </div>
      <div className="flex gap-3 justify-end pt-4 border-t mt-4">
        <button onClick={saveBulkEdit} className={btn('indigo')}>선택 {listSelected.size}건 적용</button>
        <button onClick={()=>setBulkEditOpen(false)} className={btn('gray')}>취소</button>
      </div>
    </Modal>
    <Modal open={bulkModalOpen} onClose={()=>setBulkModalOpen(false)} title="강사 결석 — 일괄 보강 등록">
      <p className="text-xs text-slate-500 mb-3">강사가 결석한 날, 수업에 등록된 학생을 선택해 일괄로 보강 등록합니다.</p>
      <div className="grid grid-cols-2 gap-3">
        <Field label="결석한 강사" required>
          <select className={inp} value={bulkTeacherId} onChange={e=>{setBulkTeacherId(e.target.value);setBulkClassId('');setBulkSelected(new Set());}}>
            <option value="">선택</option>
            {(teachers||[]).filter(t=>t.status!=='resigned').sort((a,b)=>a.name.localeCompare(b.name,'ko')).map(t=><option key={t.id} value={t.id}>{t.name}</option>)}
          </select>
        </Field>
        <Field label="결석일" required>
          <input type="date" className={inp} value={bulkAbsenceDate} onChange={e=>setBulkAbsenceDate(e.target.value)}/>
        </Field>
      </div>
      <Field label="결석한 수업" required>
        <select className={inp} value={bulkClassId} onChange={e=>{const cid=e.target.value;setBulkClassId(cid);if(cid){const sts=(students||[]).filter(s=>s.status!=='withdrawn'&&(!s.joinDate||s.joinDate<=today())&&(s.enrolledClasses||[]).includes(cid));setBulkSelected(new Set(sts.map(s=>s.id)));}else{setBulkSelected(new Set());}}} disabled={!bulkTeacherId}>
          <option value="">선택 (강사 먼저 선택)</option>
          {bulkTeacherClasses.sort((a,b)=>a.name.localeCompare(b.name,'ko')).map(c=><option key={c.id} value={c.id}>{c.name}</option>)}
        </select>
        {bulkTeacherId&&bulkTeacherClasses.length===0&&<div className="text-xs text-slate-400 mt-1">운영 중인 수업이 없습니다</div>}
      </Field>
      {bulkClassId&&<div className="bg-blue-50 border border-blue-200 rounded-xl p-3 text-sm mb-2">
        <div className="flex items-center justify-between mb-2">
          <span className="font-semibold text-blue-800">보강 대상 학생 선택 ({bulkSelected.size}/{bulkStudents.length}명)</span>
          <button type="button" onClick={toggleBulkAll} className="text-xs px-2 py-1 rounded bg-blue-200 text-blue-800 hover:bg-blue-300">{bulkSelected.size===bulkStudents.length?'전체 해제':'전체 선택'}</button>
        </div>
        <div className="flex flex-wrap gap-2">
          {bulkStudents.map(s=><label key={s.id} className={`flex items-center gap-1 px-2 py-1 rounded-lg cursor-pointer text-xs font-medium border ${bulkSelected.has(s.id)?'bg-blue-100 border-blue-300 text-blue-800':'bg-white border-gray-200 text-slate-500'}`}>
            <input type="checkbox" checked={bulkSelected.has(s.id)} onChange={()=>toggleBulkStudent(s.id)} className="accent-blue-600"/>
            {s.name}
          </label>)}
          {bulkStudents.length===0&&<span className="text-slate-500 text-xs">해당 수업 등록 학생이 없습니다</span>}
        </div>
      </div>}
      <div className="bg-slate-50 border border-slate-200 rounded-xl p-3 mb-2">
        <div className="text-xs font-semibold text-slate-600 mb-2">보강 일정 (선택사항 — 미입력 시 "미예약" 상태로 등록)</div>
        <div className="grid grid-cols-3 gap-2">
          <Field label="보강 예정일"><input type="date" className={inp} value={bulkMakeupDate} onChange={e=>setBulkMakeupDate(e.target.value)}/></Field>
          <Field label="시작 시간"><input type="time" className={inp} value={bulkStartTime} onChange={e=>setBulkStartTime(e.target.value)}/></Field>
          <Field label="종료 시간"><input type="time" className={inp} value={bulkEndTime} onChange={e=>setBulkEndTime(e.target.value)}/></Field>
        </div>
        <Field label="강의실">
          <select className={inp} value={bulkRoom} onChange={e=>setBulkRoom(e.target.value)}>
            <option value="">미정</option>
            {makeupRooms.map(r=><option key={r} value={r}>{r}</option>)}
          </select>
        </Field>
        {bulkConflicts.length>0&&<div className="mt-2 bg-red-50 border border-red-200 rounded-lg p-2 text-xs text-red-700">
          <div className="font-bold mb-1">⚠️ 강의실 시간 겹침</div>
          {bulkConflicts.map((c,i)=><div key={i}>• {c}</div>)}
        </div>}
      </div>
      <Field label="비고">
        <input className={inp} value={bulkNote} onChange={e=>setBulkNote(e.target.value)} placeholder="강사 결석으로 인한 일괄 보강 등록"/>
      </Field>
      <p className="text-xs text-amber-600 mt-2">* 이미 같은 날, 같은 수업으로 등록된 보강은 중복 등록하지 않습니다.</p>
      <div className="flex justify-end gap-3 mt-4">
        <button className={btn('indigo')} onClick={saveBulk}>{bulkSelected.size}명 일괄 등록</button>
        <button className={btn('gray')} onClick={()=>setBulkModalOpen(false)}>취소</button>
      </div>
    </Modal>
  </div>;
}

// ── 퇴원 관리 ────────────────────────────────────────────────────────────
function WithdrawalManagement({withdrawals,setWithdrawals}){
  const[confirmId,setConfirmId]=useState(null);
  const[modalOpen,setModalOpen]=useState(false);
  const[editTarget,setEditTarget]=useState(null);
  const[form,setForm]=useState({studentId:'',studentName:'',grade:'',classes:[],joinDate:today(),withdrawDate:today(),reason:'',note:'',stayMonths:0});
  const emptyForm={studentId:'',studentName:'',grade:'',classes:[],joinDate:today(),withdrawDate:today(),reason:'',note:'',stayMonths:0};
  const reasons=['이사','학업','비용','불만족','건강','기타'];

  const openAdd=()=>{setEditTarget(null);setForm(emptyForm);setModalOpen(true);};
  const openEdit=w=>{setEditTarget(w);setForm(w);setModalOpen(true);};
  const save=()=>{
    if(!form.studentName||!form.withdrawDate){alert('학생명과 퇴원일은 필수입니다.');return;}
    if(editTarget)setWithdrawals(prev=>prev.map(w=>w.id===editTarget.id?{...form,id:w.id}:w));
    else setWithdrawals(prev=>[...prev,{...form,id:genId()}]);
    setModalOpen(false);
  };
  const del=id=>{setWithdrawals(prev=>prev.filter(w=>w.id!==id));setConfirmId(null);};

  const totalWithdrawn=withdrawals.length;
  const avgStay=withdrawals.length>0?Math.round(withdrawals.reduce((s,w)=>s+(w.stayMonths||0),0)/withdrawals.length):0;
  const thisYear=withdrawals.filter(w=>w.withdrawDate.startsWith(new Date().getFullYear().toString())).length;
  const reasonStats=withdrawals.reduce((a,w)=>{a[w.reason]=(a[w.reason]||0)+1;return a;},{});

  return<div className="space-y-6">
    <div>
      <h1 className="text-2xl font-bold text-slate-900">퇴원 관리</h1>
      <p className="text-slate-600 text-sm mt-1">학생 퇴원 현황과 재원 기간을 추적하세요</p>
    </div>

    <div className="grid grid-cols-2 md:grid-cols-4 gap-3">
      <div className="bg-white rounded-2xl p-4 shadow-sm border border-slate-200">
        <div className="text-xs text-slate-600 font-semibold mb-1">총 퇴원생</div>
        <div className="text-2xl font-bold text-slate-900">{totalWithdrawn}</div>
      </div>
      <div className="bg-white rounded-2xl p-4 shadow-sm border border-slate-200">
        <div className="text-xs text-slate-600 font-semibold mb-1">평균 재원 기간</div>
        <div className="text-2xl font-bold text-slate-900">{avgStay}개월</div>
      </div>
      <div className="bg-white rounded-2xl p-4 shadow-sm border border-slate-200">
        <div className="text-xs text-slate-600 font-semibold mb-1">올해 퇴원</div>
        <div className="text-2xl font-bold text-slate-900">{thisYear}</div>
      </div>
      <div className="bg-white rounded-2xl p-4 shadow-sm border border-slate-200">
        <div className="text-xs text-slate-600 font-semibold mb-1">주요 사유</div>
        <div className="text-lg font-bold text-slate-900">{Object.entries(reasonStats).sort((a,b)=>b[1]-a[1])[0]?.[0]||'-'}</div>
      </div>
    </div>

    <button onClick={openAdd} className={btn('indigo')}>+ 퇴원 기록 추가</button>

    <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
      <div className="lg:col-span-2 bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="overflow-x-auto overflow-y-auto tbl-scroll" style={{maxHeight:'calc(100vh - 280px)'}}>
        <table className="w-full text-sm app-table">
          <thead className="bg-[#f1f5f9]"><tr className="border-b">
            <th className="px-4 py-3 text-left text-xs font-bold text-slate-600" style={{width:'90px'}}>학생명</th>
            <th className="px-4 py-3 text-left text-xs font-bold text-slate-600" style={{width:'100px'}}>레벨</th>
            <th className="px-4 py-3 text-left text-xs font-bold text-slate-600" style={{width:'120px'}}>수강수업</th>
            <th className="px-4 py-3 text-left text-xs font-bold text-slate-600" style={{width:'180px'}}>재원기간</th>
            <th className="px-4 py-3 text-left text-xs font-bold text-slate-600" style={{width:'100px'}}>퇴원일</th>
            <th className="px-4 py-3 text-left text-xs font-bold text-slate-600" style={{width:'90px'}}>사유</th>
            <th className="px-4 py-3 text-left text-xs font-bold text-slate-600" style={{width:'100px'}}>비고</th>
            <th className="px-4 py-3 text-left text-xs font-bold text-slate-600" style={{width:'110px'}}>관리</th>
          </tr></thead>
          <tbody>
            {[...withdrawals].sort((a,b)=>a.studentName.localeCompare(b.studentName,'ko')).map(w=><tr key={w.id} className="table-row border-b">
              <td className="px-4 py-3 font-semibold text-slate-900">{w.studentName}</td>
              <td className="px-4 py-3 text-slate-700">{w.grade}</td>
              <td className="px-4 py-3 text-xs text-slate-600">{w.classes.join(', ')}</td>
              <td className="px-4 py-3 text-xs text-slate-600">{w.stayMonths}개월</td>
              <td className="px-4 py-3 text-xs text-slate-600">{fDate(w.withdrawDate)}</td>
              <td className="px-4 py-3 text-slate-700">{w.reason}</td>
              <td className="px-4 py-3 text-xs text-slate-600">{w.note}</td>
              <td className="px-4 py-3 flex gap-2">
                <button onClick={()=>openEdit(w)} className={btn('gray')} style={{padding:'4px 8px',fontSize:'12px'}}>수정</button>
                <button onClick={()=>setConfirmId(w.id)} className={btn('red')} style={{padding:'4px 8px',fontSize:'12px'}}>삭제</button>
              </td>
            </tr>)}
          </tbody>
        </table>
        </div>
      </div>

      <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-5">
        <h3 className="font-bold text-slate-900 mb-4">퇴원 사유 현황</h3>
        <div className="space-y-3">
          {Object.entries(reasonStats).sort((a,b)=>b[1]-a[1]).map(([reason,count])=>{
            const pct=Math.round((count/totalWithdrawn)*100);
            return(
              <div key={reason}>
                <div className="flex justify-between text-sm mb-1">
                  <span className="text-slate-700">{reason}</span>
                  <span className="font-semibold text-slate-900">{count}명 ({pct}%)</span>
                </div>
                <div className="h-2 bg-gray-100 rounded-full"><div className="h-2 bg-orange-400 rounded-full" style={{width:pct+'%'}}/></div>
              </div>
            );
          })}
        </div>
      </div>
    </div>

    <Modal open={modalOpen} onClose={()=>setModalOpen(false)} title={editTarget?'퇴원 기록 수정':'퇴원 기록 추가'}>
      <div className="space-y-4">
        <Field label="학생명" required>
          <input className={inp} value={form.studentName} onChange={e=>setForm({...form,studentName:e.target.value})}/>
        </Field>
        <Field label="레벨">
          <input className={inp} value={form.grade} onChange={e=>setForm({...form,grade:e.target.value})} placeholder="예: 체르니30·소나티네"/>
        </Field>
        <Field label="입학일">
          <input type="date" className={inp} value={form.joinDate} onChange={e=>setForm({...form,joinDate:e.target.value})}/>
        </Field>
        <Field label="퇴원일" required>
          <input type="date" className={inp} value={form.withdrawDate} onChange={e=>setForm({...form,withdrawDate:e.target.value})}/>
        </Field>
        <Field label="재원 기간 (개월)">
          <input type="number" className={inp} value={form.stayMonths} onChange={e=>setForm({...form,stayMonths:parseInt(e.target.value)||0})}/>
        </Field>
        <Field label="퇴원 사유">
          <select className={inp} value={form.reason} onChange={e=>setForm({...form,reason:e.target.value})}>
            <option value="">선택</option>
            {reasons.map(r=><option key={r} value={r}>{r}</option>)}
          </select>
        </Field>
        <Field label="비고">
          <textarea className={inp} value={form.note} onChange={e=>setForm({...form,note:e.target.value})} rows={2}/>
        </Field>
        <div className="flex gap-3 justify-end pt-2">
          <button onClick={save} className={btn('indigo')}>저장</button>
          <button onClick={()=>setModalOpen(false)} className={btn('gray')}>취소</button>
        </div>
      </div>
    </Modal>
    <Confirm open={confirmId!==null} msg="이 퇴원 기록을 삭제하시겠습니까?" onYes={()=>del(confirmId)} onNo={()=>setConfirmId(null)}/>
  </div>;
}

// ── 근로소득 간이세액표 산출 로직 (소득세법 시행령 별표 2 방식) ───────────────────
// Austin님 결정[d]: "부양가족수 입력칸 + 실제 표 반영 (정확, 작업량 큼)"을 반영한 구현.
// 국세청이 매년 고시하는 간이세액표 자체는 급여 구간마다 1줄씩 둔 "조회표"이지만, 그 표의
// 값은 사실 아래 5단계 공식으로 국세청이 직접 계산해서 만든 것임(소득세법 시행령 §189 별표 2,
// 근로소득공제·기본공제·특별소득공제 일부·세율·근로소득세액공제 반영). 표를 통째로 베끼는
// 대신 이 공식을 그대로 구현해서, 표에 있는 모든 급여×부양가족수 조합에 대해 표와 거의
// 동일한(보통 ±수백원 이내) 금액이 나오도록 했다.
// ⚠️ 한 가지만 단순화: "8~20세 자녀 세액공제"는 자녀의 나이 정보가 시스템에 없어 반영하지
//    않음(보통 자녀 1인당 월 1만원 안팎 차이). 정확한 금액이 필요하면 홈택스 간이세액표로
//    최종 대조 확인을 권장.
function calcWithholdingTax(monthlySalary,dependents){
  const m=Number(monthlySalary)||0;
  const dep=Math.max(1,Number(dependents)||1); // 본인 포함 최소 1명
  if(m<=0)return 0;
  const annual=m*12; // 1) 연간 총급여액으로 환산

  // 2) 근로소득공제 (소득세법 §47)
  let earnedDeduction;
  if(annual<=5000000)earnedDeduction=annual*0.7;
  else if(annual<=15000000)earnedDeduction=3500000+(annual-5000000)*0.4;
  else if(annual<=45000000)earnedDeduction=7500000+(annual-15000000)*0.15;
  else if(annual<=100000000)earnedDeduction=12000000+(annual-45000000)*0.05;
  else earnedDeduction=14750000+(annual-100000000)*0.02;
  const earnedIncome=Math.max(0,annual-earnedDeduction);

  // 3) 인적공제: 기본공제(본인+부양가족 1인당 150만원) + 간이세액표 고시상 "특별소득공제 등" 근사 반영분
  const basicDeduction=dep*1500000;
  let extra;
  if(dep===1)extra=3100000+annual*0.04;
  else if(dep===2)extra=3600000+annual*0.04;
  else extra=5000000+annual*0.07; // 3명 이상은 동일 공식(가족수 차이는 위 기본공제에서 이미 반영됨)
  const taxBase=Math.max(0,earnedIncome-basicDeduction-extra);

  // 4) 산출세액 (소득세법 §55 기본세율 6~45%, TaxManagement의 calcIncomeTax와 동일한 누진표)
  const brackets=[
    {limit:14000000,rate:0.06,ded:0},
    {limit:50000000,rate:0.15,ded:1260000},
    {limit:88000000,rate:0.24,ded:5760000},
    {limit:150000000,rate:0.35,ded:15440000},
    {limit:300000000,rate:0.38,ded:19940000},
    {limit:500000000,rate:0.40,ded:25940000},
    {limit:1000000000,rate:0.42,ded:35940000},
    {limit:Infinity,rate:0.45,ded:65940000},
  ];
  let calculatedTax=0;
  for(const b of brackets){if(taxBase<=b.limit){calculatedTax=Math.max(0,taxBase*b.rate-b.ded);break;}}

  // 5) 근로소득세액공제 (소득세법 §59) — 산출세액을 한 번 더 깎아주는 세액공제, 한도 있음
  let taxCredit=calculatedTax<=1300000?calculatedTax*0.55:715000+(calculatedTax-1300000)*0.30;
  let creditLimit=740000;
  if(annual>33000000&&annual<=70000000)creditLimit=Math.max(660000,740000-Math.floor((annual-33000000)/1000000)*8000);
  else if(annual>70000000)creditLimit=Math.max(500000,660000-Math.floor((annual-70000000)/1000000)*5000);
  taxCredit=Math.min(taxCredit,creditLimit);

  const annualTax=Math.max(0,calculatedTax-taxCredit);
  return Math.floor(annualTax/12/10)*10; // 월 단위로 환산 후 10원 단위 절사
}

// ── 급여 명세서 ──────────────────────────────────────────────────────────
function PayslipManagement({teachers,academyName,role,loggedInTeacherId}){
  const todayYM=today().slice(0,7);
  const[month,setMonth]=useState(todayYM);
  const[printTeacherId,setPrintTeacherId]=useState(null);
  // 강사 계정으로 로그인하면 본인 명세서 자동 선택
  useEffect(()=>{if(role==='teacher'&&loggedInTeacherId){setPrintTeacherId(loggedInTeacherId);}},[loggedInTeacherId]);
  // 선택 월이 미래로 넘어가지 않도록 방어 (onChange에서도 max 적용)
  const handleMonthChange=e=>{if(e.target.value<=todayYM)setMonth(e.target.value);};
  // 선택된 월 기준으로 해당 월에 재직했던 강사 표시
  // 재직중(active/inactive)이거나, 퇴직강사(resigned)이더라도 퇴직일이 해당 월 이후인 경우 포함
  const[totalPopupOpen,setTotalPopupOpen]=useState(false);
  const activeTeachers=teachers.filter(t=>{
    const started=!t.contractStart||t.contractStart.slice(0,7)<=month;
    if(!started)return false;
    if(t.status!=='resigned')return true;
    // 퇴직강사: 퇴직일이 선택월 이상이면 해당 월에 재직했으므로 포함
    return t.resignedAt&&t.resignedAt.slice(0,7)>=month;
  });
  const calculateTax=(salary,dependents)=>{
    const gross=salary;
    const pension=Math.round(gross*0.045);
    const health=Math.round(gross*0.03545);
    const employment=Math.round(gross*0.009);
    const incomeTax=calcWithholdingTax(gross,dependents);
    return {pension,health,employment,incomeTax,total:pension+health+employment+incomeTax};
  };

  const calculateNet=(salary,dependents)=>{
    const deductions=calculateTax(salary,dependents).total;
    return salary-deductions;
  };

  // 월중간 합류 강사 일할 계산
  // contractStart가 해당 월에 해당하면 (일수/월총일수)×기본급 후 1000원 단위 반올림
  const calcEffectiveSalary=(t,ym)=>{
    const [my,mm]=ym.split('-').map(Number);
    const totalDays=new Date(my,mm,0).getDate();
    // 퇴직 일할계산: resignedAt가 해당 월에 해당하면 (입사 일할보다 우선 체크)
    if(t.status==='resigned'&&t.resignedAt){
      const [ry,rm,rd]=t.resignedAt.split('-').map(Number);
      if(ry===my&&rm===mm){
        const proratedDays=rd; // 1일~퇴직일까지
        const salary=Math.round(proratedDays/totalDays*t.salary/1000)*1000;
        return{salary,isProrated:true,isResignProrated:true,proratedDays,totalDays,resignedDay:rd};
      }
    }
    // 입사 일할계산: contractStart가 해당 월에 해당하면
    if(!t.contractStart)return{salary:t.salary,isProrated:false,proratedDays:null,totalDays:null};
    const [cy,cm,cd]=t.contractStart.split('-').map(Number);
    if(cy!==my||cm!==mm)return{salary:t.salary,isProrated:false,proratedDays:null,totalDays:null};
    const proratedDays=totalDays-cd+1;
    const salary=Math.round(proratedDays/totalDays*t.salary/1000)*1000;
    return{salary,isProrated:true,isResignProrated:false,proratedDays,totalDays};
  };

  const teacher=printTeacherId?teachers.find(t=>t.id===printTeacherId):null;
  const teacherSalaryInfo=teacher?calcEffectiveSalary(teacher,month):{salary:0,isProrated:false};
  const payslip=teacher?{
    salary:teacherSalaryInfo.salary,
    isProrated:teacherSalaryInfo.isProrated,
    proratedDays:teacherSalaryInfo.proratedDays,
    totalDays:teacherSalaryInfo.totalDays,
    baseSalary:teacher.salary,
    tax:calculateTax(teacherSalaryInfo.salary,teacher.dependents),
    net:calculateNet(teacherSalaryInfo.salary,teacher.dependents),
    period:teacherSalaryInfo.isResignProrated?`${month}-01 ~ ${month}-${String(teacherSalaryInfo.resignedDay).padStart(2,'0')} (퇴직 일할계산)`:teacherSalaryInfo.isProrated&&teacher.contractStart?.startsWith(month)?`${teacher.contractStart} ~ ${month}-${new Date(Number(month.split('-')[0]),Number(month.split('-')[1]),0).getDate()} (입사 일할계산)`:`${month}-01 ~ ${month}-${new Date(Number(month.split('-')[0]),Number(month.split('-')[1]),0).getDate()}`
  }:null;

  return<div className="space-y-6">
    <div>
      <h1 className="text-2xl font-bold text-slate-900">급여 명세서</h1>
      <p className="text-slate-600 text-sm mt-1">강사 월급여 명세서를 자동으로 생성하세요</p>
    </div>

    {/* ℹ️ 관리자 전용 안내 (화면에만 보이고 인쇄 시에는 빠짐) ─ Austin님 결정[d] 반영
        과거에는 "월급여의 8%"라는 단순 근사치였으나, 이제는 강사관리에 추가한 "부양가족수"
        값과 국세청 근로소득 간이세액표의 산출 공식(근로소득공제·기본공제·세율·근로소득세액공제,
        소득세법 시행령 별표 2)을 그대로 계산식으로 옮긴 calcWithholdingTax()로 정확하게 계산함.
        다만 자녀의 만 나이 정보가 시스템에 없어 "8~20세 자녀 세액공제"(자녀 1인당 월 1만원
        안팎)는 반영하지 못하므로, 이 점만 안내 배너로 계속 남겨둠. */}
    <div className="no-print bg-blue-50 border-2 border-blue-200 rounded-xl p-4 flex items-start gap-3">
      <span className="text-2xl leading-none">ℹ️</span>
      <div className="text-sm text-blue-800">
        <div className="font-bold mb-1">소득세 계산 방식 안내</div>
        <div className="leading-relaxed">
          아래 급여 명세서의 <strong>&quot;소득세&quot;</strong>는 강사관리에서 입력한 <strong>부양가족수</strong>와
          국세청 <strong>근로소득 간이세액표</strong>(소득세법 시행령 별표 2)의 계산 공식을 적용한 값입니다.
          단, 자녀의 정확한 나이 정보가 없어 <strong>8~20세 자녀 세액공제</strong>(자녀 1인당 월 약 1만원)는 반영되지 않았으니,
          이 부분이 중요한 강사가 있다면 신고/지급 전 홈택스 &quot;근로소득 간이세액표&quot;로 한 번 더 대조 확인해주세요.
        </div>
      </div>
    </div>

    <div className="flex gap-4 items-end flex-wrap">
      <div>
        <label className="block text-sm font-semibold text-slate-900 mb-2">기간</label>
        <input type="month" className={inp} value={month} onChange={handleMonthChange} style={{width:'150px'}} max={todayYM}/>
      </div>
      {!(role==='teacher'&&loggedInTeacherId)&&(()=>{
        const totGross=activeTeachers.reduce((s,t)=>s+calcEffectiveSalary(t,month).salary,0);
        const totDeduct=activeTeachers.reduce((s,t)=>s+calculateTax(calcEffectiveSalary(t,month).salary,t.dependents).total,0);
        const totNet=totGross-totDeduct;
        return<button onClick={()=>setTotalPopupOpen(true)} className={btn('blue')}>
          이달 총 지급액: {fWon(totNet)}
        </button>;
      })()}
    </div>

    {totalPopupOpen&&!(role==='teacher'&&loggedInTeacherId)&&<Modal open={totalPopupOpen} onClose={()=>setTotalPopupOpen(false)} title={`${month} 급여 총 지급 내역`}>
      <div className="space-y-3">
        {activeTeachers.map(t=>{
          const eff=calcEffectiveSalary(t,month);
          const tax=calculateTax(eff.salary,t.dependents);
          const net=eff.salary-tax.total;
          return<div key={t.id} className="flex items-center justify-between p-3 bg-[#f8fafc] rounded-xl">
            <div><div className="font-semibold text-slate-800">{t.name}</div>
              <div className="text-xs text-slate-500">{eff.isProrated?`일할 계산 (${eff.proratedDays}일)`:' 기본급'} | 공제 {fWon(tax.total)}</div>
              {t.status==='resigned'&&<span className="text-xs bg-orange-100 text-orange-600 px-1.5 py-0.5 rounded">퇴직({fDate(t.resignedAt)})</span>}
            </div>
            <div className="text-right">
              <div className="text-sm font-bold text-green-700">{fWon(net)}</div>
              <div className="text-xs text-slate-400">기본급 {fWon(eff.salary)}</div>
            </div>
          </div>;
        })}
        {activeTeachers.length===0&&<div className="text-center py-4 text-slate-500 text-sm">{month}에 재직한 강사가 없습니다</div>}
        <div className="border-t border-slate-200 pt-3 flex justify-between items-center">
          <span className="font-bold text-slate-800">합계 ({activeTeachers.length}명)</span>
          <div className="text-right">
            <div className="text-lg font-bold text-green-700">{fWon(activeTeachers.reduce((s,t)=>{const eff=calcEffectiveSalary(t,month);return s+eff.salary-calculateTax(eff.salary,t.dependents).total;},0))}</div>
            <div className="text-xs text-slate-400">총 기본급 {fWon(activeTeachers.reduce((s,t)=>s+calcEffectiveSalary(t,month).salary,0))} · 공제합계 {fWon(activeTeachers.reduce((s,t)=>{const eff=calcEffectiveSalary(t,month);return s+calculateTax(eff.salary,t.dependents).total;},0))}</div>
          </div>
        </div>
      </div>
      <div className="flex justify-end mt-4"><button className={btn('gray')} onClick={()=>setTotalPopupOpen(false)}>닫기</button></div>
    </Modal>}

    {!(role==='teacher'&&loggedInTeacherId)&&<div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
      {activeTeachers.map(t=>{
        const eff=calcEffectiveSalary(t,month);
        return(
        <div key={t.id} className="bg-white rounded-2xl shadow-sm border border-slate-200 p-4 hover:shadow-md transition-shadow">
          <div className="flex items-start justify-between mb-3">
            <div>
              <div className="font-bold text-slate-900">{t.name}{t.status==='resigned'&&<span className="ml-1 text-xs text-orange-500">(퇴직)</span>}</div>
              <div className="text-xs text-slate-600">{(t.subjects||[]).join(', ')}</div>
            </div>
            {eff.isProrated&&<span className="text-xs bg-amber-100 text-amber-700 px-2 py-0.5 rounded-full font-medium">{eff.isResignProrated?'퇴직 일할계산':'입사 일할계산'}</span>}
          </div>
          <div className="space-y-2 mb-4">
            <div className="flex justify-between text-sm">
              <span className="text-slate-600">{eff.isProrated?(eff.isResignProrated?`기본급(1~${eff.resignedDay}일, ${eff.proratedDays}/${eff.totalDays}일)`:` 기본급(${eff.proratedDays}/${eff.totalDays}일)`):' 기본급'}</span>
              <span className="font-semibold text-slate-900">{fWon(eff.salary)}</span>
            </div>
            {eff.isProrated&&<div className="flex justify-between text-xs text-slate-400"><span>월 기본급</span><span>{fWon(t.salary)}</span></div>}
            <div className="flex justify-between text-sm">
              <span className="text-slate-600">공제액</span>
              <span className="font-semibold text-red-600">{fWon(calculateTax(eff.salary,t.dependents).total)}</span>
            </div>
            <div className="border-t border-slate-200 pt-2 flex justify-between text-sm font-bold">
              <span className="text-slate-900">실수령액</span>
              <span className="text-green-700">{fWon(calculateNet(eff.salary,t.dependents))}</span>
            </div>
          </div>
          <button onClick={()=>setPrintTeacherId(t.id)} className={btn('blue')} style={{width:'100%',padding:'8px',fontSize:'13px'}}>명세서 보기</button>
        </div>
        );
      })}
    </div>}

    {printTeacherId&&payslip&&<div id="payslip-print-area"><div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-8 max-w-2xl mx-auto">
      <div className="text-center mb-6 pb-4 border-b border-slate-200">
        <h2 className="text-xl font-bold text-slate-900">급여 명세서</h2>
        <p className="text-sm text-slate-600 mt-1">{month}</p>
      </div>

      <div className="grid grid-cols-2 gap-6 mb-6">
        <div>
          <div className="text-xs text-slate-600 font-semibold mb-1">학원명</div>
          <div className="font-semibold text-slate-900">{academyName}</div>
        </div>
        <div className="text-right">
          <div className="text-xs text-slate-600 font-semibold mb-1">강사명</div>
          <div className="font-semibold text-slate-900">{teacher.name}</div>
        </div>
      </div>

      <div className="mb-6">
        <div className="text-xs text-slate-600 font-semibold mb-2">과목: {(teacher.subjects||[]).join(', ')} | 기간: {payslip.period}</div>
      </div>

      <table className="w-full mb-6 text-sm app-table">
        <thead className="bg-[#f1f5f9]"><tr>
          <th className="px-3 py-2 text-left font-bold text-slate-600">항목</th>
          <th className="px-3 py-2 text-right font-bold text-slate-600">금액</th>
        </tr></thead>
        <tbody>
          {payslip.isProrated&&<tr className="border-t bg-amber-50"><td className="px-3 py-2 text-amber-700 text-xs" colSpan="2">⚠️ 월중간 합류 ({fDate(teacher.contractStart)}) — {payslip.proratedDays}/{payslip.totalDays}일 일할 계산 적용. 월 기본급 {fWon(payslip.baseSalary)}</td></tr>}
          <tr className="border-t"><td className="px-3 py-2 text-slate-900">기본급{payslip.isProrated?` (일할)`:''}</td><td className="px-3 py-2 text-right font-semibold text-slate-900">{fWon(payslip.salary)}</td></tr>
          <tr className="border-t bg-orange-50"><td colSpan="2" className="px-3 py-2 font-bold text-orange-700">공제 내역</td></tr>
          <tr><td className="px-3 py-2 text-slate-700 pl-6">국민연금 (4.5%)</td><td className="px-3 py-2 text-right text-slate-700">{fWon(payslip.tax.pension)}</td></tr>
          <tr><td className="px-3 py-2 text-slate-700 pl-6">건강보험 (3.545%)</td><td className="px-3 py-2 text-right text-slate-700">{fWon(payslip.tax.health)}</td></tr>
          <tr><td className="px-3 py-2 text-slate-700 pl-6">고용보험 (0.9%)</td><td className="px-3 py-2 text-right text-slate-700">{fWon(payslip.tax.employment)}</td></tr>
          <tr><td className="px-3 py-2 text-slate-700 pl-6">소득세 (간이세액표, 부양가족 {teacher.dependents||1}명)</td><td className="px-3 py-2 text-right text-slate-700">{fWon(payslip.tax.incomeTax)}</td></tr>
          <tr className="border-t border-b font-bold"><td className="px-3 py-2">총 공제액</td><td className="px-3 py-2 text-right text-red-600">{fWon(payslip.tax.total)}</td></tr>
          <tr className="bg-green-50 font-bold text-lg"><td className="px-3 py-3">실수령액</td><td className="px-3 py-3 text-right text-green-700">{fWon(payslip.net)}</td></tr>
        </tbody>
      </table>

      <div className="bg-yellow-50 rounded-lg p-3 text-xs text-yellow-700 mb-4">
        <strong>참고</strong>: 위 소득세는 월급여의 8%를 적용한 간이 추정치입니다. 실제 소득세는 국세청 근로소득 간이세액표(소득세법 시행령 별표 2)에 따라 월급여와 부양가족 수를 기준으로 정해지므로, 정확한 금액은 홈택스에서 확인 후 반영해야 합니다.
      </div>

      <div className="flex gap-3 justify-center no-print">
        <button onClick={()=>window.print()} className={btn('indigo')}>🖨️ 인쇄</button>
        <button onClick={()=>setPrintTeacherId(null)} className={btn('gray')}>닫기</button>
      </div>
    </div></div>}
  </div>;
}

// ── 성취도 관리 ────────────────────────────────────────────────────────
function AchievementManagement({achievements,setAchievements,students}){
  const[modalOpen,setModalOpen]=useState(false);
  const[editTarget,setEditTarget]=useState(null);
  const[confirmId,setConfirmId]=useState(null);
  const[filterStudent,setFilterStudent]=useState('');
  const[form,setForm]=useState({studentId:'',studentName:'',subject:'',level:'유아',currentPiece:'',competitions:[],updatedDate:today(),note:''});
  const emptyForm={studentId:'',studentName:'',subject:'',level:'유아',currentPiece:'',competitions:[],updatedDate:today(),note:''};
  const levels=['유아','바이엘','체르니100','체르니30·소나티네','소나타·인벤션','콩쿠르·고급'];
  const levelColors={'유아':'bg-pink-100 text-pink-700','바이엘':'bg-blue-100 text-blue-700','체르니100':'bg-green-100 text-green-700','체르니30·소나티네':'bg-yellow-100 text-yellow-700','소나타·인벤션':'bg-orange-100 text-orange-700','콩쿠르·고급':'bg-purple-100 text-purple-700','입문':'bg-gray-100 text-gray-700','초급':'bg-blue-100 text-blue-700','중급':'bg-yellow-100 text-yellow-700','고급':'bg-orange-100 text-orange-700','최고급':'bg-purple-100 text-purple-700'};

  const openAdd=()=>{setEditTarget(null);setForm(emptyForm);setModalOpen(true);};
  const openEdit=a=>{setEditTarget(a);setForm(a);setModalOpen(true);};
  const save=()=>{
    if(!form.studentId||!form.subject){alert('학생과 과목은 필수입니다.');return;}
    if(editTarget)setAchievements(prev=>prev.map(a=>a.id===editTarget.id?{...form,id:a.id}:a));
    else setAchievements(prev=>[...prev,{...form,id:genId()}]);
    setModalOpen(false);
  };
  const del=id=>{setAchievements(prev=>prev.filter(a=>a.id!==id));setConfirmId(null);};

  const filtered=achievements.filter(a=>filterStudent?a.studentId===filterStudent:true);

  return<div className="space-y-6">
    <div>
      <h1 className="text-2xl font-bold text-slate-900">성취도 관리</h1>
      <p className="text-slate-600 text-sm mt-1">학생의 레벨과 성과를 관리하세요</p>
    </div>

    <div className="flex gap-4 items-end flex-wrap">
      <div>
        <label className="block text-sm font-semibold text-slate-900 mb-2">학생 필터</label>
        <select className={inp} value={filterStudent} onChange={e=>setFilterStudent(e.target.value)} style={{width:'200px'}}>
          <option value="">전체</option>
          {[...students].filter(s=>s.status!=='withdrawn'&&(!s.joinDate||s.joinDate<=today())).sort((a,b)=>a.name.localeCompare(b.name,'ko')).map(s=><option key={s.id} value={s.id}>{s.name}</option>)}
        </select>
      </div>
      <button onClick={openAdd} className={btn('indigo')}>+ 성취도 추가</button>
    </div>

    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
      {filtered.map(a=>(
        <div key={a.id} className="bg-white rounded-2xl shadow-sm border border-slate-200 p-4">
          <div className="flex items-start justify-between mb-3">
            <div>
              <div className="font-bold text-slate-900">{a.studentName}</div>
              <div className="text-xs text-slate-600">{a.subject}</div>
            </div>
            <span className={`badge ${levelColors[a.level]}`}>{a.level}</span>
          </div>
          <div className="mb-3">
            <div className="text-sm font-semibold text-slate-800">🎵 {a.currentPiece}</div>
            {a.note&&<div className="text-xs text-slate-600 mt-1">{a.note}</div>}
          </div>
          {a.competitions.length>0&&<div className="mb-3 pb-3 border-b border-slate-200">
            <div className="text-xs font-bold text-slate-600 mb-1">대회</div>
            {a.competitions.map((comp, idx)=>(
              <div key={idx} className="text-xs text-slate-700">
                {comp.name} ({comp.date}): <span className="font-semibold">{comp.result}</span>
              </div>
            ))}
          </div>}
          <div className="text-xs text-slate-500 mb-3">최종 업데이트: {fDate(a.updatedDate)}</div>
          <div className="flex gap-2">
            <button onClick={()=>openEdit(a)} className={btn('gray')} style={{flex:1,padding:'6px',fontSize:'12px'}}>수정</button>
            <button onClick={()=>setConfirmId(a.id)} className={btn('red')} style={{flex:1,padding:'6px',fontSize:'12px'}}>삭제</button>
          </div>
        </div>
      ))}
    </div>

    <Modal open={modalOpen} onClose={()=>setModalOpen(false)} title={editTarget?'성취도 수정':'성취도 추가'} wide>
      <div className="space-y-4">
        <Field label="학생" required>
          <select className={inp} value={form.studentId} onChange={e=>{
            const st=students.find(s=>s.id===e.target.value);
            setForm({...form,studentId:e.target.value,studentName:st?.name||''});
          }}>
            <option value="">선택</option>
            {[...students].filter(s=>s.status!=='withdrawn'&&(!s.joinDate||s.joinDate<=today())).sort((a,b)=>a.name.localeCompare(b.name,'ko')).map(s=><option key={s.id} value={s.id}>{s.name}</option>)}
          </select>
        </Field>
        <Field label="과목" required>
          <input className={inp} value={form.subject} onChange={e=>setForm({...form,subject:e.target.value})} placeholder="예: 피아노"/>
        </Field>
        <Field label="레벨">
          <select className={inp} value={form.level} onChange={e=>setForm({...form,level:e.target.value})}>
            {levels.map(l=><option key={l} value={l}>{l}</option>)}
          </select>
        </Field>
        <Field label="현재 곡/작품">
          <input className={inp} value={form.currentPiece} onChange={e=>setForm({...form,currentPiece:e.target.value})} placeholder="예: 쇼팽 녹턴"/>
        </Field>
        <Field label="대회 이력">
          <div className="space-y-2">
            {form.competitions.map((comp, idx)=>(
              <div key={idx} className="flex gap-2">
                <input className={inp} value={comp.name} onChange={e=>{
                  const newComps=[...form.competitions];
                  newComps[idx]={...comp,name:e.target.value};
                  setForm({...form,competitions:newComps});
                }} placeholder="대회명" style={{flex:1}}/>
                <input className={inp} value={comp.date} onChange={e=>{
                  const newComps=[...form.competitions];
                  newComps[idx]={...comp,date:e.target.value};
                  setForm({...form,competitions:newComps});
                }} placeholder="YYYY-MM" style={{width:'120px'}}/>
                <input className={inp} value={comp.result} onChange={e=>{
                  const newComps=[...form.competitions];
                  newComps[idx]={...comp,result:e.target.value};
                  setForm({...form,competitions:newComps});
                }} placeholder="결과" style={{width:'120px'}}/>
                <button onClick={()=>setForm({...form,competitions:form.competitions.filter((_,i)=>i!==idx)})} className={btn('red')} style={{padding:'6px 12px'}}>-</button>
              </div>
            ))}
            <button onClick={()=>setForm({...form,competitions:[...form.competitions,{name:'',date:'',result:''}]})} className={btn('blue')} style={{width:'100%',padding:'8px',fontSize:'12px'}}>+ 대회 추가</button>
          </div>
        </Field>
        <Field label="비고">
          <textarea className={inp} value={form.note} onChange={e=>setForm({...form,note:e.target.value})} rows={2}/>
        </Field>
        <Field label="마지막 업데이트">
          <input type="date" className={inp} value={form.updatedDate} onChange={e=>setForm({...form,updatedDate:e.target.value})}/>
        </Field>
        <div className="flex gap-3 justify-end pt-2">
          <button onClick={save} className={btn('indigo')}>저장</button>
          <button onClick={()=>setModalOpen(false)} className={btn('gray')}>취소</button>
        </div>
      </div>
    </Modal>
    <Confirm open={confirmId!==null} msg="이 성취도 기록을 삭제하시겠습니까?" onYes={()=>del(confirmId)} onNo={()=>setConfirmId(null)}/>
  </div>;
}

// ── 지출 증빙 (강사 지출 등록) ──────────────────────────────────────────────
function ExpenseSubmit({expenses,setExpenses,teachers,role,loggedInTeacherId}){
  const CATS=['학원용품','비품','교재/악보','외부강의비','기타'];
  const loggedInTeacher=loggedInTeacherId?teachers.find(t=>t.id===loggedInTeacherId):null;
  const loggedInName=loggedInTeacher?.name||'';
  const emptyForm={submitterName:role==='teacher'?loggedInName:'',date:today(),category:'학원용품',amount:'',description:'',memo:'',receiptImg:''};
  const[form,setForm]=useState(emptyForm);
  const[saved,setSaved]=useState(false);
  const[editTargetId,setEditTargetId]=useState(null);
  const[filterName,setFilterName]=useState('전체');
  const[confirmDel,setConfirmDel]=useState(null);
  const[imgModal,setImgModal]=useState(null);
  const activeTeachers=teachers.filter(t=>t.status==='active');
  const allReceipts=expenses.filter(e=>e._receipt===true).sort((a,b)=>b.date.localeCompare(a.date));
  // 강사 계정: 본인이 제출한 내역만 표시
  const receipts=role==='teacher'&&loggedInName?allReceipts.filter(r=>r.submittedBy===loggedInName):allReceipts;
  const submitters=[...new Set(allReceipts.map(r=>r.submittedBy).filter(Boolean))].sort();
  const filtered=role==='teacher'?receipts:(filterName==='전체'?receipts:receipts.filter(r=>r.submittedBy===filterName));
  const totalAmt=filtered.reduce((s,r)=>s+Number(r.amount||0),0);

  const handleImageChange=(e)=>{
    const file=e.target.files&&e.target.files[0];
    if(!file)return;
    if(file.size>5*1024*1024){alert('파일이 5MB를 초과합니다. 더 작은 이미지를 선택하세요.');return;}
    const reader=new FileReader();
    reader.onload=(ev)=>setForm(f=>({...f,receiptImg:ev.target.result}));
    reader.readAsDataURL(file);
  };

  const handleSubmit=()=>{
    if(!form.submitterName){alert('제출 강사를 선택하세요.');return;}
    if(!form.date){alert('날짜를 입력하세요.');return;}
    if(!Number(form.amount)||Number(form.amount)<=0){alert('금액을 입력하세요.');return;}
    if(!form.description.trim()){alert('구매 내용을 입력하세요.');return;}
    if(editTargetId){
      setExpenses(prev=>prev.map(e=>e.id===editTargetId?{...e,date:form.date,category:form.category,description:form.description,amount:Number(form.amount),memo:form.memo,receiptImg:form.receiptImg,submittedBy:form.submitterName}:e));
      setEditTargetId(null);
    }else{
      const newExp={id:genId(),date:form.date,category:form.category,description:form.description,
        amount:Number(form.amount),memo:form.memo,receiptImg:form.receiptImg,
        submittedBy:form.submitterName,_receipt:true};
      setExpenses(prev=>[...prev,newExp]);
    }
    setForm({...emptyForm,submitterName:form.submitterName});
    setSaved(true);setTimeout(()=>setSaved(false),2500);
  };
  const handleEdit=r=>{setEditTargetId(r.id);setForm({submitterName:r.submittedBy||'',date:r.date||today(),category:r.category||'학원용품',amount:r.amount||'',description:r.description||'',memo:r.memo||'',receiptImg:r.receiptImg||''});window.scrollTo({top:0,behavior:'smooth'});};
  const handleDel=(id)=>{setExpenses(prev=>prev.filter(e=>e.id!==id));setConfirmDel(null);};

  return <div className="p-6 space-y-5">
    <div>
      <h1 className="text-2xl font-bold text-slate-900">🧾 지출 증빙</h1>
      <p className="text-slate-500 text-sm mt-1">학원 용품·비품 구매 등 지출 내역을 등록하면 예산 관리에 자동 반영됩니다</p>
    </div>

    {/* 등록 폼 */}
    <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-5">
      <h2 className="font-bold text-slate-800 mb-4">{editTargetId?'✏️ 지출 수정':'➕ 지출 등록'}</h2>
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        <div>
          <label className="block text-xs font-semibold text-slate-600 mb-1">제출 강사 <span className="text-red-500">*</span></label>
          {role==='teacher'
            ?<div className="w-full border border-slate-100 bg-slate-50 rounded-xl px-3 py-2 text-sm text-slate-700 font-semibold">{loggedInName}</div>
            :<select className="w-full border border-slate-200 rounded-xl px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-blue-300"
              value={form.submitterName} onChange={e=>setForm(f=>({...f,submitterName:e.target.value}))}>
              <option value="">-- 강사 선택 --</option>
              {[...activeTeachers].sort((a,b)=>a.name.localeCompare(b.name,'ko')).map(t=><option key={t.id} value={t.name}>{t.name}</option>)}
            </select>}
        </div>
        <div>
          <label className="block text-xs font-semibold text-slate-600 mb-1">날짜 <span className="text-red-500">*</span></label>
          <input type="date" className="w-full border border-slate-200 rounded-xl px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-blue-300"
            value={form.date} onChange={e=>setForm(f=>({...f,date:e.target.value}))}/>
        </div>
        <div>
          <label className="block text-xs font-semibold text-slate-600 mb-1">항목 분류 <span className="text-red-500">*</span></label>
          <select className="w-full border border-slate-200 rounded-xl px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-blue-300"
            value={form.category} onChange={e=>setForm(f=>({...f,category:e.target.value}))}>
            {CATS.map(c=><option key={c} value={c}>{c}</option>)}
          </select>
        </div>
        <div>
          <label className="block text-xs font-semibold text-slate-600 mb-1">금액 <span className="text-red-500">*</span></label>
          <WonInput value={form.amount} onChange={v=>setForm(f=>({...f,amount:v}))} free={true}/>
        </div>
        <div className="md:col-span-2">
          <label className="block text-xs font-semibold text-slate-600 mb-1">구매 내용 <span className="text-red-500">*</span></label>
          <input type="text" placeholder="예: A4 용지 2박스, 건반 청소 키트 등"
            className="w-full border border-slate-200 rounded-xl px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-blue-300"
            value={form.description} onChange={e=>setForm(f=>({...f,description:e.target.value}))}/>
        </div>
        <div className="md:col-span-2">
          <label className="block text-xs font-semibold text-slate-600 mb-1">비고 <span className="text-slate-400 font-normal">(선택)</span></label>
          <input type="text" placeholder="구매처, 카드/현금 여부 등"
            className="w-full border border-slate-200 rounded-xl px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-blue-300 mb-3"
            value={form.memo} onChange={e=>setForm(f=>({...f,memo:e.target.value}))}/>
          {/* 영수증 사진 첨부 */}
          <div className="border-2 border-dashed border-slate-200 rounded-xl p-4 bg-slate-50">
            <div className="flex items-center gap-3 flex-wrap">
              <label className="cursor-pointer flex items-center gap-2 px-4 py-2 bg-white border border-slate-300 hover:border-blue-400 hover:bg-blue-50 rounded-xl text-sm text-slate-700 font-medium transition-colors shadow-sm">
                📷 영수증 사진 첨부
                <input type="file" accept="image/*" className="hidden" onChange={handleImageChange}/>
              </label>
              {form.receiptImg
                ?<div className="flex items-center gap-3">
                    <img src={form.receiptImg} alt="영수증 미리보기"
                      className="w-16 h-16 object-cover rounded-xl border border-slate-200 cursor-pointer hover:opacity-80 transition-opacity"
                      onClick={()=>setImgModal(form.receiptImg)}/>
                    <div className="flex flex-col gap-1">
                      <span className="text-xs text-green-600 font-semibold">✅ 사진 첨부됨</span>
                      <button onClick={()=>setForm(f=>({...f,receiptImg:''}))}
                        className="text-xs text-red-400 hover:text-red-600 text-left transition-colors">× 삭제</button>
                      <button onClick={()=>setImgModal(form.receiptImg)}
                        className="text-xs text-blue-500 hover:text-blue-700 text-left transition-colors">크게 보기</button>
                    </div>
                  </div>
                :<span className="text-xs text-slate-400">카메라로 촬영하거나 갤러리에서 선택하세요</span>}
            </div>
          </div>
        </div>
      </div>
      <div className="mt-4 flex items-center gap-3">
        <button onClick={handleSubmit}
          className="px-5 py-2 bg-blue-600 text-white rounded-xl text-sm font-semibold hover:bg-blue-700 transition-colors">
          {editTargetId?'수정 저장':'등록하기'}
        </button>
        <button onClick={()=>{setForm(emptyForm);setEditTargetId(null);}}
          className="px-4 py-2 bg-slate-100 text-slate-600 rounded-xl text-sm hover:bg-slate-200 transition-colors">
          {editTargetId?'취소':'초기화'}
        </button>
        {saved&&<span className="text-green-600 text-sm font-semibold">✅ 등록되었습니다!</span>}
      </div>
      <div className="mt-3 bg-amber-50 border border-amber-200 rounded-xl px-4 py-2 text-xs text-amber-800">
        💡 등록된 지출은 <strong>예산 관리 → 지출</strong> 탭에 자동으로 반영됩니다.
        {role==='teacher'&&' 원장님이 예산 관리에서 확인할 수 있습니다.'}
      </div>
    </div>

    {/* 제출 내역 */}
    <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-5">
      <div className="flex items-center justify-between mb-4">
        <h2 className="font-bold text-slate-800">📋 {role==='teacher'?`내 제출 내역 (${loggedInName})`:' 제출 내역'}</h2>
        {role!=='teacher'&&<div className="flex items-center gap-2">
          <span className="text-xs text-slate-500">강사별 보기:</span>
          <select className="border border-slate-200 rounded-xl px-2 py-1 text-sm focus:outline-none"
            value={filterName} onChange={e=>setFilterName(e.target.value)}>
            <option value="전체">전체</option>
            {submitters.map(s=><option key={s} value={s}>{s}</option>)}
          </select>
        </div>}
      </div>
      {filtered.length===0
        ?<div className="text-center py-8 text-slate-400 text-sm">아직 제출된 지출 내역이 없습니다</div>
        :<>
          <div className="overflow-x-auto overflow-y-auto tbl-scroll" style={{maxHeight:'calc(100vh - 320px)'}}>
            <table className="w-full text-sm app-table">
              <thead className="bg-[#f1f5f9] text-xs text-slate-600">
                <tr>
                  {['날짜','강사','항목','구매 내용','금액','영수증','관리'].map(h=><th key={h} className="px-3 py-2 text-left">{h}</th>)}
                </tr>
              </thead>
              <tbody>
                {filtered.map(r=><tr key={r.id} className="table-row border-t">
                  <td className="px-3 py-2 text-slate-600 text-xs whitespace-nowrap">{fDate(r.date)}</td>
                  <td className="px-3 py-2 font-semibold text-slate-800">{r.submittedBy||'-'}</td>
                  <td className="px-3 py-2"><span className="badge bg-blue-50 text-blue-700">{r.category}</span></td>
                  <td className="px-3 py-2 text-slate-800 max-w-xs">
                    <div className="truncate">{r.description}</div>
                    {r.memo&&<div className="text-xs text-slate-400 truncate mt-0.5">{r.memo}</div>}
                  </td>
                  <td className="px-3 py-2 font-semibold text-red-600 whitespace-nowrap">{fWon(r.amount)}</td>
                  <td className="px-3 py-2">
                    {r.receiptImg
                      ?<button onClick={()=>setImgModal(r.receiptImg)}
                          className="flex items-center gap-1.5 group">
                          <img src={r.receiptImg} alt="영수증"
                            className="w-10 h-10 object-cover rounded-lg border border-slate-200 group-hover:border-blue-400 transition-colors"/>
                          <span className="text-xs text-blue-500 group-hover:text-blue-700 font-medium whitespace-nowrap">보기</span>
                        </button>
                      :<span className="text-slate-400 text-xs">없음</span>}
                  </td>
                  <td className="px-3 py-2">
                    <div className="flex gap-1">
                      <button onClick={()=>handleEdit(r)} className="text-xs px-2 py-1 rounded bg-[#f1f5f9] text-[#1e3a5f] hover:bg-[#dbeafe]">수정</button>
                      <button onClick={()=>setConfirmDel(r.id)} className="text-xs px-2 py-1 rounded bg-red-50 text-red-500 hover:bg-red-100">삭제</button>
                    </div>
                  </td>
                </tr>)}
              </tbody>
            </table>
          </div>
          <div className="mt-3 flex justify-end">
            <span className="text-sm font-bold text-slate-800">
              합계: <span className="text-red-600">{fWon(totalAmt)}</span>
              <span className="text-slate-400 font-normal text-xs ml-2">({filtered.length}건)</span>
            </span>
          </div>
        </>}
    </div>

    {/* 영수증 사진 크게 보기 (라이트박스) */}
    {imgModal&&<div className="modal-overlay" onClick={()=>setImgModal(null)}>
      <div className="bg-white rounded-2xl shadow-2xl p-4 w-full max-w-lg mx-4" onClick={e=>e.stopPropagation()}>
        <div className="flex items-center justify-between mb-3">
          <span className="font-bold text-slate-800 text-sm">🧾 영수증 사진</span>
          <button onClick={()=>setImgModal(null)}
            className="w-8 h-8 flex items-center justify-center rounded-full bg-slate-100 hover:bg-slate-200 text-slate-600 text-lg font-bold transition-colors">×</button>
        </div>
        <img src={imgModal} alt="영수증 원본" className="w-full rounded-xl object-contain max-h-[70vh]"/>
      </div>
    </div>}

    <Confirm open={confirmDel!==null} msg="이 지출 항목을 삭제하시겠습니까?" onYes={()=>handleDel(confirmDel)} onNo={()=>setConfirmDel(null)}/>
  </div>;
}

// ── 로그인 / 아이디·비밀번호 화면 ─────────────────────────────────────────
// 강사 역할에서 숨길 페이지 ID 목록
const TEACHER_HIDDEN=['teachers','tuition','payslip','budget','tax','parent_portal','withdrawal','settings'];

function LoginScreen({onLogin,academyName,accounts,teachers}){
  const[step,setStep]=useState('role');
  const[role,setRole]=useState(null);
  const[id,setId]=useState('');
  const[pw,setPw]=useState('');
  const[err,setErr]=useState('');
  const enter=r=>{setRole(r);setStep('login');setId('');setPw('');setErr('');};
  const login=()=>{
    if(role==='director'){
      const acc=accounts.director||{id:'director',pw:'1234'};
      if(id===acc.id&&pw===acc.pw){onLogin('director',null);}
      else{setErr('아이디 또는 비밀번호가 올바르지 않습니다.');}
    } else {
      // 개별 강사 계정: loginId(기본값=이름), loginPw(기본값=0000)
      const found=(teachers||[]).find(t=>t.status==='active'&&(t.loginId||t.name)===id&&(t.loginPw||'0000')===pw);
      if(found){onLogin('teacher',found.id);}
      else{
        // 호환용 공통 강사 계정 유지
        const acc=accounts.teacher||{id:'teacher',pw:'5678'};
        if(id===acc.id&&pw===acc.pw){onLogin('teacher',null);}
        else{setErr('아이디 또는 비밀번호가 올바르지 않습니다.');}
      }
    }
  };
  const inp2={width:'100%',padding:'10px 14px',border:'1px solid #e2e8f0',borderRadius:'10px',fontSize:'14px',outline:'none',boxSizing:'border-box',marginTop:'4px'};
  return<div style={{minHeight:'100vh',display:'flex',alignItems:'center',justifyContent:'center',background:'linear-gradient(135deg,#1e3a5f 0%,#152d4a 100%)'}}>
    <div style={{position:'relative',background:'white',borderRadius:'24px',padding:'48px 40px',width:'360px',boxShadow:'0 24px 80px rgba(0,0,0,0.3)',textAlign:'center'}}>
      <div style={{position:'absolute',top:'16px',right:'16px',background:'#f59e0b',color:'white',fontSize:'10px',fontWeight:'800',padding:'3px 10px',borderRadius:'20px',letterSpacing:'0.05em'}}>DEMO</div>
      <div style={{fontSize:'48px',marginBottom:'12px'}}>🎹</div>
      <h1 style={{fontSize:'20px',fontWeight:'800',color:'#1e3a5f',marginBottom:'4px'}}>{academyName||'피아노 학원'}</h1>
      <p style={{fontSize:'13px',color:'#64748b',marginBottom:'20px'}}>학원 관리 시스템</p>
      <div style={{background:'#eff6ff',border:'1px solid #bfdbfe',borderRadius:'12px',padding:'12px 14px',marginBottom:'20px',textAlign:'left'}}>
        <p style={{fontSize:'11px',fontWeight:'700',color:'#1e40af',marginBottom:'6px'}}>🔑 데모 체험 계정</p>
        <div style={{display:'flex',flexDirection:'column',gap:'3px'}}>
          <p style={{fontSize:'11px',color:'#1e3a5f'}}><span style={{fontWeight:'700'}}>원장</span>&nbsp; ID: <code style={{background:'#dbeafe',padding:'1px 5px',borderRadius:'4px',fontSize:'11px'}}>director</code> &nbsp;PW: <code style={{background:'#dbeafe',padding:'1px 5px',borderRadius:'4px',fontSize:'11px'}}>1234</code></p>
          <p style={{fontSize:'11px',color:'#1e3a5f'}}><span style={{fontWeight:'700'}}>강사</span>&nbsp; ID: 강사 이름 &nbsp;PW: <code style={{background:'#dbeafe',padding:'1px 5px',borderRadius:'4px',fontSize:'11px'}}>0000</code></p>
        </div>
      </div>
      {step==='role'&&<>
        <p style={{fontSize:'13px',color:'#475569',fontWeight:'600',marginBottom:'16px'}}>로그인 유형을 선택하세요</p>
        <div style={{display:'flex',flexDirection:'column',gap:'12px'}}>
          <button onClick={()=>enter('director')} style={{padding:'16px',background:'#1e3a5f',color:'white',border:'none',borderRadius:'14px',fontSize:'15px',fontWeight:'700',cursor:'pointer',transition:'opacity 0.15s'}} onMouseEnter={e=>e.currentTarget.style.opacity='0.88'} onMouseLeave={e=>e.currentTarget.style.opacity='1'}>🏫 원장 로그인</button>
          <button onClick={()=>enter('teacher')} style={{padding:'16px',background:'white',color:'#1e3a5f',border:'2px solid #1e3a5f',borderRadius:'14px',fontSize:'15px',fontWeight:'700',cursor:'pointer',transition:'background 0.15s'}} onMouseEnter={e=>e.currentTarget.style.background='#f0f4ff'} onMouseLeave={e=>e.currentTarget.style.background='white'}>👨‍🏫 강사 로그인</button>
        </div>
      </>}
      {step==='login'&&<>
        <p style={{fontSize:'14px',color:'#1e3a5f',fontWeight:'700',marginBottom:'20px'}}>{role==='director'?'🏫 원장':'👨‍🏫 강사'} 로그인</p>
        <div style={{textAlign:'left',marginBottom:'12px'}}>
          <label style={{fontSize:'12px',fontWeight:'700',color:'#475569'}}>아이디</label>
          <input type="text" autoComplete="username" style={inp2} value={id} onChange={e=>{setId(e.target.value);setErr('');}}
            onKeyDown={e=>e.key==='Enter'&&login()} placeholder="아이디 입력"/>
        </div>
        <div style={{textAlign:'left',marginBottom:'16px'}}>
          <label style={{fontSize:'12px',fontWeight:'700',color:'#475569'}}>비밀번호</label>
          <input type="password" autoComplete="current-password" style={inp2} value={pw} onChange={e=>{setPw(e.target.value);setErr('');}}
            onKeyDown={e=>e.key==='Enter'&&login()} placeholder="비밀번호 입력"/>
        </div>
        {err&&<p style={{fontSize:'12px',color:'#ef4444',marginBottom:'12px',fontWeight:'600'}}>{err}</p>}
        <button onClick={login} style={{width:'100%',padding:'13px',background:'#1e3a5f',color:'white',border:'none',borderRadius:'12px',fontSize:'15px',fontWeight:'700',cursor:'pointer',marginBottom:'12px'}}>로그인</button>
        <button onClick={()=>{setStep('role');setId('');setPw('');setErr('');}} style={{fontSize:'13px',color:'#94a3b8',background:'none',border:'none',cursor:'pointer'}}>← 뒤로</button>
      </>}
    </div>
  </div>;
}

function AccountChangeModal({accounts,setAccounts,onClose}){
  const[tab,setTab]=useState('director');
  const[currPw,setCurrPw]=useState('');
  const[newId,setNewId]=useState('');
  const[newPw,setNewPw]=useState('');
  const[newPw2,setNewPw2]=useState('');
  const[err,setErr]=useState('');
  const defaultAcc={director:{id:'director',pw:'1234'},teacher:{id:'teacher',pw:'5678'}};
  const acc=accounts[tab]||defaultAcc[tab];
  const save=()=>{
    if(currPw!==acc.pw){setErr('현재 비밀번호가 올바르지 않습니다.');return;}
    const finalId=newId.trim()||acc.id;
    if(!finalId){setErr('아이디를 입력해주세요.');return;}
    if(newPw&&newPw!==newPw2){setErr('새 비밀번호가 일치하지 않습니다.');return;}
    setAccounts(p=>({...p,[tab]:{id:finalId,pw:newPw||acc.pw}}));
    setErr('');setCurrPw('');setNewId('');setNewPw('');setNewPw2('');
    alert(`${tab==='director'?'원장':'강사'} 계정 정보가 변경되었습니다.`);
    onClose();
  };
  return<Modal open onClose={onClose} title="🔐 계정 정보 변경">
    <div style={{display:'flex',gap:'8px',marginBottom:'16px'}}>
      {['director','teacher'].map(r=><button key={r} onClick={()=>{setTab(r);setCurrPw('');setNewId('');setNewPw('');setNewPw2('');setErr('');}} style={{flex:1,padding:'8px',borderRadius:'8px',border:'none',background:tab===r?'#1e3a5f':'#f1f5f9',color:tab===r?'white':'#475569',fontWeight:'700',cursor:'pointer',fontSize:'13px'}}>{r==='director'?'🏫 원장':'👨‍🏫 강사'}</button>)}
    </div>
    <p style={{fontSize:'12px',color:'#64748b',marginBottom:'12px'}}>현재 아이디: <strong>{acc.id}</strong></p>
    <Field label="현재 비밀번호"><input className={inp} type="password" value={currPw} onChange={e=>setCurrPw(e.target.value)} placeholder="현재 비밀번호"/></Field>
    <Field label="새 아이디 (변경 시에만 입력)"><input className={inp} type="text" value={newId} onChange={e=>setNewId(e.target.value)} placeholder={acc.id}/></Field>
    <Field label="새 비밀번호 (변경 시에만 입력)"><input className={inp} type="password" value={newPw} onChange={e=>setNewPw(e.target.value)} placeholder="새 비밀번호"/></Field>
    <Field label="새 비밀번호 확인"><input className={inp} type="password" value={newPw2} onChange={e=>setNewPw2(e.target.value)} placeholder="새 비밀번호 확인"/></Field>
    {err&&<p style={{color:'#ef4444',fontSize:'12px',marginBottom:'8px',fontWeight:'600'}}>{err}</p>}
    <div className="flex justify-end gap-2 mt-2">
      <button className={btn('indigo')} onClick={save}>변경</button>
      <button className={btn('gray')} onClick={onClose}>취소</button>
    </div>
  </Modal>;
}

// ── 설정 ─────────────────────────────────────────────────────────────────────
function SettingsManagement({academyName,setAcademyName,baseUrl,setBaseUrl,accounts,setAccounts,teachers,setTeachers,allData,setAllData,tuitionDaySetting,setTuitionDaySetting}){
  const[tab,setTab]=useState('academy');
  // 학원 기본 정보
  const[nameInput,setNameInput]=useState(academyName||'');
  const[urlInput,setUrlInput]=useState(baseUrl||'');
  // 수강료 납부기한 임시 설정 (저장 버튼 누를 때만 반영)
  const[draftTuition,setDraftTuition]=useState(tuitionDaySetting||{mode:'joinDate',fixedDay:1});
  const[tuitionSaved,setTuitionSaved]=useState(false);
  const saveTuitionSetting=()=>{setTuitionDaySetting(draftTuition);setTuitionSaved(true);setTimeout(()=>setTuitionSaved(false),2000);};
  // 원장 계정
  const[dCurrPw,setDCurrPw]=useState('');
  const[dNewId,setDNewId]=useState('');
  const[dNewPw,setDNewPw]=useState('');
  const[dNewPw2,setDNewPw2]=useState('');
  const[dErr,setDErr]=useState('');
  // 강사 계정 편집 모달
  const[teacherAccModal,setTeacherAccModal]=useState(null);
  const[tNewId,setTNewId]=useState('');
  const[tNewPw,setTNewPw]=useState('');
  const[tNewPw2,setTNewPw2]=useState('');
  const[tErr,setTErr]=useState('');

  const saveAcademy=()=>{
    if(!nameInput.trim()){alert('학원 이름을 입력해주세요.');return;}
    setAcademyName(nameInput.trim());
    if(urlInput.trim())setBaseUrl(urlInput.trim());
    alert('학원 기본 정보가 저장되었습니다.');
  };
  const saveDirector=()=>{
    const acc=accounts.director||{id:'director',pw:'1234'};
    if(dCurrPw!==acc.pw){setDErr('현재 비밀번호가 올바르지 않습니다.');return;}
    const finalId=dNewId.trim()||acc.id;
    if(dNewPw&&dNewPw!==dNewPw2){setDErr('새 비밀번호가 일치하지 않습니다.');return;}
    setAccounts(p=>({...p,director:{id:finalId,pw:dNewPw||acc.pw}}));
    setDCurrPw('');setDNewId('');setDNewPw('');setDNewPw2('');setDErr('');
    alert('원장 계정이 변경되었습니다.');
  };
  const openTeacherAcc=t=>{setTeacherAccModal(t);setTNewId(t.loginId||t.name||'');setTNewPw('');setTNewPw2('');setTErr('');};
  const saveTeacherAcc=()=>{
    if(!tNewId.trim()){setTErr('아이디를 입력해주세요.');return;}
    if(tNewPw&&tNewPw!==tNewPw2){setTErr('새 비밀번호가 일치하지 않습니다.');return;}
    if(tNewPw&&tNewPw.length<4){setTErr('비밀번호는 4자리 이상이어야 합니다.');return;}
    setTeachers(prev=>prev.map(t=>t.id===teacherAccModal.id?{...t,loginId:tNewId.trim(),loginPw:tNewPw||t.loginPw||'0000'}:t));
    setTeacherAccModal(null);
    alert('강사 계정이 저장되었습니다.');
  };
  const resetTeacherPw=t=>{
    if(!confirm(`${t.name} 강사의 비밀번호를 초기 비밀번호(0000)로 초기화하시겠습니까?`))return;
    setTeachers(prev=>prev.map(x=>x.id===t.id?{...x,loginPw:'0000'}:x));
    alert('비밀번호가 0000으로 초기화되었습니다.');
  };
  // 데이터 동기화
  const[importText,setImportText]=useState('');
  const[importErr,setImportErr]=useState('');
  const exportData=()=>{
    const data=JSON.stringify(allData,null,2);
    const blob=new Blob([data],{type:'application/json'});
    const url=URL.createObjectURL(blob);
    const a=document.createElement('a');
    const dateStr=today().replace(/-/g,'');
    a.href=url;a.download=`학원데이터_${academyName||'backup'}_${dateStr}.json`;
    a.click();URL.revokeObjectURL(url);
  };
  const importData=()=>{
    setImportErr('');
    try{
      const parsed=JSON.parse(importText);
      if(!parsed||typeof parsed!=='object'){setImportErr('올바른 JSON 형식이 아닙니다.');return;}
      if(!confirm('현재 모든 데이터를 가져온 데이터로 교체합니다. 기존 데이터는 사라집니다. 계속하시겠습니까?'))return;
      setAllData(parsed);
      setImportText('');
      alert('데이터 가져오기가 완료되었습니다. 페이지를 새로고침하면 반영됩니다.');
      setTimeout(()=>window.location.reload(),500);
    }catch(e){setImportErr('JSON 파싱 오류: '+e.message);}
  };
  const importFile=e=>{
    const file=e.target.files&&e.target.files[0];
    if(!file)return;
    const reader=new FileReader();
    reader.onload=ev=>setImportText(ev.target.result);
    reader.readAsText(file);
    e.target.value='';
  };
  const activeTeachers=(teachers||[]).filter(t=>t.status!=='resigned'&&!t.name.includes('(원장)'));
  const dirAcc=accounts.director||{id:'director',pw:'1234'};
  return<div className="space-y-6">
    <div>
      <h1 className="text-2xl font-bold text-slate-900">설정</h1>
      <p className="text-slate-600 text-sm mt-1">학원 기본 정보와 계정을 관리하세요</p>
    </div>
    <div className="flex gap-2 border-b border-slate-200 pb-0 flex-wrap">
      {[{id:'academy',label:'학원 기본 정보'},{id:'tuition_day',label:'수강료 납부기한'},{id:'teachers_acc',label:'강사 계정 관리'},{id:'director',label:'원장 계정'},{id:'data',label:'데이터 백업·공유'}].map(t=>(
        <button key={t.id} onClick={()=>setTab(t.id)} className={`px-4 py-2 text-sm font-semibold rounded-t-lg border-b-2 transition-colors ${tab===t.id?'border-[#1e3a5f] text-[#1e3a5f] bg-white':'border-transparent text-slate-500 hover:text-slate-700'}`}>{t.label}</button>
      ))}
    </div>
    {tab==='academy'&&<div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6 space-y-4 max-w-lg">
      <Field label="학원 이름" required><input className={inp} value={nameInput} onChange={e=>setNameInput(e.target.value)} placeholder="예: 하모니 피아노 학원"/></Field>
      <Field label="학부모 앱 URL"><input className={inp} value={urlInput} onChange={e=>setUrlInput(e.target.value)} placeholder="학부모앱.html"/><p className="text-xs text-slate-400 mt-1">공지·영상 공유 링크에 사용되는 학부모 앱 파일명</p></Field>
      <button className={btn('indigo')} onClick={saveAcademy}>저장</button>
    </div>}
    {tab==='tuition_day'&&<div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6 space-y-5 max-w-lg">
      <div>
        <h3 className="font-bold text-slate-800 mb-1">수강료 납부기한 방식</h3>
        <p className="text-xs text-slate-500">신규 학생 등록, 수강반 변경, 납부 내역 추가 시 납부기한이 자동으로 설정됩니다.</p>
      </div>
      <div className="space-y-3">
        <label className={`flex items-start gap-3 p-4 rounded-xl border-2 cursor-pointer transition-colors ${(draftTuition?.mode||'joinDate')==='joinDate'?'border-indigo-400 bg-indigo-50':'border-slate-200 hover:border-slate-300'}`}>
          <input type="radio" name="tuitionMode" value="joinDate" checked={(draftTuition?.mode||'joinDate')==='joinDate'} onChange={()=>setDraftTuition({...draftTuition,mode:'joinDate'})} className="mt-0.5 accent-indigo-600"/>
          <div>
            <div className="font-semibold text-slate-800 text-sm">등록일 기준</div>
            <div className="text-xs text-slate-500 mt-0.5">학생마다 등록일의 날짜로 다음달 같은 날짜가 납부기한이 됩니다.<br/>예) 7월 14일 등록 → 매달 14일 납부</div>
          </div>
        </label>
        <label className={`flex items-start gap-3 p-4 rounded-xl border-2 cursor-pointer transition-colors ${draftTuition?.mode==='fixed'?'border-indigo-400 bg-indigo-50':'border-slate-200 hover:border-slate-300'}`}>
          <input type="radio" name="tuitionMode" value="fixed" checked={draftTuition?.mode==='fixed'} onChange={()=>setDraftTuition({...draftTuition,mode:'fixed'})} className="mt-0.5 accent-indigo-600"/>
          <div className="flex-1">
            <div className="font-semibold text-slate-800 text-sm">매달 고정일</div>
            <div className="text-xs text-slate-500 mt-0.5">모든 학생이 매달 동일한 날짜에 납부합니다.</div>
            {draftTuition?.mode==='fixed'&&<div className="flex items-center gap-2 mt-2">
              <span className="text-sm text-slate-700">매달</span>
              <input type="number" min={1} max={28} value={draftTuition?.fixedDay||1} onChange={e=>setDraftTuition({...draftTuition,fixedDay:Math.min(28,Math.max(1,Number(e.target.value)))})} className="border border-slate-300 rounded-lg px-2 py-1 text-sm w-16 text-center focus:outline-none focus:ring-2 focus:ring-indigo-300"/>
              <span className="text-sm text-slate-700">일까지</span>
            </div>}
          </div>
        </label>
      </div>
      <div className="text-xs text-slate-400 bg-slate-50 rounded-lg p-3">설정을 바꿔도 이미 등록된 납부 내역의 기한은 자동으로 변경되지 않습니다.<br/>이후 새로 생성되는 내역부터 적용됩니다.</div>
      <div className="flex items-center gap-3">
        <button className={btn('indigo')} onClick={saveTuitionSetting}>저장</button>
        {tuitionSaved&&<span className="text-sm text-green-600 font-medium">✓ 저장되었습니다</span>}
      </div>
    </div>}
    {tab==='teachers_acc'&&<div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
      <div className="px-5 py-4 border-b border-slate-100">
        <p className="text-sm text-slate-600">각 강사의 로그인 아이디와 비밀번호를 설정합니다. 기본 비밀번호는 <strong>0000</strong>입니다.</p>
      </div>
      <div className="overflow-x-auto">
        <table className="w-full text-sm app-table">
          <thead><tr className="border-b"><th className="px-4 py-3 text-left text-xs font-bold text-slate-600">이름</th><th className="px-4 py-3 text-left text-xs font-bold text-slate-600">과목</th><th className="px-4 py-3 text-left text-xs font-bold text-slate-600">로그인 아이디</th><th className="px-4 py-3 text-left text-xs font-bold text-slate-600">비밀번호</th><th className="px-4 py-3 text-left text-xs font-bold text-slate-600">관리</th></tr></thead>
          <tbody>{activeTeachers.map(t=><tr key={t.id} className="table-row border-b">
            <td className="px-4 py-3 font-semibold text-slate-900">{t.name}</td>
            <td className="px-4 py-3 text-slate-700 text-xs">{(t.subjects||[]).join(', ')||'-'}</td>
            <td className="px-4 py-3 text-slate-700 font-mono">{t.loginId||t.name||'-'}</td>
            <td className="px-4 py-3 text-slate-400 font-mono">{t.loginPw?'••••':'미설정(0000)'}</td>
            <td className="px-4 py-3 flex gap-2">
              <button onClick={()=>openTeacherAcc(t)} className={btn('indigo')} style={{padding:'4px 8px',fontSize:'12px'}}>계정 설정</button>
              <button onClick={()=>resetTeacherPw(t)} className={btn('gray')} style={{padding:'4px 8px',fontSize:'12px'}}>초기화</button>
            </td>
          </tr>)}</tbody>
        </table>
      </div>
    </div>}
    {tab==='director'&&<div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6 space-y-4 max-w-lg">
      <p className="text-sm text-slate-600">현재 원장 아이디: <strong className="font-mono">{dirAcc.id}</strong></p>
      <Field label="현재 비밀번호"><input className={inp} type="password" value={dCurrPw} onChange={e=>{setDCurrPw(e.target.value);setDErr('');}} placeholder="현재 비밀번호"/></Field>
      <Field label="새 아이디 (변경 시만 입력)"><input className={inp} type="text" value={dNewId} onChange={e=>setDNewId(e.target.value)} placeholder={dirAcc.id}/></Field>
      <Field label="새 비밀번호"><input className={inp} type="password" value={dNewPw} onChange={e=>setDNewPw(e.target.value)} placeholder="새 비밀번호"/></Field>
      <Field label="새 비밀번호 확인"><input className={inp} type="password" value={dNewPw2} onChange={e=>setDNewPw2(e.target.value)} placeholder="새 비밀번호 확인"/></Field>
      {dErr&&<p className="text-red-500 text-xs font-semibold">{dErr}</p>}
      <button className={btn('indigo')} onClick={saveDirector}>변경 저장</button>
    </div>}
    {tab==='data'&&<div className="space-y-6 max-w-2xl">
      <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6">
        <h3 className="font-bold text-slate-900 mb-2">데이터 내보내기 (백업)</h3>
        <p className="text-sm text-slate-600 mb-4">현재 학원의 모든 데이터를 JSON 파일로 저장합니다. 다른 기기나 브라우저에서 동일한 데이터를 사용할 때 이 파일을 가져오기 하세요.</p>
        <button className={btn('indigo')} onClick={exportData}>💾 데이터 내보내기 (.json)</button>
      </div>
      <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6">
        <h3 className="font-bold text-slate-900 mb-2">데이터 가져오기 (복원/동기화)</h3>
        <p className="text-sm text-slate-600 mb-4">다른 기기에서 내보낸 JSON 파일을 업로드하거나, 아래에 JSON 텍스트를 직접 붙여넣으세요.<br/><span className="text-red-500 font-semibold">⚠️ 가져오기 시 기존 데이터가 모두 교체됩니다.</span></p>
        <label className={`${btn('gray')} cursor-pointer inline-block mb-3`}>
          📁 파일 선택
          <input type="file" accept=".json" className="hidden" onChange={importFile}/>
        </label>
        <textarea className={inp+' font-mono text-xs'} rows={6} value={importText} onChange={e=>setImportText(e.target.value)} placeholder="또는 JSON 데이터를 여기에 붙여넣기..."/>
        {importErr&&<p className="text-red-500 text-xs font-semibold mt-1">{importErr}</p>}
        <button className={`${btn('red')} mt-3`} onClick={importData} disabled={!importText.trim()}>데이터 가져오기 (교체)</button>
      </div>
      <div className="bg-amber-50 border border-amber-200 rounded-2xl p-4 text-sm text-amber-800">
        <strong>사용 방법 안내</strong><br/>
        원장 기기에서 "데이터 내보내기" → 강사 기기에서 "데이터 가져오기"를 하면 동일한 학원 데이터를 공유할 수 있습니다. 정기적으로 백업하여 데이터 분실을 예방하세요.
      </div>
    </div>}
    <Modal open={!!teacherAccModal} onClose={()=>setTeacherAccModal(null)} title={`${teacherAccModal?.name||''} 강사 계정 설정`}>
      <div className="space-y-4">
        <Field label="로그인 아이디" required><input className={inp} value={tNewId} onChange={e=>setTNewId(e.target.value)} placeholder="로그인에 사용할 아이디"/></Field>
        <Field label="새 비밀번호"><input className={inp} type="password" value={tNewPw} onChange={e=>setTNewPw(e.target.value)} placeholder="미입력 시 기존 비밀번호 유지 (기본:0000)"/></Field>
        <Field label="새 비밀번호 확인"><input className={inp} type="password" value={tNewPw2} onChange={e=>setTNewPw2(e.target.value)} placeholder="비밀번호 재입력"/></Field>
        {tErr&&<p className="text-red-500 text-xs font-semibold">{tErr}</p>}
        <div className="flex gap-3 justify-end pt-2">
          <button onClick={saveTeacherAcc} className={btn('indigo')}>저장</button>
          <button onClick={()=>setTeacherAccModal(null)} className={btn('gray')}>취소</button>
        </div>
      </div>
    </Modal>
  </div>;
}

// ── 사이드바 + 앱 ────────────────────────────────────────────────────────────
const MENU_GROUPS=[
  {
    group:null,
    items:[{id:'dashboard',label:'대시보드',icon:'🏠'}]
  },
  {
    group:'인원 관리',
    items:[
      {id:'students',label:'학생 관리',icon:'🎓'},
      {id:'teachers',label:'강사 관리',icon:'👨‍🏫'},
      {id:'classes',label:'수업 관리',icon:'📚'},
      {id:'attendance',label:'출결 관리',icon:'✅'},
    ]
  },
  {
    group:'운영 관리',
    items:[
      {id:'consultation',label:'상담 관리',icon:'💬'},
      {id:'calendar',label:'학원 캘린더',icon:'📅'},
      {id:'makeup',label:'보강 관리',icon:'🔄'},
    ]
  },
  {
    group:'재무 관리',
    items:[
      {id:'expense_submit',label:'지출 증빙',icon:'🧾'},
      {id:'tuition',label:'학원비 관리',icon:'💳'},
      {id:'payslip',label:'급여 명세서',icon:'📋'},
      {id:'budget',label:'예산 관리',icon:'💰'},
      {id:'tax',label:'세금 신고',icon:'📊'},
    ]
  },
  {
    group:'소통 · 공유',
    items:[
      {id:'notices',label:'공지사항',icon:'📢'},
      {id:'videos',label:'학생피드백',icon:'💬'},
      {id:'parent_portal',label:'학부모 포털',icon:'👨‍👩‍👧'},
    ]
  },
  {
    group:'시스템',
    items:[
      {id:'settings',label:'설정',icon:'⚙️'},
    ]
  },
];
// 기존 MENUS 배열 유지 (탑바 breadcrumb용)
const MENUS=MENU_GROUPS.flatMap(g=>g.items);

function Sidebar({page,setPage,teachers,students,classes,academyName,role,onLogout,mobileOpen,onMobileClose}){
  const[collapsed,setCollapsed]=useState(false);
  const[isMobile,setIsMobile]=useState(()=>window.innerWidth<768);
  useEffect(()=>{
    const h=()=>setIsMobile(window.innerWidth<768);
    window.addEventListener('resize',h);
    return()=>window.removeEventListener('resize',h);
  },[]);
  // 모바일에서 메뉴 클릭 시 사이드바 자동 닫기
  const go=id=>{setPage(id);if(isMobile&&onMobileClose)onMobileClose();};
  // 역할에 따라 보이는 메뉴 필터링
  const visibleGroups=MENU_GROUPS.map(g=>({
    ...g,
    items:role==='teacher'?g.items.filter(m=>!TEACHER_HIDDEN.includes(m.id)):g.items
  })).filter(g=>g.items.length>0);
  // col: 접힌 상태 (모바일에서는 항상 펼침)
  const col=isMobile?false:collapsed;
  // 모바일: 화면 위에 겹치는 드로어 / 데스크탑: 기존 사이드바
  const sideStyle=isMobile
    ?{position:'fixed',left:0,top:0,height:'100vh',width:'240px',zIndex:200,background:'#1e3a5f',overflow:'hidden',display:'flex',flexDirection:'column',flexShrink:0,transform:mobileOpen?'translateX(0)':'translateX(-100%)',transition:'transform 0.25s ease'}
    :{height:'100vh',overflow:'hidden',background:'#1e3a5f',width:collapsed?'64px':'240px',transition:'width 0.2s',display:'flex',flexDirection:'column',flexShrink:0};
  return<div style={sideStyle}>
    {/* 헤더 — 학원 이름 */}
    <div className="flex items-center justify-between shrink-0" style={{padding:'12px 14px 10px',borderBottom:'1px solid #2a4a70'}}>
      {!col&&<div className="min-w-0">
        <div className="font-bold text-white leading-tight truncate" style={{fontSize:'15px'}}>🎹 {academyName||'피아노 학원'}</div>
        <div style={{fontSize:'11px',color:'#7cb3e0',marginTop:'2px'}}>{role==='director'?'🏫 원장 모드':'👨‍🏫 강사 모드'}</div>
      </div>}
      {isMobile
        ?<button onClick={onMobileClose} className="w-8 h-8 flex items-center justify-center rounded-lg transition-colors shrink-0" style={{color:'#93c5fd',marginLeft:'auto',background:'transparent',border:'none',cursor:'pointer',fontSize:'16px'}} onMouseEnter={e=>{e.currentTarget.style.background='#2a4a70';}} onMouseLeave={e=>{e.currentTarget.style.background='transparent';}}>✕</button>
        :<button onClick={()=>setCollapsed(!collapsed)} className="w-8 h-8 flex items-center justify-center rounded-lg transition-colors shrink-0" style={{color:'#93c5fd',marginLeft:col?'auto':'8px'}} onMouseEnter={e=>{e.currentTarget.style.background='#2a4a70';e.currentTarget.style.color='#fff'}} onMouseLeave={e=>{e.currentTarget.style.background='transparent';e.currentTarget.style.color='#93c5fd'}}>{col?'▶':'◀'}</button>
      }
    </div>
    {/* 그룹별 메뉴 */}
    <nav className="flex-1 py-1" style={{overflowY:'auto',overflowX:'hidden',minHeight:0}}>
      {visibleGroups.map((g,gi)=>(
        <div key={gi}>
          {g.group&&!col&&(
            <div className="px-4 pt-2 text-xs font-bold uppercase tracking-widest" style={{color:'#5a85b0',lineHeight:'1.4'}}>{g.group}</div>
          )}
          {g.group&&!col&&<div style={{height:'1px',background:'#2a4a70',margin:'2px 12px 2px'}}/>}
          {g.items.map(m=>(
            <button key={m.id} onClick={()=>go(m.id)} onMouseDown={e=>e.preventDefault()}
              className={`sidebar-item w-full flex items-center gap-3 text-left ${page===m.id?'active':''}`}
              style={{padding:'6px 12px',borderRadius:'8px',margin:'0 6px',width:'calc(100% - 12px)'}}>
              <span style={{fontSize:'15px',lineHeight:1,flexShrink:0}}>{m.icon}</span>
              {!col&&<span className="font-semibold text-white" style={{fontSize:'13px'}}>{m.label}</span>}
            </button>
          ))}
        </div>
      ))}
    </nav>
    {/* 하단 정보 + 로그아웃 */}
    {!col&&<div className="px-4 py-2 text-xs shrink-0" style={{borderTop:'1px solid #2a4a70',color:'#7cb3e0',lineHeight:'1.5'}}>
      <div>강사 {teachers.filter(t=>t.status==='active').length}/{teachers.length}명 · 학생 {students.filter(s=>s.status!=='withdrawn'&&(!s.joinDate||s.joinDate<=today())).length}명 · 수업 {classes.length}개</div>
      <button onClick={onLogout} style={{marginTop:'6px',width:'100%',padding:'6px',background:'rgba(255,255,255,0.08)',border:'1px solid rgba(255,255,255,0.15)',borderRadius:'8px',color:'#93c5fd',fontSize:'12px',cursor:'pointer',fontWeight:'600'}} onMouseEnter={e=>e.currentTarget.style.background='rgba(255,255,255,0.15)'} onMouseLeave={e=>e.currentTarget.style.background='rgba(255,255,255,0.08)'}>🔒 로그아웃</button>
    </div>}
    {col&&<div className="shrink-0 pb-2 flex flex-col items-center gap-1.5" style={{borderTop:'1px solid #2a4a70',paddingTop:'8px'}}>
      <button onClick={onLogout} title="로그아웃" style={{width:'36px',height:'36px',background:'rgba(255,255,255,0.08)',border:'1px solid rgba(255,255,255,0.15)',borderRadius:'8px',color:'#93c5fd',fontSize:'14px',cursor:'pointer'}} onMouseEnter={e=>e.currentTarget.style.background='rgba(255,255,255,0.18)'} onMouseLeave={e=>e.currentTarget.style.background='rgba(255,255,255,0.08)'}>🔒</button>
    </div>}
  </div>;
}
// ── AI 어시스턴트 챗봇 (데모 모드 — 추후 마무리 작업 시 OpenAI API 연동 필요) ──
function AIChatbot({students,teachers,classes,attendance,tuitions,events,academyName}){
  const[open,setOpen]=useState(false);
  const initMsg=`안녕하세요! ${academyName||'학원'} 전용 AI 어시스턴트입니다 🤖\n\n현재 **데모 모드**로 실행 중이에요.\n학원 데이터를 기반으로 자주 묻는 질문에 답할 수 있어요.\n아래 버튼을 눌러 바로 질문해보세요!`;
  const[messages,setMessages]=useState([{role:'assistant',content:initMsg}]);
  const[input,setInput]=useState('');
  const[loading,setLoading]=useState(false);
  const bottomRef=useRef(null);
  const inputRef=useRef(null);

  useEffect(()=>{if(open&&bottomRef.current)bottomRef.current.scrollIntoView({behavior:'smooth'});},[messages,open,loading]);
  useEffect(()=>{if(open)setTimeout(()=>inputRef.current&&inputRef.current.focus(),100);},[open]);

  // ── 데모 모드: 키워드 기반 자동 응답 ──
  const demoReply=q=>{
    const t=q.toLowerCase();
    const todayStr=new Date().toISOString().split('T')[0];
    const activeStudents=students.filter(s=>s.status!=='withdrawn'&&(!s.joinDate||s.joinDate<=todayStr));
    const activeTeachers=teachers.filter(t=>t.status==='active');
    const todayAtt=attendance.filter(a=>a.date===todayStr);
    const presentToday=todayAtt.filter(a=>a.status==='present');
    const absentToday=todayAtt.filter(a=>a.status==='absent');
    const monthStr=todayStr.slice(0,7);
    const _effSt=t=>{if(t.status==='paid')return'paid';if(t.status==='overdue')return'overdue';if(t.dueDate&&t.dueDate<todayStr)return'overdue';return'unpaid';};
    const unpaid=tuitions.filter(t=>t.month===monthStr&&_effSt(t)!=='paid');
    const thisMonthEvents=events.filter(e=>e.date.startsWith(monthStr));
    const attByStudent=activeStudents.map(s=>{
      const recs=attendance.filter(a=>a.studentId===s.id);
      const present=recs.filter(a=>a.status==='present').length;
      const rate=recs.length?Math.round(present/recs.length*100):null;
      return{...s,attRate:rate,totalRecs:recs.length};
    });
    const lowAtt=attByStudent.filter(s=>s.attRate!==null&&s.attRate<70).sort((a,b)=>a.attRate-b.attRate);
    const name=academyName||'우리 학원';

    if(t.match(/결석|오늘.*출석|출석.*오늘/)){
      if(absentToday.length===0&&todayAtt.length===0)
        return `오늘(${todayStr}) 출결 데이터가 아직 없어요.\n출결 관리 메뉴에서 먼저 체크해주세요 ✅`;
      return `📋 **오늘 출결 현황** (${todayStr})\n\n✅ 출석: ${presentToday.length}명\n❌ 결석: ${absentToday.length}명${absentToday.length>0?'\n\n**결석 학생:**\n'+absentToday.map(a=>`• ${a.studentName||a.name||'-'}`).join('\n'):''}`;
    }
    if(t.match(/미납|납부.*안.*됨|수업료.*안/)){
      if(unpaid.length===0)return `✅ 이번 달 미납자가 없습니다! 모두 납부 완료 👍`;
      const total=unpaid.reduce((s,t)=>s+(t.amount||0),0);
      return `💳 **미납 현황**\n\n총 **${unpaid.length}건**, **${total.toLocaleString()}원** 미납\n\n**미납 학생:**\n${unpaid.map(t=>`• ${t.studentName||'-'} — ${(t.amount||0).toLocaleString()}원 (${t.month||'-'})`).join('\n')}`;
    }
    if(t.match(/출석률|출석.*낮|결석.*많/)){
      if(lowAtt.length===0)return `✅ 출석률 70% 미만 학생이 없어요! 모두 잘 나오고 있습니다 😊`;
      return `⚠️ **출석률 70% 미만 학생**\n\n${lowAtt.map(s=>`• ${s.name} — 출석률 **${s.attRate}%** (${s.totalRecs}회 기록)`).join('\n')}\n\n관리가 필요한 학생들이에요. 학부모 연락을 권장드려요.`;
    }
    if(t.match(/학생.*몇|재원|학생.*수|몇 명/)){
      return `👥 **학생 현황**\n\n재원 학생: **${activeStudents.length}명**\n전체 등록: ${students.length}명\n\n**재원 학생 목록:**\n${activeStudents.map(s=>`• ${s.name} (${s.grade||''} ${s.subject||''})`).join('\n')}`;
    }
    if(t.match(/강사|선생님|교사/)){
      return `👨‍🏫 **강사 현황**\n\n재직 강사: **${activeTeachers.length}명**\n\n${activeTeachers.map(t=>`• ${t.name} — ${(t.subjects||[]).join(', ')} (${t.phone||'연락처 미입력'})`).join('\n')}`;
    }
    if(t.match(/일정|행사|캘린더|이번.*달/)){
      if(thisMonthEvents.length===0)return `📅 이번 달(${monthStr}) 등록된 일정이 없어요.\n캘린더 메뉴에서 일정을 추가해보세요!`;
      return `📅 **이번 달 일정** (${monthStr})\n\n${thisMonthEvents.sort((a,b)=>a.date.localeCompare(b.date)).map(e=>`• ${e.date} — **${e.title}** (${e.type})`).join('\n')}`;
    }
    if(t.match(/현황|요약|대시보드|전체/)){
      const unpaidAmt=unpaid.reduce((s,t)=>s+(t.amount||0),0);
      return `🏫 **${name} 현황 요약**\n\n👥 재원 학생: ${activeStudents.length}명\n👨‍🏫 재직 강사: ${activeTeachers.length}명\n📚 수업 반: ${classes.length}개\n✅ 오늘 출석: ${presentToday.length}명 / 결석 ${absentToday.length}명\n💳 미납: ${unpaid.length}건 (${unpaidAmt.toLocaleString()}원)\n📅 이번 달 일정: ${thisMonthEvents.length}건`;
    }
    if(t.match(/휴원.*안내|휴원.*공지|쉬는.*날/)){
      return `📢 **휴원 안내문 초안**\n\n안녕하세요, ${name} 학부모님!\n\n다가오는 ○○일(○요일)은 휴원일로 수업이 없습니다.\n학생 여러분의 건강하고 즐거운 시간이 되길 바랍니다.\n\n보강 일정은 별도로 안내드리겠습니다.\n감사합니다. 🙏\n\n— ${name} 원장 드림`;
    }
    if(t.match(/감사.*문자|문자.*감사|감사.*안내/)){
      return `📱 **학부모 감사 문자 초안**\n\n안녕하세요, ${name}입니다 😊\n\n항상 저희 학원을 믿고 소중한 자녀를 맡겨주셔서 진심으로 감사드립니다.\n\n앞으로도 최선을 다해 지도하겠습니다.\n궁금한 점이 있으시면 언제든지 연락 주세요!\n\n감사합니다 🙏`;
    }
    if(t.match(/수업료.*인상|가격.*올|원비.*올/)){
      return `📢 **수업료 인상 안내문 초안**\n\n안녕하세요, ${name} 학부모님.\n\n물가 상승 및 교육 환경 개선을 위해 부득이하게 ○○년 ○월부터 수업료를 조정하게 되었습니다.\n\n• 변경 전: 월 ○○○,000원\n• 변경 후: 월 ○○○,000원\n• 적용 시작: ○○년 ○월 ○일부터\n\n학부모님의 넓은 양해를 부탁드리며, 더 나은 교육으로 보답하겠습니다.\n감사합니다.`;
    }
    if(t.match(/안녕|반가워|ㅎㅇ|hello|hi/)){
      return `안녕하세요! 😊 무엇을 도와드릴까요?\n\n아래 버튼을 눌러 자주 묻는 질문을 빠르게 확인하거나, 직접 질문해주세요!`;
    }
    return `🤖 **데모 모드 안내**\n\n현재 데모 모드로 운영 중이라 이 질문은 아직 지원하지 않아요.\n\n**지원되는 질문 예시:**\n• 오늘 결석 학생은?\n• 이번 달 미납자 알려줘\n• 출석률 낮은 학생은?\n• 학원 현황 요약해줘\n• 강사 목록 알려줘\n• 휴원 안내문 써줘\n\n💡 마무리 작업 시 AI API를 연동하면 어떤 질문이든 답할 수 있어요!`;
  };

  const send=()=>{
    if(!input.trim()||loading)return;
    const userMsg={role:'user',content:input.trim()};
    setMessages(prev=>[...prev,userMsg]);
    setInput('');
    setLoading(true);
    setTimeout(()=>{
      const reply=demoReply(userMsg.content);
      setMessages(prev=>[...prev,{role:'assistant',content:reply}]);
      setLoading(false);
    },600);
  };

  const quickQ=['오늘 결석 학생은?','이번 달 미납자 알려줘','출석률 낮은 학생은?','학원 현황 요약','휴원 안내문 써줘','학부모 감사 문자 초안'];
  const renderMsg=txt=>{const s=txt.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');return s.replace(/\*\*(.+?)\*\*/g,'<strong>$1</strong>').replace(/\n/g,'<br/>');}

  return<>
    {/* 플로팅 버튼 */}
    <button onClick={()=>setOpen(o=>!o)} title="AI 어시스턴트 (데모)"
      style={{position:'fixed',bottom:'28px',right:'28px',width:'58px',height:'58px',borderRadius:'50%',background:open?'#152d4a':'#1e3a5f',color:'white',fontSize:'22px',border:'none',cursor:'pointer',boxShadow:'0 6px 24px rgba(30,58,95,0.45)',zIndex:9999,display:'flex',alignItems:'center',justifyContent:'center',transition:'all 0.2s'}}
      onMouseEnter={e=>{e.currentTarget.style.transform='scale(1.08)';}}
      onMouseLeave={e=>{e.currentTarget.style.transform='scale(1)';}}>
      {open?'✕':'🤖'}
    </button>

    {/* 채팅 패널 */}
    {open&&<div style={{position:'fixed',bottom:'98px',right:'28px',width:'390px',maxHeight:'600px',background:'white',borderRadius:'18px',boxShadow:'0 12px 48px rgba(0,0,0,0.18)',zIndex:9998,display:'flex',flexDirection:'column',overflow:'hidden',border:'1px solid #e2e8f0',animation:'fadeIn 0.2s ease'}}>
      {/* 헤더 */}
      <div style={{background:'linear-gradient(135deg,#1e3a5f 0%,#2a4a70 100%)',padding:'14px 16px',display:'flex',alignItems:'center',justifyContent:'space-between',flexShrink:0}}>
        <div style={{display:'flex',alignItems:'center',gap:'10px'}}>
          <div style={{width:'38px',height:'38px',borderRadius:'50%',background:'rgba(255,255,255,0.15)',display:'flex',alignItems:'center',justifyContent:'center',fontSize:'20px',flexShrink:0}}>🤖</div>
          <div>
            <div style={{color:'white',fontWeight:'700',fontSize:'14px'}}>AI 어시스턴트</div>
            <div style={{color:'#fbbf24',fontSize:'11px',fontWeight:'600'}}>⚡ 데모 모드 · 마무리 시 AI API 연동 예정</div>
          </div>
        </div>
        <button onClick={()=>setMessages([{role:'assistant',content:'안녕하세요! 다시 시작합니다 😊 무엇이 궁금하신가요?'}])} title="대화 초기화"
          style={{background:'transparent',border:'none',color:'#93c5fd',cursor:'pointer',fontSize:'16px',padding:'4px',borderRadius:'6px'}}
          onMouseEnter={e=>e.currentTarget.style.background='rgba(255,255,255,0.1)'} onMouseLeave={e=>e.currentTarget.style.background='transparent'}>🔄</button>
      </div>

      {/* 메시지 목록 */}
      <div style={{flex:1,overflowY:'auto',padding:'16px',display:'flex',flexDirection:'column',gap:'12px',minHeight:0}}>
        {messages.map((m,i)=><div key={i} className="ai-msg" style={{display:'flex',justifyContent:m.role==='user'?'flex-end':'flex-start',alignItems:'flex-start',gap:'8px'}}>
          {m.role==='assistant'&&<div style={{width:'30px',height:'30px',borderRadius:'50%',background:'#dbeafe',display:'flex',alignItems:'center',justifyContent:'center',fontSize:'15px',flexShrink:0,marginTop:'2px'}}>🤖</div>}
          <div style={{maxWidth:'82%',padding:'10px 13px',borderRadius:m.role==='user'?'14px 14px 4px 14px':'4px 14px 14px 14px',
            background:m.role==='user'?'#1e3a5f':'#f1f5f9',color:m.role==='user'?'white':'#1e293b',
            fontSize:'13px',lineHeight:'1.6',wordBreak:'break-word'}}
            dangerouslySetInnerHTML={{__html:renderMsg(m.content)}}/>
        </div>)}
        {loading&&<div style={{display:'flex',alignItems:'center',gap:'8px'}}>
          <div style={{width:'30px',height:'30px',borderRadius:'50%',background:'#dbeafe',display:'flex',alignItems:'center',justifyContent:'center',fontSize:'15px'}}>🤖</div>
          <div style={{padding:'10px 14px',background:'#f1f5f9',borderRadius:'4px 14px 14px 14px',display:'flex',gap:'4px',alignItems:'center'}}>
            {[0,1,2].map(i=><span key={i} style={{width:'7px',height:'7px',borderRadius:'50%',background:'#94a3b8',display:'inline-block',animation:`bounce 1.2s ${i*0.2}s infinite`}}/>)}
          </div>
        </div>}
        <div ref={bottomRef}/>
      </div>

      {/* 빠른 질문 버튼 */}
      {messages.length<=1&&<div style={{padding:'0 12px 10px',display:'flex',gap:'6px',flexWrap:'wrap',flexShrink:0}}>
        {quickQ.map((q,i)=><button key={i} onClick={()=>{setInput(q);setTimeout(()=>{const e={target:{value:q}};},0);}}
          style={{padding:'5px 11px',background:'#dbeafe',color:'#1e3a5f',border:'none',borderRadius:'20px',fontSize:'11px',cursor:'pointer',fontWeight:'600'}}
          onMouseEnter={e=>e.currentTarget.style.background='#bfdbfe'} onMouseLeave={e=>e.currentTarget.style.background='#dbeafe'}
          onClick={()=>{
            const userMsg={role:'user',content:q};
            setMessages(prev=>[...prev,userMsg]);
            setLoading(true);
            setTimeout(()=>{setMessages(prev=>[...prev,{role:'assistant',content:demoReply(q)}]);setLoading(false);},600);
          }}>{q}</button>)}
      </div>}

      {/* 입력창 */}
      <div style={{padding:'12px',borderTop:'1px solid #e2e8f0',display:'flex',gap:'8px',alignItems:'flex-end',flexShrink:0,background:'white'}}>
        <textarea ref={inputRef} value={input} onChange={e=>setInput(e.target.value)}
          onKeyDown={e=>{if(e.key==='Enter'&&!e.shiftKey){e.preventDefault();send();}}}
          placeholder="질문을 입력하세요... (Enter 전송)"
          rows={1} style={{flex:1,padding:'9px 12px',border:'1px solid #e2e8f0',borderRadius:'10px',fontSize:'13px',resize:'none',outline:'none',lineHeight:'1.5',maxHeight:'88px',overflowY:'auto',fontFamily:'inherit'}}
          onInput={e=>{e.target.style.height='auto';e.target.style.height=Math.min(e.target.scrollHeight,88)+'px';}}/>
        <button onClick={send} disabled={loading||!input.trim()}
          style={{width:'38px',height:'38px',borderRadius:'10px',background:loading||!input.trim()?'#e2e8f0':'#1e3a5f',color:loading||!input.trim()?'#94a3b8':'white',border:'none',cursor:loading||!input.trim()?'default':'pointer',fontSize:'18px',display:'flex',alignItems:'center',justifyContent:'center',flexShrink:0}}>➤</button>
      </div>
    </div>}
  </>;
}

export default function App(){
  const[page,setPage]=useState('dashboard');
  const[teachers,setTeachers]=useLS('hm_teachers6',SAMPLE.teachers);
  const[classes,setClasses]=useLS('hm_classes6',SAMPLE.classes);
  const[students,setStudents]=useLS('hm_students6',SAMPLE.students);
  const[income,setIncome]=useLS('hm_income6',SAMPLE.income||[]);
  const[expenses,setExpenses]=useLS('hm_expenses6',SAMPLE.expenses);
  const[attendance,setAttendance]=useLS('hm_attendance6',SAMPLE.attendance);
  const[notices,setNotices]=useLS('hm_notices6',SAMPLE.notices||[]);
  const[videos,setVideos]=useLS('hm_videos6',SAMPLE.videos||[]);
  const[tuitions,setTuitions]=useLS('hm_tuitions6',SAMPLE.tuitions);
  const[consultations,setConsultations]=useLS('hm_consultations6',SAMPLE.consultations||[]);
  const[events,setEvents]=useLS('hm_events6',SAMPLE.events);
  const[makeups,setMakeups]=useLS('hm_makeups6',SAMPLE.makeups||[]);
  const[withdrawals,setWithdrawals]=useLS('hm_withdrawals6',SAMPLE.withdrawals||[]);
  const[achievements,setAchievements]=useLS('hm_achievements6',SAMPLE.achievements||[]);
  const[academyName,setAcademyName]=useLS('hm_academy_name','하모니 피아노 학원');
  const[baseUrl,setBaseUrl]=useLS('hm_base_url','학부모앱.html');
  const[tuitionDaySetting,setTuitionDaySetting]=useLS('hm_tuition_day_setting6',{mode:'joinDate',fixedDay:1});
  const[lastAutoGenMonth,setLastAutoGenMonth]=useLS('hm_last_auto_gen6','');
  // 로그인 / 권한 — role: null(로그아웃) | 'director'(원장) | 'teacher'(강사)
  const[role,setRole]=useState(null);
  const[loggedInTeacherId,setLoggedInTeacherId]=useState(null);
  const[accounts,setAccounts]=useLS('hm_accounts1',{director:{id:'director',pw:'1234'},teacher:{id:'teacher',pw:'5678'}});
  // ── Supabase 초기 동기화 ───────────────────────────────────────────────────
  useEffect(()=>{
    if(isBlank){console.log('[Blank 모드] Supabase 동기화 스킵 — 빈 상태로 시작');return;}
    (async()=>{
      try{
        const td=await dbLoad('teachers');
        if(td===null){console.warn('[Supabase] 연결 실패 — 로컬 데이터로 계속합니다');return;}
        if(td.length===0){
          // DB가 비어 있음 → 현재 로컬 데이터를 DB에 씀 (최초 1회)
          console.log('[Supabase] DB 초기 저장 중...');
          await Promise.all([
            dbSync('teachers',teachers),dbSync('classes',classes),dbSync('students',students),
            dbSync('income',income),dbSync('expenses',expenses),dbSync('attendance',attendance),
            dbSync('notices',notices),dbSync('videos',videos),dbSync('tuitions',tuitions),
            dbSync('consultations',consultations),dbSync('events',events),dbSync('makeups',makeups),
            dbSync('withdrawals',withdrawals),dbSync('achievements',achievements),
          ]);
          console.log('[Supabase] ✅ 초기 저장 완료');
        }else{
          // DB에 데이터 있음 → 불러와서 앱 상태 교체
          console.log('[Supabase] DB에서 데이터 로드 중...');
          const[cl,st,inc,exp,att,not,vid,tui,con,evt,mk,wd,ach]=await Promise.all([
            dbLoad('classes'),dbLoad('students'),dbLoad('income'),dbLoad('expenses'),
            dbLoad('attendance'),dbLoad('notices'),dbLoad('videos'),dbLoad('tuitions'),
            dbLoad('consultations'),dbLoad('events'),dbLoad('makeups'),dbLoad('withdrawals'),
            dbLoad('achievements'),
          ]);
          setTeachers(td);
          if(cl&&cl.length)setClasses(cl);
          if(st&&st.length)setStudents(st);
          if(inc&&inc.length)setIncome(inc);
          if(exp&&exp.length)setExpenses(exp);
          if(att&&att.length)setAttendance(att);
          if(not&&not.length)setNotices(not);
          if(vid&&vid.length)setVideos(vid);
          if(tui&&tui.length)setTuitions(tui);
          if(con&&con.length)setConsultations(con);
          if(evt&&evt.length)setEvents(evt);
          if(mk&&mk.length)setMakeups(mk);
          if(wd&&wd.length)setWithdrawals(wd);
          if(ach&&ach.length)setAchievements(ach);
          console.log('[Supabase] ✅ 로드 완료 - 강사:',td.length,'학생:',st?.length);
        }
      }catch(e){console.error('[Supabase] 초기화 오류:',e.message);}
    })();
  },[]);
  // ──────────────────────────────────────────────────────────────────────────
  const[pinModalOpen,setPinModalOpen]=useState(false);
  const[mobileOpen,setMobileOpen]=useState(false);
  // 대시보드 → 상세 페이지 연동 컨텍스트
  const[attContext,setAttContext]=useState(null);
  const[consultContext,setConsultContext]=useState(null);
  // 페이지 이동 시 컨텍스트 자동 클리어 (사이드바 직접 이동 시 이전 필터 초기화)
  useEffect(()=>{
    if(page!=='attendance')setAttContext(null);
    if(page!=='consultation')setConsultContext(null);
  },[page]);
  const reset=()=>{if(confirm('모든 데이터를 피아노 학원 기본 데이터로 초기화하시겠습니까?')){setTeachers(SAMPLE.teachers);setClasses(SAMPLE.classes);setStudents(SAMPLE.students);setIncome(SAMPLE.income||[]);setExpenses(SAMPLE.expenses);setAttendance(SAMPLE.attendance);setNotices(SAMPLE.notices||[]);setVideos(SAMPLE.videos||[]);setTuitions(SAMPLE.tuitions);setConsultations(SAMPLE.consultations||[]);setEvents(SAMPLE.events);setMakeups(SAMPLE.makeups||[]);setWithdrawals(SAMPLE.withdrawals||[]);setAchievements(SAMPLE.achievements||[]);}};
  // 1회성 자동 보정: 예전에 브라우저에 저장된 학원 데이터에 최신 기능(성인/청소년 분리, 개설일)이 빠져있으면
  // 화면을 열 때 자동으로 채워준다. classes는 두 가지를 보정하므로 setClasses를 한 번만 호출해서 합쳐서 적용한다
  // (만약 두 개의 useEffect로 나눠서 각각 setClasses를 부르면, 같은 시점에 둘 다 "수정 전" 값을 기준으로 계산해서
  //  나중에 실행된 쪽이 먼저 실행된 쪽의 수정 내용을 덮어써버리는 문제가 생길 수 있어 반드시 한 번에 처리해야 함).
  useEffect(()=>{
    const combined=classes.filter(c=>c.subject==='성인·청소년 과정');
    const oldC=combined.length===1?combined[0]:null;
    const teenId=oldC?oldC.id+'_teen':null;
    const needSplit=!!(oldC&&!classes.some(c=>c.id===teenId));
    const needOpenDate=classes.some(c=>!c.openDate);
    if(needSplit||needOpenDate){
      setClasses(prev=>{
        let next=prev;
        if(needSplit){
          const teenClass={...oldC,id:teenId,name:'청소년반',startTime:'18:30',endTime:'19:20'};
          next=next.map(c=>c.id===oldC.id?{...c,name:'성인반'}:c).concat(teenClass);
        }
        next=next.map(c=>c.openDate?c:{...c,openDate:(SAMPLE.classes.find(x=>x.id===c.id)||SAMPLE.classes.find(x=>x.name===c.name))?.openDate||'2024-01-01'});
        return next;
      });
      if(needSplit){
        setStudents(prev=>prev.map(s=>{
          if(s.grade==='성인')return s;
          const inOld=(s.enrolledClasses||[]).includes(oldC.id)||s.class===oldC.id;
          if(!inOld)return s;
          return{...s,enrolledClasses:(s.enrolledClasses||[]).map(id=>id===oldC.id?teenId:id),class:s.class===oldC.id?teenId:s.class};
        }));
        setAttendance(prev=>prev.map(a=>{
          if(a.type!=='student'||a.classId!==oldC.id)return a;
          const st=students.find(x=>x.id===a.refId);
          return st&&st.grade!=='성인'?{...a,classId:teenId}:a;
        }));
        setMakeups(prev=>prev.map(m=>{
          if(m.classId!==oldC.id)return m;
          const st=students.find(x=>x.id===m.studentId);
          return st&&st.grade!=='성인'?{...m,classId:teenId,className:'청소년반'}:m;
        }));
      }
    }
  },[]);
  // 매달 자동 수강료 생성: 로그인 후 이번달 내역이 없으면 전체 재원 학생 수강료를 자동 생성
  useEffect(()=>{
    if(!role)return;
    const curM=(()=>{const d=new Date();return`${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,'0')}`;})();
    if(lastAutoGenMonth===curM)return; // 이번달 이미 생성됨
    const monthStart=`${curM}-01`;
    const existingIds=new Set(tuitions.filter(t=>t.month===curM).map(t=>t.studentId));
    const activeStudents=students.filter(s=>s.status!=='withdrawn'&&s.joinDate&&s.joinDate<monthStart);
    const newRecords=[];
    activeStudents.forEach(s=>{
      if(existingIds.has(s.id))return;
      const amount=(s.enrolledClasses||[]).reduce((sum,cid)=>{
        const cls=classes.find(c=>c.id===cid);
        if(!cls)return sum;
        if(cls.closeDate&&cls.closeDate<monthStart)return sum;
        return sum+(cls.fee||0);
      },0);
      if(!amount)return;
      const dueDate=calcTuitionDueDate(s.joinDate,curM,tuitionDaySetting);
      newRecords.push({id:genId(),studentId:s.id,studentName:s.name,month:curM,amount,dueDate,paidDate:'',payMethod:'',status:'unpaid',note:'',isProrated:false});
    });
    if(newRecords.length>0)setTuitions(prev=>[...prev,...newRecords]);
    setLastAutoGenMonth(curM);
  },[role]);
  // 로그인 화면 — useEffect 포함 모든 훅 호출 후에 조건부 렌더링 (React 훅 규칙 준수)
  if(!role)return<LoginScreen onLogin={(r,tid)=>{setRole(r);setLoggedInTeacherId(tid||null);}} academyName={academyName} accounts={accounts} teachers={teachers}/>;
  return<div className="flex" style={{height:'100vh',overflow:'hidden'}}>
    {pinModalOpen&&<AccountChangeModal accounts={accounts} setAccounts={setAccounts} onClose={()=>setPinModalOpen(false)}/>}
    {/* 모바일 사이드바 열릴 때 뒤 어두운 오버레이 */}
    {mobileOpen&&<div onClick={()=>setMobileOpen(false)} style={{position:'fixed',inset:0,background:'rgba(0,0,0,0.45)',zIndex:199}}/>}
    <Sidebar page={page} setPage={setPage} teachers={teachers} students={students} classes={classes} academyName={academyName} role={role} onLogout={()=>{setRole(null);setLoggedInTeacherId(null);setPage('dashboard');setMobileOpen(false);}} mobileOpen={mobileOpen} onMobileClose={()=>setMobileOpen(false)}/>
    <div className="flex-1 flex flex-col" style={{minWidth:0,height:'100vh',overflow:'hidden'}}>
      <div className="bg-white border-b border-slate-200 px-4 py-3 flex items-center justify-between shrink-0">
        <div className="flex items-center gap-2 text-sm">
          {/* 모바일 햄버거 버튼 — 768px 미만에서만 표시 */}
          <button onClick={()=>setMobileOpen(true)} className="md:hidden w-8 h-8 flex items-center justify-center rounded-lg mr-1" style={{background:'transparent',border:'none',cursor:'pointer',color:'#1e3a5f',fontSize:'20px',lineHeight:1}}>☰</button>
          <span className="text-slate-700 font-semibold hidden md:block">🎹 {academyName}</span><span className="text-slate-400 hidden md:block">›</span>
          <span className="text-[#1e3a5f] font-bold text-base">{MENUS.find(m=>m.id===page)?.label}</span>
        </div>
        <div className="flex items-center gap-3">
          <span className={`text-xs font-bold px-2.5 py-1 rounded-full ${role==='director'?'bg-[#1e3a5f] text-white':'bg-blue-100 text-blue-700'}`}>{role==='director'?'🏫 원장':`👨‍🏫 ${loggedInTeacherId?(teachers.find(t=>t.id===loggedInTeacherId)?.name||'강사'):'강사'}`}</span>
          <span className="text-xs text-slate-700 font-semibold">{(()=>{const d=new Date();return`${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,'0')}-${String(d.getDate()).padStart(2,'0')}`;})()}</span>
          {role==='director'&&<button onClick={()=>setPinModalOpen(true)} className="text-xs text-slate-600 hover:text-slate-900 px-2 py-1 rounded hover:bg-slate-100 font-medium">🔐 계정 변경</button>}
          {role==='director'&&<button onClick={reset} className="text-xs text-slate-600 hover:text-slate-900 px-2 py-1 rounded hover:bg-slate-100 font-medium">데이터 초기화</button>}
        </div>
      </div>
      <main className="flex-1 p-6 overflow-y-auto" style={{background:'#f8fafc'}}>
        {page==='dashboard'&&<Dashboard teachers={teachers} students={students} classes={classes} income={income} expenses={expenses} tuitions={tuitions} attendance={attendance} consultations={consultations} setPage={setPage} setAttContext={setAttContext} setConsultContext={setConsultContext} role={role} loggedInTeacherId={loggedInTeacherId}/>}
        {page==='teachers'&&<TeacherManagement teachers={teachers} setTeachers={setTeachers} classes={classes} setClasses={setClasses} attendance={attendance} setAttendance={setAttendance}/>}
        {page==='classes'&&<ClassManagement classes={classes} setClasses={setClasses} teachers={teachers} students={students} role={role}/>}
        {page==='students'&&<StudentManagement students={students} setStudents={setStudents} classes={classes} withdrawals={withdrawals} setWithdrawals={setWithdrawals} tuitions={tuitions} setTuitions={setTuitions} role={role} loggedInTeacherId={loggedInTeacherId} tuitionDaySetting={tuitionDaySetting}/>}
        {page==='expense_submit'&&<ExpenseSubmit expenses={expenses} setExpenses={setExpenses} teachers={teachers} role={role} loggedInTeacherId={loggedInTeacherId}/>}
        {page==='budget'&&<BudgetManagement income={income} setIncome={setIncome} expenses={expenses} setExpenses={setExpenses}/>}
        {page==='tuition'&&<TuitionManagement tuitions={tuitions} setTuitions={setTuitions} students={students} classes={classes} income={income} setIncome={setIncome} tuitionDaySetting={tuitionDaySetting}/>}
        {page==='attendance'&&<AttendanceManagement attendance={attendance} setAttendance={setAttendance} teachers={teachers} students={students} classes={classes} attContext={attContext} clearAttContext={()=>setAttContext(null)} makeups={makeups} setMakeups={setMakeups} role={role} loggedInTeacherId={loggedInTeacherId}/>}
        {page==='notices'&&<NoticeManagement notices={notices} setNotices={setNotices} students={students} classes={classes} academyName={academyName} baseUrl={baseUrl}/>}
        {page==='videos'&&<VideoManagement videos={videos} setVideos={setVideos} students={students} teachers={teachers} academyName={academyName} baseUrl={baseUrl}/>}
        {page==='tax'&&<TaxManagement income={income} expenses={expenses}/>}
        {page==='consultation'&&<ConsultationManagement consultations={consultations} setConsultations={setConsultations} consultContext={consultContext} clearConsultContext={()=>setConsultContext(null)} teachers={teachers} role={role} loggedInTeacherId={loggedInTeacherId}/>}
        {page==='calendar'&&<CalendarView events={events} setEvents={setEvents} consultations={consultations} makeups={makeups} notices={notices} setNotices={setNotices} role={role} loggedInTeacherId={loggedInTeacherId} students={students} classes={classes}/>}
        {page==='makeup'&&<MakeupManagement makeups={makeups} setMakeups={setMakeups} students={students} classes={classes} teachers={teachers} role={role} loggedInTeacherId={loggedInTeacherId}/>}
        {page==='withdrawal'&&<StudentManagement students={students} setStudents={setStudents} classes={classes} withdrawals={withdrawals} setWithdrawals={setWithdrawals} tuitions={tuitions} setTuitions={setTuitions} role={role} loggedInTeacherId={loggedInTeacherId} tuitionDaySetting={tuitionDaySetting} defaultTab="withdrawn"/>}
        {page==='payslip'&&<PayslipManagement teachers={teachers} academyName={academyName} role={role} loggedInTeacherId={loggedInTeacherId}/>}
        {page==='achievement'&&<AchievementManagement achievements={achievements} setAchievements={setAchievements} students={students}/>}
        {page==='parent_portal'&&<ParentPortalManager students={students} notices={notices} videos={videos} attendance={attendance} academyName={academyName} setAcademyName={setAcademyName} baseUrl={baseUrl} setBaseUrl={setBaseUrl}/>}
        {page==='settings'&&<SettingsManagement
          academyName={academyName} setAcademyName={setAcademyName}
          baseUrl={baseUrl} setBaseUrl={setBaseUrl}
          accounts={accounts} setAccounts={setAccounts}
          teachers={teachers} setTeachers={setTeachers}
          tuitionDaySetting={tuitionDaySetting} setTuitionDaySetting={setTuitionDaySetting}
          allData={{teachers,classes,students,income,expenses,attendance,notices,videos,tuitions,consultations,events,makeups,withdrawals,achievements,accounts,academyName,baseUrl}}
          setAllData={d=>{
            if(d.teachers!==undefined)setTeachers(d.teachers);
            if(d.classes!==undefined)setClasses(d.classes);
            if(d.students!==undefined)setStudents(d.students);
            if(d.income!==undefined)setIncome(d.income);
            if(d.expenses!==undefined)setExpenses(d.expenses);
            if(d.attendance!==undefined)setAttendance(d.attendance);
            if(d.notices!==undefined)setNotices(d.notices);
            if(d.videos!==undefined)setVideos(d.videos);
            if(d.tuitions!==undefined)setTuitions(d.tuitions);
            if(d.consultations!==undefined)setConsultations(d.consultations);
            if(d.events!==undefined)setEvents(d.events);
            if(d.makeups!==undefined)setMakeups(d.makeups);
            if(d.withdrawals!==undefined)setWithdrawals(d.withdrawals);
            if(d.achievements!==undefined)setAchievements(d.achievements);
            if(d.accounts!==undefined)setAccounts(d.accounts);
            if(d.academyName!==undefined)setAcademyName(d.academyName);
            if(d.baseUrl!==undefined)setBaseUrl(d.baseUrl);
          }}
        />}
      </main>
    </div>
    <AIChatbot students={students} teachers={teachers} classes={classes} attendance={attendance} tuitions={tuitions} events={events} academyName={academyName}/>
  </div>;
}
